def retry_on_disconnect(count):
    def decorator(func):
        def func_wrapper(*args, **kwargs):
            tried_count = 0
            success = False
            while tried_count < count and not success:
                try:
                    tried_count += 1
                    func(*args, **kwargs)
                    success = True
                except (pexpect.EOF, pexpect.TIMEOUT):
                    pass
            if not success:
                print("SSH disconnected {} times".format(count))
        return func_wrapper
    return decorator


def check_and_wait(max_time, poll_time):
    def decorator(func):
        def func_wrapper(*args, **kwargs):
            curr_time = 0
            while curr_time <= max_time:
                res = func(*args, **kwargs)
                if res[0] == True:
                    return [True, res[1]]
                curr_time = curr_time + poll_time
                if curr_time <= max_time:
                    time.sleep(poll_time)
            return [False, res[1]]
        return func_wrapper
    return decorator


def check_tcp_port(host, port=22, timeout=5):
    """
    Checks the availability of a TCP port on a remote host.

    This function attempts to establish a TCP connection to a specific
    host and port. It is commonly used to verify if a service (like SSH,
    HTTP, or a database) is up and responding to network requests.

    Args:
        host (str): The IP address or hostname of the target machine.
        port (int, optional): The TCP port number to check. Defaults to 22 (SSH).
        timeout (int, optional): The maximum time in seconds to wait for a
            response before giving up. Defaults to 5.

    Returns:
        bool: True if the port is open and accepting connections,
              False if the connection fails or times out.

    Example:
        if check_tcp_port("192.168.1.10", port=80):
             print("Web server is active")
    """
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(timeout)
        result = sock.connect_ex((host, port))
        if result == 0:
            return True
        else:
            return False
    except socket.error:
        return False
    finally:
        sock.close()


