    def wait(self, duration, reason):
        # type: (int, str) -> None
        self.logger.info("Waiting for %d seconds. %s", duration, reason)
        time.sleep(duration)

    def hw_testbed(self):
        """ Detect if testbed is pm,vm or all vm """
        for machine in self.machines():
            if self.is_physical_machine(machine):
                return True
