    @classmethod
    def datadir(cls):
        basedir = os.path.dirname(os.path.realpath(__file__))
        return os.path.join(basedir, "data")

    def create_machine_log_folders(self):
        for machine in self.machines(mgmt_intf_required=False):
            self.mkpath(os.path.join(self.log_root, machine))

    def get_workdir(self, workdir):
        if len(os.path.dirname(workdir[:-1])) == 0:
            workdir = os.path.join(pref['testbeds_dir'], workdir)
        else:
            workdir = os.path.realpath(workdir)
        return workdir

    def load_config(self, config = None):
        if config is None:
            config = os.path.join(self.workdir, 'config.yaml')

        with open(config, 'r') as f:
            self.config = yaml.safe_load(f)

        if not self.config:
            raise YamlEmpty(config)

    def load_system_config(self):
        #workdir is now a vtest dir for systembed instead of a yamlpaht
        self.runner_systb #['system6', 'systembed_4and_7_telex', '10.99.120.11']
        yaml_path = os.path.join(self.workdir, "yamls","topology", "t"+self.runner_systb[0]+".yaml") #assumes t<systembed name>.yaml naming convention
        with open(yaml_path, 'r') as f:
            self.config = yaml.safe_load(f)

    def save_config(self, config_file=None):
        if config_file is None:
            config_file = os.path.join(self.workdir, 'config.yaml')
        with open(os.path.join(config_file), 'w') as f:
            yaml.dump(self.config, f)

    def load_state(self):
        path = os.path.join(self.workdir, 'state.yaml')

        with open(path, 'r') as f:
            self.state = yaml.safe_load(f)

        if not self.state:
            raise YamlEmpty(path)

    def save_state(self):
        with open(os.path.join(self.workdir, 'state.yaml'), 'w') as f:
            yaml.dump(self.state, f)

    def mkpath(self, path):
        try:
            os.makedirs(path)
        except OSError as ex:
            if ex.errno == errno.EEXIST and os.path.isdir(path):
                pass
            else:
                raise

    def now(self):
        return time.strftime("%Y-%m-%d %H:%M:%S")

    def verify(self, status):
        try:
            if not self.state['status'] == status:
                raise WrongState(status)
        except AttributeError:
            raise TestbedException('testbed "%s" not found' % self.workdir)

    def bringup_management_bed(self):
        self.state['status'] = 'up'
        self.state['since'] = self.now()
        self.save_state()
        res = self.setup_ssh_keys()
        return res

