    def stop_start_ftp_server(self, stop):
        self.sudo(['touch', self.workdir])
        done = []
        local_ftp_dir = os.path.join(self.workdir, 'ftp_dir')
        f = open(self.FTP,'r')
        ftp_info = f.read()
        f.close()
        ftp = os.path.join(self.workdir, os.path.basename(self.FTP))
        self.edit_ftp(ftp, ftp_info, local_ftp_dir)
        if stop:
            ret = self.ftp_server('stop', ftp)
        else:
            ret = self.ftp_server('start', ftp)
        return ret

