    def move_eth0_to_mgmt_vpn(self, confd_session, machine):
        try:
            confd_session.exec_cmd(machine, [ 'no', 'vpn', '0', 'interface', 'eth0' ], begin=True, commit=False)
            confd_session.exec_cmd(machine, [ 'vpn', '512', 'interface', 'eth0' ], begin=False, commit=False)
            confd_session.exec_cmd(machine, [ 'vpn', '512', 'interface', 'eth0', 'ip', 'dhcp-client' ], begin=False, commit=False)
            confd_session.exec_cmd(machine, [ 'no', 'vpn', '512', 'interface', 'eth0', 'shutdown' ], begin=False, commit=True, expect_timeout=2)
        except:
            confd_session.sessions['confd'][machine].close()

    def configure_vcontainer_interfaces(self, confd_session, machine):
        interfaces = self.config['machines'][machine]['interfaces']
        for interface in interfaces:
            if 'ip_list' in interfaces[interface]:
                vpn_id = interfaces[interface]['vpn']
                iface = interfaces[interface]['intf'][0]
                gateway = interfaces[interface]['gateway']
                cmd = [ 'vpn', vpn_id, 'interface', iface, 'ip', 'static-route 0.0.0.0/0', gateway ]
                confd_session.exec_cmd(machine, cmd, begin=True, commit=False)
                for ip in interfaces[interface]['ip_list']:
                    cmd = [ 'vpn', vpn_id, 'interface', iface, 'ip', 'address-list', ip ]
                    confd_session.exec_cmd(machine, cmd, begin=False, commit=False)
                confd_session.exec_cmd(machine, [ 'no', 'vpn', vpn_id, 'interface', iface, 'shutdown' ], begin=False, commit=True)

    def create_confd_session(self, machine):
        logfile = self.get_log_file_for_machine(machine)
        sessions = {'confd': {}}
        if self.machine_is_up(machine):
            session = self.get_machine_session(machine, 400, logfile)
            if session != -99:
                sessions['confd'][machine] = session
            else:
                for machine in sessions['confd']:
                    sessions['confd'][machine].close()
                    if sessions['confd'][machine].logfile != sys.stdout:
                        sessions['confd'][machine].logfile.close()
                return None
        else:
            return None

        confd_session = CONFDSession(self, sessions, self.logger)
        return confd_session

    def enable_dhcp_for_all_containers(self):
        for machine in self.machines(types=['container']):
            confd_session = None
            try:
                confd_session = self.create_confd_session(machine)
                interfaces = self.config['machines'][machine]['interfaces']
                for interface in interfaces:
                    vpn_id = interfaces[interface]['vpn']
                    iface = interfaces[interface]['intf'][0]
                    confd_session.exec_cmd(machine, [ 'vpn', vpn_id, 'interface', iface, 'ip', 'dhcp-client' ])
                    confd_session.exec_cmd(machine, [ 'no', 'vpn', vpn_id, 'interface', iface, 'shutdown'])
            finally:
                if confd_session:
                    confd_session.sessions['confd'][machine].close()

    def add_default_route(self, machine, confd_session, vpn, route):
        confd_session.exec_cmd(machine, ['vpn', vpn, 'ip', 'route', '0.0.0.0/0', route])

    def configure_vcontainer(self, machine):
        confd_session = None
        try:
            self.get_container_image(machine)
            self.machine_boot_wait(machine_list={machine:True}, hard_sleep=0)

            self.logger.info('Enabling third partition on %s' % machine)
            res = self.enable_third_partition(machine)
            time.sleep(5)
            if res[0] == False:
                self.logger.error(res[1])
            else:
                self.machine_boot_wait(machine_list={machine:True}, hard_sleep=20)

            confd_session = self.create_confd_session(machine)
            confd_session.exec_cmd(machine, ['system', 'host-name', machine])

            self.logger.info('Moving eth0 on vContainer to vpn 512')
            self.move_eth0_to_mgmt_vpn(confd_session, machine)
            time.sleep(3)
            # Creating new session because previous 'move_eth0_to_mgmt_vpn' closed the existing
            confd_session = self.create_confd_session(machine)
            print("touch on vcontainer")
            confd_session.create_files_for_signed_image('vm99')
            time.sleep(3)
            self.logger.info('Installing container image')
            self.install_container_image(confd_session, machine)
            time.sleep(3)

            self.logger.info("Configuring vcontainer's interfaces")
            self.configure_vcontainer_interfaces(confd_session, machine)
            self.logger.info("Bringing up container")
            self.bringup_containers(machine, confd_session)
            time.sleep(5)
        finally:
            if confd_session:
                confd_session.sessions['confd'][machine].close()
                if confd_session.sessions['confd'][machine].logfile != sys.stdout:
                    confd_session.sessions['confd'][machine].logfile.close()

    def bringup_containers(self, machine, confd_session):
        vc_config = self.config['machines'][machine]
        container_image = self.get_container_build(machine)
        for container in vc_config['containers']:
            confd_session.exec_cmd(
                machine, ['container', 'instance', container, 'image', container_image], begin=True, commit=False
            )
            confd_session.exec_cmd(
                machine, ['container', 'instance', container, 'memory 512'], begin=False, commit=False
            )
            confd_session.exec_cmd(
                machine,
                ['container', 'instance', container, r'allow-address 0.0.0.0/0 0 all'],
                begin=False,
                commit=False,
            )
            confd_session.exec_cmd(
                machine,
                ['container', 'instance', container, 'personality', vc_config['containers'][container]['personality']],
                begin=False,
                commit=False,
            )
            interfaces = vc_config['containers'][container]['interfaces']
            for interface in interfaces:
                confd_session.exec_cmd(machine,
                               ['container', 'instance', container, 'interface',interfaces[interface]['intf'][0], 'host-ip-address', interfaces[interface]['ip']], begin=False, commit=False)
            confd_session.exec_cmd(machine,
                           ['no', 'container', 'instance', container, 'shutdown'], begin=False, commit=True)


    def bringup_vcontainers(self):
        for machine in self.machines(types=['vm', 'pm'], include_vcontainer=True):
            if self.personality(machine) == 'vcontainer':
                print("Machine:" , machine)
                self.configure_vcontainer(machine)

