    def get_sessions(self, machine_list=None):
        """ Get the confd session """
        sessions = {'confd': {}, 'root': {}}
        if machine_list is None:
            machine_list = self.machines()
        for machine in machine_list:
            self.logger.info('[%s]: creating ssh for confd' % machine)
            logfile = self.get_log_file_for_machine(machine)
            if self.debug is True:
                logfile = sys.stdout
            confd_session = self.get_machine_session(machine, 25, logfile)
            if confd_session != -99:
                sessions['confd'][machine] = confd_session
            else:
                for machine in sessions['confd']:
                    sessions['confd'][machine].close()
                    if mch_sessions[machine].logfile != sys.stdout:
                        sessions['confd'][machine].logfile.close()
                        return None
        return sessions


    def get_http_session(self, ips=[]):
        """ Return http session handler """
        vtest_dir = os.path.dirname(os.path.dirname(os.path.realpath(__file__)))
        # setup the required params for VManage Session
        cookie_dir = os.path.join(vtest_dir, 'http_cookies')
        try:
            os.mkdir(cookie_dir)
        except OSError:
            pass
        cookie_file = os.path.join(cookie_dir, 'login.cookies')
        return VMANAGESession(self, self.logger, ips=ips)


    def get_license_session(self,
                            machine_list=None,
                            vmanage_session=None,
                            protocol_yaml=None):
        """ Return an license session """
        if machine_list is None:
            machine_list = self.machines()
        sessions = self.get_sessions(machine_list)
        vtest_dir = os.path.dirname(os.path.dirname(os.path.realpath(__file__)))
        if protocol_yaml is None:
            protocol_yaml = 'omp_dual.yaml'
        yaml_file_path = os.path.join(vtest_dir, 'yamls', 'protocols',
                                      protocol_yaml)
        api = Tests(yaml_file_path, [0, 512])
        api.set_machines_list(self.machines())
        confd = CONFDSession(self, sessions, self.logger, api)
        vs = ViptelaSession(self, api, self.logger, confd, False, False, None, None)
        return LicenseSession(self, api, confd, vs, vmanage_session, self.logger)


    def add_vsmarts_from_vmanage(self, vmanage_host, machine_list, http_session,
                                 personality):
        return_str = [True]
        for machine in machine_list:
            deviceIP = self.mgmt_ipaddr(machine)
            if deviceIP is not None:
                self.logger.info(
                    'Adding the controller : %s with ip : %s from vManage: %s' % (
                        machine, deviceIP, vmanage_host))
                res = http_session.add_controller_from_vmanage(
                    vmanage_host, deviceIP, personality)
                if res[0] == False:
                    self.logger.info(
                        'Failed to add controller : %s with ip: %s from vManage: %s'
                        % (machine, deviceIP, vmanage_host))
                    return_str[0] = False
                    return_str.append(res[1])
        return return_str


