    def generate_csr_and_send_it_to_ca_signing_server(self, vmanage, http_session,
                                                      mch_list):
        """ Generat the CSR and send it to CA signing server and wait till it is signed """
        for machine in mch_list:
            device_ip = self.get_system_ip(machine).split("/")[
                0] if self.personality(machine) == 'vmanage' else self.mgmt_ipaddr(
                    machine)
            self.logger.info('Generating csr for machine: %s with device ip: %s' %
                             (machine, device_ip))
            res = http_session.cert_generate_csr(
                vmanage, 'post', payload={
                    'deviceIP': device_ip
                })
            if res[0] == False:
                self.logger.info(
                    'Failed to generate CSR for machine: %s, deviceIP: %s, from vManage: %s'
                    % (machine, device_ip, vmanage))
                self.logger.info('Failed reason: %s' % res[1])
            time.sleep(5)
        self.wait_for_cert_installation(vmanage, http_session, mch_list)


    @check_and_wait(240, 30)
    def wait_for_cert_installation(self, vmanage, http_session, mch_list):
        self.logger.info('Wait for the CSR to be signed')
        res = http_session.cert_controller_list(vmanage)
        if res[0] == True:
            res = res[1]['data']
            status = [(item['deviceIP'], item['certInstallStatus'])
                      for item in res]
            self.logger.info('Status: %s' % status)
            status = [True if i[1] == 'Installed' else False for i in status]
            if False not in status:
                self.logger.info("All certs are installed, Send it to vBond")
                res = http_session.certificate_vsmart_list(vmanage)
                return [True, 'All certs successfully installed']
        return [False, 'Failed to install all certs']


    def do_certs_using_ca_server(self, vmanage, http_session, mch_list):
        """ Will do certs like we do for Symantec """
        self.logger.info('Configuring %s hostname to "ca"' % vmanage)
        res = self.config_common_name_on_local_signing_server(
            vmanage,
            host_name='ca')
        if res[0] == False:
            self.logger.info('Failed to configure %s\'s hostname to "ca"' %
                             vmanage)
        self.logger.info('Setting self signing url to : https://ca:1666')
        http_session.set_signing_server_url(vmanage, 'https://ca:1666')
        self.logger.info('Start CA server')
        self.start_ca_server('DUMMY')
        self.logger.info("wait for %s seconds for the server to start" % (30))
        self.logger.info('Do generate CSR for all the machines')
        self.generate_csr_and_send_it_to_ca_signing_server(vmanage, http_session,
                                                           mch_list)


