    def bringup_controllers(self, proto_yaml=None):
        """ Brings up controllers, Mostly vManage driven """
        # Make sure it doesn't setup certs. We do cert from vManage.
        mch_list = list(filter(
            self.filter_machine({
                'personality': ['vmanage', 'vsmart', 'vbond', 'ztp', 'inet']
            }),
            self.machines(types=['vm', 'pm'])))
        vmanage = list(filter(
            self.filter_machine({
                'personality': ['vmanage']
            }),
            self.machines(types=['vm'])))[-1]
        self.bringup_machines(mch_list, install_certs=False)
        http = self.get_http_session()
        ls = self.get_license_session(
            mch_list, vmanage_session=http, protocol_yaml=proto_yaml)
        res = [ls.config_machine(machine, 'vbond') if
               self.personality(machine) == 'vbond' else ls.config_machine(machine)
               for machine in mch_list]
        self.logger.info('Sleep for %s seconds before checking if vManage NMS is up' %120)
        time.sleep(120)
        self.check_if_vmanage_is_ready_for_rest_calls(vmanage, http)
        http.set_org_name_for_dca(vmanage, org_name=self.get_machine_org_name(vmanage))
        self.make_certificate_authorization_to_automated(vmanage, http)
        self.add_controllers_from_vmanage(vmanage, http)
        self.do_certs_using_ca_server(vmanage, http, mch_list)
        # TODO: Check Vbond has got the control connection to all the controllers .
        return 0


    def generate_uuid(self, number_of_uuids_to_generate, uuid_prefix=""):
        """ Generates uuids and send it as 2 list """
        uuid_list = []
        uuid_list_to_upload = []
        for i in range(number_of_uuids_to_generate):
            uuidNum = uuid.uuid4().urn.split(":")[-1]
            uuid_edited = uuid_prefix + uuidNum
            uuid_list.append(uuid_edited)
            uuid_list_to_upload.append([uuid_edited])
        return uuid_list, uuid_list_to_upload


