    def get_max_serial_id(self):
        index_file_path = os.path.join(self.workdir, 'root_ca', 'index.txt')
        max_serial_id = 0
        if os.path.isfile(index_file_path):
            with open(index_file_path, 'r') as index_file:
                for line in index_file:
                    line_parts = line.split('\t')
                    cur_serial_id = int(line_parts[3], 16) - 0x12345600
                    if cur_serial_id > max_serial_id:
                        max_serial_id = cur_serial_id
        return max_serial_id

    def setup_machines(self, machine_list, install_certs, smu=None):
        # Update Machine class's tb_config class member for machine.get_cli()
        Machines.register(self.config)
        proc_list = []
        threads = {}
        serial_id = self.get_max_serial_id()
        d = {}
        for machine in machine_list:
            serial_id += 1
            if not self.machine_setup_done(machine):
                threads[machine] = Thread(
                    target=self.run_func_and_record_exceptions,
                    args=(self.setup_machine, (machine, install_certs, serial_id, smu), d, machine),
                )
            else:
                logging.getLogger(machine).info("{} setup was already done".format(machine))
        for machine in threads:
            if not self.is_cloud_init():
                if self.is_cedge(machine):
                    time.sleep(60)
                else:
                    time.sleep(20)
            threads[machine].start()
        for machine in threads:
            threads[machine].join()
        if len(d) > 0:
            try:
                for machine in d:
                    exc_info = d[machine]
                    self.logger.error("{}: ".format(machine))
                    self.logger.error("=" * 20)
                    self.logger.error("".join(traceback.format_tb(exc_info[2])))
                    self.logger.error(exc_info[1])
                    self.logger.error("=" * 20)
            finally:
                msg = []
                for m in list(d.keys()):
                    msg.append(str(Path(VLogging.path).joinpath(m)))
                self.logger.error("For more details please examine per machine logs under:\n{}".format('\n'.join(msg)))
                raise TestbedBringupError("Setup failed for: {}".format(list(d.keys())))
        # persist config yaml changes to disk
        self.save_config()

    def setup_machine(self, machine, install_cert, serial_id, smu):
        machine_personality = self.personality(machine)
        self.logger.info(f"setup_machine({machine}) --> {machine_personality}".center(60, "-"))
        if machine_personality == 'nfvis':
            if not self.is_virtualized_nfvis(machine):
                self.setup_csr_nfvis(machine, None, None)
            else:
                self.initial_nfvis_config(machine)
        elif machine_personality == 'vcontainer':
            self.configure_vcontainer(machine)
        elif machine_personality == 'vmanage':
            self.setup_vmanage(machine, install_cert, serial_id)
        elif machine_personality == 'vbond':
            self.setup_vbond(machine, install_cert, serial_id)
        elif machine_personality == 'vsmart':
            self.setup_vsmart(machine, install_cert, serial_id)
        elif machine_personality == 'vedge' and machine.startswith("pm"):
            self.setup_pm_vedge(machine, install_cert, serial_id)
        elif machine_personality == 'vedge':
            self.setup_vm_vedge(machine, install_cert, serial_id)
        elif machine_personality in ['inet', 'ztp']:
            self.setup_vm_inet(machine, install_cert, serial_id)
        elif machine_personality == 'cedge_csr':
            if self.is_xe(machine) or self.is_autonomous(machine):
                return
            if self.is_cloud_init():
                self.upload_crt(machine)
                self.setup_cedge_netconf_interface(machine)
            else:
                self.setup_csr_cedge(machine, install_cert, serial_id, smu)
        elif machine_personality == 'cedge_c8kv_unid_esxi':
            self.setup_isr_cedge(machine, install_cert, serial_id, smu)
        elif machine_personality == 'cedge_isr':
            self.setup_isr_cedge(machine, install_cert, serial_id, smu)
        elif machine_personality == 'cedge_isrv':
            self.setup_isrv_cedge(machine, install_cert, serial_id, smu)
        elif machine_personality == 'cedge_asr':
            self.setup_isr_cedge(machine, install_cert, serial_id, smu)
        elif machine_personality == 'cedge_asr1002x':
            self.bringup_hw_cedge(machine)
            self.setup_csr_cedge(machine, install_cert, serial_id, smu)
        elif machine_personality == 'cedge_c1100':
            self.setup_c1100_cedge(machine, install_cert, serial_id, smu)
        elif machine_personality == 'cedge_sparrow':
            self.setup_c1100_cedge(machine, install_cert, serial_id, smu)
        elif self.is_highrise(machine):
            self.setup_highrise(machine, install_cert, serial_id)
        elif machine_personality == 'cedge_isr_curie':
            self.setup_isr_cedge(machine, install_cert, serial_id, smu)
        elif machine_personality == 'cedge_isr_mirabile':
            self.setup_isr_cedge(machine, install_cert, serial_id, smu)
        return

    def is_xe_mode(self, machine):
        return False

    def confd_is_up(self, machine, pexpect_session):
        pexpect_session.sendline('config-transaction')
        res = pexpect_session.expect(['Failed to connect to server', r'\(config\)#', pexpect.TIMEOUT], timeout=10)
        if res == 1:
            time.sleep(0.5)
            pexpect_session.sendline('exit')
            pexpect_session.expect(['{}#'.format(machine), "Router#", pexpect.TIMEOUT])
            return True
        else:
            return False

    def wait_for_cedge_config_transaction_ready(
        self, machine, pexpect_session, max_wait=600, poll_interval=5, expect_timeout=60
    ):
        start_time = time.time()
        while True:
            pexpect_session.sendline('config-transaction')
            res = pexpect_session.expect(
                [
                    r'\(config\)#',
                    'Services are still initializing',
                    'The system will be ready for use following the "All daemons up"',
                    'Failed to connect to server',
                    pexpect.TIMEOUT,
                ],
                timeout=expect_timeout,
            )
            if res == 0:
                return

            wait_time = int(time.time() - start_time)
            if wait_time >= max_wait:
                raise TestbedBringupError(
                    '{}: config-transaction still unavailable after waiting {} sec'.format(machine, wait_time)
                )

            self.logger.info('{}: config-transaction not ready yet, retrying in {} sec'.format(machine, poll_interval))
            try:
                pexpect_session.sendline('')
                pexpect_session.expect(r'.*#', timeout=10)
            except (pexpect.TIMEOUT, pexpect.EOF):
                pass
            time.sleep(poll_interval)

    def configure_ssh(self, machine, pexpect_session):
        pexpect_session.sendline('\r')
        res = pexpect_session.expect(
            ["{}#".format(machine), "Router#", r"{}\(config\)#".format(machine), r"Router\(config\)#"]
        )
        if res in [0, 1]:
            pexpect_session.sendline('config-transaction')
            pexpect_session.expect([r"{}\(config\)#".format(machine), r"Router\(config\)#"])
        self.logger.info("Configuring 'no logging console' on {}. With excessive logs on some platforms script may fail to catch the prompt".format(machine))
        self.send_command_and_check_prompt(pexpect_session, 'no logging console', r'\(config\)#')
        self.send_command_and_check_prompt(pexpect_session, 'commit', r'\(config\)#')
        self.send_command_and_check_prompt(pexpect_session, 'no username admin', r'\(config\)#')
        self.send_command_and_check_prompt(pexpect_session, 'commit', r'\(config\)#')
        # admin / ci5co#Net
        self.send_command_and_check_prompt(
            pexpect_session,
            'username admin privilege 15 secret 9 $9$Q4DzZWGlZeQ5R.$dSBCBBE6mootGOKvfFYvOlzqEXH9DImbad/Z1d8c66Y',
            r'\(config\)#',  # noqa: W605
        )
        self.update_machine_config(machine, 'ci5co#Net')

        pexpect_session.sendline('commit')
        res = pexpect_session.expect(['Commit complete', 'Device refused one or more commands', pexpect.TIMEOUT], timeout=5)
        if res == 1:
            self.logger.warn('Device refused one or more commands')

        time.sleep(1)
        pexpect_session.sendline('end')
        res = pexpect_session.expect(['Router#', 'Router>', '{}#'.format(machine), 'Uncommitted changes found', pexpect.TIMEOUT], timeout=5)
        if res == 3:
            pexpect_session.sendline('no')

        self.send_command_and_check_prompt(pexpect_session, 'config-transaction', r'\(config\)#')
        self.send_command_and_check_prompt(pexpect_session, 'line vty 0 4', r'\(config-line\)#')
        self.send_command_and_check_prompt(pexpect_session, 'transport input ssh', r'\(config-line\)#')
        self.send_command_and_check_prompt(pexpect_session, 'line vty 5 80', r'\(config-line\)#')
        self.send_command_and_check_prompt(pexpect_session, 'transport input ssh', r'\(config-line\)#')
        self.send_command_and_check_prompt(pexpect_session, 'exit', r'\(config\)#')
        self.send_command_and_check_prompt(pexpect_session, '\n', r'\(config\)#')
        self.send_command_and_check_prompt(pexpect_session, 'commit', r'\(config\)#', 5)


    def cedge_sdwan_save_configs(self, machine, pexpect_session):
        pexpect_session.sendline('show running-config | redirect bootflash:sdwan/ios.cli')
        res = pexpect_session.expect([r"Do you want to over write\?", pexpect.TIMEOUT])
        if res == 0:
            pexpect_session.sendline("\n")
        pexpect_session.expect(['{}#'.format(machine), 'Router'], timeout=60)
        pexpect_session.sendline('show sdwan running-config | redirect bootflash:sdwan/sdwan.cli')
        res = pexpect_session.expect([r"Do you want to over write\?", pexpect.TIMEOUT])
        if res == 0:
            pexpect_session.sendline("\n")
        pexpect_session.expect(['{}#'.format(machine), 'Router'], timeout=60)
        pexpect_session.sendline("dir bootflash:sdwan")
        pexpect_session.expect(['{}#'.format(machine), 'Router'], timeout=60)

    def cedge_sdwan_software_reset(self, machine, pexpect_session):
        pexpect_session.sendline('\n')
        pexpect_session.expect(['{}#'.format(machine), pexpect.TIMEOUT], timeout=5)
        pexpect_session.sendline('request platform software sdwan software reset')
        try:
            res = pexpect_session.expect(
                [
                    r'Are you sure you want to reset.*\[confirm\]',
                    "System is still initializing. Wait for PnP",
                    pexpect.TIMEOUT,
                ],
                timeout=10,
            )
            if res == 0:
                pexpect_session.sendline('\n')
            elif res == 1:
                raise Exception("{}: Software reset was not successful. System is still initializing".format(machine))
            pexpect_session.expect(['{}#'.format(machine), "Router#"], timeout=120)
        except pexpect.EOF:
            print("{}: SSH session closed. Assuming machine is reloading".format(machine))
        except pexpect.TIMEOUT:
            print("{}: Timed out waiting for prompt. Assuming machine is reloading".format(machine))

    def cedge_show_sdwan_software(self, machine, pexpect_session):
        pexpect_session.sendline('show sdwan software')
        pexpect_session.expect(r'#')
        return pexpect_session.before

    def cedge_sdwan_software_upgrade_confirm(self, machine, pexpect_session):
        pexpect_session.sendline('request platform software sdwan software upgrade-confirm')
        upgrade_state = pexpect_session.expect(['FAILED: install_commit', 'SUCCESS: install_commit', r'#'])
        if upgrade_state == 0:
            raise Exception("{}: Software upgrade-confirm was not successful.".format(machine))

    def cedge_sdwan_software_install(self, machine, pexpect_session, image_path, version):
        pexpect_session.sendline('\n')
        pexpect_session.expect(['{}#'.format(machine), pexpect.TIMEOUT], timeout=5)
        pexpect_session.sendline('request platform software sdwan software install {}'.format(image_path))
        pexpect_session.expect(["Started install", "Received installation request", "R0 Downloading"], timeout=240)
        pexpect_session.sendline('\n')
        pexpect_session.expect(
            ['Installation of {} complete'.format(version), "SUCCESS: install_add", pexpect.TIMEOUT], timeout=900
        )
        pexpect_session.sendline('\n')
        pexpect_session.expect(['{}#'.format(machine), pexpect.TIMEOUT], timeout=240)

    def cedge_sdwan_software_activate(self, machine, pexpect_session, version):
        activate_clean = False
        pexpect_session.sendline('\n')
        pexpect_session.expect(['{}#'.format(machine), pexpect.TIMEOUT], timeout=5)
        pexpect_session.sendline('request platform software sdwan software activate {}'.format(version))
        try:
            res = pexpect_session.expect(['{}#'.format(machine), pexpect.TIMEOUT], timeout=240)
            if res == 0:
                self.logger.info("Received the prompt after software activate")
                res = pexpect_session.expect(
                    [
                        'Please specify "clean" after activate <version> to proceed',
                        '.*Downgrade is not supported from controller. Use CLI with activate clean option',
                        pexpect.TIMEOUT,
                    ],
                    timeout=15,
                )
                if res == 0 or res == 1:
                    self.logger.info("Need to activate software with \"clean\" keyword")
                    activate_clean = True
                    pexpect_session.sendline('\n')
                    pexpect_session.expect(['{}#'.format(machine), pexpect.TIMEOUT], timeout=5)
                    pexpect_session.sendline('request platform software sdwan software activate {} clean'.format(version))
                    res = pexpect_session.expect(['{}#'.format(machine), pexpect.TIMEOUT], timeout=240)
                    if res == 0:
                        self.logger.info("Received the prompt after software activate")
                    else:
                        self.logger.error("Session timed out waiting for prompt")
            else:
                self.logger.error("Session timed out waiting for prompt")
        except pexpect.EOF:
            print("SSH session closed. Assuming machine is reloading")
        finally:
            return activate_clean

    def go_to_confd_prompt(self, machine_name, pexpect_session, hostname=None, username=None, password=None):
        self.logger.info(f"go_to_confd_prompt({machine_name})".center(60, "-"))
        max_time = 1200
        timed_out = False
        in_confd_prompt = False
        passwords = list(self.get_ssh_known_passswords(machine_name))
        pass_index = 0

        start_time = time.time()
        if not hostname:
            hostname = machine_name
        if not username:
            username = self.get_ssh_username(machine_name)
        if not password:
            if passwords:
                password = passwords[pass_index]
            else:
                password = self.get_ssh_password(machine_name)

        while not in_confd_prompt and not timed_out:
            try:
                timed_out = int(time.time() - start_time) >= max_time
                result = pexpect_session.expect(
                    [
                        'vedge#',
                        'vbond#',
                        'vsmart#',
                        'vmanage#',
                        '%s#' % hostname,
                        '(?:vbond|vsmart|vmanage|{}) login:'.format(hostname),  # 5
                        '[Pp]assword:',
                        'Login timed out',
                        'Login incorrect',  # 8
                        'System Initializing',
                        'You must set an initial admin password',  # 10
                        'Select persona for vManage',
                        'Available storage devices',
                        '(?:vedge|vbond|vsmart|vmanage|{}):'.format(hostname),
                        pexpect.TIMEOUT,
                        'vedge login:',  # 15
                    ],
                    timeout=20,
                )
                self.logger.info(f"go_to_confd_prompt({machine_name}) -> {result}".center(60, "-"))
                if result <= 4:
                    in_confd_prompt = True
                elif result == 5:
                    pexpect_session.sendline(username)
                    pexpect_session.expect(["Password:", pexpect.TIMEOUT], timeout=20)
                    pexpect_session.sendline(password)
                elif result == 6:
                    pexpect_session.sendline(password)
                elif result == 7:
                    continue
                elif result == 8:  # Login incorrect
                    if passwords:
                        pass_index = (pass_index + 1) % len(passwords)
                        password = passwords[pass_index]
                elif result == 9:
                    if "System Ready" not in pexpect_session.before:
                        pexpect_session.expect("System Ready", timeout=360)
                elif result == 10:  # 'You must set an initial admin password'
                    tmp_pass = 'ci5co#Net'
                    pexpect_session.expect(["Password:", pexpect.TIMEOUT], timeout=20)
                    pexpect_session.sendline(tmp_pass)
                    pexpect_session.expect(["Re-enter password:", pexpect.TIMEOUT], timeout=20)
                    pexpect_session.sendline(tmp_pass)
                    password = tmp_pass
                    self.update_machine_config(machine_name, tmp_pass)
                elif result == 11:
                    pexpect_session.sendline("1")
                    if pexpect_session.expect("Are you sure") == 0:
                        pexpect_session.sendline("y")
                elif result == 12:
                    self.logger.info("Creating storage device for vManage")
                    pexpect_session.expect("Select storage device to use")
                    pexpect_session.sendline("1")
                    pexpect_session.expect("Would you like to format")
                    pexpect_session.sendline("y")
                    pexpect_session.expect("Extracting vManage extra-packages", timeout=480)
                    self.logger.info("Extracting vManage extra-packages")
                    pexpect_session.expect(
                        ["Stopping services", "vManage Extra-Package Extraction Complete"], timeout=480
                    )
                    self.logger.info("Restarting vManage")
                    pexpect_session.expect("Starting services", timeout=600)
                    self.logger.info("Starting vManage services")
                    pexpect_session.expect(["System Ready", pexpect.TIMEOUT], timeout=300)
                elif result == 13:
                    pexpect_session.sendline("exit")
                    time.sleep(3)
                elif result == 14:
                    pexpect_session.sendline('\r')
                elif result == 15:
                    pexpect_session.expect(["System Ready", pexpect.TIMEOUT], timeout=300)
                    pexpect_session.sendline()
                    pexpect_session.expect(["vedge login:", pexpect.TIMEOUT], timeout=20)
                    pexpect_session.sendline(username)
                    pexpect_session.expect(["Password:", pexpect.TIMEOUT], timeout=20)
                    pexpect_session.sendline(password)
            finally:
                time.sleep(1)

        if timed_out and not in_confd_prompt:
            raise TestbedException("Couldn't get to Viptela CONFD prompt through console")

    def go_to_ios_prompt(
        self,
        machine,
        pexpect_session,
        tftp_image="tftp:image.bin",
        hostname=None,
        username=None,
        password=None,
        max_time=1200,
    ):
        in_ios_prompt = False
        timed_out = False
        passwords = list(self.get_ssh_known_passswords(machine))
        pass_index = 0

        start_time = time.time()
        if not hostname:
            hostname = machine
        if not username:
            username = self.get_ssh_username(machine)
        if not password:
            if passwords:
                password = passwords[pass_index]
            else:
                password = self.get_ssh_password(machine)

        pexpect_session.expect(['.*#', pexpect.TIMEOUT], timeout=3)
        while not in_ios_prompt and not timed_out:
            result = pexpect_session.expect(
                [
                    r'rommon\s*([1-9]|[1-9][0-9]|[1-9][0-9][0-9])\s*>',
                    'Press RETURN to get started',
                    'Username:',
                    '[Pp]assword:',
                    r'initial configuration dialog\? \[yes/no]:',
                    'Router>',  # 5
                    r'%s>' % hostname,
                    'Router#',
                    r'%s#' % hostname,
                    pexpect.TIMEOUT,
                    r'%s\(config.*\)#' % hostname,
                    'Uncommitted changes found, commit them',
                ],
                timeout=20,
            )

            if result == 9:
                time.sleep(1)
                pexpect_session.sendline('\r')
            elif result == 0:
                if not os.path.isdir('/tftpboot'):
                    raise TestbedException("HW went into rommon. And you don't have /tftpboot")
                else:
                    mgmt_ip = self.mgmt_ipaddr(machine)
                    #image_src = self.get_image_source_path(machine)
                    #self.download_image(image_src, '/tftpboot/image.bin')
                    tftp_conf = self.config['machines'][machine].get('tftp_boot_config', {})
                    pexpect_session.sendline("IP_ADDRESS={}".format(tftp_conf.get('ip_address', mgmt_ip)))
                    pexpect_session.expect([r'rommon.*>', pexpect.TIMEOUT], timeout=1)
                    pexpect_session.sendline("IP_SUBNET_MASK={}".format(tftp_conf.get('ip_subnet_mask', '255.255.255.0')))
                    pexpect_session.expect([r'rommon.*>', pexpect.TIMEOUT], timeout=1)
                    pexpect_session.sendline("DEFAULT_GATEWAY={}".format(tftp_conf.get('default_gateway', '10.0.99.1')))
                    pexpect_session.expect([r'rommon.*>', pexpect.TIMEOUT], timeout=1)
                    pexpect_session.sendline("TFTP_SERVER={}".format(tftp_conf.get('tftp_server', '10.0.99.1')))
                    pexpect_session.expect([r'rommon.*>', pexpect.TIMEOUT], timeout=1)
                    pexpect_session.sendline('boot {}'.format(tftp_image))
            elif result == 1:
                pexpect_session.sendline('\r')
                pexpect_session.sendline('\r')
                time.sleep(10)
            elif result == 2:  # 'Username:'
                pexpect_session.sendline(username)
                time.sleep(0.25)
            elif result == 3:  # '[Pp]assword:'
                pexpect_session.sendline(password)
                res = pexpect_session.expect(
                    ['password needs to be changed', 'Login invalid', 'Authentication failed', pexpect.TIMEOUT],
                    timeout=10,
                )
                if res == 0:  # 'password needs to be changed'
                    tmp_pass = 'ci5co#Net'
                    res = pexpect_session.expect(
                        ['Enter new password', pexpect.TIMEOUT],
                        timeout=5,
                    )
                    pexpect_session.sendline(tmp_pass)
                    res = pexpect_session.expect(
                        ['Confirm password', pexpect.TIMEOUT],
                        timeout=5,
                    )
                    pexpect_session.sendline(tmp_pass)
                    password = tmp_pass
                    self.update_machine_config(machine, tmp_pass)
                elif res in (1, 2):  # 'Login invalid' 'Authentication failed'
                    # looks like password didn't work, try next
                    if passwords:
                        pass_index = (pass_index + 1) % len(passwords)
                        password = passwords[pass_index]
            elif result == 4:
                pexpect_session.sendline('no')
                res = pexpect_session.expect(
                    [r'Would you like to terminate autoinstall\? \[yes\]:', pexpect.TIMEOUT], timeout=10
                )
                if res == 0:
                    pexpect_session.sendline('yes')
                    time.sleep(3)
                    pexpect_session.sendline('\r')
                pexpect_session.expect(['Press RETURN to get started', pexpect.TIMEOUT], timeout=10)
                pexpect_session.sendline('\r')
                pexpect_session.sendline('\r')
                time.sleep(150)
            elif result in [5, 6]:
                pexpect_session.sendline('enable')
                result = pexpect_session.expect(
                    ['% Error in authentication.', 'Router#', r'%s#' % hostname, pexpect.TIMEOUT], timeout=60
                )

                if result in [1, 2]:
                    pexpect_session.sendline('\r')
                elif result == 0:
                    self.logger.error(
                        'Root IOS prompt refused: "% Error in authentication.".'
                        'Attempting to drop back to login prompt'
                    )
                    pexpect_session.sendline('exit')
                    pexpect_session.expect(['Press RETURN to get started', pexpect.TIMEOUT], timeout=20)
                    pexpect_session.sendline('\r')
            elif result in [7, 8]:
                in_ios_prompt = True
                # Means last value of password had to work
                self.update_machine_config(machine, password)
            elif result == 10:
                pexpect_session.sendline('end')
            elif result == 11:
                pexpect_session.sendline('no')

            timed_out = int(time.time() - start_time) >= max_time

        if timed_out and not in_ios_prompt:
            raise TestbedException("Couldn't get IOS prompt through console")

    def wait_for_prompt(self, machine, pexpect_session):
        in_prompt = False
        timed_out = False
        max_time = 600
        start_time = time.time()
        pexpect_session.expect(['.*', pexpect.TIMEOUT], timeout=3)
        while not in_prompt and not timed_out:
            pexpect_session.sendline('\r')
            result = pexpect_session.expect(
                [
                    'rommon.*>',
                    'Username: ',
                    '[Pp]assword: ',
                    r'initial configuration dialog\? \[yes/no\]:',  # noqa: W605
                    'Router>',
                    r'%s>' % machine,  # noqa: W605
                    r'.*#',  # noqa: W605
                    'Press RETURN to get started',
                    pexpect.TIMEOUT,
                ],
                timeout=10,
            )
            if result == 8:
                time.sleep(20)
            elif result == 1:
                pexpect_session.sendline(self.get_ssh_username(machine))
                res = pexpect_session.expect(["Password: ", pexpect.TIMEOUT], timeout=3)
                if res == 0:
                    pexpect_session.sendline(self.get_ssh_password(machine))
                    res = pexpect_session.expect(['password needs to be changed', pexpect.TIMEOUT], timeout=10)
                    if res == 0:
                        pexpect_session.expect(['Enter new password', pexpect.TIMEOUT], timeout=10)
                        new_password = 'ci5co#Net'
                        pexpect_session.sendline(new_password)
                        pexpect_session.expect(['password', pexpect.TIMEOUT], timeout=10)
                        pexpect_session.sendline(new_password)
                        self.update_machine_config(machine, new_password)
            elif result == 2:
                pexpect_session.sendline(self.get_ssh_password(machine))
                res = pexpect_session.expect(['password needs to be changed', pexpect.TIMEOUT], timeout=10)
                if res == 0:
                    pexpect_session.expect(['Enter new password', pexpect.TIMEOUT], timeout=10)
                    new_password = 'ci5co#Net'
                    pexpect_session.sendline(new_password)
                    pexpect_session.expect(['password', pexpect.TIMEOUT], timeout=10)
                    pexpect_session.sendline(new_password)
                    self.update_machine_config(machine, new_password)
            elif result == 3:
                pexpect_session.sendline('no')
                res = pexpect_session.expect(
                    [r'Would you like to terminate autoinstall\? \[yes\]:', pexpect.TIMEOUT], timeout=10
                )
                if res == 0:
                    pexpect_session.sendline('yes')
                    time.sleep(3)
                    pexpect_session.sendline('\r')
                pexpect_session.expect(['Press RETURN to get started', pexpect.TIMEOUT], timeout=10)
                pexpect_session.sendline('\r')
                pexpect_session.sendline('\r')
                time.sleep(150)
            elif result in [0, 4, 5, 6]:
                in_prompt = True
            elif result == 7:
                pexpect_session.sendline('\r')
                pexpect_session.sendline('\r')
                time.sleep(90)
            timed_out = int(time.time() - start_time) >= max_time

        if timed_out and not in_prompt:
            raise TestbedException("Couldn't get IOS/rommon prompt through console")

    def go_to_dslam_prompt(self, machine, pexpect_session, user, password):
        in_dslam_prompt = False
        timed_out = False
        pexpect_session.sendline('\r\n')
        result = pexpect_session.expect(['>>User name',pexpect.TIMEOUT], timeout=5)
        if result == 0:
            pexpect_session.sendline(user)
            pexpect_session.expect(['>>User password', pexpect.TIMEOUT], timeout=1)
            pexpect_session.sendline(password)
            pass_result = pexpect_session.expect(['MA5616>', 'Username or password invalid', pexpect.TIMEOUT], timeout=1)
            if pass_result == 0:
                pexpect_session.sendline('en')
                pexpect_session.expect(['MA5616#', pexpect.TIMEOUT], timeout=1)
                pexpect_session.sendline('idle-timeout 255')
                pexpect_session.expect(['MA5616#', pexpect.TIMEOUT], timeout=1)
            elif pass_result == 1:
                raise TestbedException("login to the DSLAM box failed")

    def send_command_and_check_prompt(self, pexpect_session, command, prompt=None, timeout=15):
        ret = True
        pexpect_session.sendline(command)
        if prompt is not None:
            if type(prompt) == str:
                prompt = unicode(prompt)
            res = pexpect_session.expect([prompt, pexpect.TIMEOUT], timeout)
            ret = res == 0
            if res != 0:
                self.logger.error("Couldn't get prompt {} after: {}".format(prompt, command))
        return ret

    def cedge_stop_pnp(self, machine, pexpect_session):
        pexpect_session.logfile = self.get_log_file_for_machine(machine)
        pexpect_session.logfile.write('>>>> testbed.cedge_stop_pnp  <<<<\n')
        self.go_to_ios_prompt(machine, pexpect_session)
        start_time = time.time()
        pnp_wait = 900
        confd_is_up = False
        time_passed = 0
        while (time_passed < pnp_wait) and not confd_is_up:
            time.sleep(1)
            time_passed = int(time.time()) - int(start_time)
            pexpect_session.sendline("config-transaction")
            res = pexpect_session.expect(
                [
                    r"\(config\)#",  # noqa: W605
                    "terminate PnP with the following command",
                    "The system will be ready for use following the \"All daemons up\"",
                    "reload action requested",
                    pexpect.TIMEOUT,
                ],
                timeout=10,
            )
            if res == 0:
                confd_is_up = True
                self.logger.info("CONFD came up after {} sec".format(time_passed))
                pexpect_session.sendline('exit')
                time.sleep(1)
                pexpect_session.expect(['{}#'.format(machine), 'Router#', pexpect.TIMEOUT], timeout=10)
            elif res == 1:
                self.logger.info("{}: Terminating pnp service discovery".format(machine))
                pexpect_session.sendline('pnpa service discovery stop')
                pexpect_session.expect(
                    ["Stopping PnP Discovery", "PNP cannot be aborted because its not running", pexpect.TIMEOUT],
                    timeout=10,
                )
                pexpect_session.sendline('\n')
                pexpect_session.expect(['{}#'.format(machine), 'Router#', pexpect.TIMEOUT], timeout=10)
            elif res == 2:
                self.logger.info("{}: Waiting for \"all daemons up\" message".format(machine))
                if pexpect_session.expect(['All daemons up', pexpect.TIMEOUT], timeout=60) == 0:
                    self.logger.info("{}: Received \"All daemons up\" message".format(machine))
                    time.sleep(10)
                else:
                    self.logger.warn("{}: Didn't get \"All daemons up\" message".format(machine))
                pexpect_session.sendline('\n')
                pexpect_session.expect(['{}#'.format(machine), 'Router#', pexpect.TIMEOUT], timeout=10)
            elif res == 3:
                pexpect_session.expect("Initializing Hardware")
                self.go_to_ios_prompt(machine, pexpect_session)
            else:
                self.logger.warn("[cedge_stop_pnp]{}: Timedout after config-transaction".format(machine))
                pexpect_session.sendline('pnpa service discovery stop')
                pexpect_session.expect(
                    ["Stopping PnP Discovery", "PNP cannot be aborted because its not running", pexpect.TIMEOUT],
                    timeout=10,
                )
                time.sleep(20)
                pexpect_session.sendline('\n')
                pexpect_session.expect(['{}#'.format(machine), 'Router#', pexpect.TIMEOUT], timeout=10)
        if not confd_is_up:
            raise TestbedException("Confd is not up after trying to stop PnP for {} sec".format(time_passed))

    def initial_config(self, machine, pexpect_session):
        if self.machine_is_vm(machine):
            return self.initial_csr_config(machine)
        pexpect_session.logfile = self.get_log_file_for_machine(machine)
        pexpect_session.logfile.write('>>>> testbed.initial_config  <<<<\n')
        self.go_to_ios_prompt(machine, pexpect_session)
        start_time = time.time()
        pnp_wait = 600
        confd_is_up = False
        time_passed = 0
        while (time_passed < pnp_wait) and not confd_is_up:
            time_passed = int(time.time()) - int(start_time)
            pexpect_session.sendline("config-transaction")
            res = pexpect_session.expect(
                [
                    r"\(config\)#",
                    "terminate PnP with the following command",
                    "The system will be ready for use following the \"All daemons up\"",
                    pexpect.TIMEOUT,
                ],
                timeout=10,
            )
            if res == 0:
                confd_is_up = True
            elif res == 1:
                self.logger.info("{}: Terminating pnp service discovery".format(machine))
                pexpect_session.sendline('pnpa service discovery stop')
                pexpect_session.expect(
                    ["Stopping PnP Discovery", "PNP cannot be aborted because its not running", pexpect.TIMEOUT],
                    timeout=10,
                )
                pexpect_session.sendline('\n')
                pexpect_session.expect(['.*#', pexpect.TIMEOUT], timeout=10)
            elif res == 2:
                self.logger.info("{}: Waiting for \"all daemons up\" message".format(machine))
                if pexpect_session.expect(['All daemons up', pexpect.TIMEOUT], timeout=360) == 0:
                    self.logger.info("{}: Received \"All daemons up\" message".format(machine))
                else:
                    self.logger.warn("{}: Didn't get \"All daemons up\" message".format(machine))
                pexpect_session.sendline('\n')
                pexpect_session.expect(['.*#', pexpect.TIMEOUT], timeout=10)
            else:
                self.logger.warn("[initial_config]{}: Timedout after config-transaction".format(machine))
                pexpect_session.sendline('pnpa service discovery stop')
                pexpect_session.expect(
                    ["Stopping PnP Discovery", "PNP cannot be aborted because its not running", pexpect.TIMEOUT],
                    timeout=10,
                )
                time.sleep(20)
                pexpect_session.sendline('\n')
                pexpect_session.expect(['.*#', pexpect.TIMEOUT], timeout=10)
        if not confd_is_up:
            raise TestbedException("Confd is not up after trying to stop PnP for {} sec".format(time_passed))
        self.configure_ssh(machine, pexpect_session)
        self.send_command_and_check_prompt(pexpect_session, 'hostname %s' % machine, r'.*#')
        self.send_command_and_check_prompt(pexpect_session, 'ip domain name vtest.cisco.com', r'.*#')
        try:
            self.send_command_and_check_prompt(
                pexpect_session, 'logging discriminator nosel facility drops SELINUX', r'\(config\)#'
            )
            self.send_command_and_check_prompt(pexpect_session, 'logging console discriminator nosel', r'\(config\)#')
        except Exception as ex:
            self.logger.warn("{}: Couldn't disable SELINUX logging: {}".format(machine, ex))
        time.sleep(2)
        mgmt_intf_name = self.get_mgmt_interface_name(machine)
        mgmt_intf_ip = self.get_mgmt_interface_ip(machine)
        mgmt_intf_config = self.config['machines'][machine]['interfaces']['MGMT']
        mgmt_intf_vnet = mgmt_intf_config.get('vnet')
        mgmt_intf_source = mgmt_intf_config.get('source', 'nonlaas')
        if mgmt_intf_source == 'laas':
            mgmt_intf_netmask = mgmt_intf_config.get('netmask', '255.255.255.0')
        elif mgmt_intf_vnet in self.config['vnets']:
            mgmt_intf_netmask = self.config['vnets'][mgmt_intf_vnet].get('netmask', '255.255.255.0')
        else:
            mgmt_intf_netmask = mgmt_intf_config.get('netmask', '255.255.255.0')
        ip_address_config = 'ip address {} {}'.format(mgmt_intf_ip, mgmt_intf_netmask)
        mgmt_route_vrf = self.config['machines'][machine]['interfaces']['MGMT'].get('vrf')
        mgmt_route_default_gateway = self.config['machines'][machine]['interfaces']['MGMT'].get('default_gateway')
        host_ip = self.config['machines'][machine]['interfaces']['MGMT'].get('host_ip')
        host_ip_route_config = None
        if mgmt_route_vrf:
            ip_route_config = 'ip route vrf {} 0.0.0.0 0.0.0.0 {}'.format(mgmt_route_vrf, mgmt_route_default_gateway)
            if host_ip is not None:
                host_ip_route_config = 'ip route vrf {} {} 255.255.255.255 {}'.format(
                    mgmt_route_vrf, host_ip, mgmt_route_default_gateway
                )
        else:
            ip_route_config = 'ip route 0.0.0.0 0.0.0.0 {}'.format(mgmt_route_default_gateway)
            if host_ip is not None:
                host_ip_route_config = 'ip route {} 255.255.255.255 {}'.format(host_ip, mgmt_route_default_gateway)
        # Legacy code and test suites assume intf in vnet99 should be confifured with dhcp
        if mgmt_intf_config.get('vnet') == '99':
            ip_address_config = 'ip address dhcp'
        if mgmt_intf_config.get('type') == 'l2_vlan':
            time.sleep(5)
            self.send_command_and_check_prompt(pexpect_session, 'vlan 99', r'.*#', 5)
            time.sleep(6)
