            time.sleep(2)
            self.send_command_and_check_prompt(pexpect_session, 'exit', r'.*#', 5)
            time.sleep(2)
            self.send_command_and_check_prompt(pexpect_session, 'exit', r'.*#', 5)
            time.sleep(2)
            self.send_command_and_check_prompt(pexpect_session, 'interface {}'.format(mgmt_intf_name), r'.*#', 5)
            time.sleep(2)
            self.send_command_and_check_prompt(pexpect_session, 'switchport access vlan 99', r'.*#', 5)
            time.sleep(2)
            self.send_command_and_check_prompt(pexpect_session, 'switchport mode access', r'.*#', 5)
