            self.send_command_and_check_prompt(pexpect_session, 'no shutdown', r'.*#', 5)
            time.sleep(2)
            self.send_command_and_check_prompt(pexpect_session, 'exit', r'.*#', 5)
            time.sleep(2)
            self.send_command_and_check_prompt(pexpect_session, 'int Vlan99', r'.*#', 5)
