    def get_telnet_console(self, machine):
        console_info = self.config['machines'][machine]['console']
        telnet_ip = console_info['ip']
        telnet_port = console_info['port']
        if six.PY2:
            child = pexpect.spawn('telnet {} {}'.format(telnet_ip,telnet_port),
                              maxread=10000,
                              logfile=self.get_log_file_for_machine(machine))
        else:
            child = pexpect.spawn('telnet {} {}'.format(telnet_ip,telnet_port),
                              maxread=10000,
                              logfile=self.get_log_file_for_machine(machine), encoding='utf-8', codec_errors='ignore')

        res = child.expect(['Connected to', 'Connection closed by foreign host'])
        if res == 1:
            self.logger.error('Console for %s is locked by other session' % machine)
            raise TestbedException('Console for %s is locked by other session' % machine)

        res = child.expect(['login: ', pexpect.TIMEOUT], timeout=2)
        if res == 0:
            if "user" in console_info and "password" in console_info:
                child.sendline(console_info["user"])
                child.expect("[P|p]assword:")
                child.sendline(console_info["password"])
            else:
                raise TestbedException('{}: telnet credentials are not specified in topology YAML'.format(machine))
        child.sendline('\r\n')
        res = child.expect(['Connection closed by foreign host', pexpect.TIMEOUT], timeout=3)
        if res == 0:
            self.logger.error('Console for %s is locked by other session' % machine)
            raise TestbedException('Console for %s is locked by other session' % machine)
        return child

    def login_to_machine(self, session, machine):
        authenticated = False
        timed_out = False
        max_time = 120
        start_time = time.time()
        if session:
            session.expect(['.*', pexpect.TIMEOUT], timeout=3)
            while not authenticated and not timed_out:
                session.sendline('\r\n')
                expected_list = [
                    'rommon.*>',
                    'Username: ',
                    'Password: ',
                    r'initial configuration dialog\? \[yes/no\]:',
                    'Router[>#]',
                    '%s[>#]' % machine,
                    'Uncommitted changes found, commit them',
                    r'\(config\)#',
                    'Press RETURN to get started',
                    pexpect.TIMEOUT]
                result = session.expect(expected_list, timeout=10)
                if result in [0, 4, 5]:
                    authenticated = True
                if result == 1:
                    session.sendline(self.get_ssh_username(machine))
                    res = session.expect(["Password: ", pexpect.TIMEOUT], timeout=3)
                    if res == 0:
                        session.sendline(self.get_ssh_password(machine))
                elif result == 2:
                    session.sendline(self.get_ssh_password(machine))
                elif result == 3:
                    session.sendline('no')
                    res = session.expect(
                        [r'Would you like to terminate autoinstall\? \[yes\]:', pexpect.TIMEOUT], timeout=10
                    )
                    if res == 0:
                        session.sendline('yes')
                        time.sleep(3)
                        session.sendline('\r\n')
                    session.expect(['Press RETURN to get started', pexpect.TIMEOUT], timeout=10)
                    session.sendline('\r\n')
                    session.sendline('\r\n')
                    time.sleep(150)
                elif result == 6:
                    time.sleep(1)
                    session.sendline('no')
                    time.sleep(1)
                elif result == 7:
                    time.sleep(1)
                    session.sendline('end')
                    time.sleep(1)
                elif result == 8:
                    session.sendline('\r\n')
                    session.sendline('\r\n')
                    time.sleep(90)
                timed_out = int(time.time() - start_time) >= max_time

