    def setup_dhcpd_conf(self):
        '''
        Launch a dhcpd on vnet 5 to serve dhcp to nfvis vm's running on
        external ucs.
        Returns True if dhcpd.conf file was written. It updates the file,
        not overwrites, but won't preserve any comments
        '''
        dh = DhcpdConf('/etc/dhcp/dhcpd.conf')
        vnet, router_ip = self.get_route_info('vm3', 5)
        if not router_ip:
            return False
        dhcp_range = ['10.0.5.102', '10.0.5.120']
        pnp_ip = '10.0.5.180'
        dh.add_subnet(router_ip, vnet['subnet'], vnet['netmask'],
                      dhcp_range=dhcp_range,
                      vendor_options='5A1D;B2;K4;I%s;J9191'%pnp_ip)
        # Add NFVIS devices to dhcp hosts file
        machines = self.get_machine_configs('nfvis')
        for machine_name, config in machines.items():
            machine_pref = pref.get(
                    'machine-settings', {}).get(machine_name, {})
            ifname = machine_pref.get('nfvis-ifname', 'colo-mgmt')
            interface = self.get_interface(machine_name, ifname)
            assert interface, '%s missing interface "%s"' % (machine_name, ifname)

            # This value is still needed in individual hosts, seems like
            # only provisioning router entry with this is not sufficient.
            # TODO: Get the right pnp ip from the associated router or
            # switch instead of individual machine setting.
            pnp_ip = '10.0.5.180'
            dhcp_options = machine_pref.get('dhcp-options', {})
            dh.add_host(machine_name, ipaddr=interface['ip'],
                        netmask='255.255.255.0',
                        router_ip=dhcp_options.get('routers', router_ip),
                        domain=dhcp_options.get('domain-name', ''),
                        dns=dhcp_options.get('domain-name-servers', ''),
                        dhcp_id=interface.get('dhcp-id', ''),
                        hwaddr=interface.get('mac', ''),
                        vendor_options='5A1D;B2;K4;I%s;J9191'%pnp_ip)
        # Configure switches relative to their cluster if in one
        switches = pref.get('sw_config', {})
        clusters = pref.get('clusters', {})
        for name, switch in list(switches.items()):
            if not switch.get('mac', None):
                continue
            cluster = [ v for v in list(clusters.values(
                                )) if name in v.get('switches', []) ]
            cluster = cluster[0] if cluster else {}
            # Get pnp ip from cluster but if the setting is in the switch
            # then that takes precedence. If it's nowhere, then default to
            # 10.0.5.180
            pnp_ip = switch.get('pnp-ip', cluster.get('pnp-ip', '10.0.5.180'))
            dh.add_host(name, hwaddr=switch['mac'],
                        ipaddr=switch['ip'],
                        vendor_options='5A1D;B2;K4;I%s;J9191'%pnp_ip)
        dh.dump('/etc/dhcp/dhcpd.conf', superuser=True)
        return True

    def get_machine_pref(self, machine):
        # XXX: machine-settings in local.preference.yaml is an outdated way to
        # override settings in the config yaml, back when there wasn't any good
        # vtest infrastructure. This should no longer be used for anything, and
        # should be deleted completely.
        return pref.get('machine-settings', {}).get(machine, {})

    def setup_dhcp_for_nfvis(self):
        machines = self.get_machine_configs('nfvis')
        nfvis_with_mac = set(
            self.config['machines'][machine]["interfaces"]["MGMT"].get("mac", None)
            for machine in machines
            if self.config['machines'][machine]["interfaces"]["MGMT"].get("mac", None)
        )

        if not nfvis_with_mac:
            return

        # FIXME: Adjust below assert for RH flavor
        assert os.path.exists('/etc/default/isc-dhcp-server'),\
            'Please run `sudo apt install isc-dhcp-server`'
        if self.setup_dhcpd_conf():
            Dhcpd().start()

    def setup_csr_nfvis(self, machine, install_cert, serial_id):
        config = self.config['machines'][machine]
        if not config.get('password', None):
            config['password'] = NfvisSession.password
        ucs_name = config['ucs']
        ucs_config = self.config['machines'][ucs_name]
        if not ucs_config.get('password', None):
            ucs_config['password'] = UcsSession.password
        ucs_ip = self.mgmt_ipaddr(ucs_name)
        ip = None
        with UcsSession(ucs_ip, name=ucs_name) as ucs:
            with ucs.get_nfvis_serial_session(verbose=True) as nfvis:
                ip = nfvis.renew_dhcp()
        if ip != self.mgmt_ipaddr(machine):
            if ip == None:
                raise Exception('Unable to retrieve IP address for Nfvis(%s)'%(
                                machine))
            self.patch_mgmt_ip(machine, ip)
        logging.getLogger(machine).info("Done setting up machine: {}".format(machine))
        return 0

    def setup_virtual_cedge(self, machine, install_cert, serial_id, smu):
        self.logger.info(f"setup_virtual_cedge({machine})".center(60, "-"))
        self.validate_smu_with_base(machine, smu)
        mgmt_ip = self.mgmt_ipaddr(machine)
        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.setup_virtual_cedge <<<<\n")
        cert = Cert(self, None, None, serial_id, self.logger)
        with CedgeSession(mgmt_ip, logfile) as cedge_session:
            cedge_session.discard_uncommitted_changes()
            cedge_session.logging_persistent()
            cedge_session.set_hostname(machine)
            cedge_session.set_time()

        if install_cert:
            self.setup_cedge_certs(machine, serial_id)
        self.setup_cedge_netconf_interface(machine)
        self.mark_machine_as_done(machine)
        if smu and re.match(r'^(vm5|pm5)$', machine):
            return self.apply_smu_patch(machine, smu)
        logging.getLogger(machine).info("Done setting up machine: {}".format(machine))
        return 0

    def setup_isrv_cedge(self, machine, install_cert, serial_id, smu):
        if self.machine_boot_wait(hard_sleep=10, machine_list={machine: True}, max_wait=600) == 0:
            return self.setup_virtual_cedge(machine, install_cert, serial_id, smu)
        else:
            raise TestbedBringupError("Couldn't SSH to {}".format(machine))

    def setup_csr_cedge(self, machine, install_cert, serial_id, smu):
        self.logger.info(f"setup_csr_cedge({machine})".center(60, "-"))
        self.initial_csr_config(machine)
        return self.setup_virtual_cedge(machine, install_cert, serial_id, smu)

    def setup_cedge_certs(self, machine, serial_id):
        self.logger.info(f"setup_cedge_certs({machine})".center(60, "-"))
        machine_personality = self.personality(machine)
        org_name = self.get_machine_org_name(machine)
        mgmt_ip = self.mgmt_ipaddr(machine)
        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.setup_cedge_certs <<<<\n")
        self.clear_cedge_certificates(machine)
        with CedgeSession(mgmt_ip, logfile) as cedge_session:
            cedge_session.set_organization_name(org_name)
        self.setup_cedge_root_certificate(machine, serial_id)
        if machine_personality in ["cedge_csr", "cedge_c8kv", "cedge_isrv", "cedge_asr1002x", "cedge_c8kv_unid_esxi"]:
            self.setup_cedge_signed_certificate(machine, serial_id, org_name)

    def clear_cedge_certificates(self, machine):
        self.logger.info(f"clear_cedge_certificates({machine})".center(60, "-"))
        cedge_pexpect_session = self.get_cisco_csr_session(machine, 30)
        try:
            confd = CONFDSession(self, {'confd': {machine: cedge_pexpect_session}}, self.logger)
            self.logger.info(f"confd.clear_install_cert({machine})".center(60, "-"))
            result = confd.clear_install_cert(machine)
            if result[0]:
                self.logger.info("Certificates cleared on %s" % machine)
            else:
                self.logger.error(result[1])
        except Exception as ex:
            self.logger.exception(ex)
        finally:
            cedge_pexpect_session.close()

    def setup_cedge_root_certificate(self, machine, serial_id):
        self.logger.info(f"setup_cedge_root_certificate({machine})".center(60, "-"))
        root_ca_path = os.path.join(self.workdir, 'root_ca')
        mgmt_ip = self.mgmt_ipaddr(machine)
        cert = Cert(self, None, None, serial_id, self.logger)
        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.setup_cedge_root_certificate <<<<\n")
        with CedgeSession(mgmt_ip, logfile) as cedge_session:
            self.copy_to_machine(machine, os.path.join(root_ca_path, 'cacert.pem'), 'sdwan/cacert.pem')
            cedge_session.request_root_cert_chain_install('bootflash:sdwan/cacert.pem')

    def setup_cedge_signed_certificate(self, machine, serial_id, org_name):
        mgmt_ip = self.mgmt_ipaddr(machine)
        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.setup_cedge_signed_certificate <<<<\n")
        if (not self.openssl_checked) and (not self.is_cloud_init()):
            check_openssl_version()
            self.openssl_checked = True
        with CedgeSession(mgmt_ip, logfile) as cedge_session:
            cedge_session.request_csr_upload('bootflash:sdwan/csr', org_name)
            self.copy_from_machine(machine, 'sdwan/csr', os.path.join(self.workdir, machine, 'csr'))
            if self.is_cloud_init():
                self.sign_machine_csr_cloud_init(machine, org_name)
            else:
                self.sign_machine_csr(machine, serial_id)
            self.copy_to_machine(machine, os.path.join(self.workdir, machine, 'crt'), 'sdwan/crt')
            cedge_session.request_certificate_install('bootflash:sdwan/crt')

    def setup_c1100_cedge(self, machine, install_cert, serial_id, smu):
        time.sleep(120)
        return self.setup_isr_cedge(machine, install_cert, serial_id, smu)

    def setup_highrise(self, machine, install_cert, serial_id):
        root_ca_path = os.path.join(self.workdir, 'root_ca')
        machine_config = self.config['machines'][machine]
        image_path = os.path.join(self.workdir, machine, "{}.bin".format(machine))
        host_router_config = machine_config['host_router']
        host_router_name = host_router_config['name']
        host_mgmt_ip = host_router_config['mgmt_ip']
        host_username = host_router_config['username']
        host_password = host_router_config['password']
        host_intf = host_router_config['interfaces'][0]['intf']
        host_intf_address = host_router_config['interfaces'][0]['ip']
        host_mgmt_network = host_router_config['mgmt_ip'].split('.')[0] + '.0.0.0'

        aon_secure_password_configured = False

        cert = Cert(self, None, None, serial_id, self.logger)
        if not os.path.isfile(image_path):
            raise Exception("Image {} not found at".format(image_path))
        self.logger.info("Copying highrise.bin to host router")
        self.copy_to_machine(
            machine, image_path, 'highrise.bin', mgmt_ip=host_mgmt_ip, user=host_username, password=host_password
        )
        if not self.is_aon(machine):
            self.logger.info("Copying CA cert to host router")
            self.copy_to_machine(
                machine,
                os.path.join(root_ca_path, 'cacert.pem'),
                'sdwan/cacert.pem',
                mgmt_ip=host_mgmt_ip,
                user=host_username,
                password=host_password,
            )
        logfile = self.get_log_file_for_machine(machine)
        host_console_config = host_router_config['console']

        self.logger.info("Logging to the host router")
        with ConsoleFactory(host_console_config) as host_console_session:
            host_console_session.logfile = logfile
            self.go_to_ios_prompt(host_router_name, host_console_session, username=host_username,password=host_password)
            self.logger.info("Found prompt of the host router, starting configuration process")
            host_console_session.sendline('config-transaction')
            host_console_session.expect('connected')
            host_console_session.expect(r'\(config\)#')
            host_console_session.sendline('interface {}'.format(host_intf))
            host_console_session.sendline('ip address {} 255.255.255.0'.format(host_intf_address))
            # For AON setup, there is no need to configure tunnels
            # so this code snippet is omitted
            if not self.is_aon(machine):
                host_console_session.sendline('ip address dhcp')
                host_console_session.expect(r'\(config-if\)#')
                host_console_session.sendline('interface Tunnel0')
                host_console_session.sendline('ip unnumbered {}'.format(host_intf))
                host_console_session.sendline('tunnel source {}'.format(host_intf))
                host_console_session.sendline('tunnel mode sdwan')
                host_console_session.expect(r'\(config-if\)#')
                host_console_session.sendline('ip tftp source-interface {}'.format(host_intf))
                host_console_session.expect(r'\(config\)#')
                host_console_session.sendline('sdwan')
                host_console_session.expect(r'\(config-sdwan\)#')
                host_console_session.sendline('interface {}'.format(host_intf))
                host_console_session.sendline('tunnel-interface')
                host_console_session.sendline('encapsulation ipsec')
                host_console_session.sendline('allow-service all')
                host_console_session.expect(r'\(config-tunnel-interface\)#')
                host_console_session.sendline('tftp-server bootflash:sdwan/cacert.pem')
                host_console_session.expect(r'\(config\)#')
            host_console_session.sendline('tftp-server bootflash:highrise.bin')
            host_console_session.expect(r'\(config\)#')
            host_console_session.sendline('ip route %s 255.0.0.0 %s dhcp' % (host_mgmt_network,host_intf))
            host_console_session.expect(r'\(config\)#')
            host_console_session.sendline('commit')
            host_console_session.expect(['Commit complete', '% No modifications to commit'])
            host_console_session.sendline('end')
            host_console_session.expect('{}#'.format(host_router_name))
            if not self.is_aon(machine):
                host_console_session.sendline('show ip inter b | inc {}'.format(host_intf))
                host_console_session.expect(r'\d+\.\d+\.\d+\.\d+')
                highrise_ip = host_console_session.after
            else:
                highrise_ip = host_intf_address
            self.logger.info("Configuration completed")
        console_config = machine_config['console']
        machine_hostname = machine_config.get('hostname', machine)
        if not self.is_aon(machine):
            time.sleep(10)
        self.logger.info("Starting console session with the {}".format(machine))
        with ConsoleFactory(console_config) as console_session:
            console_session.logfile = logfile
            self.logger.info("Trying to find prompt")
            if not self.is_aon(machine):
                self.go_to_ios_prompt(machine, console_session, hostname=machine_hostname)
            else:
                try:
                    self.go_to_ios_prompt(machine, console_session, hostname=machine_hostname, max_time=60)
                except TestbedException:
                    self.logger.info("iOS prompt not found. Trying to login with secure password.")
                    self.go_to_ios_prompt(
                        machine,
                        console_session,
                        hostname=machine_hostname,
                        password=self.get_secure_password(machine),
                        max_time=60,
                    )
                    aon_secure_password_configured = True
            date_format = 'date %Y-%m-%d time %H:%M:%S'
            date = datetime.datetime.now(tz=pytz.utc)
            clock_cmd = 'gw-action:request clock set %s' % date.strftime(date_format)
            console_session.sendline('')
            console_session.expect('#')
            self.logger.info("Starting upgrade process")
            console_session.sendline("gw-action:request software upgrade tftp://{}/highrise.bin".format(highrise_ip))
            console_session.expect(r'Continue\? \[no,yes\]')
            console_session.sendline('yes')
            if self.is_aon(machine):
                index = console_session.expect(
                    [
                        'Software Download successful and file highrise.bin successfully verified',
                        "corrupted",
                        pexpect.TIMEOUT,
                    ],
                    timeout=600,
                )
                if index != 0:
                    self.logger.info('Single step update process of %s failed. Trying a multi-stage one.' % machine)
                    console_session.sendline(
                        "gw-action:request software download tftp://{}/highrise.bin".format(highrise_ip)
                    )
                    console_session.expect('Download successful', timeout=600)
                    self.logger.info("Image download successful")
                    console_session.sendline("gw-action:request software activate highrise.bin")
                    console_session.expect('Software Succesfully activated highrise.bin', timeout=1500)
            else:
                console_session.expect('Software Download succesful', timeout=1200)
                console_session.expect('Software Succesfully upgraded', timeout=240)
            console_session.expect('#')
            self.logger.info("Successfully upgraded {}".format(machine))
            console_session.sendline(clock_cmd)
            console_session.expect('#')
            if not self.is_aon(machine):
                console_session.sendline(
                    "gw-action:request file download tftpip {} filename sdwan/cacert.pem".format(highrise_ip)
                )
                console_session.expect('#')
                console_session.sendline(
                    "gw-action:request file download tftp://{}/sdwan/cacert.pem".format(highrise_ip)
                )
                console_session.expect('#')
                self.logger.info("downloaded cert on {}".format(machine))
                console_session.sendline("request root-cert-chain install /flash/cacert.pem")
                console_session.expect('#')
                self.logger.info("installed cert on {}".format(machine))
            console_session.sendline("gw-action:request system reboot")
            console_session.expect(r'System is about to reload, Continue\?')
            console_session.sendline("yes")
            self.logger.info("Rebooting {}".format(machine))
            time.sleep(120)
            if not self.is_aon(machine):
                self.go_to_ios_prompt(machine, console_session, hostname=machine_hostname)
            else:
                # If aon_secure_password_configured is set, we're sure that AON is using secure password
                if aon_secure_password_configured:
                    self.logger.info("Logging in using secure password")
                    self.go_to_ios_prompt(
                        machine,
                        console_session,
                        hostname=machine_hostname,
                        password=self.get_secure_password(machine),
                        max_time=300,
                    )
                # There can be a case, when AON is already logged in while running the script
                # in such case we won't have information if AON is using default or secure password
                # that's why we need to check both options
                else:
                    try:
                        self.go_to_ios_prompt(machine, console_session, hostname=machine_hostname, max_time=300)
                    except TestbedException:
                        self.logger.info("Trying to login with secure password.")
                        self.go_to_ios_prompt(
                            machine,
                            console_session,
                            hostname=machine_hostname,
                            password=self.get_secure_password(machine),
                            max_time=300,
                        )
        self.state['machines'][machine]['state'] = 'up'
        self.save_state()

    def setup_isr_cedge(self, machine, install_cert, serial_id, smu):
        self.logger.info(f"setup_isr_cedge({machine})".center(60, "-"))
        self.validate_smu_with_base(machine, smu)
        self.bringup_hw_cedge(machine)
        if self.is_cloud_init():
            self.logger.info("{}: Waiting for SSH to be ready and enable netconf".format(machine))
            self.wait_machine_ssh_ready(machine, max_wait=300)
            self.setup_cedge_netconf_interface(machine)
            return 0

        machine_path = os.path.join(self.workdir, machine)
        root_ca_path = os.path.join(self.workdir, 'root_ca')
        mgmt_ip = self.mgmt_ipaddr(machine)

        if self.machine_boot_wait(max_wait=20, machine_list={machine: True}) == 1:
            self.enable_ssh_on_isr(machine)
        # Opening logfile and session again due to reboot
        logfile = self.get_log_file_for_machine(machine)
        logfile.write("Setting up HW cEdge")
        print("Continue configuring HW node")
        cert = Cert(self, None, None, serial_id, self.logger)
        with CedgeSession(mgmt_ip, logfile) as cedge_session:
            pnp_wait = 450
            if not cedge_session.is_confd_running():
                cedge_session.stop_pnp()
                time.sleep(pnp_wait)
            if not cedge_session.is_confd_running():
                raise TestbedBringupError('Confd is still not up after stopping PnP and waiting for {} sec'.format(pnp_wait))
            cedge_session.discard_uncommitted_changes()
            cedge_session.logging_persistent()
            cedge_session.set_hostname(machine)
            cedge_session.set_time()
        if install_cert:
            self.setup_cedge_certs(machine, serial_id)
        self.setup_cedge_netconf_interface(machine)

        # leave console in clean state
        if "console" in self.config['machines'][machine]:
            console_config = self.config['machines'][machine]['console']
            with ConsoleFactory(console_config) as session:
                self.login_to_machine(session, machine)

        self.mark_machine_as_done(machine)
        logging.getLogger(machine).info("Done setting up machine: {}".format(machine))
        if smu and re.match(r'^(vm5|pm5)$', machine):
            return self.apply_smu_patch(machine, smu)

        return 0

    def config_upgrade_timer(self, machine, session, timer=5):
        """
        Configure the upgrade timer on the machine.

        :param machine: The name of the machine.
        :param session: The console session.
        :param timer: The upgrade timer value in minutes.
        """
        try:
            session.sendline('config-transaction')
            session.expect('connected')
            session.expect([r'\(config\)#', pexpect.TIMEOUT], timeout=60)
            session.sendline("system upgrade-confirm {}".format(timer))
            session.expect([r'\(config-system\)#', pexpect.TIMEOUT], timeout=60)
            session.sendline('commit')
            session.expect(['Commit complete', '% No modifications to commit'])
            res = session.expect([r"#", pexpect.TIMEOUT], timeout=10)  # noqa: W605
            session.sendline('end')
            res = session.expect([r"#", pexpect.TIMEOUT], timeout=10)  # noqa: W605
            if res == 0:
                self.logger.info("config system upgrade-confirm completed {}".format(machine))
                return 0
            else:
                self.logger.info("config system upgrade-confirm failed  for {}".format(machine))
                return 0
        except pexpect.TIMEOUT as e:
            self.logger.error("Timeout occurred while configuring upgrade timer for {0}: {1}".format(machine, e))

    def clear_install_state(self, machine, session):
        """
        Configure the service internal and clear install state on the machine.

        :param machine: The name of the machine.
        :param session: The console session.
        """
        try:
            session.sendline('config-transaction')
            session.expect('connected')
            session.expect([r'\(config\)#', pexpect.TIMEOUT], timeout=60)
            session.sendline("service internal")
            session.expect([r'\(config\)#', pexpect.TIMEOUT], timeout=60)
            session.sendline('commit')
            session.expect(['Commit complete', '% No modifications to commit'])
            session.expect([r"#", pexpect.TIMEOUT], timeout=10)  # noqa: W605
            session.sendline('end')
            session.expect([r"#", pexpect.TIMEOUT], timeout=10)  # noqa: W605
            session.sendline('clear install state')
            session.expect(['Press y to continue [y/n]', pexpect.TIMEOUT], timeout=60)
            session.sendline('y')
            res = session.expect(['Username:', pexpect.TIMEOUT], timeout=600)
            if res == 0:
                self.go_to_ios_prompt(machine, session)
                self.logger.info("clear install state completed {}".format(machine))
                return 0
            else:
                self.logger.info("config system upgrade-confirm failed  for {}".format(machine))
                raise TestbedBringupError("FAILED:to clear the install state")
        except pexpect.TIMEOUT as e:
            self.logger.error("error occured while clear the install state for {0}: {1}".format(machine, e))
            raise TestbedBringupError("error occured while clear the install state")

    def validate_smu_with_base(self, machine, smu):
        """
        validate an SMU patch to a machines base image.

        :param machine: The name of the machine to apply the patch to.
        :param smu: The SMU file path.
        """
        if smu and re.match(r'^(vm5|pm5)$', machine):
            image_path = os.path.join(self.workdir, machine, "{}.bin".format(machine))
            cmd1 = [
                'strings',
                image_path,
                '|',
                'grep',
                '-m',
                '1',
                '"CW_FULL_VERSION"',
                '|',
                'cut',
                '-f2',
                '-d',
                '"$"',
                '|',
                'cut',
                '-f1-5',
                '-d"."',
            ]
            cmd2 = [
                'strings',
                smu,
                '|',
                'grep',
                '-m',
                '1',
                '"CW_FULL_VERSION"',
                '|',
                'cut',
                '-f2',
                '-d',
                '"$"',
                '|',
                'cut',
                '-f1-5',
                '-d"."',
            ]

            ver1 = subprocess.Popen(cmd1, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
            ver2 = subprocess.Popen(cmd2, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
            ver1out, ver1err = ver1.communicate()
            ver2out, ver2err = ver2.communicate()
            if ver1out == ver2out:
                self.logger.info("SMU {0} match with base BASE {1}".format(ver2out, ver1out))
                return 0
            else:
                raise TestbedBringupError("SMU {0} mismatch with base BASE {1}".format(ver2out, ver1out))

    def apply_smu_patch(self, machine, smu):
        """
        Apply an SMU patch to a machine.

        :param machine: The name of the machine to apply the patch to.
        :param smu: The SMU file path.
        """
        # Retrieve the current software version on the machine
        version_info = self.get_cedge_version(machine)
        image_file_name = os.path.basename(smu)
        if version_info:
            version = version_info[1]
            self.logger.info(
                "Machine '{0}' is currently running software version '{1}'. Preparing to apply SMU patch.".format(
                    machine, version
                )
            )
        else:
            self.logger.info(
                "Applying SMU patch '{0}' to machine '{1}' with software version '{2}'.".format(
                    image_file_name, machine, version
                )
            )
            raise TestbedBringupError("FAILED: Unable to retrieve software version.")

        # Extract the image file name from the SMU file path
        self.copy_to_machine(machine, smu, image_file_name)
        console_config = self.config['machines'][machine]['console']
        smu_file = self.generate_smu_file(machine, image_file_name)
        self.logger.info("generate_smu_file result: {smu_file}".format(**{"smu_file": smu_file}))

        with ConsoleFactory(console_config) as session:
            try:
                self.go_to_ios_prompt(machine, session)
                self.cedge_stop_pnp(machine, session)
                result = self.config_upgrade_timer(machine, session)
                self.logger.info("config_upgrade_timer result: {result}".format(**{"result": result}))
                result = self.install_smu(machine, session, image_file_name)
                self.logger.info("install_smu result: {result}".format(**{"result": result}))
                if result:
                    raise TestbedBringupError("install_smu failed")
                smu_type = self.get_smu_type(machine, image_file_name)
                self.logger.info("smu type: {smu_type}".format(**{"smu_type": smu_type}))
                result = self.activate_smu(machine, session, smu_file)
                self.logger.info("activate_smu result: {result}".format(**{"result": result}))
                if result == 1:
                    raise TestbedBringupError("activate_smu failed")
                if smu_type == "reload":
                    time.sleep(20)
                    self.go_to_ios_prompt(machine, session)
                    self.cedge_stop_pnp(machine, session)
                result = self.commit_installation(machine, session)
                self.logger.info("commit_installation result: {result}".format(**{"result": result}))
                if result:
                    raise TestbedBringupError("commit_installation failed")
                res = self.verify_smu_installation(machine, session, "SMU   C")
                self.logger.info("verify_smu_installation result: {result}".format(**{"result": res}))
                if res:
                    raise TestbedBringupError("smu_installation  failed to C - Activated & Committed")
            except Exception as e:
                raise TestbedBringupError("smu_installation encountered an error: {}".format(e))
        return result

    def get_smu_type(self, machine, image_file_name):
        """
        get type of SMU reload/non-reload on the machine.

        :param machine: The name of the machine.
        :param image_file_name: The image file name.
        """
        try:
            confd = self.create_confd_session(machine)
            ncs = NewCedgeSession(machine, confd, timeout=60)
            result = ncs.show("show install package bootflash:" + image_file_name + " | section SMU Type:")
            smu_type = result[1].split(':')
            return smu_type[-1].strip().split('\r')[0]
        except Exception as e:
            raise TestbedBringupError("get_smu_type encountered an error: {}".format(e))

    def generate_smu_file(self, machine, image_file_name):
        """
        generate the SMU <version.cdetid> on the machine.

        :param machine: The name of the machine.
        :param image_file_name: The image file name.
        """
        try:
            confd = self.create_confd_session(machine)
            ncs = NewCedgeSession(machine, confd, timeout=60)
            result = self.show_smu_version(ncs, image_file_name)
            return result
        except Exception as e:
            raise TestbedBringupError("generate_smu_file encountered an error: {e}".format(**{"e": e}))

    def verify_smu_installation(self, machine, session, state=""):
        """
        verify the SMU on the machine.

        :param machine: The name of the machine.
        :param session: The console session.
        :param state: The smu state.
        """
        try:
            logging.getLogger(machine).info('Verifying show install summary')
            confd = self.create_confd_session(machine)
            ncs = NewCedgeSession(machine, confd, timeout=60)
            result = ncs.show("show install summary")
            logging.getLogger(machine).info('result:{}'.format(result))
            if state in result[1]:
                return 0
            return 1
        except Exception as e:
            raise TestbedBringupError("verify_smu encountered an error: {}".format(e))

    def install_smu(self, machine, session, image_file_name):
        """
        Install the SMU on the machine.

        :param machine: The name of the machine.
        :param session: The console session.
        :param image_file_name: The image file name.
        """
        try:
            logger = logging.getLogger(machine)
            logger.info('install add SMU')
            cmd = "request platform software sdwan smu install bootflash:{0}".format(image_file_name)
            session.sendline(cmd)
            result = session.expect(
                ["SUCCESS: install_add.*", "FAILED: install_add.*", "FAILED: Improper State", pexpect.TIMEOUT],
                timeout=600,
            )
            if result == 2:
                self.clear_install_state(machine, session)
                session.sendline(cmd)
                result = session.expect(
                    ["SUCCESS: install_add.*", "FAILED: install_add.*", "FAILED: Improper State", pexpect.TIMEOUT],
                    timeout=600,
                )
            return result
        except Exception as e:
            raise TestbedBringupError("install_smu encountered an error: {}".format(e))

    def activate_smu(self, machine, session, smu):
        """
        Activate the SMU on the machine.

        :param machine: The name of the machine.
        :param session: The console session.
        :param smu: The smu name.
        """
        try:
            logger = logging.getLogger(machine)
            logger.info('install add SMU')
            cmd = "request platform software sdwan smu activate {0}".format(smu)
            session.sendline(cmd)
            result = session.expect(
                ["SUCCESS: install_activate .*", "FAILED: install_activate .*", "Username:", pexpect.TIMEOUT],
                timeout=600,
            )
            return result
        except Exception as e:
            raise TestbedBringupError("activate_smu encountered an error: {}".format(e))

    def commit_installation(self, machine, session):
        """
        Upgrade the SMU on the machine.

        :param machine: The name of the machine.
        :param session: The console session.
        """
        try:
            logger = logging.getLogger(machine)
            logger.info('install add SMU')
            cmd = "request platform software sdwan smu upgrade-confirm"
            session.sendline(cmd)
            result = session.expect(
                ["SUCCESS: install_commit .*", "FAILED: install_commit .*", "Username:", pexpect.TIMEOUT], timeout=600
            )
            return result
        except Exception as e:
            raise TestbedBringupError("commit_installation encountered an error: {}".format(e))

    def deactivate_smu(self, machine, smu):
        """
        Deactivate the SMU on the machine.

        :param machine: The name of the machine.
        :param session: The console session.
        :param smu: The smu name.
        """
        try:
            image_file_name = os.path.basename(smu)
            smu_file = self.generate_smu_file(machine, image_file_name)
            self.logger.info("generate_smu_file result: {smu_file}".format(**{"smu_file": smu_file}))
            logger = logging.getLogger(machine)
            logger.info('install deactivate SMU')
            console_config = self.config['machines'][machine]['console']
            with ConsoleFactory(console_config) as session:
                self.go_to_ios_prompt(machine, session)
                smu_type = self.get_smu_type(machine, image_file_name)
                cmd = "request platform software sdwan smu deactivate {0}".format(smu_file)
                session.sendline(cmd)
                result = session.expect(
                    ["SUCCESS: install_deactivate .*", "FAILED: install_deactivate .*", pexpect.TIMEOUT], timeout=600
                )
                if smu_type == "reload":
                    time.sleep(20)
                    self.go_to_ios_prompt(machine, session)
                    self.cedge_stop_pnp(machine, session)
                cmd = "request platform software sdwan smu upgrade-confirm"
                session.sendline(cmd)
                res = session.expect(
                    ["SUCCESS: install_commit .*", "FAILED: install_commit .*", "Username:", pexpect.TIMEOUT],
                    timeout=600,
                )
            if result or res:
                raise TestbedCleanupError("SMU deactivation failed")
        except Exception as e:
            raise TestbedCleanupError("SMU deactivate encountered an error: {e}".format(**{"e": e}))

    def remove_smu(self, machine, smu):
        """
        remove the SMU on the machine.

        :param machine: The name of the machine.
        :param session: The console session.
        :param image_file_name: The image file name.
        """
        try:
            image_file_name = os.path.basename(smu)
            smu_file = self.generate_smu_file(machine, image_file_name)
            self.logger.info("generate_smu_file result: {smu_file}".format(**{"smu_file": smu_file}))
            logger = logging.getLogger(machine)
            logger.info('install remove SMU')
            console_config = self.config['machines'][machine]['console']
            with ConsoleFactory(console_config) as session:
                self.go_to_ios_prompt(machine, session)
                cmd = "request platform software sdwan smu remove {0}".format(smu_file)
                session.sendline(cmd)
                result = session.expect(
                    ["SUCCESS: install_remove .*", "FAILED: install_remove .*", "Username:", pexpect.TIMEOUT],
                    timeout=600,
                )
            if result:
                raise TestbedCleanupError("SMU removing failed")
        except Exception as e:
            raise TestbedCleanupError("SMU removing encountered an error: {e}".format(**{"e": e}))

