    def setup_viptela_vm(self, machine_name, install_cert, serial_id):
        self.logger.info(f"setup_viptela_vm({machine_name})".center(60, "-"))
        machine_config = self.config['machines'][machine_name]
        if 'console' in machine_config:
            # MultiprocessPdb().set_trace()
            with ConsoleFactory(machine_config['console']) as pexpect_session:
                # MultiprocessPdb().set_trace()
                pexpect_session.logfile = self.get_log_file_for_machine(machine_name)
                self.go_to_confd_prompt(machine_name, pexpect_session)
        # Setup new password
        # MultiprocessPdb().set_trace()
        machine = Machines('all').get(machine_name)
        with machine.get_confd(prompt_timeout=180) as cli:
            self.logger.info(f"setup_viptela_vm({machine_name}) --> set_password({DEFAULT_CONFIGURED_PASSWORD})".center(60, "-"))
            self.logger.info(f"setup_viptela_vm({machine_name}) --> unhide_viptela()".center(60, "-"))
            self.logger.info(f"setup_viptela_vm({machine_name}) --> _touch_testbed()".center(60, "-"))
            # MultiprocessPdb().set_trace()
            if cli.set_password(password=DEFAULT_CONFIGURED_PASSWORD):
                self.update_machine_config(machine_name, DEFAULT_CONFIGURED_PASSWORD)
            else:
                raise TestbedBringupError(f'[{machine_name}] Could not set new {password}')

