    def enable_vty_cedge(self, machine):
        """Config more vty in cedge"""
        pexpect_timeout = 25
        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.enable_vty_cedge <<<<\n")
        child = self.get_cisco_csr_session(machine, pexpect_timeout, logfile=logfile)
        try:
            child.sendline('config terminal')
            child.expect('.*#')
            child.sendline('line vty 0 4')
            child.expect('.*#')
            child.sendline('exec-timeout 0 0')
            child.expect('.*#')
            child.sendline('login local')
            child.expect('.*#')
            child.sendline('transport input ssh')
            child.expect('.*#')
            child.sendline('line vty 5 80')
            child.expect('.*#')
            child.sendline('exec-timeout 0 0')
            child.expect('.*#')
            child.sendline('login local')
            child.expect('.*#')
            child.sendline('transport input ssh')
            child.expect('.*#')
            time.sleep(1)
            child.sendline('commit')
            child.expect(['Commit complete', '% No modifications to commit', '.*#'])
            child.sendline('end')
            index = child.expect([pexpect.EOF, '.*#', '.*commit them?'])
            if index == 2:
                child.sendline('no')
                child.expect(r'.*#')
        finally:
            child.close()

    def exec_cisco_cedge_commands(self, machine_session, cmds):
        """Execute cisco style commands in cedge"""
        results = []
        err_msg = ''
        machine_session.sendline('config terminal')
        machine_session.expect(r'.*#')
        for cmd in cmds:
            machine_session.sendline(cmd)
            machine_session.expect(r'.*#')
            cmd_config_output = machine_session.after
            #Cisco iosxe says invalid input detected when command fails
            if 'Invalid input detected' in cmd_config_output:
                err_msg += 'cmd [%s] failed with error [%s]'%(cmd, cmd_config_output)
                results.append(False)
        machine_session.sendline('end')
        machine_session.expect(r'.*#')
        commit_error = machine_session.after
        if False in results:
            return [False, err_msg]
        return [True, '']

    def enable_netconf_debug_cedge(self, machine):
        """Enable netconf and corresponding debug logs
        This is temporary and should be removed once these are made part of cedge bootup
        """
        pexpect_timeout = 25
        cisco_iosxe_session = self.get_iosxe_cli_session(machine, pexpect_timeout, None)
        try:
            cmds = ['no netconf-yang cisco-ia intelligent-sync ;']
            cmds += ['netconf-yang cisco-ia logging nes-log-level debug ;']
            cmds += ['netconf-yang cisco-ia logging sync-log-level debug ;']
            #cmds += ['netconf-yang cisco-ia preserve-ned-path /native/interface/Tunnel ;']
            #cmds += ['netconf-yang cisco-ia preserve-paths-enabled ;']
            cmds += ['netconf-yang']
            netconf_enabled_status = self.exec_cisco_cedge_commands(cisco_iosxe_session, cmds)
        finally:
            cisco_iosxe_session.close()

        if netconf_enabled_status[0]:
            return True
        else:
            self.logger.info('Error: netconf log enabled failed [%s]'%(netconf_enabled_status[1]))
            return False

    def stop_pnp_service_cedge(self, machine):
        """Stop pnp service on cedge"""
        pexpect_timeout = 25
        cisco_iosxe_session = self.get_iosxe_cli_session(machine, pexpect_timeout, None)
        try:
            cmds = ['pnpa service discovery stop;']
            netconf_enabled_status = self.exec_cisco_cedge_commands(cisco_iosxe_session, cmds)
        finally:
            cisco_iosxe_session.close()

        if netconf_enabled_status[0]:
            return True
        else:
            self.logger.info('Error: Not able to stop pnpa service  [%s]'%(netconf_enabled_status[1]))
            return False

