    def wait_for_pm_vedge_system_ready(self, pexpect_session):
        """ Using console session provided waits until it gets "System Ready" from device."""
        boot_start_time = time.time()
        pexpect_session.expect("Starting services", timeout=600)
        self.logger.info("Got 'Starting services' after {} sec".format(time.time() - boot_start_time))
        services_start_time = time.time()
        res = pexpect_session.expect(["System Ready", pexpect.TIMEOUT], timeout=400)
        if res == 0:
            services_time_passed = time.time() - services_start_time
            boot_time_passed = time.time() - boot_start_time
            self.logger.info("Services up after {} sec".format(services_time_passed))
            self.logger.info("Boot time: {} sec".format(boot_time_passed))
        else:
            services_time_passed = time.time() - services_start_time
            boot_time_passed = time.time() - boot_start_time
            self.logger.info("Services are not up after {} sec".format(services_time_passed))
            res = pexpect_session.expect(["System Ready", pexpect.TIMEOUT], timeout=200)
            services_time_passed = time.time() - services_start_time
            boot_time_passed = time.time() - boot_start_time
            if res == 0:
                self.logger.info("Services are up after {} sec".format(services_time_passed))
            else:
                self.logger.info("Services are not up after {} sec".format(services_time_passed))
                raise TestbedException("Total wait {} sec".format(boot_time_passed))

