    def patch_csr(self, machine, patchfile):
        src_path = patchfile
        filename = os.path.split(src_path)[1]
        self.logger.info("Uploading patch")
        mgmt_ip = self.mgmt_ipaddr(machine)
        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.patch_csr <<<<\n")
        with CedgeSession(mgmt_ip, logfile) as cs:
            self.logger.info('Performing software reset')
            #cs.delete_force_recursive('bootflash:ovf-env.xml.md5')
            cs.sdwan_software_reset()
            #time.sleep(400)
            if self.ssh_went_down(machine, maxwait = 120):
                self.logger.info("Machine is reloading after reset command")
            else:
                raise Exception("Machined didn't start reloading, reset must have failed")
            self.check_and_start_ssh(machine)
            self.check_and_start_confd(machine)
            #cs.sdwan_config_reset()
        version = self.get_patch_version_from_cedge_image(src_path)
        self.logger.warn('Uploading image version: {}'.format(version))
        self.copy_to_machine(machine, src_path, dest='{}.bin'.format(version))

        with CedgeSession(mgmt_ip, logfile) as cs:
            self.logger.info("Softwares installed: \n %s" % cs.show_sdwan_software())
            cs.save_configs_before_upgrade()
            cs.sdwan_software_install('bootflash:{}.bin'.format(version))
            cs.sdwan_software_activate(version)
            if self.ssh_went_down(machine, maxwait = 120):
                self.logger.info("Machine is reloading after activate command")
            else:
                raise Exception("Machined didn't start reloading, activation must have failed")

        self.check_and_start_ssh(machine)
        self.check_and_start_confd(machine)

        with open(logfile_path, 'a+') as logfile:
            with CedgeSession(mgmt_ip, logfile) as cs:
                cs.sdwan_software_upgrade_confirm()
                self.logger.info("Softwares installed: \n %s" % cs.show_sdwan_software())

