    def _remove_vmanage_config(self, vmanage, confd):
        """Remove system-ip, tunnel-interface on vmanage"""
        remove = True
        vpn = 0
        vmanage_system_ip = None
        iface_list, color_list = ['eth0', 'eth1'], ['default', 'default']
        system_ip = self.system_ip(vmanage).split('/')[0]
        remove_system_ip_status = confd.config_system_ip(vmanage, system_ip, remove)
        remove_system_ip_status = confd.config_vmanage_system_ip(vmanage, vmanage_system_ip, remove)
        remove_tunnel_interface_status = confd.config_tunnel_interface(vmanage, vpn, iface_list, color_list, None, None, True)
        print('Removed system-ip & tunnel interface on vManage')
        return True

    def _upgrade_nms_appserver(self, machine, patchfile):
        mgmt_ip = self.mgmt_ipaddr(machine)
        cmd_bld = SSHCommandBuilder(host=mgmt_ip, user=self.get_ssh_username(machine), logger=self.logger)
        cmd_bld.add_kv_option('ConnectTimeout', 40)
        cmd = cmd_bld.build()
        if six.PY2:
            child = pexpect.spawn(cmd)
        else:
            child = pexpect.spawn(cmd, encoding='utf-8', codec_errors='ignore')
        try:
            child.expect('.*#')
            child.sendline('request nms application-server software upgrade {}'.format(patchfile))
            child.expect([pexpect.EOF, '.*#'], timeout=60)
            child.sendline('request nms all restart')
            child.expect([pexpect.EOF, '.*#'], timeout=120)
        finally:
            child.close()

    def create_root_ca(self, machine, ca_authority_name, emailId = 'narendra@viptela.com', serial_id = '12345801', root_ca_dir= '/tmp', passwd = 'ZjNycmFyMQ==', subj = {'C':'US','ST' : 'California', 'L': 'San Jose', 'OU' : 'vIPtela Test', 'O' : 'vIPtela Inc'}):
        subject = "/C=%s/ST=%s/L=%s/OU=%s/O=%s/emailAddress=%s"%(subj['C'],subj['ST'],subj['L'],subj['OU'],subj['O'],emailId)
        password = str(base64.decodestring(passwd.encode()).decode())

        root_ca_path = os.path.join(root_ca_dir,"root_ca")
        private_dir = os.path.join(root_ca_path, 'private')
        key_path = os.path.join(private_dir, 'cakey.pem')
        cert_path = os.path.join(root_ca_path, 'cacert.pem')
        new_certs_dir = os.path.join(root_ca_path, 'newcerts')
        openssl_cnf_path = os.path.join(root_ca_path, 'openssl.cnf')
        index_file = os.path.join(root_ca_path, 'index.txt')
        # serial File
        serial_file = 'serial'
        serial_file_path = os.path.join(root_ca_path, 'serial')

        # remove old root ca folder
        if os.path.exists(root_ca_path):
            self.logger.info('Removing existing directory %s'%(root_ca_path))
            subprocess.check_call('sudo rm -rf %s'%(root_ca_path), shell=True)
        self.logger.info('Creating root ca directory %s'%(root_ca_path))
        self.mkpath(root_ca_path)
        self.logger.info('Creating private key directory %s'%(private_dir))
        self.mkpath(private_dir)
        self.logger.info('Creating new cert directory %s'%(new_certs_dir))
        self.mkpath(new_certs_dir)
        subprocess.check_call('touch %s'%(index_file), shell=True)
        subprocess.check_call('touch %s'%(serial_file_path), shell=True)
        subprocess.check_call('echo %s > %s'%(serial_id, serial_file_path), shell=True)

        # create openssl conf file
        self.create_openssl_cnf(openssl_cnf_path, root_ca_path, ca_authority_name, serial_file)

        # create root ca
        cmd = "openssl req -new -x509 -extensions v3_ca -keyout %s -out %s -days 3650 -config %s -subj \"%s\" -passout pass:%s"%(key_path, cert_path, openssl_cnf_path, subject, password)
        subprocess.check_call(cmd, shell=True)
        return [True, "Root ca created successfully"]

    def create_openssl_cnf(self, openssl_cnf_path, root_ca_path, ca_authority_name, serial_file):
        """ create openssl cnf for root ca """
        f = open(openssl_cnf_path, 'w')
        f.write('#\n')
        f.write('# OpenSSL configuration file\n')
        f.write('# Please dont edit it, this file has been generated by script\n')
        f.write('#\n')

        f.write('# Establish working directory.\n')
        f.write('\n')
        f.write('dir         = %s\n' % (root_ca_path))
        f.write('\n')
        f.write('[ ca ]\n')
        f.write('default_ca      = CA_default\n')
        f.write('\n')
        f.write('[ CA_default ]\n')
        f.write('serial          = $dir/%s\n'%(serial_file))
        f.write('database        = $dir/index.txt\n')
        f.write('new_certs_dir   = $dir/newcerts\n')
        f.write('certificate     = $dir/cacert.pem\n')
        f.write('private_key     = $dir/private/cakey.pem\n')
        f.write('default_days    = 365\n')
        f.write('default_md      = sha256\n')
        f.write('preserve        = no\n')
        f.write('email_in_dn     = no\n')
        f.write('nameopt         = default_ca\n')
        f.write('certopt         = default_ca\n')
        f.write('policy          = policy_match\n')
        f.write('\n')
        f.write('[ policy_match ]\n')
        f.write('localityName            = optional\n')
        f.write('countryName             = match\n')
        f.write('stateOrProvinceName     = match\n')
        f.write('organizationName        = optional\n')
        f.write('organizationalUnitName  = optional\n')
        f.write('commonName              = supplied\n')
        f.write('emailAddress            = optional\n')
        f.write('\n')
        f.write('[ req ]\n')
        f.write('default_bits        = 2048          # Size of keys\n')
        f.write('default_keyfile     = key.pem       # name of generated keys\n')
        f.write('default_md          = sha256        # message digest algorithm\n')
        f.write('string_mask         = nombstr       # permitted characters\n')
        f.write('distinguished_name  = %s\n'%(ca_authority_name))
        f.write('req_extensions      = v3_req\n')
        f.write('\n')
        f.write('[ %s ]\n'%(ca_authority_name))
        f.write('# Variable name       Prompt string\n')
        f.write('#----------------------   ----------------------------------\n')
        f.write('0.organizationName      = Organization Name (company)\n')
        f.write('organizationalUnitName  = Organizational Unit Name (department, division)\n')
        f.write('emailAddress            = Email Address\n')
        f.write('emailAddress_max        = 40\n')
        f.write('localityName            = Locality Name (city, district)\n')
        f.write('stateOrProvinceName     = State or Province Name (full name)\n')
        f.write('countryName             = Country Name (2 letter code)\n')
        f.write('countryName_min         = 2\n')
        f.write('countryName_max         = 2\n')
        f.write('commonName              = Common Name (hostname, IP, or your name)\n')
        f.write('commonName_max          = 64\n')
        f.write( '\n')
        f.write('# Default values for the above, for consistency and less typing.\n')
        f.write('# Variable name           Value\n')
        f.write('#------------------------------   ------------------------------\n')
        f.write('0.organizationName_default  = vIPtela Inc\n')
        f.write('localityName_default        = San Jose\n')
        f.write('stateOrProvinceName_default = California\n')
        f.write('countryName_default         = US\n')
        f.write(' \n')
        f.write('[ v3_ca ]\n')
        f.write('basicConstraints        = CA:TRUE\n')
        f.write('subjectKeyIdentifier    = hash\n')
        f.write('authorityKeyIdentifier  = keyid:always,issuer:always\n')
        f.write('\n')
        f.write('[ v3_req ]\n')
        f.write('basicConstraints    = CA:FALSE\n')
        f.write('subjectKeyIdentifier    = hash\n')
        f.close()


    def set_per_machine_loggers(self):
        for machine in self.machines(types = ['vm', 'pm'], include_vcontainer = True):
            log_file_path = os.path.join(self.log_root, machine, 'bringup.log')
            machine_logger = logging.getLogger(machine)
            machine_logger.setLevel(logging.INFO)
            file_handler = logging.FileHandler(log_file_path)
            file_handler.setLevel(logging.INFO)
            file_handler.setFormatter(self.log_formatter)
            stream_handler = logging.StreamHandler()
            stream_handler.setLevel(logging.INFO)
            machine_logger.addHandler(file_handler)
            machine_logger.addHandler(stream_handler)

    def bringup_machines(self, machine_list, install_certs=True):
        ret = self.try_lock()
        if ret == False:
            raise LockException()
        self.set_per_machine_loggers()
        for machine in machine_list:
            if self.machine_is_vm(machine):
                self.bringup_vm(machine)
            elif self.machine_is_pm(machine):
                self.bringup_pm(machine)
        self.setup_machines(machine_list, install_certs)

