    def filters_to_dict(self, filters):
        result = {}
        for filterstr in filters:
            keyvalue = filterstr.strip().split('=')
            key = keyvalue[0]
            value = keyvalue[1]
            if ',' in value:
                value = value.split(',')
            result[key] = value
        return result

    def filter_machines(self, filters={}):
        return list(filter(self.filter_machine(filters), self.machines()))

    def filter_machine(self, filters={}):
        def inner_func(machine):
            final_result = True
            machine_config = self.config['machines'][machine]
            for filter_key in list(filters.keys()):
                cur_key_result = False
                if filter_key in machine_config:
                    filter_value = filters[filter_key]
                    if type(filter_value) is str:
                        cur_key_result = cur_key_result or (machine_config[filter_key] == filter_value)
                    elif type(filter_value) is list:
                        cur_key_result = cur_key_result or (machine_config[filter_key] in filter_value)
                final_result = final_result and cur_key_result

            return final_result
        return inner_func

