    @retry_on_disconnect(3)
    def generate_csr(self, machine):
        logging.getLogger(machine).info("Generate csr on vm: %s" % machine)
        org_name = self.get_machine_org_name(machine)
        mgmt_ip = self.mgmt_ipaddr(machine)
        cmd_bld = SSHCommandBuilder(host=mgmt_ip, user=self.get_ssh_username(machine), logger=self.logger)
        cmd_bld.add_kv_option('ConnectTimeout', 40)
        cmd = cmd_bld.build()
        if six.PY2:
            child = pexpect.spawn(cmd)
        else:
            child = pexpect.spawn(cmd, encoding='utf-8', codec_errors='ignore')
        try:
            child.expect('.*#')
            child.sendline('request csr upload /home/admin/csr')
            child.expect("Enter [O|o](rganization-unit)|(rganization) name            :")
            child.sendline(org_name)
            child.expect("(Re-enter)|(ReEnter) [O|o](rganization-unit)|(rganization) name          :")
            child.sendline(org_name)
            child.expect(["CSR upload successful", pexpect.EOF])
        finally:
            child.close()

    @retry_on_disconnect(3)
    def sign_machine_csr(self, machine, serial_id):
        ca_key_path = os.path.join(self.workdir, 'root_ca', 'private', 'cakey.pem')
        ca_cert_path = os.path.join(self.workdir, 'root_ca', 'cacert.pem')
        open_ssl_config_path = os.path.join(self.workdir, 'root_ca', 'openssl{}.cnf'.format(serial_id))
        machine_dir = os.path.join(self.workdir, machine)
        csr_path = os.path.join(self.workdir, machine, 'csr')
        signed_cert_path = os.path.join(self.workdir, machine, 'crt')
        cmd = 'openssl ca -batch -out %s -config %s -cert %s -keyfile %s -passin pass:f3rrar1 -outdir %s -infiles %s'
        cmd = cmd % (signed_cert_path, open_ssl_config_path, ca_cert_path, ca_key_path, machine_dir, csr_path)
        os.chdir(os.path.join(self.workdir, machine))
        logfile = self.get_log_file_for_machine(machine)
        subprocess.call(cmd, stdout=logfile, stderr=logfile, shell=True)
        os.chdir(self.workdir)

    def sign_machine_csr_cloud_init(self, machine, org_name):
        machine_dir = os.path.join(self.workdir, machine)

        # Read the serial number from the file
        serial_file = os.path.join(machine_dir, "cert_serial_number.txt")
        with open(serial_file, 'r') as f:
            serial = f.read().strip()

        # Initialize the SDWANcert object
        cert = SDWANcert(organization_name=org_name)
        ca_private_key, cacert_pem = cert.create_self_signed_ca_cert()

        # Read CSR from the file
        csr_path = os.path.join(machine_dir, 'csr')
        with open(csr_path, 'r') as f:
            csr_string = f.read()

        # Sign certificate and save it to the file
        signed_crt, cert_serial_number = cert.sign_cert(controller_csr_string=csr_string, cert_serial_number=serial)
        signed_cert_path = os.path.join(machine_dir, 'crt')
        with open(signed_cert_path, 'w') as f:
            f.write(signed_crt)

