    def get_ssh_known_passswords(self, machine=None):
        if machine is None:
            return list(WELL_KNOWN_DEFAULT_PASSWORDS)
        else:
            default_password = self.get_ssh_password(machine)
            known_passwords = list(WELL_KNOWN_DEFAULT_PASSWORDS)
            try:
                known_passwords.remove(default_password)
            except ValueError:
                pass
            # Make sure current default is on first place to increase number of successfull logins with it
            known_passwords.insert(0, default_password)
            return known_passwords

