    def copy_to_machine(self, machine, source, dest, mgmt_ip=None, user=None, password=None, port=22, timeout=1800):
        """
        Copies a file from the host machine to the specified machine

        Params:
            machine(str):  Device to which the file is to be copied
            source(str):   Path to the file to be copied on host machine
            dest(str):     Path to the file on the destination device
            mgmt_ip(str):  Management IP of the destination device
            user(str):     Username of destination device
            password(str): Password of destination device
            port(int):     SSH port(default 22)

        Returns:
            On success - [True, success_message(str)]
            On failure - None (Raise exception)
        """
        if not mgmt_ip:
            mgmt_ip = self.mgmt_ipaddr(machine)
        if not user:
            user = self.get_ssh_username(machine)
        if not password:
            password = self.get_ssh_password(machine)
        cmd = 'scp -P {} -o StrictHostKeyChecking=no'.format(port)
        cmd += ' -o UserKnownHostsFile=/dev/null'
        cmd += ' -o ConnectTimeout=20'
        cmd += ' -o  LogLevel=QUIET '
        cmd += ' {src} {user}@{host}:{dst}'.format(src=source,
                                                   user=user,
                                                   host=mgmt_ip,
                                                   dst=dest)
        if six.PY2:
            child = pexpect.spawn(cmd, timeout=timeout)
        else:
            child = pexpect.spawn(cmd, timeout=timeout, encoding='utf-8', codec_errors='ignore')
        child.logfile = self.get_log_file_for_machine(machine)
        try:
            prompt = child.expect(['.*assword:', '100%'])
            if prompt == 0:
                child.sendline(password)
                res = child.expect(['100%'])
                if res == 0:
                    child.expect([pexpect.EOF])
                else:
                    raise TestbedException("Failed to copy")
            elif prompt == 1:
                child.expect([pexpect.EOF])
            self.logger.info('Copied from {} to {}:{}'.format(source, machine, dest))
        except Exception:
            self.logger.error('Exception copying', exc_info=True)
            raise
        finally:
            child.close()

        return [True, 'Copied file successfully.']

    def copy_from_machine(
        self, machine, source, dest, to_machine=False, mgmt_ip=None, user=None, password=None, hide_info=False
    ):
        self.logger.info('copy_from_machine machine::{} , source::{} dest::{} '.format(machine, source, dest))
        if not mgmt_ip:
            mgmt_ip = self.mgmt_ipaddr(machine)
        if not user:
            user = self.get_ssh_username(machine)
        if not password:
            password = self.get_ssh_password(machine)

        cmd = 'scp -o StrictHostKeyChecking=no'
        cmd += ' -o UserKnownHostsFile=/dev/null'
        cmd += ' -o ConnectTimeout=20'
        cmd += ' -o LogLevel=QUIET'
        if to_machine:
            cmd += ' {src} {user}@{host}:{dst}'.format(user=user,
                                                   host=mgmt_ip,
                                                   src=source,
                                                   dst=dest)
        else:
            cmd += ' {user}@{host}:{src} {dst}'.format(user=user,
                                                   host=mgmt_ip,
                                                   src=source,
                                                   dst=dest)
        if six.PY2:
            child = pexpect.spawn(cmd, timeout=600)
        else:
            child = pexpect.spawn(cmd, timeout=600, encoding='utf-8', codec_errors='ignore')
        try:
            prompt = child.expect(['.*assword:', '100%'])
            if prompt == 0:
                child.sendline(password)
                res = child.expect(['100%'])
                if res == 0:
                    child.expect([pexpect.EOF])
                else:
                    raise TestbedException("Failed to copy")
            elif prompt == 1:
                child.expect([pexpect.EOF])
            if not hide_info:
                self.logger.info('Copied from {}:{} to {}'.format(machine, source, dest))
        except:
            self.logger.error('Exception copying', exc_info=True)
            self.logger.debug(traceback.format_exc())
            # Try another way
            machine = Machines().get(machine)
            machine.get_file(source, dest, privileged=True)
        finally:
            child.close()

    @retry_on_disconnect(3)
    def ssh_copy_id(self, machine, remoteuser=None):
        username = remoteuser or self.get_ssh_username(machine)
        password = self.get_ssh_password(machine)
        logging.getLogger(machine).info("Copying ssh key to vm: %s" % machine)
        mgmt_ip = self.mgmt_ipaddr(machine)
        cmd_bld = SSHCommandBuilder(host=mgmt_ip, user=remoteuser, logger=self.logger)
        cmd_bld.add_kv_option('ConnectTimeout', 20)
        cmd = cmd_bld.build()
        if six.PY2:
            child = pexpect.spawn(cmd)
        else:
            child = pexpect.spawn(cmd, encoding='utf-8', codec_errors='ignore')
        try:
            prompt = child.expect(['.*password:', '.*#'])
            if prompt == 0:
                child.sendline(password)
                child.expect(['.*#'])
                child.sendline('vshell')
                child.expect([r'.*\$'])
                child.sendline('mkdir -p /home/admin/.ssh')
                child.expect([r'.*\$'])
                child.sendline('echo "{}" >> /home/admin/.ssh/authorized_keys && echo "success"'.format(self.sshpubkey))
                result = child.expect([pexpect.TIMEOUT, pexpect.EOF, 'success'])
                if result == 2:
                    logging.getLogger(machine).info('SSH key copied')
                elif result == 1:
                    if 'success' in child.before:
                        logging.getLogger(machine).info('SSH key copied')
                    else:
                        logging.getLogger(machine).error(child.before)
                else:
                    logging.getLogger(machine).error(child.before)
        finally:
            child.close()

