    def initial_nfvis_config(self, machine):
        console_config = self.config['machines'][machine]['console']
        console_config['personality'] = self.config['machines'][machine]['personality']
        with ConsoleFactory(console_config) as pexpect_session:
            logfile = self.get_log_file_for_machine(machine)
            self.logger.info("[NFVIS] You can see console logs in {}.".format(logfile))
            pexpect_session.logfile = logfile
            res = pexpect_session.expect(['Active console session exists', pexpect.TIMEOUT], timeout=2)
            if res == 0:
                self.logger.error('Console for %s is locked by other session' % machine)
                raise TestbedException('Console for %s is locked by other session' % machine)
            self.go_to_nfvis_prompt(machine, pexpect_session)
            self.nfvis_initial_config_ip_connectivity(machine, pexpect_session)
            if self.config['machines'][machine]["interfaces"]["MGMT"].get("mac", None):
                self.nfvis_setup_dhcp(machine, pexpect_session)
            else:
                self.nfvis_setup_static_ip(machine, pexpect_session)
            self.nfvis_initial_enable_vdaemon(machine)
            self.nfvis_discard_uncommitted_changes(machine, pexpect_session)
            self.nfvis_initial_config_hostname(machine)
            self.nfvis_execute_tunnel_config(machine)
            self.nfvis_execute_viptela_config(machine)

    def go_to_nfvis_prompt(self, machine, pexpect_session, hostname=None, username=None, password=None):
        in_nfvis_prompt = False
        timed_out = False
        start_time = time.time()
        default_password = "Admin123#"
        if not hostname:
            hostname = machine
        if not username:
            username = self.get_ssh_username(machine)
        if not password:
            password = self.get_ssh_password(machine)
        self.logger.info("[NFVIS] Waiting for NFVIS login prompt ...")
        while not in_nfvis_prompt and not timed_out:
            result = pexpect_session.expect(
                [
                    r'(Last login:|Last failed login:)',
                    'login:',
                    'Login incorrect',
                    'Permission denied, please try again',
                    'Password:',
                    'Please reset the password :',
                    r'nfvis\S*#',  # 5
                    'Login timed out',
                    'Login incorrect',
                    'Do you wish to proceed? [y or n]',
                    r'Preparing transaction from installation source(\r\n|\r|\n)Installing',
                    'Performing post-installation setup tasks',  # 10
                    'Restarting system.',
                    'Escape character is ',
                    pexpect.TIMEOUT,
                ],
                timeout=20,
            )
            if result == 0:
                continue
            elif result == 1:
                pexpect_session.sendline(username)
                pexpect_session.expect(["Password: ", pexpect.TIMEOUT], timeout=3)
                pexpect_session.sendline(password)
                res = pexpect_session.expect(['nfvis login:', pexpect.TIMEOUT], timeout=10)
                if res == 0:
                    pexpect_session.sendline(username)
                    pexpect_session.expect(["Password: ", pexpect.TIMEOUT], timeout=3)
                    pexpect_session.sendline(default_password)
            elif result in [2, 3]:
                pexpect_session.sendline(username)
                pexpect_session.expect(["Password: ", pexpect.TIMEOUT], timeout=3)
                pexpect_session.sendline(default_password)
            elif result == 4:
                pexpect_session.sendline(password)
                pexpect_session.expect(['password', pexpect.TIMEOUT], timeout=10)
                pexpect_session.sendline(password)
            elif result == 5:
                pexpect_session.sendline(password)
                pexpect_session.expect(['Please reenter the password :', pexpect.TIMEOUT], timeout=10)
                pexpect_session.sendline(password)
            elif result == 6:
                in_nfvis_prompt = True
                self.logger.info("[NFVIS] Connected to nfvis machine.")
            elif result in [7, 8]:
                continue
            elif result == 9:
                pexpect_session.sendline('n')
                time.sleep(50)
            elif result == 11:
                self.logger.info("[NFVIS] Starting system installation.")
            elif result == 11:
                self.logger.info("[NFVIS] Performing post-installation setup tasks.")
            elif result == 12:
                self.logger.info("[NFVIS] Restarting system.")
            elif result == 13:
                pexpect_session.sendline('\n')
            elif result == 14:
                time.sleep(1)
                pexpect_session.sendline('\n')

            timed_out = int(time.time() - start_time) >= NFVIS_INSTALLATION_TIMEOUT

        if timed_out and not in_nfvis_prompt:
            raise TestbedException("Couldn't get NFVIS prompt through console")

    def nfvis_discard_uncommitted_changes(self, machine, pexpect_session):
        pexpect_timeout = 10
        pexpect_session.logfile = self.get_log_file_for_machine(machine)
        pexpect_session.logfile.write('>>>> testbed.nfvis_discard_uncommitted_changes <<<<\n')

        self.logger.info("[NFVIS] Discard Uncommited changes if any.")
        pexpect_session.expect([r"nfvis\S*#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("config shared")
        res = pexpect_session.expect(
            [r"nfvis\S*\(config\)#", r"There are uncommitted changes. Discard changes\?", pexpect.TIMEOUT],
            timeout=pexpect_timeout,
        )
        if res == 1:
            pexpect_session.sendline('yes')
            pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)

        pexpect_session.sendline("exit")
        result = pexpect_session.expect([r"nfvis\S*#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        if not result == 0:
            raise TestbedException("Unable to Discard Uncommitted Changes on NFVIS")

    def nfvis_initial_config_ip_connectivity(self, machine, pexpect_session):
        pexpect_timeout = 10
        pexpect_session.logfile = self.get_log_file_for_machine(machine)
        pexpect_session.logfile.write('>>>> testbed.nfvis_initial_config_ip_connectivity  <<<<\n')

        nfvis_mgmt_address = self.config['machines'][machine]["system-ip"]
        nfvis_mgmt_netmask = self.config['machines'][machine]["system-netmask"]
        nfvis_wan_ifname = self.config['machines'][machine]["nfvis-ifname"]
        nfvis_wan_ip_addr = self.config['machines'][machine]["interfaces"]["MGMT"]["ip"]

        access_interfaces = {
            "https": "accept",
            "icmp": "accept",
            "netconf": "accept",
            "scpd": "accept",
            "ssh": "accept",
        }
        self.logger.info("[NFVIS] Setting up initial connectivity config.")
        pexpect_session.expect([r"nfvis\S*#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("config")
        pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        # XXX: we have to get rid of DHCP system wide to have
        #      possibility to configure default GW manually
        pexpect_session.sendline("bridges bridge wan2-br")
        pexpect_session.expect([r"nfvis\S*\(config-bridge-wan2-br\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("no dhcp")
        pexpect_session.expect([r"nfvis\S*\(config-bridge-wan2-br\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("top")
        pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("system settings mgmt ip address {} {}".format(nfvis_mgmt_address, nfvis_mgmt_netmask))
        pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)

        pexpect_session.sendline("system settings ip-receive-acl 0.0.0.0/0")
        pexpect_session.expect(
            [r"nfvis\S*\(config-ip-receive-acl-0.0.0.0/0\)#", pexpect.TIMEOUT], timeout=pexpect_timeout
        )
        for service, action in access_interfaces.items():
            pexpect_session.sendline("service {} action {} priority 2".format(service, action))
            pexpect_session.expect(
                [r"nfvis\S*\(config-ip-receive-acl-0.0.0.0/0\)#", pexpect.TIMEOUT], timeout=pexpect_timeout
            )

        pexpect_session.sendline("top")
        pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("commit")
        pexpect_session.expect(
            [r"nfvis\S*\(config\)#", "% No modifications to commit.", pexpect.TIMEOUT], timeout=pexpect_timeout
        )
        pexpect_session.sendline("exit")
        # When VM14 was up and running and we started configuration then we must also expect "nfvis-vm14#" prompt.
        # We change hostname during configuration procedure to nfvis-vm14.
        result = pexpect_session.expect([r"nfvis\S*#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        if not result == 0:
            raise TestbedException(
                "Unable to configure IP connectivity: {} on {} on NFVIS instance.".format(
                    nfvis_wan_ip_addr, nfvis_wan_ifname
                )
            )

    def nfvis_setup_static_ip(self, machine, pexpect_session):
        pexpect_timeout = 10

        nfvis_wan_ifname = self.config['machines'][machine]["nfvis-ifname"]
        nfvis_default_gw = self.config['machines'][machine]["default-gw"]
        nfvis_wan_ip_addr = self.config['machines'][machine]["interfaces"]["MGMT"]["ip"]
        nfvis_wan_netmask = self.config['machines'][machine]["wan-netmask"]

        pexpect_session.sendline("config")
        pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline(
            "bridges bridge {} ip address {} {}".format(nfvis_wan_ifname, nfvis_wan_ip_addr, nfvis_wan_netmask)
        )
        pexpect_session.expect(
            [r"nfvis\S*\(config-bridge-{}\)#".format(nfvis_wan_ifname), pexpect.TIMEOUT], timeout=pexpect_timeout
        )
        pexpect_session.sendline("system settings default-gw {}".format(nfvis_default_gw))
        pexpect_session.expect(
            [r"nfvis\S*\(config-bridge-{}\)#".format(nfvis_wan_ifname), pexpect.TIMEOUT], timeout=pexpect_timeout
        )
        pexpect_session.sendline("top")
        pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("commit")
        pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("exit")
        result = pexpect_session.expect([r"nfvis\S*#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        if not result == 0:
            raise TestbedException(
                "Unable to configure static IP address: {} on {} on NFVIS instance.".format(
                    nfvis_wan_ip_addr, nfvis_wan_ifname
                )
            )

    def nfvis_setup_dhcp(self, machine, pexpect_session):
        pexpect_timeout = 10

        dh = DhcpdConf('/etc/dhcp/dhcpd.conf')
        nfvis_wan_ifname = self.config['machines'][machine]["nfvis-ifname"]
        pexpect_session.sendline("config")
        pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("no system:system settings wan ip")
        pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("no system:system settings default-gw")
        pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("system settings wan dhcp")
        pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("commit")
        pexpect_session.expect([r"nfvis\S*\(config\)#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("exit")
        pexpect_session.expect([r"nfvis\S*#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        pexpect_session.sendline("show bridge-settings {} ip-info".format(nfvis_wan_ifname))
        pexpect_session.expect([r"nfvis\S*#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        time.sleep(pexpect_timeout)
        bridge_settings = pexpect_session.before
        search_for_mac = r'(?<=mac_address)(.*?)(?=\\s+|$)'
        mac_address = re.search(search_for_mac, bridge_settings, flags=re.MULTILINE).group(0).strip()

        machine_pref = pref.get('machine-settings', {}).get(machine, {})  # noqa: F405
        dhcp_options = machine_pref.get('dhcp-options', {})
        interface = self.get_interface(machine, nfvis_wan_ifname)
        vnet, router_ip = self.get_route_info('vm3', 5)
        pnp_ip = '10.0.5.180'
        dh.add_host(
            machine,
            ipaddr=interface['ip'],
            netmask='255.255.255.0',
            router_ip=dhcp_options.get('routers', router_ip),
            domain=dhcp_options.get('domain-name', ''),
            dns=dhcp_options.get('domain-name-servers', ''),
            dhcp_id=interface.get('dhcp-id', ''),
            hwaddr=mac_address,
            vendor_options='5A1D;B2;K4;I%s;J9191' % pnp_ip,
        )
        dh.dump('/etc/dhcp/dhcpd.conf', superuser=True)
        Dhcpd().start()
        pexpect_session.sendline("hostaction bridge-dhcp-renew bridge {}".format(nfvis_wan_ifname))
        time.sleep(pexpect_timeout)
        result = pexpect_session.expect([r"nfvis\S*#", pexpect.TIMEOUT], timeout=pexpect_timeout)
        if not result == 0:
            raise TestbedException("Unable to configure dhcp for NFVIS instance.")

    def nfvis_initial_enable_vdaemon(self, machine):
        self.logger.info("[NFVIS] Starting vDaemon.")

        nfvis_host = self.config['machines'][machine]["interfaces"]["MGMT"]["ip"]
        nvfis_username = self.get_ssh_username(machine)
        nfvis_password = self.get_ssh_password(machine)
        headers = {"Content-type": 'application/vnd.yang.data+xml'}
        no_proxies = {
            "http": None,
            "https": None,
        }
        try:
            requests.post(
                NFVIS_VDAEMON_START_URL.format(nfvis_host),
                verify=False,
                headers=headers,
                auth=(nvfis_username, nfvis_password),
                proxies=no_proxies,
            )
            self.logger.info("[NFVIS] Waiting for vDaemon service to start, you might need to wait up to 3 minutes.")
            time.sleep(NFVIS_VDAEMON_WAIT_TIME)
        except requests.exceptions.ConnectionError:
            self.logger.error("[NFVIS] Could not connect to %s to enable vDaemon", nfvis_host)

    def netconf_request(self, machine, xml, username=None, password=None):
        with self.netconf_client(machine, look_for_keys=False, username=username, password=password) as m:
            try:
                m.lock('candidate')
                conf = m.edit_config(config=xml, target='candidate')
                m.commit()
            finally:
                m.unlock('candidate')
            # Wait 5 seconds to ensure lock is released.
            time.sleep(5)
            xml_str = conf.xml
            if "<ok/>" in xml_str:
                return 0
            else:
                self.logger.error("Error reposnse during netconf session: {}".format(xml_str))
                return 1

    def nfvis_execute_tunnel_config(self, machine):
        vpn_num = self.config['machines'][machine]["vpn"]
        tunnel_ifname = self.config['machines'][machine]['nfvis-ifname']
        tunnel_color = self.config['machines'][machine]["tunnel_color"]
        tunnel_encapsulation = self.config['machines'][machine]["tunnel_encapsulation"]

        self.logger.info("[NFVIS] Configuring system tunnel interface.")
        config = ET.Element("config", xmlns="urn:ietf:params:xml:ns:netconf:base:1.0")
        vpn = ET.SubElement(config, "vpn", xmlns="http://viptela.com/vpn")

        vpn_instance = ET.SubElement(vpn, "vpn-instance")
        ET.SubElement(vpn_instance, "vpn-id").text = str(vpn_num)

        interface = ET.SubElement(vpn_instance, "interface")
        ET.SubElement(interface, "if-name").text = tunnel_ifname
        tunnel_interface = ET.SubElement(interface, "tunnel-interface")

        encapsulation = ET.SubElement(tunnel_interface, "encapsulation")
        ET.SubElement(encapsulation, "encap").text = tunnel_encapsulation

        color = ET.SubElement(tunnel_interface, "color")
        ET.SubElement(color, "value").text = tunnel_color
        ET.SubElement(interface, "shutdown").text = "false"

        xml_string = xml.dom.minidom.parseString(ET.tostring(config)).toprettyxml()

        res = self.netconf_request(machine, xml_string)
        if res == 0:
            self.logger.info("[NFVIS] System Tunnel interface successfully configured.")

    def nfvis_execute_viptela_config(self, machine):
        site_id = self.config['machines'][machine]["site-id"]
        org_name = self.config['machines'][machine]["org_name"]
        system_ip = self.config['machines'][machine]["system-ip"]
        vbond_ip = self.config['machines'][machine]["vbond_ip"]
        vbond_port = self.config['machines'][machine]["vbond_port"]

        config = ET.Element("config", xmlns="urn:ietf:params:xml:ns:netconf:base:1.0")
        system = ET.SubElement(config, "system", xmlns="http://viptela.com/system")

        ET.SubElement(system, "system-ip").text = system_ip
        ET.SubElement(system, "site-id").text = str(site_id)
        ET.SubElement(system, "sp-organization-name").text = org_name
        ET.SubElement(system, "organization-name").text = org_name

        vbond = ET.SubElement(system, "vbond")
        ET.SubElement(vbond, "remote").text = vbond_ip
        ET.SubElement(vbond, "port").text = str(vbond_port)

        xml_string = xml.dom.minidom.parseString(ET.tostring(config)).toprettyxml()

        res = self.netconf_request(machine, xml_string)
        if res == 0:
            self.logger.info("vBond and viptela:system info was successfully configured.")

    def nfvis_initial_config_hostname(self, machine):
        nfvis_hostname = "nfvis-{}".format(machine)
        self.logger.info("[NFVIS] Changing  hostname to: {}.".format(nfvis_hostname))
        config = ET.Element("config", xmlns="urn:ietf:params:xml:ns:netconf:base:1.0")
        system = ET.SubElement(config, "system", xmlns="http://www.cisco.com/nfv")
        settings = ET.SubElement(system, "settings")
        ET.SubElement(settings, "hostname").text = nfvis_hostname

        xml_string = xml.dom.minidom.parseString(ET.tostring(config)).toprettyxml()

        res = self.netconf_request(machine, xml_string)
        if res == 0:
            self.logger.info("[NFVIS] Successfully changed hostname to: {} on NFVIS instance.".format(nfvis_hostname))

    def close_virsh_console(self, machine_console):
        if machine_console.isalive():
            machine_console.close()

    def cloud_init_bringup(self):
        cedge_sims = {
            k: v for (k, v) in self.machines().items() if 'sim' in self.personality(k) and not self.is_skip_vm(k)
        }
        self.logger.info("cedge simulators: {}".format(cedge_sims))

        c8kvs = {
            k: v for (k, v) in self.machines().items() if 'cedge_csr' == self.personality(k) and not self.is_skip_vm(k)
        }
        self.logger.info("cedge c8kvs: {}".format(c8kvs))

        hw_cedges = {
            k: v
            for (k, v) in self.machines().items()
            if 'cedge' in self.personality(k)
            and self.personality(k) not in ["cedge_csr", "sim"]
            and 'skip' not in self.config['machines'][k].get('flags', [])
        }
        self.logger.info("hw cedge: {}".format(hw_cedges))

        skip_mchs = {k: v for (k, v) in self.machines().items() if self.is_skip_vm(k)}
        self.logger.info("Skip cloud_init machines: {}".format(skip_mchs))

        all_machines_except_skip = {k: v for (k, v) in self.machines().items() if not self.is_skip_vm(k)}

        # upgrade cloud-init HW cedge
        self.setup_machines(hw_cedges, install_certs=False)

        # Waiting for sshd service to come up on all machines
        res = self.machine_boot_wait(hard_sleep=0, machine_list=all_machines_except_skip)

        if res != 0:
            raise TestbedBringupError('Issues with machines coming up after software activate')

        # cEdge simulator needs another reboot, it will trigger reboot itself
        if cedge_sims:
            hard_sleep = 30
            self.logger.info(
                "Sleep {}s, Check the second reboot for simulators bringup: {}".format(hard_sleep, cedge_sims)
            )
            time.sleep(hard_sleep)
            res = self.machine_boot_wait(machine_list=cedge_sims)

            if res != 0:
                raise TestbedBringupError('Issues with cedge simulators second reboot bringup')

        # setup cert for cEdge c8kvs, for vmanage/vbond/vsmart/vedge, skip setup_machines
        self.setup_machines(c8kvs, install_certs=False)

        if self.config.get("skip_ssh_key", False):
            return

        # setup SSH keys
        res = self.setup_ssh_keys()
        if res != 0:
            raise TestbedBringupError('Issues with setting up ssh keys')
        self.sudo(['chmod', '700', os.path.join(os.environ['HOME'], '.ssh', 'authorized_keys')])

        # NCS service patch
        self.ncs_service_patch()

    def bringup(
        self,
        restart=False,
        clear_cdb=False,
        console_logger=True,
        certs=True,
        date=None,
        sw_licensing=False,
        no_parallel_cert=False,
        bringup_fast=False,
        smu=None,
    ):
        self.logger.info("bringup()".center(60, "="))
        """ Testbed Bringup """
        if bringup_fast:
            return self.bringup_fast(
                restart, clear_cdb, console_logger, certs, date, sw_licensing, no_parallel_cert, smu
            )
        self.state['status'] = 'up'
        self.state['since'] = self.now()
        self.save_state()
        self.bringup_vcontainers()
        machines_to_setup = dict()
        viptela_vms = {
            k: v
            for (k, v) in self.machines(types=['vm']).items()
            if self.personality(k) in ['vedge', 'vbond', 'ztp', 'inet', 'vsmart', 'vmanage']
        }
        self.logger.info("viptela_vms: {}".format(viptela_vms))
        cedges = {k: v for (k, v) in self.machines().items() if 'cedge' in self.personality(k)}
        self.logger.info("cedges: {}".format(cedges))
        nfvis = {k: v for (k, v) in self.machines().items() if 'nfvis' in self.personality(k)}
        self.logger.info("nfvis: {}".format(nfvis))

        machines_to_setup.update(viptela_vms)
        machines_to_setup.update(cedges)
        machines_to_setup.update(nfvis)

        # cloud-init path
        if self.is_cloud_init():
            self.cloud_init_bringup()
            return 0

        # pdb.set_trace()
        # no cloud-init path
        self.logger.info("bringup.setup_machines()".center(60, "="))
        self.setup_machines(machines_to_setup, install_certs=True, smu=smu)
        # pdb.set_trace()

        highrise_pms = {k: v for (k, v) in self.machines(mgmt_intf_required=False).items() if self.is_highrise(k)}
        self.setup_machines(highrise_pms, install_certs=True)
        # pdb.set_trace()

        # Waiting for sshd service to come up on all machines
        self.logger.info("bringup.machine_boot_wait()".center(60, "="))
        res = self.machine_boot_wait(hard_sleep=0)

        if res != 0:
            raise TestbedBringupError('Issues with machines coming up after software activate')

        next_reboot = {}
        for machine in self.machines():
            if self.personality(machine) not in ['vmanage', 'vcontainer'] and not self.is_cedge(
                    machine) and not self.is_ucs(machine) and not self.is_nfvis(machine):
                if self.set_machine_personality_next(machine):
                    next_reboot[machine] = True
        # pdb.set_trace()

        self.logger.info("next_reboot:" , next_reboot)
        if len(list(next_reboot.keys())) > 0:
            res = self.machine_boot_wait(30, machine_list=next_reboot)
            if res != 0:
                raise TestbedBringupError('Issues with machines coming up after setting personality')

        self.logger.info("bringup.start_monitor()".center(60, "="))
        self.start_monitor(60.0)
        # pdb.set_trace()

        try:
            self.logger.info("bringup.setup_ssh_keys()".center(60, "="))
            res = self.setup_ssh_keys()
            if res != 0:
                raise TestbedBringupError('Issues with setting up ssh keys')
            self.sudo(['chmod', '700', os.path.join(os.environ['HOME'], '.ssh', 'authorized_keys')])
            #res = self.set_testbed_uboot_env()
            #it_netconf_mgmt_intf(clear_cdb)

            self.logger.info("bringup.enable_fips_mode_during_bringup()".center(60, "="))
            self.enable_fips_mode_during_bringup()
            # pdb.set_trace()

            self.logger.info("bringup.init_netconf_mgmt_intf_in_parallel()".center(60, "="))
            self.init_netconf_mgmt_intf_in_parallel(clear_cdb)
            # pdb.set_trace()

            if self.first_time or clear_cdb:
                # Change vManages' host name in vpn0 for the http --> https change (in https, certificate requires
                # Common Name, and it's set to viptela.testbed)
                viptela_devices = [x for x in self.machines() if self.personality(x) in ['vedge', 'vsmart', 'vbond', 'vmanage']]
                vmanage_list =  [x for x in self.machines() if self.personality(x) == 'vmanage']
                if certs == True:
                    if no_parallel_cert == True:
                        res = self.setup_vdaemon_certs(sw_licensing)
                    else:
                        self.logger.info("bringup.setup_vdaemon_certs_in_parallel()".center(60, "="))
                        self.setup_vdaemon_certs_in_parallel(sw_licensing)

                for machine in viptela_devices:
                    # pdb.set_trace()
                    self.logger.info(f"bringup.get_machine_session({machine})".center(60, "="))
                    with self.get_machine_session(machine, 25, None) as confd_session:
                        confd = CONFDSession(self, {'confd': {machine: confd_session}}, self.logger)  # noqa: F405
                        self.logger.info(f"confd.get_version({machine})".center(60, "="))
                        version = confd.get_version(machine)
                        confd_session.close()
                    self.logger.info(f"bringup.get_ssh_session({machine})".center(60, "="))
                    session = self.get_ssh_session(machine)
                    session.timeout = 10
                    try:
                        if session.expect(['[P|p]assword:', pexpect.TIMEOUT], timeout=5) == 0:
                            session.sendline(self.get_ssh_password(machine))
                        prompt_list = self.get_expect_prompt_list(machine)
                        self.logger.info(f"config --> system mode insecure".center(60, "="))
                        session.expect(prompt_list)
                        session.sendline('config')
                        session.expect(prompt_list)
                        session.sendline('system logging disk priority debug')
                        session.expect(prompt_list)
                        session.sendline('commit and-quit')
                        session.expect(['Commit complete', 'No modifications to commit'])
                        session.expect(prompt_list)
                        session.sendline('debug netconf traces')
                        session.expect(prompt_list)
                        session.sendline('debug confd developer-log')
                        session.expect(prompt_list)
                        if compare_version(version, '26.2', op.ge):
                            session.sendline('show system insecure mode')
                            if session.expect(['Insecure mode: Disabled', pexpect.TIMEOUT]) == 0:
                                session.sendline('\n')
                                session.expect(prompt_list)
                                session.sendline('config')
                                session.expect(prompt_list)
                                session.sendline('system mode insecure')
                                session.expect(prompt_list)
                                session.sendline('no system aaa password-policy')
                                session.expect(prompt_list)
                                session.sendline('commit and-quit')
                                session.expect(['Commit complete', 'No modifications to commit', pexpect.TIMEOUT])
                                session.expect(prompt_list)
                        session.sendline('exit')
                    finally:
                        session.close(force=True)

                for machine in vmanage_list:
                    self.logger.info('Configuring %s hostname to "viptela.testbed"' % machine)
                    self.logger.info(f"bringup.config_common_name_on_local_signing_server({machine})".center(60, "="))
                    tmp = self.config_common_name_on_local_signing_server(machine)
                    self.logger.info(tmp[1])
                    if tmp[0] == False:
                        self.logger.info('Failed to configure %s\'s hostname to "viptela.testbed"' % machine)

            # pdb.set_trace()
            # NCS service patch stage
            self.ncs_service_patch()
            # NCS service patch stage complete
            self.logger.info(f"bringup.enable_dhcp_for_all_containers()".center(60, "="))
            # pdb.set_trace()
            self.enable_dhcp_for_all_containers()
            if self.dynamips_config():
                return self.dynamips_state('bringup')
            else:
                return 0
        finally:
            self.purge()
            self.logger.info(f"bringup.stop_monitor()".center(60, "="))
            # pdb.set_trace()
            self.stop_monitor()

    def bringup_fast(
        self,
        restart=False,
        clear_cdb=False,
        console_logger=True,
        certs=True,
        date=None,
        sw_licensing=False,
        no_parallel_cert=False,
        smu=False,
    ):
        """Testbed Bringup"""
        self.state['status'] = 'up'
        self.state['since'] = self.now()
        self.save_state()
        self.bringup_vcontainers()
        machines_to_setup = dict()
        viptela_vms = {
            k: v
            for (k, v) in self.machines(types=['vm']).items()
            if self.personality(k) in ['vedge', 'vbond', 'ztp', 'inet', 'vsmart', 'vmanage']
        }

        cedges = {k: v for (k, v) in self.machines().items() if 'cedge' in self.personality(k)}
        self.logger.info("cedges: {}".format(cedges))

        if self.is_cloud_init():
            self.cloud_init_bringup()
            return 0

        machines_to_setup.update(viptela_vms)
        machines_to_setup.update(cedges)
        self.setup_machines(machines_to_setup, install_certs=True)

        highrise_pms = {
            k: v for (k, v) in self.machines(mgmt_intf_required=False).items() if self.personality(k) == 'highrise'
        }
        self.setup_machines(highrise_pms, install_certs=True)

        nfvis = {k: v for (k, v) in self.machines().items() if 'nfvis' in self.personality(k)}
        self.logger.info("nfvis: {}".format(nfvis))
        self.setup_machines(nfvis.keys(), install_certs=False)

        # XXX: (5-12-2021) Quick and dirty hack to make `testbed` skip waiting for SSH
        #      on NFVIS VMs on KVM, in current stage we don't have IP address
        #      yet. To be revisited later while integrating `addons/nfvis_kvm_instance.py`
        #      into testbed framework.
        nfvis_kvm = [k for k in nfvis if self.is_nfvis(k) and self.is_virtualized_nfvis(self.config["machines"][k])]
        booting_machines = {k: v for (k, v) in self.machines().items() if k not in nfvis_kvm}
        if nfvis_kvm:
            log_message = (
                "Skipping bringup for following NFVIS VMs: {}. "
                "Current workflow require to create those VMs with `addons/nfvis_kvm_instance.py`."
            )
            self.logger.info(log_message.format(nfvis_kvm))

        res = self.machine_boot_wait(hard_sleep=0, machine_list=booting_machines)
        if res != 0:
            raise TestbedBringupError('Issues with machines coming up after software activate')

        res = self.setup_ssh_keys()
        if res != 0:
            raise TestbedBringupError('Issues with setting up ssh keys')
        self.sudo(['chmod', '700', os.path.join(os.environ['HOME'], '.ssh', 'authorized_keys')])

        self.enable_fips_mode_during_bringup()

        self.init_netconf_mgmt_intf_in_parallel(clear_cdb)

        if self.first_time or clear_cdb:
            if certs:
                if no_parallel_cert:
                    res = self.setup_vdaemon_certs(sw_licensing, bringup_fast=True)
                else:
                    self.setup_vdaemon_certs_in_parallel(sw_licensing, bringup_fast=True)
        return 0

    def has_efi_boot(self, machine):
        return ('boot' in self.config['machines'][machine]) and (self.config['machines'][machine]['boot'] == 'efi')

    def copy_iperf_to_machines(self):
        self.logger.warning('Try to use preinstalled iperf instead!')
        return 0

    def start_console_logger(self):
        """Starts the console logger sessions for the testbed"""
        self.console_logger(True)

    def stop_console_logger(self):
        """Kills all console logger sessions for the testbed"""
        self.console_logger(False)

    def console_logger(self, start=True):
        """Starts or stops the console logger sessions"""
        vtest_dir = os.path.dirname(os.path.dirname(os.path.realpath(__file__)))
        console_logger = os.path.join(vtest_dir, 'tools', 'console_logger.py')
        for machine in self.machines():
            if 'pm' in machine and pref.__contains__('console_logger'):
                terminal_server = self.terminal_server_ip()
                if terminal_server:
                    port = self.console_logger_port(machine)
                    output_file = os.path.join(self.workdir, "console_output", machine+'_out.txt')
                    if not os.path.exists(output_file):
                        create_index_file = subprocess.Popen('touch '+output_file, shell = True, stdout = subprocess.PIPE, stderr=subprocess.PIPE)
                        #print create_index_file.stdout.read()
                        out, err = create_index_file.communicate()
                    if port is not None:
                        if start == True:
                            cmd = 'nohup python2.7 %s %s %s %s -start &' % (console_logger, output_file, terminal_server, port)
                            action = 'Started'
                        else:
                            cmd = 'nohup python2.7 %s %s %s %s -stop &' % (console_logger, output_file, terminal_server, port)
                            action = 'Stopped'
                        time.sleep(5)
                        subprocess.call(cmd, shell=True)
                        self.logger.info('%s recording %s console (port: %s) to %s' % (action, machine, port, output_file))

    def restart_random_daemon(self):
        """Restarts random daemon then waits for daemon to come up"""
        machine_list = list(self.machines().keys())
        machine_index = random.randint(0, len(machine_list)-1)
        machine = machine_list[machine_index]
        daemon_restart_list = self.get_daemon_restart_list(machine)
        if daemon_restart_list is not None:
            daemon_index = random.randint(0, len(daemon_restart_list)-1)
            daemon = daemon_restart_list[daemon_index]
            self.kill_daemon(machine, daemon)
            sleep_time = self.daemon_restart_wait_time()
            self.logger.info('Sleeping for %s seconds while %s restarts on %s' % (sleep_time, daemon, machine))
            time.sleep(sleep_time)

