    def check_and_start_ssh(self, machine):
        if not self.is_cedge_ssh_up(machine):
            if self.machine_boot_wait(hard_sleep=10, max_wait=30, machine_list={machine:True}) != 0:
                if self.machine_is_vm(machine):
                    self.initial_csr_config(machine)
                else:
                    self.enable_ssh_on_isr(machine)
                #increasing the wait time to 2 mins to prevent ssh failures
                ssh_wait = 120
                if self.machine_boot_wait(hard_sleep=0, max_wait=ssh_wait, machine_list={machine:True}) != 0:
                    raise TestbedCreateError('Cannot SSH after configuring through console and waiting for {} sec'.format(ssh_wait))

    def check_and_start_confd(self, machine):
        machine_path = os.path.join(self.workdir, machine)
        mgmt_ip = self.mgmt_ipaddr(machine)
        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.check_and_start_confd <<<<\n")
        with CedgeSession(mgmt_ip, logfile) as cedge_session:
            pnp_wait = 450
            if not cedge_session.is_confd_running():
                self.logger.warn('Confd: Failed to connect to server.')
                self.logger.warn('Trying to stop PnP discovery')
                cedge_session.stop_pnp()
                self.logger.info('Sleep for {} to let Confd start'.format(pnp_wait))
                time.sleep(pnp_wait)
                result = cedge_session.show_sdwan_software()
                self.logger.info('Softwares installed after pnp stop: \n %s' % result)
                if "% No entries found" in result:
                    time.sleep(60)
            if not cedge_session.is_confd_running():
                raise TestbedCreateError('Confd is still not up after stopping PnP and waiting for {} sec'.format(pnp_wait))

    def cedge_confd_running(self, machine, pexpect_session):
        pexpect_session.sendline('config-transaction')
        res = pexpect_session.expect(['Failed to connect to server', r'\(config\)#', pexpect.TIMEOUT], timeout=3)
        if res == 1:
            pexpect_session.sendline('end')
            pexpect_session.expect(r'.*#')
            return True
        else:
            return False

    def get_version_from_cedge_image(self, path):
        # returns string like: 'CW_VERSION=$16.9.87$\n'
        output = subprocess.check_output(
            'strings {} | grep -m 1 "CW_VERSION"'.format(path), shell=True, universal_newlines=True
        )
        return output.split('$')[1]

    def get_patch_version_from_cedge_image(self, path):
        # returns string like: 'CW_VERSION=$16.9.87$\n'
        output = subprocess.check_output(
            'strings {} | grep -m 1 "CW_FULL_VERSION"'.format(path), shell=True, universal_newlines=True
        )
        output = output.split('$')[1]
        return '.'.join(output.split('.')[:5])

    def make_nfvis_dir(self, machine, zip_file):
        machine_path = os.path.join(self.workdir, machine)
        if not os.path.isdir(machine_path):
            os.mkdir(machine_path)
        return 0

    def patch_mgmt_interface(self, machine, key, value):
        '''
        Patch the config of nfvis machine with the queried mac or ip of
        its mgmt interface
        '''
        try:
            mgmt_interface = self.config['machines'][machine]['interfaces']['MGMT']
        except KeyError:
            raise TestbedException("MGMT interface must be specified in topology yaml.")

        mgmt_interface[key] = value
        return value

    def patch_mgmt_ip(self, machine, ip):
        return self.patch_mgmt_interface(machine, 'ip', ip)

    def patch_mgmt_mac(self, machine, mac):
        return self.patch_mgmt_interface(machine, 'mac', mac)

    def patch_ucs_serial_id(self, ucs_name, serial):
        """
            Method patches in-memory configuration, read from
            yaml files by adding `serial-id` to UCS entry
            and `dhcp-id` to MGMT NFVIS interface.

            In case of missing entries method throws TestbedException.
        """
        nfvis_mgmt_vnet = 5  # nfvis requires to be connected with vmanage via vnet5
        try:
            ucs_config = self.config["machines"][ucs_name]
            nfvis_machine = ucs_config["nfvis"]
            nfvis_config = self.config["machines"][nfvis_machine]
        except KeyError as err:
            if err.args[0] == ucs_name:
                raise_msg = "Missing UCS machine: {}. Please make sure `pm` entry for machine exists".format(ucs_name)
            elif err.args[0] == "nfvis":
                raise_msg = "Missing `nfvis` key in {} machine. ".format(ucs_name)
                raise_msg += "Please make sure to include NFVIS mapping under machine entry"
            else:
                raise_msg = "Missing NFVIS entry: {}. ".format(nfvis_machine)
                raise_msg += "Please make sure NFVIS machine `vm` entry exists"
            raise_msg += " in provided yaml file for NFVIS topology."
            raise TestbedException(raise_msg)

        ucs_config['serial-id'] = serial
        nfvis_dhcp_iface = self.iface_from_vnet(nfvis_machine, nfvis_mgmt_vnet)
        try:
            nfvis_config['interfaces'][nfvis_dhcp_iface]['dhcp-id'] = serial
        except KeyError:
            raise_msg = "Missing iterface: {} under {} entry. ".format(nfvis_mgmt_vnet, nfvis_machine)
            raise_msg += "Please make sure in-bound mgmt interface definition "
            raise_msg += "exists in provided yaml file for NFVIS topology."
            raise TestbedException(raise_msg)

    def make_hw_ucs_dir(self, machine, image):
        '''
        This function runs before vnets are created, so NFVIS has to
        be accessed through the emulated serial console of the UCS.
        '''
        machine_path = os.path.join(self.workdir, machine)
        mgmt_ip = self.mgmt_ipaddr(machine)
        if not os.path.isdir(machine_path):
            os.mkdir(machine_path)
        ucs = UcsSession(mgmt_ip, name=machine, tb_path=self.workdir)
        serial_number = ucs.get_serial_number()
        nfvis = ucs.get_nfvis_serial_session(verbose=True)
        mac = nfvis.get_mgmt_mac_address()
        if not mac:
            raise Exception('%s: Failed to obtain mac address'%machine)
        # Patch the mac address of the UCS's NFVIS VM in the testbed
        # config file
        config = self.config['machines'][machine]
        nfvis_name = config['nfvis']
        self.load_config()
        self.patch_mgmt_mac(nfvis_name, mac)
        # Also patch in the UCS serial number for use as dhcp id
        self.patch_ucs_serial_id(machine, serial_number)
        self.save_config()
        # In an attempt to provision NFVIS with the IP address specified in
        # the config.yaml, we stop its DHCP client here, and have it issue
        # a dhcp renew after bringing up the vnets and dhcp server.
        # However, we are not able to stop dhcp client without root.
        del nfvis # login conservation
        return 0

    def get_route_info(self, machine_name, vnet_num):
        vnet = self.config['vnets'].get(vnet_num, None)
        if not vnet:
            return None, None
        router = self.config['machines'].get(machine_name, None)
        if not router:
            return None, None
        interfaces = router['interfaces']
        ifc = [ifc for ifc in interfaces.values() if ifc['vnet'] == vnet_num]
        if not ifc:
            return None, None
        router_ifc = ifc[0]
        return vnet, router_ifc['ip']

    def get_machine_configs(self, personalities):
        if isinstance(personalities, basestring):
            personalities = [personalities]
        configs = {
            box: specs for box, specs in self.config["machines"].items()
                        if "personality" in specs and specs["personality"] in personalities
        }
        return configs

    def takedown_isrv(self, machine):
        if 'encs_ip' in self.config['machines'][machine]:
            encs_ip = self.config['machines'][machine]['encs_ip']
            encs_user = self.config['machines'][machine]['encs_user']
            encs_password = self.config['machines'][machine]['encs_password']
            self.encs_undeploy(encs_ip, encs_user, encs_password, machine)
            time.sleep(5)
        else:
            raise Exception("ecns_ip must be specified in topology yaml for ISRv")

    def deploy_isrv_targz(self, machine_name, image_file):
        machine_path = os.path.join(self.workdir, machine_name)
        mgmt_ip = self.mgmt_ipaddr(machine_name)
        image_file_name = os.path.basename(image_file)
        encs_dut_image_name = "dut.tar.gz"
        encs_dut_image_path = "/data/intdatastore/uploads/dut.tar.gz"
        logfile = self.get_log_file_for_machine(machine_name)
        logfile.write(">>>> testbed.deploy_isrv_targz <<<<\n")
        if not os.path.isdir(machine_path):
            os.mkdir(machine_path)

        encs_ip = self.config['machines'][machine_name]['encs_ip']
        encs_user = self.config['machines'][machine_name]['encs_user']
        encs_password = self.config['machines'][machine_name]['encs_password']
        encs_deployment_cfg = self.config['machines'][machine_name]['encs_deployment_cfg']

        resp = self.encs_undeploy(encs_ip, encs_user, encs_password, machine_name)
        self.logger.info("Deleting {}, response code: {}".format(machine_name, resp))
        time.sleep(10)
        resp = self.encs_delete_image(encs_ip, encs_user, encs_password, encs_dut_image_name)
        self.logger.info("Deleting image {}, response code: {}".format(encs_dut_image_name, resp))
        time.sleep(10)
        resp = self.encs_delete_file_from_datastore(encs_ip, encs_user, encs_password, encs_dut_image_path)
        self.logger.info("Deleting file {} from datastore, response code: {}".format(encs_dut_image_path, resp))
        time.sleep(10)
        self.copy_to_machine(machine_name,
                             image_file,
                             encs_dut_image_path,
                             mgmt_ip=encs_ip,
                             user=encs_user,
                             password=encs_password,
                             port="22222")
        resp = self.encs_register_image(encs_ip, encs_user, encs_password, encs_dut_image_name, "file://{}".format(encs_dut_image_path))
        self.logger.info("Registering image {}, response code: {}".format(encs_dut_image_name, resp))
        image_is_active = False
        cnt = 0
        resp = None
        while not image_is_active and cnt < 30:
            cnt += 1
            time.sleep(20)
            resp = self.get_encs_image_state(encs_ip, encs_user, encs_password, encs_dut_image_name)
            if "IMAGE_ACTIVE_STATE" in resp.text:
                image_is_active = True
            elif "IMAGE_ERROR_STATE" in resp.text:
                break
            else:
                self.logger.info("Image is not active yet after waiting 20sec")
        if image_is_active:
            self.logger.info("Image {} is activated".format(encs_dut_image_name))
        else:
            if resp:
                self.logger.error("HTTP response: {}".format(resp.text))
            raise TestbedException("ISRv/C8Kv didn't become active on ENCS")
        resp = self.encs_deploy(encs_ip, encs_user, encs_password, encs_deployment_cfg)
        self.logger.info("Deploying {} on ENCS, response code: {}".format(machine_name, resp))
        return 0

    def check_nfvis_confd_version(self, encs_ip, encs_user, encs_password):
        '''
        Retrieve the confd version of nfvis usign the below cli:
        support show confd status | include vsn
        Return True if the confd version is > 8.0.8 (for 17.14.1 and above releases)
        otherwise return False
        '''
        cmd = ['support show confd status | include vsn']
        passwd = encs_password.encode("utf-8")
        if six.PY3:
            encode_passwd = base64.b64encode(passwd).decode('utf-8')
        else:
            encode_passwd = base64.b64encode(passwd)
        confd_ver_output = self.exec_paramiko_commands(encs_ip, encs_user, encode_passwd, cmd, return_output=True)
        confd_ver_output_status, confd_ver_output_str = confd_ver_output[0], confd_ver_output[1]
        try:
            if confd_ver_output_status:
                version = re.search(r"vsn: (.*)", confd_ver_output_str).group(1)
                if version:
                    self.logger.info("nfvis confd version: {} ".format(version))
        except Exception as ex:
            self.logger.exception('{}: Failed to retrieve nfvis confd version: {}'.format(encs_ip, ex))
        if compare_version(version, '8.0.8', op.ge):
            return [True, 'NFVIS confd version is > 8.0']
        else:
            return [False, 'NFVIS confd version is < 8.0']

    def deploy_isrv(self, machine, image_file):
        machine_path = os.path.join(self.workdir, machine)
        mgmt_ip = self.mgmt_ipaddr(machine)
        image_file_name = os.path.basename(image_file)
        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.deploy_isrv <<<<\n")
        if not os.path.isdir(machine_path):
            os.mkdir(machine_path)
        if 'encs_ip' in self.config['machines'][machine]:
            encs_ip = self.config['machines'][machine]['encs_ip']
            encs_user = self.config['machines'][machine]['encs_user']
            encs_password = self.config['machines'][machine]['encs_password']
            encs_deployment_cfg = self.config['machines'][machine]['encs_deployment_cfg']
            self.encs_undeploy(encs_ip, encs_user, encs_password, machine)
            time.sleep(5)
            self.encs_deploy(encs_ip, encs_user, encs_password, encs_deployment_cfg)
            self.machine_boot_wait(hard_sleep=0, max_wait=300, machine_list={machine: True})
            time.sleep(30)
            self.copy_to_machine(machine, image_file, image_file_name)
            with CedgeSession(mgmt_ip, logfile) as cs:
                base_ver = self.get_base_ver(machine)
                if len(base_ver.split('.')) == 3:
                    version = self.get_version_from_cedge_image(image_file)
                else:
                    version = self.get_patch_version_from_cedge_image(image_file)
                cs.save_configs_before_upgrade()
                cs.sdwan_software_install('bootflash:{}'.format(image_file_name))
                cs.sdwan_software_activate(version)
                if self.ssh_went_down(machine, maxwait=300):
                    self.logger.info("Machine is reloading after activate command")
                else:
                    raise Exception("Machined didn't start reloading, activation must have failed")
                self.machine_boot_wait(hard_sleep=0, max_wait=600, machine_list={machine: True})
            return 0

    def is_in_ios_prompt(self, session):
        return False

    def is_in_rommon(self, session):
        session.sendline('\r\n')
        result = session.expect(
            [
                'rommon.*>',
                'Username: ',
                'Password: ',
                r'initial configuration dialog\? \[yes/no\]:',
                r'.*#',
                'Press RETURN to get started',
                pexpect.TIMEOUT,
            ],
            timeout=10,
        )
        if result == 0:
            print("In Rommon")
            return True
        else:
            print("Not in rommon")
            return False

    def go_to_rommon(self, machine):
        if "console" in self.config['machines'][machine]:
            console_config = self.config['machines'][machine]['console']
            with ConsoleFactory(console_config) as session:
                self.wait_for_prompt(machine, session)
                if self.is_in_rommon(session):
                    self.logger.info("Device is in rommon")
                    return
                else:
                    self.login_to_machine(session, machine)
                    session.sendline('en')
                    session.expect('.*#')
                    session.sendline('reload')
                    try:
                        res = session.expect(
                            [
                                r'.*Continue to reload\?',
                                r'configuration has been modified. Save\?',
                                r'.*Proceed with reload\?',
                                pexpect.TIMEOUT,
                            ],
                            timeout=2,
                        )
                        if res == 0:
                            session.sendline('yes\n')
                        elif res == 1:
                            session.sendline('no')
                        elif res == 2:
                            session.sendline('\n')
                    except:
                        print('Session closed. Assuming machine went for reload')
                    time.sleep(30)
                    if self.is_in_rommon(session):
                        self.logger.info("Device went into rommon")

    def power_cycle_raritan(self, machine, pdu_config):
        logfile = self.get_log_file_for_machine(machine)
        pdu_ip = pdu_config["ip"]
        pdu_user = pdu_config["user"]
        pdu_outlet = pdu_config["outlet"]
        child = None
        try:
            cmd_bld = SSHCommandBuilder(host=pdu_ip, user=pdu_user, logger=self.logger)
            cmd_bld.add_kv_option('ConnectTimeout', 20)
            cmd = cmd_bld.build()
            if six.PY2:
                child = pexpect.spawn(cmd)
            else:
                child = pexpect.spawn(cmd, encoding='utf-8', codec_errors='ignore')
            child.logfile = logfile
            child.sendline("\n")
            res = child.expect(["password:", pexpect.TIMEOUT], timeout=3)
            if res == 0:
                if "password" in pdu_config:
                    child.sendline(pdu_config["password"])
                else:
                    self.logger.warning("PDU {} is asking passwrod. It is not configured in topology YAML".format(pdu_ip))
                    raise Exception("PDU password is not specified in the topology YAML")
            child.expect([">", "#"], timeout=300)
            child.sendline("power outlets {} cycle /y".format(pdu_outlet))
            child.expect([">", "#"], timeout=300)
            output = child.before.splitlines()
            pdu_output = ' '.join(output)
            if "Outlets can't be switched" in pdu_output:
                logfile.write("Outlets can't be switched - repeat power cycle ")
                time.sleep(10)
                child.sendline("power outlets {} cycle /y".format(pdu_outlet))
                child.expect([">", "#"])
        except Exception as ex:
            self.logger.exception("Failure to power-cycle")
        finally:
            try:
                if child: child.close()
            except:
                pass

    def power_cycle(self, machine, pdu_config):
        if pdu_config["type"] == "raritan":
            self.power_cycle_raritan(machine, pdu_config)

    def bringup_hw_cedge_day0(self, machine, image_file):
        machine_path = os.path.join(self.workdir, machine)
        if not os.path.isdir(machine_path):
            os.mkdir(machine_path)
        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.bringup_hw_cedge_day0 <<<<\n")

        assert os.path.isfile(image_file), "%s doesn't exist" % image_file
        assert "console" in self.config['machines'][machine], "Missing console details for {}".format(machine)
        assert "pdu" in self.config['machines'][machine], "Missing PDU details for {}".format(machine)
        assert os.path.isdir('/tftpboot'), "Missing /tftpboot. Make sure to have TFTP server installed"

        pdu_config = self.config['machines'][machine]["pdu"]
        console_config = self.config['machines'][machine]['console']
        tftp_conf = self.config['machines'][machine].get('tftp_boot_config', {})
        tftp_base_image = tftp_conf.get('tftp_base_image')
        if tftp_base_image:
            self.logger.info("Using base image {} defined in topology YAML".format(tftp_base_image))
            image_name = tftp_base_image
        else:
            image_name = os.path.basename(image_file)
            self.logger.info(
                "Topology YAML doesn't have 'tftp_base_image' defined for {}. Using {} instead".format(
                    machine, image_name
                )
            )
        mgmt_ip = self.mgmt_ipaddr(machine)
        shutil.copy(image_file, "/tftpboot")
        self.power_cycle(machine, pdu_config)

        with ConsoleFactory(console_config) as session:
            session.logfile = logfile

            def wait_for_ios_or_rommon(timeout):
                end_time = time.time() + timeout
                while time.time() < end_time:
                    res = session.expect(
                        [
                            "Cisco IOS Software",
                            "rommon .* >",
                            "Image validated",
                            "validate package: passed",
                        ],
                        timeout=600,
                    )
                    if res == 0 or res == 2 or res == 3:
                        return "ios"
                    if res == 1:
                        return "rommon"
                raise pexpect.TIMEOUT("Timed out waiting for IOS or ROMMON prompt")

            def set_rommon_var():
                session.sendline("DEVICE_MANAGED_MODE=controller")
                session.expect("rommon .* >")
                session.sendline("IP_ADDRESS={}".format(tftp_conf.get('ip_address', mgmt_ip)))
                session.expect("rommon .* >")
                session.sendline("IP_SUBNET_MASK={}".format(tftp_conf.get('ip_subnet_mask', '255.255.255.0')))
                session.expect("rommon .* >")
                session.sendline("DEFAULT_GATEWAY={}".format(tftp_conf.get('default_gateway', '10.0.99.1')))
                session.expect("rommon .* >")
                session.sendline("TFTP_SERVER={}".format(tftp_conf.get('tftp_server', '10.0.99.1')))
                session.expect("rommon .* >")
            session.expect(
                [
                    "Initializing Hardware",
                    "Rom image verified",
                    "Booting Cisco ROMMON",
                    "System Bootstrap",
                ],
                timeout=120,
            )
            in_rommon = False
            while not in_rommon:
                session.sendcontrol("]")
                session.expect("telnet>")
                time.sleep(0.3)
                session.sendline("send brk")
                time.sleep(0.3)
                session.sendline()
                res = session.expect(["rommon .* >", pexpect.TIMEOUT], timeout=2)
                if res == 0:
                    in_rommon = True

            if self.personality(machine) == "cedge_isr_mirabile":
                session.sendline("confreg 0x1860")
            else:
                session.sendline("confreg 0x40")
            session.expect("rommon .* >")
            set_rommon_var()
            session.sendline("sync")
            session.expect("rommon .* >")
            session.sendline("reset")
            session.expect("Resetting")
            session.expect(
                [
                    "Initializing Hardware",
                    "Rom image verified",
                    "Booting Cisco ROMMON",
                    "System Bootstrap",
                ],
                timeout=120,
            )
            session.expect("rommon .* >", timeout=60)
            set_rommon_var()
            session.sendline('boot tftp:{}'.format(image_name))
            boot_state = wait_for_ios_or_rommon(timeout=600)
            if boot_state == "rommon":
                upgrade_markers = (
                    "BootRomUpgrade",
                    "Rommon upgrade requested",
                    "Upgrade in progress",
                    "Detected a secure upgrade request",
                    "ROMMON upgrade successful",
                )
                if any(marker in session.before for marker in upgrade_markers):
                    self.logger.info("{} - ROMMON upgraded, booting primary image {}".format(machine, image_name))
                    set_rommon_var()
                    session.sendline('boot tftp:{}'.format(image_name))
                    session.expect(['Image validated', 'validate package: passed', 'Cisco IOS Software'], timeout=600)
            if (
                self.personality(machine) == "cedge_isr_mirabile"
            ):
                sed_status = session.expect(['SED Drive is locked, not mounting it', pexpect.TIMEOUT], timeout=60)
                if sed_status == 0:
                    session.expect(
                        ['SED drive is locked, reloading router to unlock the SED drive', pexpect.TIMEOUT], timeout=120
                    )
                    session.expect(['rommon .* >'], timeout=120)
                    session.sendline('boot tftp:{}'.format(image_name))
                    session.expect(['Image validated', 'validate package: passed', 'Cisco IOS Software'], timeout=600)
            # Begin logic to check if machine is Fugazi C8500L and if during boot up it
            # is performing firmware update.  If yes, Fugazi C8500L will reload, go back
            # to rommon and require another boot.
            # Check if machine personality is cedge_isr and
            # checks if image is Fugazi i.e. contains "c8000aes"
            if self.personality(machine) == 'cedge_isr':
                cmd = 'strings {} | grep -m 1 "c8000aes"'.format(image_file)
                # Send cmd to run_command_on_ubuntu to check if image is Fugazi or not
                # run_command_on_ubuntu will return list with first element being True or False
                fugazi_output = self.run_command_on_ubuntu(machine, cmd)
                # If run_command_on_ubuntu returns True then it means grep found a match
                # and image is Fugazi
                # If run_command_on_ubuntu returns False then it means grep found no match
                # and image is not Fugazi.  In this case skip remaining code and continue with device boot up.
                if fugazi_output[0]:
                    # run_command_on_ubuntu returned True meaning image is Fugazi
                    # Check for message if Fugazi is performing firmware update
                    fw_update_start = session.expect(['Updating MACs', pexpect.TIMEOUT], timeout=240)
                    if fw_update_start == 0:
                        # Fugazi is performing firmware update
                        self.logger.info("{} - Updating MACs - firmware update in progress".format(machine))
                        # Check for message Fugazi firmware update is complete
                        fw_update_complete = session.expect(
                            ["Update complete, reloading device", pexpect.TIMEOUT], timeout=120
                        )
                        if fw_update_complete == 0:
                            # Fugazi firmware update completed
                            self.logger.info("{} - Update complete, reloading device".format(machine))
                            # Check Fugazi is in rommon prompt
                            rommon_prompt = session.expect(["rommon 1 >", pexpect.TIMEOUT], timeout=120)
                            if rommon_prompt == 0:
                                # Fugazi is in rommon prompt
                                self.logger.info("{} - firmware update complete and device in rommon".format(machine))
                                # boot Fugazi image again
                                session.sendline('boot tftp:{}'.format(image_name))
                                session.expect(['Image validated', 'validate package: passed'], timeout=600)
                            else:
                                self.logger.info(
                                    "{} - firmware update completed but device not returned to rommon".format(machine)
                                )
                        else:
                            self.logger.info(
                                "{} - firmware update started but did not receive Update complete, reloading device".format(
                                    machine
                                )
                            )
            self.go_to_ios_prompt(machine, session)
            session.sendline("delete /force /recursive bootflash:vmanage-admin/tmp-admintech*.tar.gz")
            session.expect(r".*#")
            session.sendline("delete /force /recursive bootflash:vmanage-admin/*admin-tech.tar.gz")
            session.expect(r".*#")

    def get_base_ver(self, machine):
        result = self.get_iosxe_ssh_output(machine, 'sh sdwan software')
        for i in result.splitlines()[3:]:
            if i != "":
                active = i.split()[1]
                if active == 'true' or active == 'True':
                    active_image = i.split()[0]
                    return active_image

    def bringup_hw_cedge(self, machine):
        image_path = os.path.join(self.workdir, machine, "{}.bin".format(machine))
        machine_config = self.config['machines'][machine]
        self.logger.info(f"bringup_hw_cedge({machine})".center(60, "-"))
        if self.is_cloud_init():
            return self.bringup_hw_cedge_upgrade(machine, image_path)

        if "boot_mode" in machine_config:
            self.logger.info("Bringing up HW cEdge: {} boot_mode: {}.".format(machine, machine_config["boot_mode"]))
            if machine_config["boot_mode"] == "day0":
                return self.bringup_hw_cedge_day0(machine, image_path)
            elif machine_config["boot_mode"] == "regression":
                return self.bringup_hw_cedge_for_regression(machine, image_path)
            elif machine_config["boot_mode"] == "config_reset":
                return self.bringup_hw_cedge_config_reset(machine, image_path)
            elif machine_config["boot_mode"] == "software_reset":
                return self.bringup_hw_cedge_software_reset(machine)
            elif machine_config["boot_mode"] == "software_upgrade":
                return self.bringup_hw_cedge_upgrade(machine, image_path)
        else:
            self.logger.info("Bringing up HW cEdge: {} boot_mode not set, using upgrade method.".format(machine))
            return self.bringup_hw_cedge_upgrade(machine, image_path)

    def clean_non_sdwan(self, machine, pexpect_session):
        self.logger.info("Removing old packages from bootflash of {}".format(machine))
        expected_prompts = ["{}#".format(machine), "Router#"]
        pexpect_session.sendline("enable")
        pexpect_session.expect(expected_prompts)
        pexpect_session.sendline("install remove inactive")
        res = pexpect_session.expect([r"Do you want to remove the above files\? \[y/n\]", r"SUCCESS"], timeout=100)
        if res == 0:
            pexpect_session.sendline("y")
            pexpect_session.expect("SUCCESS")
        pexpect_session.expect(expected_prompts)
        pexpect_session.sendline("delete /force /recursive bootflash:sdwan")
        pexpect_session.expect(expected_prompts)
        pexpect_session.sendline("delete /force /recursive bootflash:*.pkg")
        pexpect_session.expect(expected_prompts)
        pexpect_session.sendline("delete /force /recursive bootflash:*.bin")
        pexpect_session.expect(expected_prompts)
        pexpect_session.sendline("delete /force /recursive bootflash:vmanage-admin")
        pexpect_session.expect(expected_prompts)
        pexpect_session.sendline("delete /force /recursive bootflash:*.conf")
        pexpect_session.expect(expected_prompts)

    def upgrade_non_sdwan(self, machine, pexpect_session, image_path):
        self.logger.info("Upgrade {} to {}".format(machine, image_path))
        expected_prompts = ["{}#".format(machine), "Router#"]
        pexpect_session.sendline("enable")
        pexpect_session.expect(expected_prompts)
        self.logger.info("Controller-mode reset on {} to remove all configuration files of old images".format(machine))
        pexpect_session.sendline("controller-mode reset")
        pexpect_session.expect("Continue", timeout=10)
        pexpect_session.sendline()
        pexpect_session.expect(["Initializing Hardware", "Rom image verified"], timeout=300)
        self.go_to_ios_prompt(machine, pexpect_session, tftp_image=image_path)
        pexpect_session.sendline("config terminal")
        pexpect_session.expect(r"\(config\)#")
        pexpect_session.sendline("no boot system")
        pexpect_session.expect(r"\(config\)#")
        pexpect_session.sendline("boot system flash {}".format(image_path))
        pexpect_session.expect(r"\(config\)#")
        pexpect_session.sendline("config-register 0x2102")
        pexpect_session.expect(r"\(config\)#")
        pexpect_session.sendline("end")
        pexpect_session.expect(expected_prompts)
        pexpect_session.sendline("write")
        pexpect_session.expect(r"\[OK\]")
        pexpect_session.expect(expected_prompts)
        pexpect_session.sendline("reload")
        res = pexpect_session.expect([r"System configuration has been modified\. Save\?", pexpect.TIMEOUT], timeout=2)
        if res == 0:
            pexpect_session.sendline("no")
        pexpect_session.expect(r"Proceed with reload\?")
        pexpect_session.sendline()
        pexpect_session.expect(["Initializing Hardware", "Rom image verified"], timeout=120)

