    def send_and_confirm_cmd(self, machine, session, cmd):
        session.sendline(cmd)
        res = session.expect([r".*\[confirm\]", pexpect.TIMEOUT], timeout=10)  # noqa: W605
        if res == 0:
            session.sendline()
        else:
            self.logger.info("Didn't get confirmation request from {} after cmd {}".format(machine, cmd))

    def bringup_hw_cedge_config_reset(self, machine, image_file):
        self.logger.info("Config reset and reload on {}".format(machine))
        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.bringup_hw_cedge_config_reset <<<<\n")
        console_config = self.config['machines'][machine]['console']
        with ConsoleFactory(console_config) as session:
            session.logfile = logfile
            self.cedge_stop_pnp(machine, session)
            self.go_to_ios_prompt(machine, session)
            self.send_and_confirm_cmd(machine, session, "request platform software sdwan config reset")
            session.expect(["{}#".format(machine), "Router#", pexpect.TIMEOUT], timeout=10)
            if "Config reset is raised successfully, device will reload shortly." in session.before:
                self.logger.info("Got reload confirmation from {}, waiting for reboot...".format(machine))
            else:
                if "Reload is required for config-reset" in session.before:
                    self.logger.info("{} required reload after config-reset".format(machine))
                else:
                    self.logger.info(
                        "{} didn't require reload after config-reset. Proceeding with reload regardless".format(machine)
                    )
                self.send_and_confirm_cmd(machine, session, "reload")
            session.expect(["Initializing Hardware", "Rom image verified"], timeout=300)
            self.go_to_ios_prompt(machine, session)
            self.initial_config(machine, session)

    def bringup_hw_cedge_software_reset(self, machine):
        self.logger.info("Software reset and reload on {}".format(machine))
        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.bringup_hw_cedge_software_reset <<<<\n")
        console_config = self.config['machines'][machine]['console']
        with ConsoleFactory(console_config) as session:
            session.logfile = logfile
            self.cedge_stop_pnp(machine, session)
            self.go_to_ios_prompt(machine, session)
            self.send_and_confirm_cmd(machine, session, "request platform software sdwan software reset")
            result = session.expect([".*FACTORY_RESET.*", ".*System Bootstrap.*", pexpect.TIMEOUT], timeout=600)
            if result in [0, 1]:
                self.logger.info("Got software reset confirmation from {}, waiting for reboot...".format(machine))
                result = session.expect(["Press RETURN to get started!", pexpect.TIMEOUT], timeout=1800)
                if result == 0:
                    self.logger.info("{} software reset is finished, machine is back".format(machine))
                    self.go_to_ios_prompt(machine, session)
                    self.initial_config(machine, session)
                    return
                elif result == 1:
                    self.logger.error("{} reset is taking too long".format(machine))
            elif result == 2:
                self.logger.error("Can't get software reset confirmation from {} check machine logs".format(machine))

            raise TestbedException("Software reset failed")

    def bringup_hw_cedge_for_regression(self, machine, image_file):
        machine_path = os.path.join(self.workdir, machine)
        mgmt_ip = self.mgmt_ipaddr(machine)
        if not os.path.isdir(machine_path):
            os.mkdir(machine_path)

        if not os.path.isfile(image_file):
            raise TestbedBringupError("%s doesn't exist" % image_file)

        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.bringup_hw_cedge_for_regression <<<<\n")
        console_config = self.config['machines'][machine]['console']
        with ConsoleFactory(console_config) as session:
            session.logfile = logfile
            if "pdu" in self.config['machines'][machine]:
                self.logger.info("Power-cycling {}".format(machine))
                pdu_config = self.config['machines'][machine]["pdu"]
                self.power_cycle(machine, pdu_config)
            elif self.is_in_rommon(session):
                session.sendline("reset")
                session.expect("Resetting")
            else:
                self.logger.info("Device is not in rommon")
                self.logger.info("No PDU info for {}. Trying to reload through CLI".format(machine))
                self.go_to_ios_prompt(machine, session)
                session.sendline("reload")
                res = session.expect([r"System configuration has been modified\. Save\?", pexpect.TIMEOUT], timeout=2)
                if res == 0:
                    session.sendline("no")
                session.expect(r"Proceed with reload\?")
                session.sendline()

            session.expect(["Initializing Hardware", "Rom image verified"], timeout=120)
            in_rommon = False
            while not in_rommon:
                session.sendcontrol("]")
                session.expect("telnet>")
                time.sleep(0.3)
                session.sendline("send brk")
                time.sleep(0.3)
                session.sendline()
                res = session.expect(["rommon 1 >", pexpect.TIMEOUT], timeout=2)
                if res == 0:
                    in_rommon = True

            session.sendline("confreg 0x40")
            session.expect("rommon 2 >")
            mgmt_ip = self.mgmt_ipaddr(machine)
            tftp_conf = self.config['machines'][machine].get('tftp_boot_config', {})
            tftp_base_image = tftp_conf.get('tftp_base_image')
            if tftp_base_image:
                self.logger.info("Using base image {} defined in topology YAML".format(tftp_base_image))
            else:
                self.logger.info("Topology YAML doesn't have 'tftp_base_image' defined for {}. Using base.bin instead" .format(machine))
                tftp_base_image = "base.bin"
            session.sendline("DEVICE_MANAGED_MODE=autonomous")
            session.expect("rommon 3 >")
            session.sendline("IP_ADDRESS={}".format(tftp_conf.get('ip_address', mgmt_ip)))
            session.expect("rommon 4 >")
            session.sendline("IP_SUBNET_MASK={}".format(tftp_conf.get('ip_subnet_mask', '255.255.255.0')))
            session.expect("rommon 5 >")
            session.sendline("DEFAULT_GATEWAY={}".format(tftp_conf.get('default_gateway', '10.0.99.1')))
            session.expect("rommon 6 >")
            session.sendline("TFTP_SERVER={}".format(tftp_conf.get('tftp_server', '10.0.99.1')))
            session.expect("rommon 7 >")
            session.sendline("sync")
            session.expect("rommon 8 >")
            session.sendline("reset")
            session.expect("Resetting")
            session.expect(["Initializing Hardware", "Rom image verified"], timeout=120)
            session.expect("rommon 1 >", timeout=60)
            session.sendline("boot tftp:{}".format(tftp_base_image))
            session.expect(['Image validated', 'validate package: passed'], timeout=600)
            self.go_to_ios_prompt(machine, session)
            self.clean_non_sdwan(machine, session)
            self.configure_ssh_non_sdwan(machine, session)
            self.copy_to_machine(machine, image_file, 'image.bin')
            self.go_to_ios_prompt(machine, session)
            self.upgrade_non_sdwan(machine, session, "bootflash:image.bin")
            self.go_to_ios_prompt(machine, session)
            session.sendline("controller-mode enable")
            session.expect(r"Continue\? \[confirm\]")
            session.sendline()
            res = session.expect([r"Do you want to abort\?", pexpect.TIMEOUT])
            if res == 0:
                session.sendline("no")
            res = session.expect(
                [r"Warning: Detected device with smaller bootflash.*Continue\? \[confirm\]", pexpect.TIMEOUT], timeout=5
            )
            if res == 0:
                session.sendline()
            session.expect("Mode change success")
            session.expect(["Initializing Hardware", "Rom image verified"], timeout=300)
            self.go_to_ios_prompt(machine, session)
            self.logger.info("sleep 30s before pnpa service discovery stop")
            time.sleep(30)
            session.sendline("pnpa service discovery stop")
            #self.logger.info("Expecting {} to reload after 'pnpa service discovery stop'".format(machine))
            session.expect(["{}#".format(machine), "Router#"])
            session.expect("Completed expand package", timeout=600)
            #session.expect("reload action requested", timeout=300)
            #session.expect("Initializing Hardware", timeout=300)
            #self.logger.info("{} is reloading".format(machine))
            session.expect("Started install commit", timeout=100)
            session.expect("Completed install commit", timeout=100)
            res = session.expect(
                ["Device is running in bundle boot mode. Reloading the device to enable install mode", pexpect.TIMEOUT],
                timeout=30,
            )
            if res == 0:
                self.logger.info('install mode initiated via pnp stop')
                session.expect(["Initializing Hardware", "Rom image verified"], timeout=300)
                self.go_to_ios_prompt(machine, session)
                session.sendline("pnpa service discovery stop")
            self.go_to_ios_prompt(machine, session)
            session.sendline("request platform software sdwan software upgrade-confirm")
            session.expect("Started install commit", timeout=100)
            session.expect("Completed install commit", timeout=100)
            session.sendline()
            session.expect(["{}#".format(machine), "Router#"])
            session.sendline("show version | include packages.conf")
            res = session.expect(['bootflash:packages.conf', pexpect.TIMEOUT], timeout=3)
            if res == 0:
                self.logger.info('install mode completed')
            else:
                self.logger.info('install mode initiated via software reset')
                session.sendline("request platform software sdwan software reset")
                res = session.expect([r'Are you sure you want to reset.*\[confirm\]', pexpect.TIMEOUT], timeout=3)
                if res == 0:
                    session.sendline()
                session.expect(["Initializing Hardware", "Rom image verified"], timeout=300)
            self.go_to_ios_prompt(machine, session)
            self.initial_config(machine, session)
        return 0

    def delete_bootstrap_file(self, machine, pexpect_session):
        # Delete bootstrap file, it is used for sdwan-init hw

        for bootstrap_file in ["ciscosdwan_cloud_init.cfg", "ciscosdwan.cfg"]:
            self.logger.info("{}: delete bootstrap file: {}".format(machine, bootstrap_file))
            self.clear_pexpect_session_cache(pexpect_session)
            pexpect_session.sendline('delete bootflash:{}'.format(bootstrap_file))
            while True:
                res = pexpect_session.expect(['.*#', "confirm", r"\?"], timeout=30)
                if res == 0:
                    break
                if res == 1 or res == 2:
                    pexpect_session.sendline('\n')

    def need_cloud_init_software_reset(self, machine):
        is_cloud_init = self.config.get("sdwan_init", False)

        machine_config = self.config["machines"][machine]
        skip_software_reset = machine_config.get("skip_software_reset", True)

        return all([is_cloud_init, skip_software_reset])

    def copy_cloud_init_to_hw(self, machine):
        cloud_init_cfg = os.path.join(self.workdir, machine, "cloud_init.cfg")

        # ASR1000, ISR4000, ISR1000, C8500, C8300...
        self.copy_to_machine(machine, cloud_init_cfg, 'ciscosdwan.cfg')

        # CSR1000v, ISRv, ASR1002-X
        self.copy_to_machine(machine, cloud_init_cfg, 'ciscosdwan_cloud_init.cfg')

    def show_smu_version(self, new_cedge_session, image_file_name):
        ret = new_cedge_session.show(
            "show install package bootflash:" + image_file_name + " | section SMU Compatible with Version:"
        )
        version = ret[1].split(':')
        ret = new_cedge_session.show("sh ins pack bootflash:" + image_file_name + " | section Defect ID:")
        defect_id = ret[1].split(':')
        if len(version) == 2 and len(defect_id) == 2:
            return version[-1].strip().split('\r')[0] + '.' + defect_id[-1].strip().split('\r')[0]
        else:
            raise TestbedBringupError('Cannot retrive the version and cdetid for the specified SMU')

    def remove_other_files_than_mounted_version(self, machine, new_cedge_session, version):
        '''
        version = 002049 for below example is version we want to preserve

        Remove files with name patter c1100*.[pkg|conf]
        [pm5:/]$ ls -lah  /bootflash/c1100*.conf c1100*.pkg |  grep -v 002049
        -rw-rw-rw-. 1 root root  14M Mar  4 02:03 /bootflash/c1100-firmware_c1100_gfast.BLD_V1717_THROTTLE_LATEST_20250303_002711.SSA.pkg
        -rw-rw-rw-. 1 root root  12M Mar  4 02:03 /bootflash/c1100-firmware_c1100_shdsl.BLD_V1717_THROTTLE_LATEST_20250303_002711.SSA.pkg
        -rw-rw-rw-. 1 root root 5.5M Mar  4 02:03 /bootflash/c1100-firmware_c1100_vadsl.BLD_V1717_THROTTLE_LATEST_20250303_002711.SSA.pkg
        -rw-rw-rw-. 1 root root 8.3M Mar  4 02:03 /bootflash/c1100-firmware_p_1t.BLD_V1717_THROTTLE_LATEST_20250303_002711.SSA.pkg
        '''

        def _list_files(msg):
            self.logger.info(msg)
            cmd = 'ls /bootflash/c1100*.conf /bootflash/c1100*.pkg | xargs du -h'
            ret = new_cedge_session.shell_exec_cmd(cmd)
            if not ret[0]:
                self.logger.warning("Could not get files for listing")
                return

            self.logger.info('/bootflash/ .conf and .pkg files:')
            for line in [li for li in ret[1].splitlines() if li.endswith(".pkg") or li.endswith(".conf")]:
                self.logger.info(line)
            return

        _list_files('Listing files before leftovers removal(preserve files with {})'.format(version))

        cmd = 'ls -lah /bootflash/c1100*.conf /bootflash/c1100*.pkg | grep -v {}'.format(version)
        ret = new_cedge_session.shell_exec_cmd(cmd)
        if not ret[0]:
            return False, "Could not get files to remove with version={}".format(version)

        files = []
        for line in [li for li in ret[1].splitlines() if li.endswith(".pkg") or li.endswith(".conf")]:
            # grab only file path
            file = line.split()[-1]
            files.append(file)

        if files:
            self.logger.warning("{}: Removing following files considered as leftovers:".format(machine))
            self.logger.warning(files)
            cmds = ['rm -f {}'.format(f) for f in files]
            ret = new_cedge_session.shell_exec_cmd(cmds)
            _list_files('Listing files after leftovers removal(preserve files with {})'.format(version))
            if not ret[0]:
                return False, 'Error when removing lefotovers:\n{}'.format(ret[1])
            return True, 'Leftover files removed'
        return True, 'No leftover files found for removal'

    def get_mounted_image_version(self, machine, new_cedge_session):
        '''
        Looking for _20250308_002049. in that case in:
        /dev/mapper/c1100-mono-universalk9.BLD_V1717_THROTTLE_LATEST_20250308_002049.SSA.pkg on /tmp/sw/mount/c1100-mono-universalk9.BLD_V1717_THROTTLE_LATEST_20250308_002049.SSA.pkg type squashfs (ro,relatime,seclabel)
        or looking for  _20250311_033833_
        /dev/mapper/c1100-mono-universalk9.BLD_V1717_THROTTLE_LATEST_20250311_033833_V17_17_0_53.SSA.pkg on /tmp/sw/mount/c1100-mono-universalk9.BLD_V1717_THROTTLE_LATEST_20250311_033833_V17_17_0_53.SSA.pkg type squashfs (ro,relatime,seclabel)
        After having a match groupd of exactly 6 digits is extracted, i.e _20250311_033833_  => 033833
        '''
        cmd = 'mount | grep SSA.pkg | head -n 1'
        ret = new_cedge_session.shell_exec_cmd(cmd)
        pattern = r'_(\d{8})_(\d{6})[\.|_]'

        if not ret[0]:
            if ret[1] == "session is down":
                self.logger.warning('Reloading cEdge session...')
                new_cedge_session.relogin_cedge_session()
                time.sleep(2)
                ret = new_cedge_session.shell_exec_cmd(cmd)
            else:
                return False, "Could not get image version: {}".format(ret[1])

        if not ret[0]:
            return False, "Could not get image version: {}".format(ret[1])

        for line in ret[1].splitlines():
            line_with_ssa_pkg = None
            if 'SSA.pkg' in line:
                line_with_ssa_pkg = line
                file = line.split()[0]
                match = re.search(pattern, file)
                if match:
                    # _20250308_002049. -> 002049
                    # _20250311_033833_ -> 033833
                    return True, match.group(2)
                break
        msg = "Could not get image version"
        if line_with_ssa_pkg:
            msg = msg + ' in : ' + line_with_ssa_pkg

        return False, msg

    def get_software_active_default_state(self, machine, new_cedge_session):
        show_version = "show sdwan software"
        ret = new_cedge_session.show(show_version)
        if not ret[0]:
            if ret[1] == "session is down":
                self.logger.warning('Reloading cEdge session...')
                new_cedge_session.relogin_cedge_session()
                ret = new_cedge_session.show(show_version)
            else:
                raise Exception("{}: error: {}".format(machine, ret[1]))

        if not ret[0]:
            raise Exception("{}: error: {}".format(machine, ret[1]))

        software_version_info_dict = {}

        """
        fg. ret[1] should be below string.

        pm5#show sdwan software
        VERSION            ACTIVE  DEFAULT  PREVIOUS  CONFIRMED  TIMESTAMP
        ------------------------------------------------------------------------------------
        17.12.01.0.173596  false   false    true      auto       2023-02-09T02:53:30-00:00
        17.12.01.0.174234  true    true     false     auto       2023-02-21T13:13:47-00:00

        Total Space:387M Used Space:161M Available Space:221M

        pm5#
        """

        for line in ret[1].splitlines():
            # fg. line is "17.12.01.0.174234  true    true     false     auto       2023-02-21T13:13:47-00:00"
            records = line.split()
            # Normally records should be 6
            if len(records) >= 5 and records[1].upper() in ["TRUE", "FALSE"]:
                version = records[0]
                active_version = records[1].upper()
                default_version = records[2].upper()

                software_version_info_dict[version] = {
                    "active_version": active_version,
                    "default_version": default_version,
                }

        return software_version_info_dict

    def set_active_software_default(self, machine, new_cedge_session):
        software_version_info_dict = self.get_software_active_default_state(machine, new_cedge_session)

        # set active-software default
        for software_version in software_version_info_dict:
            software_version_info = software_version_info_dict[software_version]

            active_version = software_version_info["active_version"]
            default_version = software_version_info["default_version"]

            if active_version == "TRUE" and default_version == "FALSE":

                set_default_version = "request platform software sdwan software set-default {}".format(software_version)
                self.logger.info("{}: set current active image: {} default".format(machine, set_default_version))
                ret = new_cedge_session.show(set_default_version)
                if not ret[0]:
                    raise Exception("{}: set-default software {}, failed: {}".format(machine, software_version, ret[1]))
                break

    def delete_non_active_image_ssh(self, machine, new_cedge_session):
        software_version_info_dict = self.get_software_active_default_state(machine, new_cedge_session)

        # remove non-default software default
        for software_version in software_version_info_dict:
            software_version_info = software_version_info_dict[software_version]

            active_version = software_version_info["active_version"]

            if active_version != "TRUE":
                remove_version = "request platform software sdwan software remove {}".format(software_version)
                self.logger.info("{}: remove image: {}".format(machine, remove_version))
                ret = self.get_iosxe_ssh_output(machine, remove_version)
                self.logger.info(ret)

    def delete_non_active_image(self, machine, new_cedge_session):
        software_version_info_dict = self.get_software_active_default_state(machine, new_cedge_session)

        # remove non-default software default
        for software_version in software_version_info_dict:
            software_version_info = software_version_info_dict[software_version]

            active_version = software_version_info["active_version"]

            if active_version != "TRUE":
                remove_version = "request platform software sdwan software remove {}".format(software_version)
