    def is_cloud_init(self):
        return self.config.get("sdwan_init", False)

    def get_console_config(self, machine):
        machine_config = self.config['machines'].get(machine, {})
        serial_port = machine_config.get("serial_port", 0)
        ucs_name = machine_config.get("ucs", "default")

        ucs_configs = self.config.get("ucs", {})
        ucs_config = ucs_configs.get(ucs_name, {})

        default_ip = ucs_config.get("ip", "localhost")
        vtest_ip = ucs_config.get("vtest_ip", default_ip)

        console_config = {}
        if serial_port:
            console_config["type"] = "telnet"
            console_config["ip"] = vtest_ip
            console_config["port"] = serial_port

        return console_config

    def dump_ca(self, testbed_cloud_init, logger=None):
        # to be compatible with openssl
        cert = Cert(self, logger=logger)
        private_key_path = cert.private_key_path
        cert_chain_path = cert.cert_chain_path

        ca_cert = testbed_cloud_init.cacert_pem_string
        ca_key = testbed_cloud_init.ca_private_key_string

        with open(cert_chain_path, "w") as f_ca_cert, open(private_key_path, "w") as f_ca_key:
            f_ca_cert.write(ca_cert)
            f_ca_key.write(ca_key)

    def dump_cloud_init(self, cloud_init_machine_config, machine_dir):
        cloud_init_parameter = cloud_init_machine_config["cloud_init_parameter"]
        cloud_init = cloud_init_machine_config["cloud_init"]

        if not cloud_init:
            return

        csr = cloud_init_parameter["csr"]
        crt = cloud_init_parameter["crt"]
        key = cloud_init_parameter["private_key"]
        cert_serial_number = cloud_init_parameter["cert_serial_number"]

        cloud_init_config = cloud_init["config"]
        cloud_init_iso = cloud_init["iso"]

        if all([csr, crt, key]):
            with open(os.path.join(machine_dir, "server.csr"), "w") as f:
                f.write(csr)
            with open(os.path.join(machine_dir, "server.crt"), "w") as f:
                f.write(crt)
            with open(os.path.join(machine_dir, "server.key"), "w") as f:
                f.write(key)

        with open(os.path.join(machine_dir, "cert_serial_number.txt"), "w") as f:
            f.write(cert_serial_number)
        with open(os.path.join(machine_dir, "cloud_init.cfg"), "w") as f:
            f.write(cloud_init_config)
        with open(os.path.join(machine_dir, "seed.iso"), 'wb') as f:
            f.write(cloud_init_iso)

    def update_sdwan_init_machine_password(self, machine, cloud_init_machine_config):
        cloud_init_parameter = cloud_init_machine_config.get("cloud_init_parameter", None)
        if not cloud_init_parameter:
            self.logger.error("{}, cloud_init_parameter not found, skip the machine".format(machine))
            return
        admin_password = cloud_init_parameter.get("admin_password", None)
        if not admin_password:
            self.logger.error("{}, did not get the admin password, skip the machine".format(machine))
            return

        self.config["machines"][machine]["password"] = admin_password
        self.save_config()

    def dump_serials_to_dir(self, testbed_cloud_init, tb_dir):
        def change_serial_simulator(organization_viptela_dict, serial_set, multi_certs):
            # This function is used for simulator to change the serial num in serial.viptela
            organization_viptela_dict = copy.deepcopy(organization_viptela_dict)
            # Random Value, just used as protection
            last_serial = "81CD73D8C323FF2D"
            for chassis in organization_viptela_dict["chassis_list"]:
                if "serial" in chassis:
                    serial = chassis["serial"]
                    while True:
                        if serial in serial_set:
                            if multi_certs:
                                raise Exception("Multi certs, serial {} is duplicated".format(serial))

                            serial_int = int(last_serial, 16) + 1
                            serial = format(serial_int, "X")
                            last_serial = serial
                        else:
                            break

                    chassis["serial"] = serial
                    last_serial = serial
                    serial_set.add(serial)
                else:
                    serial_list = chassis["serial_list"]
                    for serial_dict in serial_list:
                        serial = serial_dict["sudi_cert_serial"]

                        while True:
                            if serial in serial_set:
                                if multi_certs:
                                    raise Exception("Multi certs, serial {} is duplicated".format(serial))
                                serial_int = int(last_serial, 16) + 1
                                serial = format(serial_int, "X")
                                last_serial = serial
                            else:
                                break

                        serial_dict["sudi_cert_serial"] = serial
                        serial_dict["serial"] = serial
                        last_serial = serial
                        serial_set.add(serial)
            return organization_viptela_dict

        def dump_serials(
            folder,
            csv_serial=None,
            manual_serial=None,
            json_serial=None,
            json_serial_sim_instances=None,
            serial_set=None,
            multi_certs=None,
        ):
            if csv_serial:
                csv_serial_file = os.path.join(folder, "serial.csv")
                with open(csv_serial_file, "w") as f:
                    f.write(csv_serial)

            if manual_serial:
                manual_serial_file = os.path.join(folder, "manual_serial.txt")
                with open(manual_serial_file, "w") as f:
                    f.write(manual_serial)

            if multi_certs:
                # merge json_serial and json_serial_sim_instances
                def merge_json_serial_and_json_serial_sim_instances(json_serial, json_serial_sim_instances):
                    organization_viptela_dict = dict()
                    for organization_chassis_dict in json_serial:
                        organization = organization_chassis_dict["organization"]
                        chassis_list = organization_chassis_dict["chassis_list"]
                        if organization in organization_viptela_dict:
                            organization_viptela_dict[organization]["chassis_list"].extend(chassis_list)
                        else:
                            organization_viptela_dict[organization] = organization_chassis_dict

                    for organization_chassis_dict in json_serial_sim_instances:
                        organization = organization_chassis_dict["organization"]
                        chassis_list = organization_chassis_dict["chassis_list"]
                        if organization in organization_viptela_dict:
                            organization_viptela_dict[organization]["chassis_list"].extend(chassis_list)
                        else:
                            organization_viptela_dict[organization] = organization_chassis_dict

                    return list(organization_viptela_dict.values())

                if json_serial and json_serial_sim_instances:
                    json_serial = json.loads(json_serial)
                    json_serial_sim_instances = json.loads(json_serial_sim_instances)

                    json_serial = merge_json_serial_and_json_serial_sim_instances(
                        json_serial, json_serial_sim_instances
                    )
                    json_serial = json.dumps(json_serial)
                elif json_serial_sim_instances:
                    json_serial = json_serial_sim_instances

                dump_json_serial_viptela(json_serial, folder, "serial.json", "serial.viptela", serial_set, multi_certs)
                return

            if json_serial:
                dump_json_serial_viptela(json_serial, folder, "serial.json", "serial.viptela", serial_set, multi_certs)

            if json_serial_sim_instances:
                dump_json_serial_viptela(
                    json_serial_sim_instances, folder, "serial_sim.json", "serial_sim.viptela", serial_set, multi_certs
                )

        def dump_json_serial_viptela(json_serial, folder, json_file_name, viptela_file_name, serial_set, multi_certs):
            json_serial_file = os.path.join(folder, json_file_name)
            with open(json_serial_file, "w") as f:
                f.write(json_serial)

            time_stamp = time.strftime("%Y-%m-%d_%H:%M:%S", time.localtime())
            json_serial = json.loads(json_serial)
            for organization_viptela in json_serial:
                organization = organization_viptela["organization"]
                organization_viptela["timestamp"] = time_stamp
                organization_viptela_file_name = "{}_{}".format(organization.replace(" ", "_"), viptela_file_name)
                organization_viptela_file = os.path.join(folder, organization_viptela_file_name)

                viptela_serial_file_viptela_tar = zprov(
                    change_serial_simulator(organization_viptela, serial_set, multi_certs)
                )
                with open(organization_viptela_file, "wb") as f:
                    f.write(viptela_serial_file_viptela_tar)

        csv_serial = getattr(testbed_cloud_init, "csv_serial", None)
        manual_serial = getattr(testbed_cloud_init, "manual_serial", None)
        json_serial = getattr(testbed_cloud_init, "json_serial", None)
        json_serial_sim_instances = getattr(testbed_cloud_init, "json_serial_sim_instances", None)
        multi_certs = getattr(testbed_cloud_init, "multi_certs", None)

        dump_dict = {
            "folder": tb_dir,
            "csv_serial": csv_serial,
            "manual_serial": manual_serial,
            "json_serial": json_serial,
            "json_serial_sim_instances": json_serial_sim_instances,
            "serial_set": set(),
            "multi_certs": multi_certs,
        }

        dump_serials(**dump_dict)

    def upload_crt(self, machine):
        # Some cEdge SSH service is available, but cert shows it is not installed, needs wait for a while
        @check_and_wait(max_time=60, poll_time=5)
        def cert_installed(machine, session):
            show_local_prop = "show sdwan control local-properties"
            ret = session.show(show_local_prop)
            if not ret[0]:
                raise TestbedBringupError("{}: show sdwan control local-properties failed: {}".format(machine, ret[1]))

            for line in ret[1].splitlines():
                serial_matched = re.match("serial-num", line)
                if serial_matched:
                    break
            else:
                return [False, "{}: could not find serial in {}".format(machine, ret[1])]

            if "No certificate installed" in line:
                return [False, "No certificate installed"]
            else:
                return [True, line]

        confd = self.create_confd_session(machine)
        c8kv = NewCedgeSession(machine, confd, timeout=60)

        # 17.12 and late(CSCwe53725), c8kv supports cert installed through cloud-init. so there is no need to install cert.
        # Before it,  we still need manual install cert.
        if cert_installed(machine, c8kv)[0]:
            return

        org_name = self.get_machine_org_name(machine)
        self.setup_cedge_signed_certificate(machine, None, org_name)

        confd = self.create_confd_session(machine)
        c8kv = NewCedgeSession(machine, confd, timeout=60)
        if not cert_installed(machine, c8kv)[0]:
            raise TestbedBringupError("{}: cert install failed".format(machine))

    def setup_vdaemon_certs(self, sw_licensing=False, bringup_fast=False):
        self.verify('up')
        sessions = {'confd': {}, 'root': {}}
        vmanage_node = None if bringup_fast else Machines().get_vmanage()
        for machine in self.machines():
            # Log to certs.log
            logfile = self.get_log_file_for_machine(machine)
            if self.debug is True:
                logfile = sys.stdout

            # Create confd sessions for all machines
            confd_session = self.get_machine_session(machine, 25, logfile)
            if confd_session != -99:
                sessions['confd'][machine] = confd_session
            else:
                for machine in sessions['confd']:
                    sessions['confd'][machine].close()
                    if mch_sessions[machine].logfile != sys.stdout:
                        sessions['confd'][machine].logfile.close()
                return 1

            # Create root sessions for all machines
            root_session = self.get_machine_session(machine, 25, logfile, False, False, True)
            if root_session != -99:
                sessions['root'][machine] = root_session
            else:
                for machine in sessions['root']:
                    sessions['root'][machine].close()
                    if sessions['root'][machine].logfile != sys.stdout:
                        sessions['root'][machine].logfile.close()
                return 1

        # Create instances for confd, vs, cert
        confd = CONFDSession(self, sessions, self.logger)
        vs = ViptelaSession(self, None, self.logger, confd, False, False, None, None)
        cert = Cert(self, confd, vs)
        # For now add files requried for image signing here.
        for machine in self.machines():
            if not self.is_cedge(machine):
                confd.create_files_for_signed_image(machine)

        vedges = [k for k in list(self.machines().keys()) if 'vedge' in self.personality(k)]
        yaml_has_vedges = len(vedges) > 0
        cert_serial_num_dict = {}
        machines = self.machines()
        vsmarts = [ k for k in machines if self.personality(k) == 'vsmart' ]
        vmanages = [ k for k in machines if self.personality(k) == 'vmanage' ]
        vbonds = [ k for k in machines if self.personality(k) in ['vbond', 'ztp', 'vbond_sw'] ]
        vedges = [ k for k in machines if 'vedge' in self.personality(k) ]
        fail = 0

        if not sw_licensing:
            for vedge_name in vedges:
                res = cert.cert_generate_and_sign_vedge_certs(cert_serial_num_dict, machine)
                if res == None:
                    fail += 1
                    self.logger.error('Could not setup certs on %s' % machine)

        for machine in vsmarts + vmanages:
            res = cert.cert_generate_and_sign_vsmart_certs(cert_serial_num_dict, machine)
            if res == None:
                fail += 1
                self.logger.error('Could not setup certs on %s' % machine)
        #this loop should be called only after you run through all vedges and vsmarts as vsmart list needs to be installed on vmanage
        for machine in vmanages:
            if self.is_arbitrator_vmanage(machine):
                continue
            serial_file = 'vsmart_serial_file'
            if self.is_standby_vmanage(machine):
                serial_file = 'standby_vsmart_serial_file'
            res = cert.cert_install_vsmart_file_on_vmanage(machine, serial_file)
            if res == None:
                fail += 1
                self.logger.error('Could not setup certs on %s' % machine)
        for machine in vbonds:
            iface = 1
            vbond_iface_name = self.intf_name(machine, iface)
            vbond_ip = self.ipaddr(machine, iface)
            if self.is_aws_machine(machine) and self.personality(machine) in ['vbond_sw']:
                #If vEdgde is in aws, then use 172 network address to config vBond and install vBond certs
                mask = self.netmask(172)
                vbond_cidr_mask = self.prefixlen(mask)
                res = cert.cert_generate_and_sign_vbond_certs(cert_serial_num_dict, machine, vbond_iface_name, vbond_ip, vbond_cidr_mask, True, self.valgrind_flag)
            else:
                mask = self.netmask(100)
                vbond_cidr_mask = self.prefixlen(mask)
                if self.personality(machine) == 'vbond':
                    res = cert.cert_generate_and_sign_vbond_certs(cert_serial_num_dict, machine, vbond_iface_name, vbond_ip, vbond_cidr_mask, True, self.valgrind_flag)
                else:
                    res = cert.cert_generate_and_sign_vbond_certs(cert_serial_num_dict, machine, vbond_iface_name, vbond_ip, vbond_cidr_mask, False, self.valgrind_flag)
            if res == None:
                fail += 1
                self.logger.error('Could not setup certs on %s' % machine)
        # Make sure you upload the vEdge and vSmart serial file  on all the vbond machines
        if not vmanage_node or not vmanage_node.is_mt():
            for machine in vbonds:
                # Uploading vSmart Serial File
                return_str = cert.upload_vsmart_serial_file_on_vbond(machine)
                if False in return_str:
                    self.logger.error('Could not upload vSmart serial file on machne - %s' %machine)
            # Make sure you upload the vEdge serial file on all vsmart Machines
            for machine in vsmarts + vbonds + vmanages:
                if yaml_has_vedges:
                    return_str = cert.upload_vedge_serial_file_to_controller(machine)
                    if False in return_str:
                        self.logger.error('Could not upload vedge serial file on machne - %s' %machine)
        # Software Licensing - make all the configs before the certs.log file is closed.
        if sw_licensing:
            # Initiatize the required classes here. For API use the OMP yaml
            # since majority of scripts use that .
            vtest_dir = os.path.dirname(os.path.dirname(os.path.realpath(__file__)))
            yaml_file_path = os.path.join(vtest_dir, 'yamls', 'protocols',
            'omp.yaml')
            api = Tests(yaml_file_path, [0,512])
            # setup the required params for VManage Session
            cookie_dir = os.path.join(vtest_dir, 'http_cookies')
            try:
                os.mkdir(cookie_dir)
            except OSError:
                pass
            cookie_file = os.path.join(cookie_dir, 'login.cookies')
            vmanage = VMANAGESession(self, self.logger, True, True, True, cookie_file)
            ls = LicenseSession(self, api, confd, vs, vmanage)
            return_list = ls.setup_sw_licensing()
        for machine in self.machines():
            sessions['confd'][machine].close()
            sessions['root'][machine].close()
            if sessions['root'][machine].logfile != sys.stdout:
                sessions['root'][machine].logfile.close()
        if fail > 0:
            return 1
        return 0

    def is_csp_testbed(self):
        if hasattr(self, '_is_csp_testbed'):
            return self._is_csp_testbed
        self._is_csp_testbed = False
        for m in self.machines():
            if self.is_ucs(m):
                self._is_csp_testbed = True
                break
        return self._is_csp_testbed

    def setup_vdaemon_certs_in_parallel(self, sw_licensing=False, bringup_fast=False):
        """Install certs in all machines in parallel"""
        if not self.machines():
            return

        self.logger.info("Configure certs on all machines")
        self.verify('up')
        retval = 0

        manager = multiprocessing.Manager()
        result_code = manager.dict()

        error_machines1 = []
        vedge_cert_processes = {}
        vsmart_cert_processes = {}
        vbond_cert_processes = {}
        vmanage_cert_processes = {}
        vmange_device_list = []
        serial_id = self.get_max_serial_id()
        for machine in self.machines():
            serial_id += 1
            personality = self.personality(machine)
            if (
                personality == 'vcontainer'
                or self.is_cedge(machine)
                or self.is_ucs(machine)
                or self.is_highrise(machine)
                or self.is_nfvis(machine)
            ):
                # TODO don't burn the serial id
                continue
            p = multiprocessing.Process(target=self.setup_vdaemon_certs_on_machine_proc, args=(machine, personality, sw_licensing, serial_id, result_code))

            if personality == 'vmanage' and not self.is_sdavc(machine):
                vmanage_cert_processes[machine] = p
                vmange_device_list.append(machine)
            elif personality == 'vsmart':
                vsmart_cert_processes[machine] = p
            elif personality == 'vbond_sw':
                vbond_cert_processes[machine] = p
            elif personality in ['vbond', 'ztp']:
                vbond_cert_processes[machine] = p
                # Create one more process for vedge personality
                p1 = multiprocessing.Process(target=self.setup_vdaemon_certs_on_machine_proc, args=(machine, 'vedge', sw_licensing, serial_id, result_code))
                vedge_cert_processes[machine] = p1
            else:
                vedge_cert_processes[machine] = p

        controller_cert_processes = {}
        controller_cert_processes.update(vsmart_cert_processes)
        controller_cert_processes.update(vmanage_cert_processes)
        controller_cert_processes.update(vbond_cert_processes)

        # Run a single process first to intialize Cert class
        # The run remaining processes in parallel using same cert class
        try:
            first_cert_process = dict([vedge_cert_processes.popitem()])
        except Exception:
            first_cert_process = dict([controller_cert_processes.popitem()])

        process_chunks = [first_cert_process, vedge_cert_processes, controller_cert_processes]

        for process_list in process_chunks:
            self.logger.info('Installing cert in parallel for %s' % list(process_list.keys()))
            for machine in list(process_list.keys()):
                process_list[machine].start()
            for machine in list(process_list.keys()):
                process_list[machine].join()
                if process_list[machine].exitcode != 0 or result_code[machine] != 0:
                    error_machines1.append(machine)

        # Upload serila numbers on Controllers
        result_code1 = manager.dict()
        serial_upload_processes = {}
        error_machines2 = []
        for machine in self.machines():
            if self.is_ucs(machine) or self.is_nfvis(machine):
                continue
            p = multiprocessing.Process(target=self.upload_serial_files_on_controllers, args=(machine, result_code1))
            p.start()
            serial_upload_processes[machine] = p
        for machine in list(serial_upload_processes.keys()):
            serial_upload_processes[machine].join()
            if serial_upload_processes[machine].exitcode != 0 or result_code1[machine] != 0:
                error_machines2.append(machine)
        # Init software licesing part
        if sw_licensing:
            res = self.init_sw_licensing_classes()
            if res != 0:
                raise TestbedBringupError('Cannot initialize software licensing classes')

        # moving this part towards the end because in some cases people want to proceed even with errors
        if error_machines1 != []:
            raise ConfigCertError('Setup vdaemon certs failure on %s' % error_machines1)

        if error_machines2 != []:
            raise ConfigCertError('Serial upload failed on machines %s' % error_machines2)

        return 0

    def setup_vdaemon_certs_on_machine_proc(self,  machine, personality, sw_licensing = False, serial_id = None, result_code = None):
        exit(self.setup_vdaemon_certs_on_machine(machine, personality, sw_licensing, serial_id, result_code))

    def setup_vdaemon_certs_on_machine(self, machine, personality, sw_licensing = False, serial_id = None, result_code = None):
        if self.personality(machine) == 'vcontainer' or self.is_cedge(machine):
            return 0
        # Log to certs.log
        logfile = self.get_log_file_for_machine(machine)
        if self.debug is True:
            logfile = sys.stdout

        # Create confd sessions for all machines
        if self.is_physical_machine(machine):
            confd_session = self.get_machine_session(machine, 360, logfile, False, True)
        else:
            confd_session = self.get_machine_session(machine, 90, logfile, False, True)

        if confd_session == -99:
            self.logger.error('Cannot get ssh session for %s' % machine)
            if result_code is not None: result_code[machine]= 1
            return 1

        result = 0
        # Create instances for confd, vs, cert
        confd = CONFDSession(self, {'confd': {machine: confd_session}}, self.logger)
        vs = ViptelaSession(self, None, self.logger, confd, False, False, None, None)
        cert = Cert(self, confd, vs, serial_id)

        cert_serial_num_dict = {}
        if personality == 'vmanage':
            res = cert.cert_generate_and_sign_vsmart_certs(cert_serial_num_dict, machine)
            if res == None:
                self.logger.error('Could not setup certs on %s' % machine)
                result = 1

        elif personality == 'vsmart':
            res = cert.cert_generate_and_sign_vsmart_certs(cert_serial_num_dict, machine)
            if res == None:
                result = 1
        elif personality == 'vbond':
            iface = 1
            vbond_iface_name = self.intf_name(machine, iface)
            vbond_ip = self.ipaddr(machine, iface)
            mask = self.netmask(100)
            vbond_cidr_mask = self.prefixlen(mask)
            res = cert.cert_generate_and_sign_vbond_certs(cert_serial_num_dict, machine, vbond_iface_name, vbond_ip, vbond_cidr_mask, True, self.valgrind_flag)
        elif personality in ['vbond_sw', 'ztp']:
            # Generate and sign vbond certs
            iface = 1
            vbond_iface_name = self.intf_name(machine, iface)
            vbond_ip = self.ipaddr(machine, iface)
            if self.is_aws_machine(machine) and self.personality(machine) in ['vbond_sw']:
                #If vEdgde is in aws, then use 172 network address to config vBond and install vBond certs
                mask = self.netmask(172)
                vbond_cidr_mask = self.prefixlen(mask)
                res = cert.cert_generate_and_sign_vbond_certs(cert_serial_num_dict, machine, vbond_iface_name, vbond_ip, vbond_cidr_mask, True, self.valgrind_flag)
            else:
                mask = self.netmask(100)
                vbond_cidr_mask = self.prefixlen(mask)
                res = cert.cert_generate_and_sign_vbond_certs(cert_serial_num_dict, machine, vbond_iface_name, vbond_ip, vbond_cidr_mask, False, self.valgrind_flag)
            if res == None:
                result = 1
        elif personality == 'nfvis':
            res = cert.cert_generate_and_sign_nfvis_certs(cert_serial_num_dict, machine)
            if res is None:
                result = 1
        else:
            if not sw_licensing:
                # If software licesning is specified we need to skip this and come bringup overlay
                res = cert.cert_generate_and_sign_vedge_certs(cert_serial_num_dict, machine)
                if res == None:
                    result = 1

        confd_session.close()

        if self.debug == False and logfile != sys.stdout:
            logfile.close()

        if result != 0:
            if result_code is not None: result_code[machine]= 1
            return 1

        if result_code is not None: result_code[machine]= 0
        return 0

    def is_arbitrator_vmanage(self, machine_id):
        machine = self.config['machines'][machine_id]
        return machine.get('dr_role', '') == 'arbitrator'

    def is_standby_vmanage(self, machine_id):
        machine = self.config['machines'][machine_id]
        return machine.get('function', '') == 'vmanage_scaling_6'

    def upload_serial_files_on_controllers(self, machine, result_code=None, bringup_fast=False):
        # Log to certs.log
        vmanage = None if bringup_fast else Machines().get_vmanage()
        logfile = self.get_log_file_for_machine(machine)
        if self.debug is True:
            logfile = sys.stdout

        if self.is_cedge(machine):
            if result_code is not None: result_code[machine]= 0
            return 0
        # Create confd sessions for all machines
        confd_session = self.get_machine_session(machine, 360, logfile, False, True)
        if confd_session == -99:
            self.logger.error('Cannot get ssh session for %s' % machine)
            if result_code is not None: result_code[machine]= 1
            return 1

        # Create instances for confd, vs, cert
        confd = CONFDSession(self, {'confd': {machine: confd_session}}, self.logger)
        vs = ViptelaSession(self, None, self.logger, confd, False, False, None, None)
        cert = Cert(self, confd, vs, 0)
        vedges = [k for k in list(self.machines().keys()) if 'vedge' in self.personality(k)]
        yaml_has_vedges = len(vedges) > 0
        result = 0
        if self.personality(machine) == 'vmanage':
            if not vmanage or not vmanage.is_mt():
                if yaml_has_vedges:
                    # Make sure you upload the vEdge serial file on all vManage Machines
                    self.logger.info('Waiting for 30 sec before uploading vEdge serial file on %s' % machine)
                    time.sleep(30)
                    return_str = cert.upload_vedge_serial_file_to_controller(machine)
                    if False in return_str:
                        self.logger.error('Could not upload vEdge serial file on %s' % machine)
                        result = 1
                self.logger.info('Waiting for 10 sec before uploading vSmart serial file on %s' % machine)
                time.sleep(10)
                serial_file = 'vsmart_serial_file'
                if self.is_standby_vmanage(machine):
                    serial_file = 'standby_vsmart_serial_file'
                if not self.is_arbitrator_vmanage(machine):
                    res = cert.cert_install_vsmart_file_on_vmanage(machine, serial_file)
                    if res == None:
                        self.logger.error('Could not upload vSmart serial file on %s' % machine)
                        result = 1

        elif self.personality(machine) == 'vsmart':
            # Make sure you upload the vEdge serial file on all vsmart Machines
            if yaml_has_vedges:
                if not vmanage or not vmanage.is_mt():
                    return_str = cert.upload_vedge_serial_file_to_controller(machine)
                    if False in return_str:
                        self.logger.error('Could not upload vEdge serial file on %s' % machine)
                        result = 1

        elif self.personality(machine) in ['vbond_sw', 'vbond', 'ztp']:
            # Make sure you upload the vEdge and vSmart serial file  on all the vbond machines
            # Uploading vSmart Serial File
            if not vmanage or not vmanage.is_mt():
                return_str = cert.upload_vsmart_serial_file_on_vbond(machine)
                if False in return_str:
                    self.logger.error('Could not upload vSmart serial file on %s' % machine)
                    result = 1
                if yaml_has_vedges:
                    # Uploading vEdge Serial File
                    return_str = cert.upload_vedge_serial_file_to_controller(machine)
                    if False in return_str:
                        self.logger.error('Could not upload vEdge serial file on %s' % machine)
                        result = 1

        confd_session.close()
        if self.debug == False and logfile != sys.stdout:
            logfile.close()

        if result != 0:
            if result_code is not None: result_code[machine]= 1
            return 1

        if result_code is not None: result_code[machine]= 0
        return 0

    def init_sw_licensing_classes(self):
        sessions = {'confd': {}, 'root': {}}
        for machine in self.machines():
            if self.is_ucs(machine) or self.is_nfvis(machine) or self.is_highrise(machine):
                continue
            # Log to certs.log
            logfile = self.get_log_file_for_machine(machine)
            if self.debug is True:
                logfile = sys.stdout

            # Create confd sessions for all machines
            confd_session = self.get_machine_session(machine, 25, logfile)
            if confd_session != -99:
                sessions['confd'][machine] = confd_session
            else:
                for machine in sessions['confd']:
                    sessions['confd'][machine].close()
                    if mch_sessions[machine].logfile != sys.stdout:
                        sessions['confd'][machine].logfile.close()
                return 1

        confd = CONFDSession(self, sessions, self.logger)
        vs = ViptelaSession(self, None, self.logger, confd, False, False, None, None)

        # Initiatize the required classes here. For API use the OMP yaml
        # since majority of scripts use that .
        vtest_dir = os.path.dirname(os.path.dirname(os.path.realpath(__file__)))
        yaml_file_path = os.path.join(vtest_dir, 'yamls', 'protocols',
        'omp.yaml')
        #api = Tests('/Users/manoj/src/vtest/yamls/protocols/omp.yaml', [0, 512])
        api = Tests(yaml_file_path, [0,512])
        # setup the required params for VManage Session
        cookie_dir = os.path.join(vtest_dir, 'http_cookies')
        try:
            os.mkdir(cookie_dir)
        except OSError:
            pass
        cookie_file = os.path.join(cookie_dir, 'login.cookies')
        vmanage = VMANAGESession(self, self.logger, True, True, True, cookie_file)
        ls = LicenseSession(self, api, confd, vs, vmanage)
        return_list = ls.setup_sw_licensing()

        for machine in self.machines():
            sessions['confd'][machine].close()
            if sessions['confd'][machine].logfile != sys.stdout:
                sessions['confd'][machine].logfile.close()
        return 0

    def sign_csr(self, machine, csr_file_name, thru_ui = False, new_root_ca_path = None, out_file_name= None):
        result = [True, '']
        root_ca_path = os.path.join(self.workdir, "root_ca/")
        if new_root_ca_path != None:
            root_ca_path = new_root_ca_path
        newcerts_path = root_ca_path + 'newcerts'
        private_path = root_ca_path + 'private'
        index_file = root_ca_path + 'index.txt'
        serial_file = root_ca_path + 'serial'
        open_ssl_config_path = os.path.join(root_ca_path, "openssl.cnf")
        private_key_path = os.path.join(root_ca_path, "private/cakey.pem")
        cert_chain_path = os.path.join(root_ca_path, "cacert.pem")

        if thru_ui:
            home = os.environ.get('HOME')
            download_path = os.path.join(home,'Downloads')
            csr_path = os.path.join(download_path, csr_file_name)
            shutil.copy(csr_path, root_ca_path)

        #delete and retouch the index file to so that csr from same node can be signed again and again
        if not os.path.exists(index_file):
            create_index_file = subprocess.Popen('touch '+index_file, shell = True, stdout = subprocess.PIPE, stderr=subprocess.PIPE)
            #print create_index_file.stdout.read()
            out, err = create_index_file.communicate()
            self.logger.info('output \n'+str(out))
            self.logger.info('err \n'+str(err))
            self.logger.info("Created ->"+index_file)
        else :
            self.logger.info("Exists ->"+index_file)
            delete_index_file = subprocess.Popen('rm -rf '+index_file, shell = True, stdout = subprocess.PIPE, stderr=subprocess.PIPE)
            #print delete_index_file.stdout.read()
            out, err = delete_index_file.communicate()
            self.logger.info('output \n'+str(out))
            self.logger.info('err \n'+str(err))
            self.logger.info("Deleted ->"+index_file)
            if not os.path.exists(index_file):
                create_index_file = subprocess.Popen('touch '+index_file, shell = True, stdout = subprocess.PIPE, stderr=subprocess.PIPE)
                #print create_index_file.stdout.read()
                out, err = create_index_file.communicate()
                self.logger.info('output \n'+str(out))
                self.logger.info('err \n'+str(err))
                self.logger.info("Created ->"+index_file)
            else:
                return [False, 'Index file deletion failed']

        if not os.path.exists(index_file):
            self.logger.info('Index file creation must have failed - re-attempting to create the index file')
            create_index_file = subprocess.Popen('touch '+index_file, shell = True, stdout = subprocess.PIPE, stderr=subprocess.PIPE)
            #print create_index_file.stdout.read()
            out, err = create_index_file.communicate()
            self.logger.info('output \n'+str(out))
            self.logger.info('err \n'+str(err))
            self.logger.info("Created ->"+index_file)

        if not os.path.exists(index_file):
            return [False, 'Index file creation has failed twice - catastrophic failure']

        if not out_file_name:
            out_file_name = "%s.pem"%csr_file_name
        open_ssl_sign_csr_cmd = 'openssl ca -batch -out %s/%s -config %s -cert %s -keyfile %s -passin pass:f3rrar1 -outdir %s -infiles %s/%s' % (root_ca_path, out_file_name, open_ssl_config_path, cert_chain_path, private_key_path, newcerts_path, root_ca_path, csr_file_name)

        #open_ssl_sign_csr = subprocess.Popen(open_ssl_sign_csr_cmd, shell = True, stdout = subprocess.PIPE)
        #print "Signed Cert \n" + open_ssl_sign_csr.stdout.read()
        open_ssl_sign_csr = subprocess.Popen(open_ssl_sign_csr_cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, shell=True)
        out, err = open_ssl_sign_csr.communicate()
        self.logger.info('output \n'+str(out))
        self.logger.info('err \n'+str(err))

        open_ssl_get_serial_cmd = 'openssl x509 -in %s/%s -noout -serial' % (root_ca_path, out_file_name)
        open_ssl_get_serial_process = subprocess.Popen(
            open_ssl_get_serial_cmd, shell=True, stdout=subprocess.PIPE, stderr=subprocess.PIPE
        )
        out, err = open_ssl_get_serial_process.communicate()
        if open_ssl_get_serial_process.returncode != 0:
            return [False, "Get certificate serial failed: %s" % err]
        if not isinstance(out, str):
            out = out.decode('utf-8')
        (serial, number) = re.split('=', out)
        if number != '':
            if thru_ui:
                cert_file= out_file_name
                cert_path = os.path.join(root_ca_path,cert_file)
                # upload_path = os.path.abspath(os.path.join(os.path.dirname( __file__ ),'../tests/scripts/protractor/specs/config/certificate_mgmt'))
                upload_path = os.path.join(download_path, cert_file)
                shutil.copy(cert_path, upload_path)
            return [True, number.rstrip()]
        else :
            return [False, "Couldn't find serial number, certificate signing failed."]

    def create_dummy_serial_file(self, machine, dummy_serial_file, valid_serial_list = [], invalid_serial_list = [], garbage_list = []):
        """This function is used by cert tests. Give a serial file location, valid, invalid, garbage serial lists, this function will creates a serial file """
        f = open(dummy_serial_file, "w")
        garbage_names = ['inval','vali','in-valid','not-vali','not','busted']
        for serial in valid_serial_list:
            f.write(str(serial)+",valid\n")
        for serial in invalid_serial_list:
            f.write(str(serial)+",invalid\n")
        for serial in garbage_list:
            x = random.randint(0,len(garbage_names)-1)
            f.write(str(serial)+","+garbage_names[x]+"\n")
        f.close()
        if os.path.exists(dummy_serial_file):
            return [True,"File creation sucessfull"]
        else :
            return [False, "File Creation failed"]

    def create_huge_dummy_vedge_serial_file(self, machine, dummy_serial_file, invalidate_valid = False, num_valid = 0, num_invalid = 0, num_garbage = 0):
        """This function is used by cert tests. This function creates vedge serial file. It stores the valid serail file in list which is used in later tests """
        f = open(dummy_serial_file, "w")
        garbage_names = ['inval','vali','in-valid','not-vali','not','busted']
        if invalidate_valid == False :
            for c,s in zip(list(range(0,num_valid)), list(range(0,num_valid))):
                chassis = 111111 + c
                serial = 111111 + s
                self.valid_vedge_serial_list.append('ABCDE'+str(chassis)+','+'A'+str(serial))

            for c,s in zip(list(range(0,num_invalid)), list(range(0,num_invalid))):
                chassis = 222222 + c
                serial = 222222 + s
                self.invalid_vedge_serial_list.append('BBCDE'+str(chassis)+','+'B'+str(serial))

            for c,s in zip(list(range(0,num_garbage)), list(range(0,num_garbage))):
                chassis = 222222 + c
                serial = 222222 + s
                self.garbage_vedge_serial_list.append('CBCDE'+str(chassis)+','+'C'+str(serial))

            for serial in self.valid_vedge_serial_list:
                f.write(str(serial)+",valid\n")
            for serial in self.invalid_vedge_serial_list:
                f.write(str(serial)+",invalid\n")
            for serial in self.garbage_vedge_serial_list:
                x = random.randint(0,len(garbage_names)-1)
                f.write(str(serial)+","+garbage_names[x]+"\n")
            f.close()

        if invalidate_valid == True :
            #Make sure that self.valid_vedge_serial_list has values before using this part of code
            for serial in self.valid_vedge_serial_list:
                f.write(str(serial)+",invalid\n")
            f.close()

        if os.path.exists(dummy_serial_file):
            return [True,"File creation sucessfull"]
        else :
            return [False, "File Creation failed"]

