    def enable_third_partition(self, machine, timeout=25, wait_time=30):
        """Given a machine IP address username and password, this function logs into the devices and creates an expect handle"""
        cmd_bld = SSHCommandBuilder(
            host=self.mgmt_ipaddr(machine), user=self.get_ssh_username(machine), logger=self.logger
        )
        cmd_bld.add_kv_option('ConnectTimeout', 20)
        cmd = cmd_bld.build()
        child1 = None
        done = False
        retry_times = 0
        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.enable_third_partition <<<<\n")
        vm = Machines().get(machine)
        with vm.get_cli() as cli:
            pass
        while not done and not (retry_times >= 3):
            retry_times += 1
            if six.PY2:
                child1 = pexpect.spawn(cmd, timeout = int(timeout))
            else:
                child1 = pexpect.spawn(cmd, timeout = int(timeout), encoding='utf-8', codec_errors='ignore')
            if self.debug is True:
                child1.logfile = sys.stdout
            else:
                child1.logfile = logfile
            try:
                index = child1.expect(['.*password:', 'Password:', 'device to use:', r'.*#'])
                if index < 2:
                    child1.sendline(self.get_ssh_password(machine))
                    index = child1.expect(['.*password:', 'Password:', 'device to use:', r'.*#'])
                if index >= 3:
                    # already done
                    self.logger.info('3rd parition already appears to be enabled.')
                    break
                if 'hdb' in child1.before:
                    self.logger.info('3rd partition found %s' % child1.before)
                else:
                    self.logger.info('3rd partition not found')
                child1.sendline('1')
                child1.expect(['Would you like to format'])
                child1.sendline('y')

                for x in range(6):
                    index = child1.expect(['Extracting vManage extra-packages', pexpect.TIMEOUT], timeout=120)
                    if index == 0:
                        self.logger.info('Extracting vManage extra-packages found')
                        break
                    elif index == 1:
                        self.logger.info('Extracting vManage extra-packages not found and TIMEOUT')

                for x in range(6):
                    index = child1.expect(['Package Extraction Complete', pexpect.TIMEOUT], timeout=120)
                    if index == 0:
                        self.logger.info('Package Extraction Complete found')
                        break
                    elif index == 1:
                        self.logger.info('Package Extraction Complete not found and TIMEOUT')

                child1.expect('The system is going down for reboot NOW!', timeout=60)
                done = True
                self.logger.info('Enabled 3rd parition, %s is now rebooting', machine)
                self.wait(wait_time, reason="Waiting for %s to be up after reboot" % machine)
            except pexpect.EOF as ex:
                if not done:
                    self.logger.warn("Not able to login or SSH connection terminated")
                    self.logger.warn(ex)
                    time.sleep(5)
            except pexpect.TIMEOUT as ex:
                self.logger.warn(ex)
            finally:
                if child1:
                    child1.close()
        return [True, '']

    def get_machine_session_with_pw_auth(self, machine, machine_ip, timeout=25):
        """Given a machine IP address username and password, this function logs into the devices and creates an expect handle"""
        cmd_bld = SSHCommandBuilder(
            host=machine_ip, user=self.get_ssh_username(machine), logger=self.logger, no_multiplexing=True
        )
        cmd_bld.add_kv_option('ConnectTimeout', 20)
        # cmd_bld.add_kv_option('PreferredAuthentications', password)
        cmd = cmd_bld.build()
        password = self.get_ssh_password(machine)
        if six.PY2:
            self.aaa_child1 = pexpect.spawn(cmd, timeout = int(timeout))
        else:
            self.aaa_child1 = pexpect.spawn(cmd, timeout = int(timeout), encoding='utf-8', codec_errors='ignore')
        try:
            self.aaa_child1.expect(['.*password:', 'Password:'])
            self.aaa_child1.sendline(password)
            self.aaa_child1.expect('#')
            return [True, 'Login to %s was successfull with Username %s Password %s' %(machine_ip, username, password)]
        except (pexpect.EOF, pexpect.TIMEOUT):
            return [False, 'Login to %s failed with Username %s Password %s' % (machine_ip, username, password)]

    def aaa_get_machine_session_cedge(self, machine, machine_ip, username=None, password=None, timeout = 25, mode='priv', enable=False, enable_password=None):
        """Given a machine IP address username and password, this function logs into the cedge and creates an expect handle as per mode and enable """
        username = username or self.get_ssh_username(machine)
        password = password or self.get_ssh_password(machine)
        cmd_bld = SSHCommandBuilder(host=machine_ip, user=username, logger=self.logger, no_multiplexing=True)
        cmd_bld.add_kv_option('ConnectTimeout', timeout)
        cmd_bld.add_kv_option('PreferredAuthentications', 'password')
        cmd_bld.add_kv_option('PubkeyAuthentication', 'no')
        cmd = cmd_bld.build()
        if six.PY2:
            self.aaa_child1 = pexpect.spawn(cmd, timeout = int(timeout))
        else:
            self.aaa_child1 = pexpect.spawn(cmd, timeout = int(timeout), encoding='utf-8', codec_errors='ignore')
        self.aaa_child1.logfile = sys.stdout
        try:
            self.aaa_child1.expect(['.*password:', 'Password:'])
            self.aaa_child1.sendline(password)
            if mode == 'exec':
                self.aaa_child1.expect('>')
                if enable:
                    self.aaa_child1.sendline('enable')
                    if enable_password is None:
                        self.aaa_child1.expect('#')
                    else:
                        self.aaa_child1.expect(['.*password:', 'Password:'])
                        self.aaa_child1.sendline(enable_password)
                        self.aaa_child1.expect('#')
            else:
                self.aaa_child1.expect('#')
                #self.aaa_child1.sendline('config-transaction')
            return [True, 'Login to %s was successfull with Username %s Password %s' %(machine_ip, username, password)]
        except (pexpect.EOF, pexpect.TIMEOUT):
            return [False, 'Login to %s failed with Username %s Password %s' % (machine_ip, username, password)]

