    def get_paramiko_session(self, machine_ip, uname, passwd, timeout = 20):
        ssh_session = paramiko.SSHClient()
        ssh_session.set_missing_host_key_policy(paramiko.AutoAddPolicy())
        try:
            ssh_session.connect(
                machine_ip,
                username=uname,
                password=str(base64.decodestring(passwd.encode()).decode()),
                timeout=timeout,
                allow_agent=False,
                look_for_keys=False,
            )
        except (paramiko.SSHException, socket.error, paramiko.AuthenticationException) as e:
            self.logger.error('Error: %s' % repr(e))
            return [False, repr(e)]
        return [True, ssh_session]

    def exec_tcpdump_ubuntu_machine(self, machine_ip, uname, passwd, cmd_list, timeout = 20, read_stdout = True):
        ssh_session = self.get_paramiko_session(machine_ip, uname, passwd, timeout = timeout)
        if ssh_session[0] == False:
            return [False, 'Error : %s' % ssh_session[1]]
        else:
            for cmd in cmd_list:
                _, stdout, stderr = ssh_session[1].exec_command(cmd)
                if read_stdout:
                    out = stderr.read()
                    stderr.close()
                    if out:
                        stdout = stdout.read()
                        self.logger.info(stdout)
        ssh_session[1].close()
        return [True, 'Given commands were successfully executed']

    def exec_paramiko_commands(self, machine_ip, uname, passwd, cmd_list, timeout = 20, read_stdout = True, return_output=False):
        ssh_session = self.get_paramiko_session(machine_ip, uname, passwd, timeout = timeout)
        if ssh_session[0] == False:
            self.logger.info('-------SESSION COULD NOT BE CREATED ON THE UBUNTU-------')
            return [False, 'Error : %s' % ssh_session[1]]
        else:
            assert isinstance(ssh_session[1], paramiko.SSHClient)
            for cmd in cmd_list:
                _, stdout, stderr = ssh_session[1].exec_command(cmd)
                time.sleep(2)
                self.logger.info(cmd)
                exit_code = stdout.channel.recv_exit_status()
                self.logger.info("exit code: %s", exit_code)
                if read_stdout:
                    stdout_output = stdout.read()
                    out = stderr.read()
                    if six.PY3:
                        stdout_output = stdout_output.decode()
                        out = out.decode()
                    stderr.close()
                    if  out != '':
                        self.logger.info('-------In stdERROR case-------')
                        self.logger.info(out)
                        ssh_session[1].close()
                        #Any wget command will by default be written into stderr (see manpage), so creating this exception case
                        if 'wget' in cmd and (('reset' not in out) and ('Unable' not in out) and ('not found' not in out)):
                            self.logger.info('------Treating stdERROR as SUCCESS-----')
                            return [True, 'Given commands were successfully executed']
                        #When executing any bash script/cmd, the file may already have ben executed. So "File exists" will be written in stdERR and hence this exception case
                        if 'File exists' in out:
                            self.logger.info('------Treating stdERROR as SUCCESS as the file already exists-----')
                            if return_output:
                                self.logger.info(stdout_output)
                                return [True, stdout_output]
                            return [True, 'Given commands were successfully executed']
                        if 'curl' in cmd and 'outlet' in cmd:
                            self.logger.info('------Treating stdERROR as SUCCESS-----')
                            return [True, 'Given commands were successfully executed']
                        if 'killall' in cmd or 'del ppp' in cmd:
                            if 'no process found' in out or 'No such file or directory' in out:
                                return [True, 'Given commands were successfully executed']
                        if 'del' in cmd and 'No such process' in out:
                            self.logger.info('------Treating stdERROR as SUCCESS as the file is already deleted-----')
                            if return_output:
                                self.logger.info(stdout_output)
                                return [True, stdout_output]
                            return [True, 'Given commands were successfully executed']
                        return [False, 'Command %s failed' % cmd]
                    else:
                        if stdout_output:
                            self.logger.info('-------In stdout case-------')
                            self.logger.info(stdout_output)
                        if return_output:
                            return [True, stdout_output]
                        if 'ping' in cmd or 'nslookup' in cmd:
                            if 'Destination Net Unreachable' in stdout_output or 'no servers could be reached' in stdout_output or '100% packet loss' in stdout_output or "server can't find" in stdout_output:
                                return [False, 'Command %s failed' % cmd]
        ssh_session[1].close()
        return [True, 'Given commands were successfully executed']

    def cnw_exec_paramiko_commands(self, machine_ip, uname, passwd, cmd_list, timeout = 20, poll_time = 10, max_time = 100, read_stdout = True, present=True, return_output=False):
        curr_time = 0
        while curr_time <= max_time:
            return_val_list = self.exec_paramiko_commands(machine_ip, uname, passwd, cmd_list, timeout, read_stdout, return_output)
            ret_val, ret_str = return_val_list[0], return_val_list[1]
            if (ret_val == True) and (present == True):
                self.logger.info(curr_time)
                return [True, ret_str]
            elif (ret_val == False) and (present == False):
                self.logger.info(curr_time)
                return [True, ret_str]
            else:
                curr_time += poll_time
                if curr_time <= max_time:
                    time.sleep(poll_time)
        return [False, ret_str]

    def check_pkg_on_server(self, machine_ip, uname, passwd, timeout, pkg):
        ssh_session = self.get_paramiko_session(machine_ip, uname, passwd, timeout=timeout)
        if ssh_session[0] == False:
            self.logger.info('-------SESSION COULD NOT BE CREATED ON THE UBUNTU-------')
            return [False, 'Error : %s' % ssh_session[1]]
        else:
            cmd = 'dpkg -l %s' %pkg
            _, stdout, stderr = ssh_session[1].exec_command(cmd)
            out = stderr.read()
            if six.PY3:
                out = out.decode()
            if out != '':
                return [False, 'Error while executing command']
            out = stdout.read().decode()
            search_str = 'no packages found matching %s'%pkg
            a = re.search(search_str , out)
            if a is not None:
                return [False, 'pkg %s is not installed on server' %pkg]
        return [True, 'pkg %s is already installed on server' %pkg]

    def run_commond_on_remote_machine(self, machine_ip, uname, passwd, cmd, output = False, timeout = 20):
        """ Run command on remote machine """
        ssh_session = self.get_paramiko_session(machine_ip, uname, passwd, timeout=timeout)
        if ssh_session[0] == False:
            self.logger.info('-------SESSION COULD NOT BE CREATED ON THE UBUNTU-------')
            return [False, 'Error : %s' % ssh_session[1]]
        else:
            _, stdout, stderr = ssh_session[1].exec_command(cmd)
            out = stdout.read()
            error = stderr.read()
            if six.PY3:
                out = out.decode()
                error = error.decode()
        if output:
            return [True, [out, error]]
        else:
            return [True, 'cmd %s executed successfully'%(cmd)]

