    def check_and_create_snmp_mib_dir_on_host(self, machine_ip, uname, passwd, timeout = 20):
        ssh_session = self.get_paramiko_session(machine_ip, uname, passwd, timeout = timeout)
        if ssh_session[0] == False:
            return [False, 'Error : %s' % ssh_session[1]]
        else:
            #Check ~/.snmp/mibs/
            cmd = 'cd ~/.snmp/mibs/'
            _, stdout, stderr = ssh_session[1].exec_command(cmd)
            out = stderr.read()
            if six.PY3:
                out = out.decode()
            stderr.close()
            if 'No such file or directory' in out:
                self.logger.info('Need to create snmp mib directory...')
                cmd = 'mkdir -p ~/.snmp/mibs'
                _, stdout, stderr = ssh_session[1].exec_command(cmd)
                out = stderr.read()
                if six.PY3:
                    out = out.decode()
                stderr.close()
                if out != '':
                    self.logger.info('Not able to create ~/.snmp/mibs directory')
