    def install_package_ubunutu(self, machine, package_name):
        """ Install package in testbed """
        try:
            install_status = (
                subprocess.check_output(
                    "dpkg -l \"%s\"" % (package_name), stderr=subprocess.STDOUT, shell=True, universal_newlines=True
                )
                .strip()
                .split('\n')[-1]
                .split()[0]
            )
        except subprocess.CalledProcessError as exc:
            return [False, "Failed to find package 'dpkg -l \"%s\"', error: %s"%(package_name, exc)]

        if install_status == 'ii':
            return [True, "Package %s already installed"%(package_name)]
        # Install package
        try:
            proc = subprocess.Popen(
                'sudo apt-get install -y %s' % (package_name),
                shell=True,
                stdin=None,
                stdout=open(os.devnull, "wb"),
                stderr=subprocess.STDOUT,
                executable="/bin/bash",
                universal_newlines=True,
            )
            proc.wait()
        except subprocess.CalledProcessError as exc:
            return [False, 'error in installation of package %s, error : %s'%(package_name, exc)]

        return [True, "Package %s installed successfully"%(package_name)]

    def create_credential_file_to_mount_windows_fs(self, machine, username, passwd):
        """ create creadential file for mounting """
        # Create credential file
        try:
            subprocess.call('touch ~/.cifs', shell=True)
            subprocess.call('echo username=%s > ~/.cifs'%(username), shell=True)
            subprocess.call('echo password=%s >> ~/.cifs'%(passwd), shell=True)
            subprocess.call('sudo cp ~/.cifs /root/.cifs', shell=True)
            subprocess.call('rm -f ~/.cifs', shell=True)
        except subprocess.CalledProcessError as exc:
            return [False, "Failed to create credential file"]
        return [True, "credentail file for mounting created successfully"]

    def setup_file_sharing_windows_ubuntu(self, machine, windows_machine_ip, share_folder_name, mount_point, username=None, passwd=None):
        """ setup file sharing between windows machin and ubuntu machine
            Example:
            mount_point = /home/tester/Windows-Share    in ubuntu machine
            windows_machine_ip = '192.168.10.197'
            share_folder_name = 'result'
            username = 'tester'
        """
        # Create credential file
        if username != None and passwd != None:
            result = self.create_credential_file_to_mount_windows_fs(machine, username, passwd)
            if result[0] == False:
                return [False, "%s"%(result[1])]

        # mount shared folder on ubnutu machine
        result = self.mount_unmount_cifs_fs(windows_machine_ip,share_folder_name, mount_point)
        if result[0] == False:
            return [False, "%s"%(result[1])]
        return [True, "Mounting of shared folder done successfullys"]

    def mount_unmount_cifs_fs(self, windows_machine_ip, share_folder_name, mount_point, mount=True):
        """ mount / unmount shared folder """

        # check mounting exist
        if mount:
            mounting_exist = (
                int(
                    subprocess.check_output(
                        'sudo mount | grep "%s" | wc -l' % (mount_point),
                        stderr=subprocess.STDOUT,
                        shell=True,
                        universal_newlines=True,
                    ).strip()
                )
                == 1
            )
            if mounting_exist:
                return [True, "mounting already exist"]
        try:
            if mount:
                subprocess.call('mkdir %s'%(mount_point), shell=True)
                subprocess.call('sudo mount.cifs //%s/%s %s -o credentials=/root/.cifs'%(windows_machine_ip,share_folder_name,mount_point), shell=True)
            else:
                subprocess.call('sudo umount %s'%(mount_point), shell=True)
                subprocess.call('rmdir %s'%(mount_point), shell=True)
        except subprocess.CalledProcessError as exc:
            if mount:
                return [False, "Failed to mount shared folder in windows machine to ubuntu machine"]
            else:
                return [False, "Failed to unmount shared folder, unmount point %s"%(mount_point)]
        return [True, ""]

    def isConnectedToVnet0(self):
        index = -2
        domiflist = subprocess.check_output(
            'virsh domiflist ubuntu-services', stderr=subprocess.STDOUT, shell=True, universal_newlines=True
        )
        domiflist_list = domiflist.strip('\n').split('\n')
        for entry in domiflist_list:
            if 'vnet0' in entry:
                break
            index += 1
        if index == (len(domiflist_list) - 2):
            return False
        return True

    @check_and_wait(300, 10)
    def configure_interface_route_on_ubuntu_services(self, machine, machine_ip, uname, passwd, interface, kvm_tb=True):
        """Configure interfaces and routes on ubuntu_services"""
        # configure interface and routes on ubuntu_services
        ssh_session = self.get_paramiko_session(machine_ip, uname, passwd)
        if ssh_session[0] == False:
            return [False, "Can not get pramiko session"]
        if kvm_tb:
            vnet0_present = 'vnet0' in subprocess.check_output(
                'virsh net-list', stderr=subprocess.STDOUT, shell=True, universal_newlines=True
            ).strip('\n')
            # check ubuntu_service has internet facing interface and it has ip, if not then
            # configure /etc/network/interfaces
            cmd_restart_network = "sudo service networking restart"
            self.logger.info(cmd_restart_network)
            _, stdout, stderr = ssh_session[1].exec_command(cmd_restart_network)
            stdout = stdout.read()
            stderr = stderr.read()
            self.logger.info('stdout: %s\nstderr: %s'%(stdout, stderr))
            if vnet0_present:
                cmd = 'ifconfig %s | grep -o "192.168.122.[0-9]*" | wc -l' % interface
                self.logger.info(cmd)
                _, stdout, stderr = ssh_session[1].exec_command(cmd)
                stdout = stdout.read()
                stderr = stderr.read()
                if six.PY3:
                    stdout = stdout.decode()
                    stderr = stderr.decode()
                self.logger.info('stdout: %s\nstderr: %s'%(stdout, stderr))
                cmd_list = []
                if stderr != '':
                    return [False, "wrong interface found, %s,  %s" % (cmd, stderr)]
                if int(stdout.strip('\n')) == 0:
                    # need to configure ip address in /etc/network/interfaces and routes to access internet, other machines and ipsec tunnel end point
                    cmd_list = ["sudo echo \"auto %s\" >> /etc/network/interfaces" % interface,
                                "sudo echo \"iface %s inet dhcp\" >> /etc/network/interfaces" % interface,
                                "sudo service networking restart"]
                    for cmd1 in cmd_list:
                        self.logger.info(cmd1)
                        _, stdout, stderr = ssh_session[1].exec_command(cmd1)
                        self.logger.info('stdout: %s\nstderr: %s'%(stdout.read(), stderr.read()))

                # check interface got ip address 192.168.122.*
                self.logger.info(cmd)
                _, stdout, stderr = ssh_session[1].exec_command(cmd)
                stdout = stdout.read()
                stderr = stderr.read()
                self.logger.info('stdout: %s\nstderr: %s'%(stdout, stderr))
                if int(stdout.strip()) == 0:
                    return [False, "%s interface on ubuntu_service did not get ip address" % interface]

            # remove default routes if any exist
            cmd = "ip route show"
            self.logger.info(cmd)
            _, stdout, stderr = ssh_session[1].exec_command(cmd)
            stdout = stdout.read()
            stderr = stderr.read()
            if six.PY3:
                stdout = stdout.decode()
                stderr = stderr.decode()
            self.logger.info('stdout: %s\nstderr: %s'%(stdout, stderr))
            stdout_list = stdout.strip('\n').split('\n')
            for entry in stdout_list:
                entry = entry.split()
                if 'default' in entry:
                    cmd = "sudo route del default gw %s dev %s" % (entry[2], entry[4])
                    self.logger.info(cmd)
                    _, stdout, stderr = ssh_session[1].exec_command(cmd)
                    stdout = stdout.read()
                    stderr = stderr.read()
                    self.logger.info('stdout: %s\nstderr: %s'%(stdout, stderr))
                    if stderr != b'':
                        self.logger.info("Error while deleting default gateway")
        # configure routing on ubuntu_services
        cmd_list = ["sudo route add -net 10.0.1.0 netmask 255.255.255.0 gw 10.0.1.1",
                     "sudo route add -net 10.1.16.0 netmask 255.255.255.0 gw 10.1.15.13"]
        if kvm_tb:
            cmd_list.append("sudo route add default gw 192.168.122.1")
        for cmd1 in cmd_list:
            self.logger.info(cmd1)
            _, stdout, stderr = ssh_session[1].exec_command(cmd1)
            self.logger.info('stdout: %s\nstderr: %s'%(stdout.read(), stderr.read()))
        return [True, "interface and route on ubuntu_service are configured to access inernet"]

    def check_package_installed(self, machine, uname, passwd, machine_ip, package, kvm =False, esxi=False, timeout = 20):
        """ Check particular package installed on remote machine """
        exec_flag = False
        if kvm == True and self.is_kvm_tb():
            exec_flag = True
        elif esxi == True and self.is_esxi_tb():
            exec_flag = True
        elif kvm == False and esxi == False:
            exec_flag = True
        if exec_flag:
            cmd = 'sudo dpkg -l %s'%(package)
            ssh_session = self.get_paramiko_session(machine_ip, uname, passwd, timeout = timeout)
            if ssh_session[0] == False:
                return [False, 'Error : %s' % ssh_session[1]]
            else:
                _, stdout, stderr = ssh_session[1].exec_command(cmd)
                error = stderr.read()
                stderr.close()
                stdout = stdout.read()
                if six.PY3:
                    stdout = stdout.decode()
                    error = error.decode()
                self.logger.info('stdout: %s\nstderr: %s'%(stdout, error))
                if "no packages found matching" in error or "un" in stdout.strip().split('\n')[-1].split()[0]:
                    return [False, "Package %s is not installed, %s,%s"%(package,stdout,stderr )]
                elif "ii" in stdout.strip().split('\n')[-1].split()[0]:
                    return [True, "Package %s is installed, %s,%s"%(package,stdout,stderr )]
            ssh_session[1].close()
        return [True, ""]

    def exec_ipsec_install_ubuntu_machine(self, machine, machine_ip, uname, passwd, cmd, timeout = 20, reinstall=False):
        """downloads strongswan tarball file, does scp to remote machine
            checks strongswan installed on remote machine, if not then installs it using tar file
            """
        err_msg = ''
        results = []
        install_cmd = 'sudo apt-get install -y strongswan'
        reinstall_cmd_list = ['sudo apt-get purge -y strongswan', 'sudo apt-get remove -y l'] + [cmd]

        # check is strongswan installed on ubuntu_service, if not then install it through tar file
        ssh_session = self.get_paramiko_session(machine_ip, uname, passwd, timeout = timeout)
        if ssh_session[0] == False:
            return [False, 'Error : %s' % ssh_session[1]]
        else:
            if reinstall:
                for rcmd in reinstall_cmd_list:
                    self.logger.info(rcmd)
                    _, stdout, stderr = ssh_session[1].exec_command(rcmd)
                    error = stderr.read()
                    stderr.close()
                    stdout = stdout.read()
                    if six.PY3:
                        error = error.decode()
                        stdout = stdout.decode()
                    self.logger.info('stdout: %s\nstderr: %s'%(stdout.read(), error))
                if "un" in stdout.strip().split('\n')[-1].split()[0]:
                    self.logger.info(stdout)
                else:
                    err_msg += "not able to remove strongswan %s"%(stdout)
                    results.append(False)
                # install strongswan
                self.logger.info(install_cmd)
                _, stdout, stderr = ssh_session[1].exec_command(install_cmd)

                # check strongswan installed
                _, stdout1, stderr1 = ssh_session[1].exec_command(cmd)
                error = stderr1.read()
                stderr1.close()
                stdout = stdout.read()
                if six.PY3:
                    error = error.decode()
                    stdout = stdout.decode()
                if "ii" in stdout.strip().splitlines()[-1].split()[0]:
                    self.logger.info(stdout)
                else:
                    err_msg += "not able to find strongswan package %s"%(stdout)
                    results.append(False)
            else:
                _, stdout, stderr = ssh_session[1].exec_command(cmd)
                error = stderr.read()
                stderr.close()
                stdout = stdout.read()
                if six.PY3:
                    error = error.decode()
                    stdout = stdout.decode()
                if "no packages found matching" in error or "un" in stdout.strip().split('\n')[-1].split()[0]:
                    if not self.is_kvm_tb():
                        return [False, "Package strongswan is not installed, %s,%s"%(stdout,stderr)]
                    # install strongswan on ubuntu_service
                    _, stdout1, stderr1 = ssh_session[1].exec_command(install_cmd)
                    error1 = stderr1.read()
                    stderr1.close()
                    stdout1 = stdout1.read()
                    # check strongswan got installed
                    _, stdout2, stderr2 = ssh_session[1].exec_command(cmd)
                    error2 = stderr2.read()
                    stderr2.close()
                    stdout = stdout2.read()
                    if six.PY3:
                        error2 = error2.decode()
                        stdout = stdout.decode()
                    if "no packages found matching" in error2:
                        return [False, "Installation of strongswan failed, %s, error:%s"%(install_cmd, error1)]
                if "ii" in stdout.strip().split('\n')[-1].split()[0]:
                    self.logger.info(stdout)
                else:
                    err_msg += "not able to find strongswan package %s"%(stdout)
                    results.append(False)
        if False in results:
            return [False, "%s"%err_msg]
        ssh_session[1].close()
        return [True, 'Given commands were successfully executed']

    def install_strongswan_on_ubuntu(self, machine, machine_ip, uname, passwd, timeout=20, reinstall=False):
        """ Install ipsec on ubuntu Machine """
        # check strongswan present if not then install it.
        cmd = 'dpkg -l strongswan'
        result = self.exec_ipsec_install_ubuntu_machine(machine, machine_ip, uname, passwd, cmd)
        if result[0] == False:
            return [False, "Unable to install strongswan on ubuntu_service %s, %s"%(machine_ip, result[1])]

        # Handling of "Aggressive Mode PSK disabled for security reasons"
        strongswan_conf = "charon {\n\tload_modular = yes\n\ti_dont_care_about_security_and_use_aggressive_mode_psk = yes\n\tplugins {\n\t\tinclude strongswan.d/charon/*.conf\n\t}\n}\n\ninclude strongswan.d/*.conf"
        subprocess.call('touch /home/tester/standard_strongswan.conf', shell=True)
        subprocess.call('echo "%s" > /home/tester/standard_strongswan.conf'%(strongswan_conf), shell=True)
        result = self.scp_to_server("TB", machine_ip, '/home/tester/standard_strongswan.conf', '/etc/strongswan.conf', 'root', passwd)
        subprocess.call('rm -rf /home/tester/standard_strongswan.conf', shell=True)
        return [True, "Strongswan installed successfully"]


    def configure_ipsec_on_ubuntu(self, machine, machine_ip, uname, passwd, ipsec_config, ipsec_secrets, start_ipsec = True):
        ## Load ipsec config, /etc/ipsec.conf and /etc/ipsec.secrets
        subprocess.call('touch /home/tester/standard_ipsec.conf && touch /home/tester/standard_ipsec.secrets', shell=True)
        subprocess.call('cp /dev/null /home/tester/standard_ipsec.conf && cp /dev/null /home/tester/standard_ipsec.secrets', shell=True)
        for line in ipsec_config:
            subprocess.call('echo "%s" >> /home/tester/standard_ipsec.conf'%(line), shell=True)
        for line in ipsec_secrets:
            subprocess.call('echo "%s" >> /home/tester/standard_ipsec.secrets'%(line), shell=True)

        # scp standard_ipsec.conf and standard_ipsec.secrets to ubuntu_service at location /etc/
        result = self.scp_to_server("TB", machine_ip, '/home/tester/standard_ipsec.conf', '/etc/ipsec.conf', 'root', passwd)
        if result[0] == False:
            return [False, "Unable to tranfer ipsec.conf on ubuntu_service %s" % (machine_ip)]
        result = self.scp_to_server("TB", machine_ip, '/home/tester/standard_ipsec.secrets', '/etc/ipsec.secrets', 'root', passwd)
        if result[0] == False:
            return [False, "Unable to tranfer ipsec.secrets on ubuntu_service %s" % (machine_ip)]

        subprocess.call('rm -rf /home/tester/standard_ipsec.conf && rm -rf /home/tester/standard_ipsec.secrets', shell=True)
        # start ipsec
        if start_ipsec:
            self.restart_ipsec_server_on_ubuntu(machine, machine_ip, uname, passwd)
        return [True, ""]

    def exec_ipsec_command_ubuntu_machine(self, machine, machine_ip, uname, passwd, cmd_list, timeout = 20, read_stdout = True):
        """ run start / stop / restart/ status /statusall command  """
        cmd_error = []
        results = []
        ssh_session = self.get_paramiko_session(machine_ip, uname, passwd, timeout = timeout)
        if ssh_session[0] == False:
            return [False, 'Error : %s' % ssh_session[1]]
        else:
            for cmd in cmd_list:
                _, stdout, stderr = ssh_session[1].exec_command(cmd)
                if read_stdout:
                    out = stderr.read()
                    stdout = stdout.read()
                    if six.PY3:
                        out = out.decode()
                        stdout = stdout.decode()
                    stderr.close()
                    if out != '':
                        result = False
                        if ' start' in cmd and ( "already running" in  out or "Starting strongSwan" in out):
                            result = True
                        if 'stop' in cmd and ( "Stopping strongSwan IPsec failed: starter is not running" in out or "Stopping strongSwan IPsec..." in out):
                            result = True
                        if 'restart' in cmd and ( "Stopping strongSwan IPsec failed: starter is not running" in out or ("Stopping strongSwan IPsec..." in out and "Starting weakSwan" in out)):
                            result = True
                        if 'status' in cmd:
                            result = True
                        if result == False:
                            results.append(False)
                            cmd_error.append((cmd, out))
        ssh_session[1].close()
        if False in results:
            return [False, "Failed to do %s, stdout:%s, stderr: %s"%(cmd,stdout,out)]
        return [True, 'Given commands were successfully executed']

    def start_ipsec_server_on_ubuntu(self, machine, machine_ip, uname, passwd):
        """Start ipsec server on ubuntu machine """
        cmd_list = ['sudo ipsec start']
        return self.exec_ipsec_command_ubuntu_machine(machine, machine_ip, uname, passwd, cmd_list)

    def stop_ipsec_server_on_ubuntu(self, machine, machine_ip, uname, passwd):
        """Start ipsec server on ubuntu machine """
        cmd_list = ['sudo ipsec stop']
        return self.exec_ipsec_command_ubuntu_machine(machine, machine_ip, uname, passwd, cmd_list)

    def restart_ipsec_server_on_ubuntu(self, machine, machine_ip, uname, passwd):
        """Start ipsec server on ubuntu machine """
        cmd_list = ['sudo ipsec restart']
        return self.exec_ipsec_command_ubuntu_machine(machine, machine_ip, uname, passwd, cmd_list)

    def status_ipsec_server_on_ubuntu(self, machine, machine_ip, uname, passwd):
        """Start ipsec server on ubuntu machine """
        cmd_list = ['sudo ipsec status']
        return self.exec_ipsec_command_ubuntu_machine(machine, machine_ip, uname, passwd, cmd_list)

    def statusall_ipsec_server_on_ubuntu(self, machine, machine_ip, uname, passwd):
        """Start ipsec server on ubuntu machine """
        cmd_list = ['sudo ipsec statusall']
        return self.exec_ipsec_command_ubuntu_machine(machine, machine_ip, uname, passwd, cmd_list)

    def run_nmap_script(self, machine, vmanage_ip, start_port=23456, end_port=24156, step_increment=100):
        """ run nmap vulnaribility scirpts on testbed which scans vmanage """
        nmap_install_cmd_list = ['cd /home/tester/','wget https://nmap.org/dist/nmap-7.50.tar.bz2','bzip2 -cd nmap-7.50.tar.bz2 | tar xvf -', 'cd nmap-7.50','./configure','make','sudo make install']
        # check nmap is on version 7.5 and more
        nmap_installed = (
            int(
                subprocess.check_output(
                    'which nmap| wc -l', stderr=subprocess.STDOUT, shell=True, universal_newlines=True
                ).strip()
            )
            == 1
        )
        if nmap_installed:
            nmap_installed = (
                int(
                    subprocess.check_output(
                        '`which nmap` -v | grep 7.50 | wc -l',
                        stderr=subprocess.STDOUT,
                        shell=True,
                        universal_newlines=True,
                    ).strip()[-1]
                )
                == 1
            )
        if not nmap_installed:
            # install nmap
            for nmap_install_cmd in nmap_install_cmd_list:
                subprocess.call('%s' % (nmap_install_cmd), shell=True)
            nmap_installed = (
                int(
                    subprocess.check_output(
                        'which nmap| wc -l', stderr=subprocess.STDOUT, shell=True, universal_newlines=True
                    ).strip()
                )
                == 1
            )
            if nmap_installed:
                return [False, "not able to install nmap"]

        # run nmap script
        ipv6 = ''
        if not misc.is_ipv4_addr(vmanage_ip): ipv6 = '-6'
        nmap_shell_script ='#! /bin/bash\nipv6=\'%s\'\nfor x in `seq 1 1`\n\tdo\n\tfor i in {%s..%s..%s}\n\t\tdo\n\t\techo "sudo `which nmap` -sV \\$ipv6 --script ssl-cert-intaddr.nse -p \\$i \\$1";\n\t\tsudo `which nmap` -sV \\$ipv6 --script ssl-cert-intaddr.nse -p \\$i \\$1;\n\t\techo "sudo `which nmap` -sV \\$ipv6 --script ssl-cert.nse -p \\$i \\$1";\n\t\tsudo `which nmap` -sV \\$ipv6 --script ssl-cert.nse -p \\$i \\$1;\n\t\techo "sudo `which nmap` -sV \\$ipv6 --script ssl-date.nse -p \\$i \\$1";\n\t\tsudo `which nmap` -sV \\$ipv6 --script ssl-date.nse -p \\$i \\$1;\n\t\techo "sudo `which nmap` -sV \\$ipv6 --script ssl-dh-params.nse -p \\$i \\$1";\n\t\tsudo `which nmap` -sV \\$ipv6 --script ssl-dh-params.nse -p \\$i \\$1;\n\t\techo "sudo `which nmap` -sV \\$ipv6 --script ssl-enum-ciphers.nse -p \\$i \\$1";\n\t\tsudo `which nmap` -sV \\$ipv6 --script ssl-enum-ciphers.nse -p \\$i \\$1;\n\t\techo "sudo `which nmap` -sV \\$ipv6 --script ssl-heartbleed.nse -p \\$i \\$1";\n\t\tsudo `which nmap` -sV \\$ipv6 --script ssl-heartbleed.nse -p \\$i \\$1;\n\t\techo "sudo `which nmap` -sV \\$ipv6 --script ssl-known-key.nse -p \\$i \\$1";\n\t\tsudo `which nmap` -sV \\$ipv6 --script ssl-known-key.nse -p \\$i \\$1;\n\t\techo "sudo `which nmap` -sV \\$ipv6 --script ssl-poodle.nse -p \\$i \\$1";\n\t\tsudo `which nmap` -sV \\$ipv6 --script ssl-poodle.nse -p \\$i \\$1;\n\t\techo "sudo `which nmap` -sV \\$ipv6 --script sslv2-drown.nse -p \\$i \\$1";\n\t\tsudo `which nmap` -sV \\$ipv6 --script sslv2-drown.nse -p \\$i \\$1;\n\t\techo "sudo `which nmap` -sV \\$ipv6 --script sslv2.nse -p \\$i \\$1";\n\t\tsudo `which nmap` -sV \\$ipv6 --script sslv2.nse -p \\$i \\$1;\n\tdone\ndone'%(ipv6, start_port, end_port, step_increment)
        # nmap_shell_script = 'for x in 1\n\tdo\n\tfor i in {%s..%s..%s}\n\t\tdo\n\t\techo sudo /usr/local/bin/nmap -sV --script ssl-cert-intaddr.nse -p $i $1;\n\t\t#sudo /usr/local/bin/nmap -sV --script ssl-cert-intaddr.nse -p $i $1;\n\t\techo sudo /usr/local/bin/nmap -sV --script ssl-cert.nse -p $i $1;\n\t\t#sudo /usr/local/bin/nmap -sV --script ssl-cert.nse -p $i $1;\n\t\techo sudo /usr/local/bin/nmap -sV --script ssl-date.nse -p $i $1;\n\t\t#sudo /usr/local/bin/nmap -sV --script ssl-date.nse -p $i $1;\n\t\techo sudo /usr/local/bin/nmap -sV --script ssl-dh-params.nse -p $i $1;\n\t\t#sudo /usr/local/bin/nmap -sV --script ssl-dh-params.nse -p $i $1;\n\t\techo sudo /usr/local/bin/nmap -sV --script ssl-enum-ciphers.nse -p $i $1;\n\t\t#sudo /usr/local/bin/nmap -sV --script ssl-enum-ciphers.nse -p $i $1;\n\t\techo sudo /usr/local/bin/nmap -sV --script ssl-heartbleed.nse -p $i $1;\n\t\t#sudo /usr/local/bin/nmap -sV --script ssl-heartbleed.nse -p $i $1;\n\t\techo sudo /usr/local/bin/nmap -sV --script ssl-known-key.nse -p $i $1;\n\t\t#sudo /usr/local/bin/nmap -sV --script ssl-known-key.nse -p $i $1;\n\t\techo sudo /usr/local/bin/nmap -sV --script ssl-poodle.nse -p $i $1;\n\t\t#sudo /usr/local/bin/nmap -sV --script ssl-poodle.nse -p $i $1;\n\t\techo sudo /usr/local/bin/nmap -sV --script sslv2-drown.nse -p $i $1;\n\t\t#sudo /usr/local/bin/nmap -sV --script sslv2-drown.nse -p $i $1;\n\t\techo sudo /usr/local/bin/nmap -sV --script sslv2.nse -p $i $1;\n\t\t#sudo /usr/local/bin/nmap -sV --script sslv2.nse -p $i $1;\n\tdone\ndone'%(start_port, end_port, step_increment)
        subprocess.call('echo "%s" > /tmp/temp_nmap.sh'%(nmap_shell_script), shell=True)
        run_nmap_cmd = '/bin/bash /tmp/temp_nmap.sh %s'%(vmanage_ip)
        run_nmap_cmd_list = shlex.split(run_nmap_cmd)
        nmap_script_output,nmap_script_error = subprocess.Popen(run_nmap_cmd_list, stdout = subprocess.PIPE, stderr= subprocess.PIPE).communicate()
        self.logger.info('%s\n%s'%(nmap_script_output,nmap_script_error))
        if len(nmap_script_error) != 0:
            return [False, "Error running nmap shell script, %s"%(nmap_script_error)]
        subprocess.call('rm -rf /tmp/temp_nmap.sh', shell=True)
        return [True, "script run successfully"]

    def get_kvm_interface_attrinbute(self, machine, mac_addr, attribute):
        """ get kvm interface attribute """
        if self.is_kvm_tb():
            interface_output = subprocess.check_output(
                "virsh dumpxml %s | grep \"%s\" -A 5" % (machine, mac_addr),
                stderr=subprocess.STDOUT,
                shell=True,
                universal_newlines=True,
            ).strip()
            try:
                attribute_value = re.search(r"%s='(\w+)'"%(attribute),interface_output).group(1)
            except AttributeError as e:
                return [False, "no match pattern found, interface_output: %s, attribute_value: %s"%(interface_output, attribute_value)]
            return [True, "%s"%(attribute_value)]
        else:
            return [False, "Testbed is not kvm testbed"]

    def add_remove_interface_to_from_bridge_kvm(self, bridge, interface, operation='add'):
        """ add or remove interface to or from bridge in kvm"""
        if operation == 'add':
            option = 'addif'
            compare_val = 1
        else:
            option = 'delif'
            compare_val = 0
        if self.is_kvm_tb():
            subprocess.call('sudo brctl %s %s %s' % (option, bridge, interface), shell=True)
            brctl_output = int(
                subprocess.check_output(
                    "brctl show %s | grep %s | wc -l" % (bridge, interface),
                    stderr=subprocess.STDOUT,
                    shell=True,
                    universal_newlines=True,
                ).strip()
            )
            if brctl_output == compare_val:
                return [True, "successfully %s interface %s to/from bridge %s"%(operation, interface, bridge)]
            else:
                return [False, "not able to %s interface %s to/from bridge %s"%(operation, interface, bridge)]
        else:
            return [False, "Testbed is not kvm testbed"]

    def map_phy_interface_to_vm_interface_kvm(self, machine, phy_intf, vm_intf, confd, cleanup = False):
        """ Map testbed physical interface to vm's interface """
        subprocess.call('sudo ip link set %s down'%(phy_intf), shell=True)
        subprocess.call('sudo ip link set %s up'%(phy_intf), shell=True)
        mac_addr = confd.get_mac_address_from_interface(machine, vm_intf)
        if mac_addr[0] == False:
            return [False, "failed to get mac address, %s"%(mac_addr[1])]
        mac_addr = mac_addr[1]
        bridge = self.get_kvm_interface_attrinbute(machine, mac_addr, 'bridge')
        if bridge[0] == False:
            return [False, "failed to get bridge connected to interface %s, %s"%(vm_intf, bridge[1])]
        bridge = bridge[1]
        if not cleanup:
            operation = 'add'
            output = self.add_remove_interface_to_from_bridge_kvm(bridge, phy_intf, operation= operation)
        else:
            operation = 'del'
            output = self.add_remove_interface_to_from_bridge_kvm(bridge, phy_intf, operation= operation)
        if output[0] == False:
            return [False, "Failed to %s interface %s from bridge %s, %s"%(operation, phy_intf, bridge, output[1])]
        return [True, "Successfully %s mapping of phy interface %s and vm_interface %s"%(operation, phy_intf, vm_intf)]

    def get_ubuntu_mgmt_interface(self, dest_ip_to_ping='171.70.168.183'):
        if 'mgmt_intf' in pref:
            return pref['mgmt_intf']
        else:
            # $ ip route show to match 171.70.168.183
            # default via 10.29.30.1 dev enp15s0f0 onlink
            output = subprocess.check_output(
                ['ip', 'route', 'show', 'to', 'match', dest_ip_to_ping], universal_newlines=True
            )
            return output.split(' ')[4]

    def get_ubuntu_iface_addr(self, ifname):
        s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        s.connect(("8.8.8.8", 80))
        return s.getsockname()[0]

    def get_ubuntu_tb_addr_dns(self):
        output, err = self.popen(['hostname'])
        output1, err1 = self.popen(['nslookup', output.strip('\n'), '171.70.168.183'])
        return output1.split(' ')[-1].strip('\n')

    def remove_old_ubuntu_nat_rules(self):
        for num in self.get_ubuntu_nat_rule_list():
            output, err = self.popen(['sudo', 'iptables', '-t', 'nat', '-D', 'PREROUTING', '1'])

    def get_ubuntu_nat_rule_list(self):
        output, err = self.popen(['sudo', 'iptables', '-t', 'nat', '--line-numbers', '-L'])
        return [[_f for _f in item.split(' ') if _f][7][4:] for item in output.split('\n')[2:] if 'DNAT' in item]

    def verify_ubuntu_nat_ports(self):
        nat_port_list = self.get_ubuntu_nat_rule_list()
        for machine in self.machines(types=['vm']):
            ipaddr = self.mgmt_ipaddr(machine)
            dport = 9000 + int(machine[2:])
            if str(dport) in nat_port_list:
                self.logger.info("%s SSH: %s" % (machine, dport))
            if self.personality(machine) == 'vmanage':
                dport += 900
                if str(dport) in nat_port_list:
                    self.logger.info("%s HTTPS: %s" % (machine, dport))

    def popen(self, cmd):
        p = subprocess.Popen(cmd, stdin=subprocess.PIPE, stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        return p.communicate()

    def get_config(self, config):
        vtest = os.path.dirname(os.path.dirname(os.path.realpath(__file__)))
        yamls_dir = os.path.join(vtest, 'yamls')
        if config != 'default':
            if config.endswith('.yaml') == False:
                config = os.path.join(yamls_dir, 'topology', '%s.yaml' % config)
                if not os.path.isfile(config):
                    raise ConfigNotFound(config)
        else:
            specific_config = os.path.join(yamls_dir, 'topology',
                                           '%s.yaml' % socket.gethostname().split('.')[0])
            if os.path.isfile(specific_config):
                config = specific_config
            else:
                try:
                    specific_config = pref['topology_file']
                    if os.path.isfile(specific_config):
                        config = specific_config
                    else:
                        raise ConfigNotFound(specific_config)
                except KeyError:
                    config = os.path.join(yamls_dir, 'topology', 'viptela.yaml')
        return config

    def create_host_vlans(self):
        self.host_vlan_management()

    def destroy_host_vlans(self):
        self.logger.info('Removing host VLANs')
        self.host_vlan_management(True)

    def host_vlan_management(self, destroy = False):
        if self.adapters():
            create_result = 1
            delete_result = 1
            for adapter in self.adapters():
                if ('.' in adapter):
                    if 'en' in adapter:
                        vlan_name = adapter
                        device_name = adapter.split('.')[0]
                        vlan_tag = adapter.split('.')[1]
                        if destroy == False:
                            vlan_cmd = ['sudo', 'networksetup', '-createVLAN',
                                        vlan_name, device_name, vlan_tag]
                            create_result = subprocess.call(vlan_cmd)
                        else:
                            vlan_cmd = ['sudo', 'networksetup', '-deleteVLAN',
                                        vlan_name, device_name, vlan_tag]
                            delete_result = subprocess.call(vlan_cmd)
                    elif ('eth' in adapter) or ('em' in adapter):
                        vlan_name = adapter
                        device_name = adapter.split('.')[0]
                        vlan_tag = adapter.split('.')[1]
                        if destroy == False:
                            vlan_cmd = ['sudo', 'ip', 'link', 'add', 'link',
                                        device_name, 'name', vlan_name, 'type',
                                        'vlan', 'id', vlan_tag]
                            create_result = subprocess.call(vlan_cmd)
                        else:
                            vlan_cmd = ['sudo', 'ip', 'link', 'del', vlan_name]
                            delete_result = subprocess.call(vlan_cmd)
                    if create_result == 0:
                        self.logger.info('Created %s' % vlan_name)
                    if delete_result == 0:
                        self.logger.info('Deleted %s' % vlan_name)

    def setup_ssh_keys(self):
        host_auth_keys = os.path.join(os.environ['HOME'], '.ssh', 'authorized_keys')
        host_auth_backup = os.path.join(self.workdir, 'host_authorized_keys.bak')
        machine_keys = os.path.join(self.workdir, 'authorized_keys')
        content = ''
        self.verify('up')
        self.logger.info('Setting up ssh keys for the machines...')
        if os.path.isfile(machine_keys) == False:
            result = self.generate_ssh_keys(machine_keys)
            if result[0] == False:
                self.logger.error(result[1])
                return 1
        try:
            shutil.copy(host_auth_keys, host_auth_backup)
            f2 = open(host_auth_backup, 'r')
            content = f2.read()
            f2.close()
        except IOError:
            open(host_auth_backup, 'w').close()
        except OSError:
            pass
        f1 = open(host_auth_keys, 'w')
        f1.write(content + '\n')
        f3 = open(machine_keys, 'r')
        content = f3.read()
        f3.close()
        f1.write(content + '\n')
        tb_key_file = os.path.join(os.environ['HOME'], '.ssh', 'id_rsa.pub')
        if os.path.isfile(tb_key_file):
            with open(tb_key_file, 'r') as f:
                tb_key_data = f.read()
                f1.write(tb_key_data+'\n')
        f1.close()
        return 0

    def generate_ssh_keys(self, keys_file):
        self.first_time = True
        self.logger.info('First time testbed bringup...')
        self.logger.info('Generating ssh keys for the machines...')
        try:
            host_key_file = os.path.join(os.environ['HOME'], '.ssh', 'id_dsa.pub')
            host_key_file_handle = open(host_key_file, 'r')
        except IOError:
            host_key_file = os.path.join(os.environ['HOME'], '.ssh', 'id_rsa.pub')
            host_key_file_handle = open(host_key_file, 'r')
        host_pub_key = host_key_file_handle.read().strip('\n')
        host_key_file_handle.close()
        res = self.generate_and_populate_keys(keys_file, host_pub_key)
        if res[0] == False and 'Confd did not come up' in res[1]:
            self.logger.info(res[1])
            self.logger.info('Waiting for another 30s then trying again')
            time.sleep(30)
            res = self.generate_and_populate_keys(keys_file, host_pub_key)
        elif res[0] == False:
            self.logger.error('Could not generate/get keys for the machines')
            self.logger.error(res[1])
            self.logger.error('Trying once more ...')
            res = self.generate_and_populate_keys(keys_file, host_pub_key)
        return res

    def generate_and_populate_keys(self, keys_file, host_pub_key):
        p = []
        q = queue.Queue(len(self.machines()))
        f = open(keys_file, 'w')

        # Call it once, and make visible to all threads via self.local_ssh_key_md5
        self.local_ssh_key_md5 = self.get_ssh_key_md5()

        for machine in self.machines():
            if (
                self.is_nfvis(machine)
                or self.is_highrise(machine)
                or self.is_autonomous(machine)
                or self.is_xe(machine)
            ):
                continue
            if self.is_cloud_init():
                password_key = "admin_password"
                if "gui_default_password" in self.config['machines'][machine]:
                    password_key = "gui_default_password"
                self.update_machine_config(
                    machine, self.config['machines'][machine].get(password_key, DEFAULT_CONFIGURED_PASSWORD)
                )
            if self.is_cedge(machine):
                proc = Thread(
                    target=self.call_func_as_process,
                    args=(self.generate_and_populate_keys_per_cedge_machine, (machine, f, host_pub_key), q),
                )
            else:
                proc = Thread(
                    target=self.call_func_as_process,
                    args=(self.generate_and_populate_keys_per_machine, (machine, f, host_pub_key), q),
                )
            proc.start()
            p.append(proc)
        for proc in p:
            proc.join()
        f.close()
        errors = [True, '']
        while q.empty() == False:
            res = q.get()
            errors[0] = errors[0] and res[0]
            errors[1] += '%s\n' % res[1]
        if errors[0] == False:
            os.remove(keys_file)
        return errors

    def get_ssh_key_md5(self, file_path="~/.ssh/id_rsa.pub", cisco_cfg_compatibile=True):
        # Expand the tilde (~) to the full home directory path
        expanded_path = os.path.expanduser(file_path)
        try:
            # Run the command and capture output
            # Example of an output
            # 4096 MD5:da:71:8c:76:78:66:1d:8a:36:9f:4c:08:e1:fd:2b:66 no comment (RSA)
            result = subprocess.run(
                ['ssh-keygen', '-l', '-E', 'md5', '-f', expanded_path], capture_output=True, text=True, check=True
            )
            # result.stdout contains the fingerprint string
            if cisco_cfg_compatibile:
                # Example of an output
                # 4096 MD5:da:71:8c:76:78:66:1d:8a:36:9f:4c:08:e1:fd:2b:66 no comment (RSA)
                # gives
                # da718c7678661d85369f4c08e1fd2b66
                return "".join(result.stdout.strip().split()[1].split(":")[1:])
            else:
                return result.stdout.strip()
        except subprocess.CalledProcessError as e:
            self.logger.error(f"For key {file_path}: {str(e.stderr)}")
            return None

    def generate_and_populate_keys_per_cedge_machine(self, machine, f, host_pub_key):
        mgmt_ip = self.mgmt_ipaddr(machine)
        user_name = self.get_ssh_username(machine)
        cmd_bld = SSHCommandBuilder(host=mgmt_ip, user=user_name, logger=self.logger)
        mch_cmd = cmd_bld.build()

        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.generate_and_populate_keys_per_cedge_machine <<<<\n")

        if self.local_ssh_key_md5 is None:
            return [False, f'[{machine}] could not get md5 sum of local (UCS) ssh key to configure on {machine}']

        child = pexpect.spawn(mch_cmd, timeout=300, encoding='utf-8', codec_errors='ignore')

        if self.debug is True:
            child.logfile = sys.stdout
        else:
            child.logfile = logfile
        try:
            index = child.expect(['[pP]assword:'] + self.get_expect_prompt_list(machine, 1))
            if index == 0:
                child.sendline(self.get_ssh_password(machine))
                child.expect(self.get_expect_prompt_list(machine, 1))

            time.sleep(1)
            child.sendline('config-transaction')
            child.expect(fr'.*{machine}\(config\)#')
            child.sendline('ip ssh pubkey-chain')
            child.expect(fr'.*{machine}\(conf-ssh-pubkey\)#')
            child.sendline(f'username {user_name}')
            child.expect(fr'.*{machine}\(conf-ssh-pubkey-user\)#')
            child.sendline(f'key-hash ssh-rsa {self.local_ssh_key_md5}')
            child.expect(fr'.*{machine}\(config-key-hash-ssh-rsa/{self.local_ssh_key_md5}\)#')
            child.sendline('exit')
            child.expect(fr'.*{machine}\(conf-ssh-pubkey-user\)#')
            child.sendline('exit')
            child.expect(fr'.*{machine}\(conf-ssh-pubkey\)#')
            child.sendline('exit')
            child.expect(fr'.*{machine}\(config\)#')
            child.sendline('commit')
            child.expect(fr'.*{machine}\(config\)#')
            child.sendline('exit')
            child.expect(fr'.*{machine}#')
            # final exit from ssh session
            child.sendline('exit')

        except pexpect.TIMEOUT:
            f.close()
            error_str = 'Could not generate/get keys for the machine: %s' % machine
            self.logger.error(error_str)
            return [False, error_str]
        except pexpect.EOF:
            f.close()
            error_str = 'Confd did not come up on %s' % machine
            self.logger.error(error_str)
            return [False, error_str]
        finally:
            if logfile is not None and logfile != sys.stdout:
                logfile.close()
            child.close()
        return [True, '']

    def generate_and_populate_keys_per_machine(self, machine, f, host_pub_key):
        mgmt_ip = self.mgmt_ipaddr(machine)
        user_name = self.get_ssh_username(machine)
        cmd_bld = SSHCommandBuilder(host=mgmt_ip, user=user_name, logger=self.logger)
        mch_cmd = cmd_bld.build()

        logfile = self.get_log_file_for_machine(machine)
        logfile.write(">>>> testbed.generate_and_populate_keys_per_machine <<<<\n")

        child = pexpect.spawn(mch_cmd, timeout=300, encoding='utf-8', codec_errors='ignore')

        if self.debug is True:
            child.logfile = sys.stdout
        else:
            child.logfile = logfile
        try:
            index = child.expect(['.*password:', 'Password:'] + self.get_expect_prompt_list(machine, 1))
            if index <= 1:
                child.sendline(self.get_ssh_password(machine))
                child.expect(self.get_expect_prompt_list(machine, 1))
            time.sleep(5)
            child.sendline('vshell')
            child.expect(self.get_expect_prompt_list(machine, 2))
            child.sendline('mkdir /home/admin/.ssh')
            child.expect(self.get_expect_prompt_list(machine, 2))
            child.sendline('ssh-keygen')
            child.expect('Enter.*:')
            child.sendline('/home/admin/.ssh/id_rsa')
            index = child.expect(['Enter.*:', r'Overwrite.*\?'])
            if index == 0:
                child.sendline('')
                child.expect('Enter.*:')
                child.sendline('')
            else:
                child.sendline('n')
            child.expect(self.get_expect_prompt_list(machine, 2))
            ssh_dir = '/home/admin/.ssh'
            child.sendline('cat %s/id_rsa.pub' % ssh_dir)
            index = child.expect(['No such file or directory'] + self.get_expect_prompt_list(machine, 3))
            if index == 0:
                raise TestbedBringupError(f'Key generation failed on machine: {machine}')
            fcntl.lockf(f, fcntl.LOCK_EX)
            f.write(child.before.split('\n')[1] + machine + '\n')
            fcntl.lockf(f, fcntl.LOCK_UN)

            child.sendline('echo "%s" > %s/authorized_keys' % (host_pub_key, ssh_dir))
            child.expect(self.get_expect_prompt_list(machine, 3))
            #Setup vmanage keys under /etc/viptela as well to allow us to deal with newer vmanage images
            if self.personality(machine) == 'vmanage':
                ssh_dir = '/etc/viptela/.ssh'
                child.sendline('cat %s/id_dsa.pub' % ssh_dir)
                index = child.expect(['No such file or directory'] + self.get_expect_prompt_list(machine, 3))
                if index == 0:
                    raise TestbedBringupError(f'Key generation failed on machine: {machine}')
                fcntl.lockf(f, fcntl.LOCK_EX)
                f.write(child.before.split('\n')[1] + machine + '\n')
                fcntl.lockf(f, fcntl.LOCK_UN)

                child.sendline('echo "%s" > %s/authorized_keys' % (host_pub_key, ssh_dir))
                child.expect(self.get_expect_prompt_list(machine, 3))
        except pexpect.TIMEOUT:
            f.close()
            error_str = 'Could not generate/get keys for the machine: %s' % machine
            self.logger.error(error_str)
            return [False, error_str]
        except pexpect.EOF:
            f.close()
            error_str = 'Confd did not come up on %s' % machine
            self.logger.error(error_str)
            return [False, error_str]
        finally:
            if logfile is not None and logfile != sys.stdout:
                logfile.close()
            child.close()
        return [True, '']

    def set_testbed_uboot_env(self):
        self.logger.info('Check for testbed env in uboot on hw nodes ...')
        for machine in self.machines():
            if self.is_mips_machine(machine):
                result = self.call(machine, 'fw_printenv testbed', root=True)
                if result != 0:
                    self.logger.info('testbed env not set for %s in uboot. Will be set now....' %machine)
                    result = self.call(machine, 'fw_setenv testbed 1', root=True)
        return [True, None]

    def init_netconf_mgmt_intf(self, clear_cdb):
        self.logger.info('Configuring netconf management interfaces ...')
        sessions = {'confd': {}}
        mch_chk_list = [mch for mch in self.machines()]
        mch_rechk_list = [0 for mch in mch_chk_list]
        while len(mch_chk_list)>0:
            for machine in mch_chk_list:
                try:
                    cmd_bld = SSHCommandBuilder(host=self.mgmt_ipaddr(machine), user='admin', logger=self.logger)
                    cmd = cmd_bld.build()
                    if six.PY2:
                        child = pexpect.spawn(cmd, timeout = 25)
                    else:
                        child = pexpect.spawn(cmd, timeout = 25, encoding='utf-8', codec_errors='ignore')
                    if self.debug is True:
                        child.logfile = sys.stdout
                    child.expect(self.get_expect_prompt_list(machine, 1))
                    sessions['confd'][machine] = child
                    mch_rechk_list.pop(mch_chk_list.index(machine))
                    mch_chk_list.pop(mch_chk_list.index(machine))
                except pexpect.EOF:
                    child.kill(0)
                    if mch_rechk_list[mch_chk_list.index(machine)] == 1:
                        return [False, 'ERROR: Failed establishing session to %s' % machine]
                    else:
                        mch_rechk_list[mch_chk_list.index(machine)] = 1
                    time.sleep(20)
        confd = CONFDSession(self, sessions, self.logger)
        vs = ViptelaSession(self, None, self.logger, confd, False, False, None, None)
        p = []
        q = queue.Queue(len(self.machines()) * 2)
        p1 = []
        q1 = queue.Queue(len(self.machines()))
        for machine in self.machines():
            proc = Thread(target = self.call_func_as_process, args = (confd.clock_set_date_time, (machine,), q1))
            proc.start()
            p1.append(proc)
        for proc in p1:
            proc.join()
        for machine in self.machines():
            if self.image_type_is_vsmart(machine) or self.is_aws_machine(machine):
                # Cannot configure netconf on aws machines
                continue
            proc = Thread(target = self.call_func_as_process, args = (self.conf_netconf_intf, (machine, confd, vs, clear_cdb), q))
            proc.start()
            p.append(proc)
        for proc in p:
            proc.join()
        #CHANGE: add error checking for q1
        errors = 0
        while q.empty() == False:
            res = q.get()
            errors += res
        for machine in self.machines():
            sessions['confd'][machine].close()
        return errors

    def init_netconf_mgmt_intf_in_parallel(self, clear_cdb):
        self.logger.info("Configure netconf interface on all machines")
        error_machines = []
        config_netconf_processes = {}
        manager = multiprocessing.Manager()
        result_code = manager.dict()
        for machine in self.machines():
            if any([x in self.personality(machine) for x in ['vedge','ztp', 'inet','vsmart','vbond','vmanage']]):
                p = multiprocessing.Process(target=self.config_netconf_intf_on_machine, args=(machine, clear_cdb, result_code))
                config_netconf_processes[machine] = p
                p.start()
        for machine in list(config_netconf_processes.keys()):
            config_netconf_processes[machine].join()
            if config_netconf_processes[machine].exitcode != 0 or result_code[machine] != 0:
                error_machines.append(machine)

        if error_machines != []:
            raise TestbedBringupError('Failed while setting up management interfaces on %s' % error_machines)
        return 0

    def config_netconf_intf_on_machine(self, machine, clear_cdb, result_code = None):
        # Not a best way to do when running multiple process
        # Found issues with multiple process using same confd, vs
        # Each process creates confd, vs instances

        # Fix mgmt interface for vbond_on_vsmart - move eth0 to vpn 512
        if self.personality_is_vbond_on_vsmart(machine):
            self.mgmt_vpn0_to_vpn512(machine)

        if self.is_physical_machine(machine):
            child1 = self.get_machine_session(machine, 360, None, False, True)
        else:
            child1 = self.get_machine_session(machine, 90, None, False, True)

        if child1 == -99:
            self.logger.error('Cannot get ssh session for %s' % machine)
            if result_code is not None: result_code[machine]= 1
            return 1

        confd = CONFDSession(self, {'confd': {machine: child1}}, self.logger)

        if self.image_type_is_vsmart(machine) or self.is_aws_machine(machine):
            # Cannot configure netconf on aws machines
            if result_code is not None: result_code[machine]= 0
            return 0
        res = self.conf_netconf_intf(machine, confd, clear_cdb)
        if result_code is not None: result_code[machine]= res
        return res

    def conf_netconf_intf(self, machine, confd, clear_cdb):
        """ Config netconf interface """
        if not self.personality_is_vbond_on_vsmart(machine):
            self.remove_default_tunnel_interface(machine, confd, clear_cdb)

        iface = self.iface_from_vnet(machine, 100)
        iface_name = self.intf_name(machine, iface)
        ip = self.ipaddr(machine, iface)
        mask = self.netmask(100)
        cidr_mask = self.prefixlen(mask)
        conf_res = confd.config_hostname(machine, machine)
        conf_res = confd.config_vpn_interface(machine, None, iface_name, ip, cidr_mask)

        if not self.personality_is_vbond_on_vsmart(machine):
            self.remove_poe_interface(machine, confd)
            self.remove_cellular_interface(machine, confd)

        enable_res = confd.config_vpn_interface_shutdown(machine, None, iface_name, True)
        if conf_res[0] == False:
            self.logger.error(conf_res[1])
            return 1
        elif enable_res[0] == False:
            self.logger.error(conf_res[1])
            return 1
        return 0

    def remove_poe_interface(self, machine, confd):
        #Remove the default tunnel-intf config that gets put in because of vBabu
        result, chassis_type = self.get_hardware_chassis_type(machine, confd)
        if result:
            if chassis_type == "vEdge-100":
                print('removing poe on %s' % machine)
                remove_poe = confd.config_vpn_interface_poe(machine, '0', 'ge0/0', remove = True)
        return 1

    def remove_cellular_interface(self, machine, confd):
        #Remove the default tunnel-intf config that gets put in because of vBabu
        result, chassis_type = self.get_hardware_description_type(machine, confd)
        if result:
            if "vEdge100m".lower() in chassis_type.lower():
                print('removing cellular on %s' % machine)
                remove_cellular = confd.config_vpn_interface(machine, '0', 'cellular0', None, None, remove = True)
        return 1

    def do_upgrade_confirm(self, machine,confd):
        result = confd.request_upgrade_confirm(machine)
        return 1

    def get_hardware_chassis_type(self, machine, confd):
        #vEdge-1000/vEdge-2000/vEdge-100/vEdge-5000
        if not self.is_cedge(machine):
            show_cmd = 'show hardware inventory Chassis 0 part-number'
            hw_inv = confd.show_cli_cmd(machine, show_cmd)
            vEdgeType = hw_inv.split('\r\n')[1].split()[1]
            self.logger.info("get_hardware_chassis_type %s : %s " % (machine, vEdgeType))
            if vEdgeType in ["vEdge-5000", "vEdge-2000", "vEdge-1000", "vEdge-100", \
                                    "vEdge-Cloud", "81000735400", "81000730400",\
                                    "81000733000", "81001735400",  "81001730400",\
                                    "81001733000", "VIPTELA123", "810-017354-00"]:
                return [True , vEdgeType]
            else:
                return [False, vEdgeType]
        else:
            vEdgeType = 'cEdge'
            return [False , vEdgeType]

    def get_platform_type_cedge(self, machine, confd):
        """ get cedge platform type """
        show_cmd = "show sdwan system status | in Model"
        hw_inv = confd.show_cli_cmd(machine, show_cmd)
        if re.search("Model name:", hw_inv) == None:
            return [False, None]
        #Model name:              CSR1000V
        cEdgeType = hw_inv.split('\r\n')[1].split()[-1]
        if re.search("ISR1100", cEdgeType):
            cEdgeType = "vedge-" + cEdgeType + "-XE"
        else:
            cEdgeType = re.sub("CSR", "CSR-", cEdgeType)
            cEdgeType = re.sub("ASR", "ASR-", cEdgeType)
            cEdgeType = re.sub("ISR", "ISR-", cEdgeType)
            cEdgeType = re.sub("1000V", "1000v", cEdgeType)
            # ISR4331/K9
            cEdgeType = re.sub("/K9", "", cEdgeType)
            cEdgeType = "vedge-" + cEdgeType
        return [True, cEdgeType]

    def get_platform_type(self, machine, confd):
        #vedge-1000/vedge-2000/vedge-100b/vedge-100m/vedge-100wm/vEdge-5000
        if self.is_cedge(machine):
            return self.get_platform_type_cedge(machine,confd)
        show_cmd = 'show hardware inventory Chassis 0 hw-description'
        hw_inv = confd.show_cli_cmd(machine, show_cmd)
        vEdgeType = hw_inv.split('\r\n')[1].split()[1]
        # vEdge-100. is shown for 100wm in hw-description
        platform_list = ["vEdge-5000", "vEdge-2000", "vEdge-1000", "vEdge-100b", "vEdge-100m", "vEdge-100.", "vEdge100m", "ISR1100-6G", "ISR1100-4G", "vEdge-Cloud"]
        for platform in platform_list:
            if platform in vEdgeType:
                if platform == 'vEdge-100.':
                    return [True, 'vEdge-100-M']
                if platform == "vEdge100m":
                    return [True, 'vEdge-100-M']
                if platform == "vEdge-Cloud":
                    return [True, 'vedge-cloud']
                return [True, platform]
        return [False, 'The platform couldnt be retrieved properly']

    def get_hardware_description_type(self, machine, confd):
        #vEdge-100m
        show_cmd = 'show hardware inventory Chassis 0 hw-description'
        hw_inv = confd.show_cli_cmd(machine, show_cmd)
        vEdgeType = hw_inv.split('\r\n')[1].split()[1]
        if "vEdge100m".lower() in vEdgeType.lower() or \
                "vEdge-100m".lower() in vEdgeType.lower() or \
                "vEdge-100wm".lower() in vEdgeType.lower() or \
                "vEdge100wm".lower() in vEdgeType.lower():
            return [True , 'vEdge100m']
        return [False , vEdgeType]

    def remove_default_tunnel_interface(self, machine, confd, clear_cdb):
        #Remove the default tunnel-intf config that gets put in because of vBabu
        if self.first_time or clear_cdb:
            result, chassis_type = self.get_hardware_chassis_type(machine, confd)
            if result:
                ztp_interface_list = []
                if chassis_type in ["vEdge-1000", "vEdge-Cloud"]:
                    ztp_interface_list = ['ge0/0']
                if chassis_type == "vEdge-2000":
                    ztp_interface_list = ['ge2/0']
                if chassis_type == "vEdge-5000":
                    ztp_interface_list = ['ge0/0', 'ge1/0', 'ge2/0', 'ge3/0', '10ge0/0', '10ge1/0', '10ge2/0', '10ge3/0']
                if chassis_type == "vEdge-100":
                    ztp_interface_list = ['ge0/4']
                if chassis_type in ["81000735400", "81000730400", "81000733000", "81001735400",  "81001730400", "81001733000", "VIPTELA123", "810-017354-00"]:
                    ztp_interface_list = ['ge0/4']

                for ztp_interface in ztp_interface_list:
                    remove_tun_intf = confd.config_tunnel_interface(machine, '0', ztp_interface, None, remove=True)
                    remove_ip_dhcp = confd.config_vpn_interface_ip_addr(machine, '0', ztp_interface, 'dhcp', None, None, remove= True)
                    remove_ip_dhcp6 = confd.config_vpn_interface_ip_addr(machine, '0', ztp_interface, 'dhcp6', None, None, remove= True)
        return 1

    def init_host_adapters(self):
        for adapter in self.adapters():
            subnet = self.adapter_ip(adapter)
            vnet = self.adapter_vnet(adapter)
            netmask = self.netmask(vnet)
            if ('en' in adapter):
                if ('.' not in adapter):
                    device_name = self.adapter_name(adapter)
                else:
                    device_name = '%s Configuration' % adapter
                subprocess.call("sudo networksetup -setmanual '%s' %s %s" %
                                (device_name, subnet, netmask), shell = True)

    def self_ping(self, machine):
        self.verify('up')
        try:
            subprocess.call(['ping', self.mgmt_ipaddr(machine)])
        except KeyboardInterrupt:
            return 1

    def ncs_call(self, machine):
        """Starts ncs pexpect session to execute passed shell command"""
        return self.new_call(machine, 'ncs')

    def call(self, machine, *args, **named_params):
        """Starts pexpect session to execute passed shell command"""
        return self.new_call(machine, 'confd', *args, **named_params)

    def new_call(self, machine, session, *args, **named_params):
        """Starts pexpect session to execute passed shell command"""
        shell_bool = False
        opts = {}
        opts['StrictHostKeyChecking'] = 'no'
        opts['UserKnownHostsFile'] = '/dev/null'
        opts['LogLevel'] = 'QUIET'
        opts['User'] = self.get_ssh_username(machine)
        if 'timeout' in named_params and named_params['timeout'] > 5:
            expect_timeout = named_params['timeout']
        else:
            expect_timeout = -1
        cmd = ['ssh']
        for opt in opts:
            cmd += ['-o', '%s=%s' % (opt, opts[opt])]
        args = list(args)
        cmd += [self.mgmt_ipaddr(machine)]
        cmd = ' '.join(cmd)
        known_passwords = list(self.get_ssh_known_passswords(machine))
        try:
            if len(args) > 0 or session == 'ncs':
                child = pexpect.spawn(
                    cmd, timeout=MACHINE_SESSION_PEXPECT_TIMEOUT, encoding='utf-8', codec_errors='ignore'
                )
                if '-u' in args:
                    child.logfile_read = sys.stdout
                child.logfile = self.get_log_file_for_machine(machine)
                if self.debug is True:
                    child.logfile = sys.stdout
                self._check_auth(cmd, known_passwords, child, machine, 1)
                if '-u' in args:
                    child.sendline('show version')
                    child.expect(self.get_expect_prompt_list(machine, 1))
                    child.sendline('\n')
                    child.expect(self.get_expect_prompt_list(machine, 1))
                    try:
                        child.interact()
                    except OSError:
                        pass

                else:
                    child.sendline('vshell')
                    prompt = child.expect(self.get_expect_prompt_list(machine, 2))
                    if ('root' in named_params and named_params['root'] == True) or session == 'ncs':
                        self.logger.warning('You tried to gain root access. Please review your code')
                    if session == 'ncs':
                        self.logger.warning("You tried to use 'ncs_cli_user'!!!!!!!!!!")
                        child.sendline('ncs_cli_user')
                        child.interact()
                    else:
                        child.sendline(' '.join(args))
                        index = child.expect(['root.*password:', 'Password:'] + self.get_expect_prompt_list(machine, 2) + self.get_expect_prompt_list(machine, 0), timeout = expect_timeout)
                    if index <= 1:
                        child.sendline(str(base64.decodestring(self.get_passwd(machine).encode()).decode()))
                        child.expect(self.get_expect_prompt_list(machine, 2) + self.get_expect_prompt_list(machine, 0), timeout = expect_timeout)
                    child.sendline('echo $?')
                    child.expect(self.get_expect_prompt_list(machine, 2) + self.get_expect_prompt_list(machine, 0), timeout = expect_timeout)
                    try:
                        val = int(child.before.split('\n')[-2].strip())
                    except (ValueError, IndexError) as err:
                        print(child.before.split('\n'))
                        val = 1
                    child.close()
                    return val
            else:
                self.logger.debug(f"[{machine}]Calling {cmd=} without interactive password", stack_info=True)
                subprocess.call(cmd, shell = True)
        except KeyboardInterrupt:
            return 1
        finally:
            try:
                child.close()
            except Exception:
                pass

    def execute_shell_cmd(self, machine, cmd, root = True):
        ret_val = self.call(machine, cmd, root = root)
        if ret_val == 0:
            return [True,"Command executed successfully"]
        return [False, "Command execution in shell failed"]

    def ulimit_call(self, machine, *args, **named_params):
        ulimit = 'ulimit -c unlimited; '
        cmd = ulimit + ' '.join(args)
        return self.call(machine, cmd, **named_params)

    def try_lock(self, log = True):
        """Tries to acquire testbed lock.

        If lock exists and owner with workdir match current one, then acquires the lock.
        """
        user = getpass.getuser()
        workdir = self.workdir.rstrip('/')
        if self.lock.locked():
            if self.lock.owner == user and str(self.lock.testbed) == workdir:
                if log:
                    self.logger.info("You already own the lock.")
                return True
            else:
                self.logger.error(
                    "Could not acquire lock. Lock is owned by {}\n{}\nSince {}".format(
                        self.lock.owner, self.lock.testbed, self.lock.date
                    )
                )
                tb = self.lock.testbed.name
                destroy_cmd = "testbed {} release_lock && testbed {} destroy".format(tb, tb)
                self.logger.info("To release lock and remove previous testbed run command: {}".format(destroy_cmd))
                return False

        try:
            self.lock.acquire()
            if log:
                self.logger.info('Successfully acquired testbed lock')
            return True
        except LockException:
            self.logger.exception("Failed to create lockfile")
            return False

    def release_lock(self):
        if self.lock.locked():
            try:
                self.lock.release()
            except LockException as e:
                self.logger.exception("Errored while trying to release the lock: {}".format(e))
                return False
        return True

    def check_machine_ping(self, machine, fail_time):
        start = int(time.time())
        if self.os_type == 'Darwin':
            wait_tag = 't'
        elif self.os_type == 'Linux':
            wait_tag = 'W'
        while (int(time.time()) - start) <= fail_time:
            ret = subprocess.call(['ping', '-c1', '-%s1.5' % wait_tag, '%s' %
                                  self.mgmt_ipaddr(machine)],
                                  stdout=open(os.devnull, 'w'),
                                  stderr=open(os.devnull, 'w'))
            if ret == 0:
                return True
        return False

    def check_machine_ping_with_retries(self, machine, fail_time=5, max_wait_time=400, wait_interval=40):
        ping_res = self.check_machine_ping(machine, fail_time)
        if ping_res is False:
            self.logger.info("%s mgmt ip is not reachable from the host" % machine)
            current_time = 0
            for t in range(0, max_wait_time, wait_interval):
                self.logger.info("Wait %s sec for %s to come up.." % (wait_interval, machine))
                time.sleep(wait_interval)
                ping_res = self.check_machine_ping(machine, fail_time)
                if ping_res is False:
                    continue
                else:
                    self.logger.info("%s mgmt ip is reachable now" % machine)
                    break
            else:
                #Else in for-loop means, for-loop completed without break
                self.logger.error("%s is not reachable after %s sec" % (machine, max_wait_time))
                return False
        return True

    def wait_till_machine_starts_reboot(self, machine, fail_time):
        start = int(time.time())
        if self.os_type == 'Darwin':
            wait_tag = 't'
        elif self.os_type == 'Linux':
            wait_tag = 'W'
        while (int(time.time()) - start) <= fail_time:
            ret = subprocess.call(['ping', '-c1', '-%s1.5' % wait_tag, '%s' %
                                  self.mgmt_ipaddr(machine)],
                                  stdout=open(os.devnull, 'w'),
                                  stderr=open(os.devnull, 'w'))
            if ret != 0:
                return True
        return False

    def restart_vm(self, machine):
        self.call(machine, 'restart')
        if result != 0:
            return [False, result]
        return [True, None]

    def configure_loopback(self, machine, ip, mask):
        result = self.call(machine, 'ifconfig', 'lo', '%s/%s' % (ip, mask))
        if result != 0:
            return [False, result]
        return [True, None]

    def create_loopback(self, machine, ip, mask, name):
        result = self.call(machine, 'tunctl', '-t', name, '>', '/dev/null')
        if result != 0:
            return [False, result]
        try:
            int(mask)
            result = self.call(machine, 'ifconfig', name, ip + '/' + mask)
        except ValueError:
            result = self.call(machine, 'ifconfig', name, ip, 'netmask', mask)
        if result != 0:
            return [False, result]
        return [True, None]

    def delete_loopback(self, machine, name):
        result = self.call(machine, 'tunctl', '-d', name, '>', '/dev/null')
        if result != 0:
            return [False, result]
        return [True, None]

    def setup_nat(self, machine, out_iface, private_ip):
        result = self.call(machine, 'iptables', '--table', 'nat', '--append',
                           'POSTROUTING', '--out-interface', out_iface, '-j',
                           'MASQUERADE')
        if result != 0:
            return [False, result]
        result = self.call(machine, 'iptables', '-t', 'nat', '-A',
                           'PREROUTING', '-i', out_iface, '-j', 'DNAT',
                           '--to-destination', private_ip)
        if result != 0:
            return [False, result]
        return [True, None]

    def clear_nat(self, machine):
        result = self.call(machine, 'iptables', '--table', 'nat', '--flush')
        if result != 0:
            return [False, result]
        return [True, None]

    def kill_daemon(self, machine, daemon):
        result = self.call(machine, 'killall', daemon)
        if result != 0:
            return [False, result]
        return [True, None]

    def add_default_gateway(self, machine, route):
        result = self.call(machine, 'route', 'add', 'default', 'gw', route)
        if result != 0:
            return [False, result]
        return [True, None]

    def remove_default_gateway(self, machine):
        result = self.call(machine, 'route', 'delete', 'default', '&>',
                           '/dev/null')
        if result != 0:
            return [False, result]
        return [True, None]

    def start_vdaemon(self, machine, vtype, client_ip, vbond_ip, system_ip, path):
        if system_ip != None:
            result = self.ulimit_call(machine, path, '-d', vtype,
                                      '-s', system_ip, '-b', vbond_ip,
                                      '-w', client_ip)
        else:
            result = self.ulimit_call(machine, path, '-d', vtype,
                                      '-w', client_ip)
        if result != 0:
            return [False, result]
        return [True, None]

    def enable_ip_forwarding(self, machine):
        result = self.call(machine, 'echo "1" > /proc/sys/net/ipv4/ip_forward')
        if '1\n' in self.ssh_output(machine,
                                    'cat /proc/sys/net/ipv4/ip_forward'):
            return [True, None]
        else:
            return [False, 'Could not enable ip forwarding']

    def ssh_output(self, machine, cmd):
        """Shells into the designated machine then returns the output of the passed shell command"""
        output = []
        cmd_bld = SSHCommandBuilder(
            host=self.mgmt_ipaddr(machine), user=self.get_ssh_username(machine), logger=self.logger
        )
        shell_cmd = cmd_bld.build()
        if six.PY2:
            child = pexpect.spawn(shell_cmd, timeout = 60)
        else:
            child = pexpect.spawn(shell_cmd, timeout = 60, encoding='utf-8', codec_errors='ignore')
        try:
            child.logfile = self.get_log_file_for_machine(machine)
            if self.debug is True:
                child.logfile = sys.stdout
            prompt = child.expect(['.*password:', 'Password:'] + self.get_expect_prompt_list(machine, 1))
            if prompt <= 1:
                child.sendline(self.get_ssh_password(machine))
                child.expect(self.get_expect_prompt_list(machine, 1))

            child.sendline('vshell')
            child.expect(self.get_expect_prompt_list(machine, 3))
            child.sendline('stty cols 200')
            child.expect(self.get_expect_prompt_list(machine, 3))
            res = child.before
            if not 'stty' in res:
                child.expect(self.get_expect_prompt_list(machine, 3))
            if type(cmd) != list:
                cmd = [cmd]
            for item in cmd:
                child.sendline(item)
                child.expect(self.get_expect_prompt_list(machine, 3))
                result = ' '.join(child.before.split('\n')[1:-1])
                result = ''.join(result.split('\r'))

                child.sendline('echo $?')
                child.expect(self.get_expect_prompt_list(machine, 3))
                code = int(child.before.split('\n')[-2].strip())
                if code == 0:
                    output.append(result)
                else:
                    output.append('-99')
            if len(output) == 1:
                return output[0]
            return output
        finally:
            child.close()

    def get_iosxe_ssh_output(self, machine, cmd):
        """Get cisco iosxe enable prompt output"""
        pexpect_timeout = 25
        cisco_iosxe_session = self.get_iosxe_cli_session(machine, pexpect_timeout, None)
        if not cisco_iosxe_session.isalive():
            # log error message to help investigation, but do not raise exception
            self.logger.error(
                'get_iosxe_ssh_output() operated on pexpect session which is not alive, error may occure !'
            )
        cisco_iosxe_session.sendline(cmd)
        cisco_iosxe_session.expect(['vm.*#', 'pm.*#', 'Router#'])
        result = cisco_iosxe_session.before
        cisco_iosxe_session.close()
        return result

