    def cnw_is_process_running(self, machine, grep_command, poll_time = 2, max_time = 32, present=True):
        curr_time = 0
        while curr_time <= max_time:
            return_val_list = self.is_process_running(machine, grep_command)
            ret_val, ret_str = return_val_list[0], return_val_list[1]
            if (ret_val == True) and (present == True):
                self.logger.info(curr_time)
                return [True, ret_str]
            elif (ret_val == False) and (present == False):
                self.logger.info(curr_time)
                return [True, ret_str]
            else:
                curr_time += poll_time
                if curr_time <= max_time:
                    time.sleep(poll_time)
        return [False, ret_str]

    def is_process_running(self, machine, grep_command):
        idx = 1
        pid = self.ssh_output(machine, grep_command)
        if len(pid) > 0 and pid != '-99':
            return [True, 'Process found with id %s' % (pid.split()[idx])]
        else:
            return [False, 'Process not found']

    def start_zdaemon(self, machine, daemon_cmd, valgrind_daemons=[]):
        name = daemon_cmd.split('/')[-1]
        if name in valgrind_daemons:
            result = self.call(machine, 'valgrind', '--leak-check=full',
                               '--track-origins=yes',
                               '--log-file=/home/root/%s_%s.log %s -f &' %
                               (machine, name, daemon_cmd), shell = True)
        else:
            result = self.ulimit_call(machine, daemon_cmd)
        if result != 0:
            return [False, 'Could not start daemon']
        return [True, None]

    def prefixlen(self, mask, outcome = 'length',ipv6=False):
        # Takes a provided mask in either length or dotted decimal and returns the other format
        if outcome == 'length':
            #For Ipv6, return mask as it is given, if it is not in dotted format
            if (self.trans_ipv6 or self.serv_ipv6 or ipv6) and not misc.is_ipv4_addr(mask):
                return int(mask)
            split_mask = mask.split('.')
            mask =  (int(split_mask[0]) << 24)
            mask += (int(split_mask[1]) << 16)
            mask += (int(split_mask[2]) << 8)
            mask +=  int(split_mask[3])
            bin_mask = bin(mask)
            prefixlen = 0
            for i in range(2, len(bin_mask)):
                if bin_mask[i] == '0':
                    break
                else:
                    prefixlen += 1
            return prefixlen
        elif outcome == 'dotted':
            bin_mask = 0xffffffff << (32 - int(mask))
            mask_end_A = int(bin_mask >> 24 & 0x000000ff)
            mask_end_B = int(bin_mask >> 16 & 0x000000ff)
            mask_end_C = int(bin_mask >> 8 & 0x000000ff)
            mask_end_D = int(bin_mask & 0x000000ff)
            dotmask = '%s.%s.%s.%s' % (str(mask_end_A), str(mask_end_B), str(mask_end_C), str(mask_end_D))
            return dotmask

    def stepvalue(self, mask, step_increment):
        # Takes a defined mask in length and returns a step value in dotted based on the combined mask and increment supplied
        bin_mask = int(step_increment)
        bin_mask = bin_mask << (32 - int(mask))
        mask_end_A = int(bin_mask >> 24 & 0x000000ff)
        mask_end_B = int(bin_mask >> 16 & 0x000000ff)
        mask_end_C = int(bin_mask >> 8 & 0x000000ff)
        mask_end_D = int(bin_mask & 0x000000ff)
        dotmask = '%s.%s.%s.%s' % (str(mask_end_A), str(mask_end_B), str(mask_end_C), str(mask_end_D))
        return dotmask

