    def set_uboot_env(self, machine, env_var, env_val, flash_part=0):
        if self.is_mips_machine(machine):
            self.logger.info('set %s env from uboot partition# %s from %s ' % (env_var, flash_part, machine))
            cmd = "echo 0x%s > /sys/niagara/misc/flash_bank" % flash_part
            self.ssh_output(machine, cmd)
            cmd = "/sbin/fw_setenv %s %s" % (env_var, env_val)
            res = self.ssh_output(machine, cmd)
            if flash_part:
                cmd = "echo 0x0 > /sys/niagara/misc/flash_bank"
                self.ssh_output(machine, cmd)
            if res:
                err = 'ERROR: Unable to set %s to %s on %s - %s' % (env_var, env_val, machine, str(res))
                return [False, err]
            return [True, res.strip()]
        return [True, None]

    def get_uboot_env(self, machine, env_var, flash_part=0):
        if self.is_mips_machine(machine):
            self.logger.info('Get %s env from uboot partition# %s from %s ' % (env_var, flash_part, machine))
            cmd = "echo 0x%s > /sys/niagara/misc/flash_bank" % flash_part
            self.ssh_output(machine, cmd)
            # get the param
            cmd = "/sbin/fw_printenv %s | cut -d'=' -f2" % env_var
            res = self.ssh_output(machine, cmd)
            # reverting to bank 0
            if flash_part:
                cmd = "echo 0x0 > /sys/niagara/misc/flash_bank"
                self.ssh_output(machine, cmd)
            if res == '-99':
                err = 'ERROR: Unable to get %s from %s - %s' % (env_var, machine, str(res))
                return [False, err]
            return [True, res.strip()]
        return [True, None]

