    def set_vshared_size(self):
        self.logger.info('Check vshared_size env in uboot on hw nodes ...')
        for machine in self.machines():
            if self.is_mips_machine(machine):
                result = self.get_vshared_size(machine)
                chs = self.get_chassis_type(machine)
                if chs[1] == 'cust_n822':
                    val = '0x40000000'
                else:
                    val = '0x20000000'
                if result[1] != val:
                    self.logger.info('shared memory size not set to correct value for %s in uboot. Will be set now....' %machine)
                    result = self.call(machine, 'fw_setenv vshared_size %s' % val, root=True)
        return [True, None]

