    def flip_active_partition(self, machine):
        output = self.get_active_partition(machine)
        if output[0] == False:
            return [False, output[1]]
        if output[1] == '1':
            newact = '2'
        if output[1] == '2':
            newact = '1'
        print('On %s current active partition is %s. Will flip to %s' % (machine,output[1],newact))
        cmd = '/sbin/fw_setenv primary %s' % newact
        output = self.ssh_output(machine, cmd)
        if output == '-99':
            err = 'ERROR: Unable to set active partition on %s - %s' % (machine, str(output))
            return [False, err]
        return [True, newact]

