    def check_core_background(self):
        core_found = False
        while core_found is not True:
            for machine in self.machines():
                if machine is not None:
                    result = self.check_core_files(machine)
                    if result[0] == False:
                        core_found = True
                        os.system("echo" + " "+ getpass.getuser() + ", we have a problem!!! You have a core on" +" "+ machine + " | wall")
            time.sleep(120)

    def backup_core_files(self, machine, remove_cores = False, folder='old_dumps'):
        if self.is_cedge(machine) or self.is_ucs(machine) or self.is_nfvis(machine) or self.is_highrise(machine):
            #TODO: Check with Achar, Rauf
            return [True, None]
        if remove_cores == True:
            rm_cores_cmd = 'rm -f /var/crash/%s/*' % folder
            rm_cores_result = self.call(machine, rm_cores_cmd)
            if rm_cores_result != 0:
                return [False, rm_cores_result]
        ls_grep_dumps_cmd = 'ls /var/crash | grep %s' % folder
        ls_grep_dumps_result = self.call(machine, ls_grep_dumps_cmd)
        if ls_grep_dumps_result != 0:
            mkdir_cmd = 'mkdir /var/crash/%s' % folder
            mkdir_result = self.call(machine, mkdir_cmd)
            if mkdir_result != 0:
                return [False, mkdir_result]
        ls_grep_core_cmd = 'ls /var/crash | grep core'
        ls_grep_core_result = self.call(machine, ls_grep_core_cmd)
        if ls_grep_core_result == 0:
            old_cores = self.ssh_output(machine, ls_grep_core_cmd)
            self.logger.info('Moving core files on %s:' % machine)
            self.logger.info(old_cores.strip().split('\r\r'))
            mv_cmd = 'mv /var/crash/*core* /var/crash/%s' % folder
            mv_result = self.call(machine, mv_cmd)
            if mv_result != 0:
                return [False, mv_result]
        return [True, None]

    def move_core_files(self, machine, dir='to', folder='current_run', remove_core = False):
        if dir == 'to':
            return self.backup_core_files(machine, remove_core, folder)
        else:
            ls_grep_dumps_cmd = 'ls /var/crash | grep %s' % folder
            ls_grep_dumps_result = self.call(machine, ls_grep_dumps_cmd)
            if ls_grep_dumps_result != 0:
                return [True, 'No current_run folder found']
            ls_grep_core_cmd = 'ls /var/crash/%s | grep core' % folder
            ls_grep_core_result = self.call(machine, ls_grep_core_cmd)
            if ls_grep_core_result == 0:
                old_cores = self.ssh_output(machine, ls_grep_core_cmd)
                #self.logger.info('Moving core files on %s:' % machine)
                #self.logger.info(old_cores.strip().split('\r\r'))
                mv_cmd = 'mv /var/crash/%s/*core* /var/crash/' % folder
                mv_result = self.call(machine, mv_cmd)
                if mv_result != 0:
                    return [False, mv_result]
            return [True, None]

