    def check_processes_running(self, machine, daemons):
        error_msg = ''
        overall = True
        cmds = []
        if self.is_cedge(machine):
            #TODO: Check with Achar, Rauf
            return [True, None]
        for daemon in daemons:
            cmds.append("ps aux | grep \"%s\" | grep -v grep" % daemon)
        ret = self.ssh_output(machine, cmds)
        for daemon, result in zip(daemons, ret):
            if result == '-99':
                overall = False
                error_msg += 'Process %s not found. It might have exited/crashed' % daemon + '\n'
        return [overall, error_msg]

