    def int_to_dotted(self, area):
        """Converts integer to dotted decimal string"""
        dotted_area = str(area%256)
        for i in reversed(list(range(0, 3))):
            area = math.floor(old_div(area,256))
            dotted_area = str(int(area%256)) + '.' + dotted_area
        return dotted_area

    def dotted_to_int(self, area):
        """Converts dotted decimal to int"""
        area = area.split('.')
        int_area = int(area[3]) + int(area[2])*256
        int_area += int(area[1])*(256^2) + int(area[0])*(256^3)
        return int_area

    def incr_ip_addr(self, prefix, incr_val=1, incr_flag=True):
        """Increments ip address by 1"""
        #incr_val = 1
        max_val = 256
        if incr_flag == False:
            incr_val = -1
            max_val = -1
        ip_addr_list = prefix.split('.')
        byte_counter = 3
        while (byte_counter >= 0):
            ip_addr_list[byte_counter] = int(ip_addr_list[byte_counter]) + incr_val
            if ip_addr_list[byte_counter] != max_val:
                break
            if byte_counter == 0:
                return 'ERROR'
            ip_addr_list[byte_counter] = 0
            byte_counter -= 1
        ip_addr = str(ip_addr_list[0]) + '.' + str(ip_addr_list[1]) + '.' + str(ip_addr_list[2]) + '.' + str(ip_addr_list[3])
        return ip_addr

    def incr_ip_addr_list(self, prefix, num=1):
        ip_list = []
        count = 1
        new_value = prefix
        ip_list.append(prefix)
        while count < num:
            new_value = self.incr_ip_addr(new_value)
            ip_list.append(new_value)
            count += 1
        return ip_list

    def incr_mac(self, mac, offset=1, num=1):
        """Return mac with incremented offset or list of num of mac with incremented offset"""
        mac_list=[]
        new_value = ''.join(mac.split(':'))
        count = 0
        while count < num:
            new_value = "{:012X}".format(int(new_value, 16) + offset)
            mac_list.append(':'.join(new_value[i:i+2] for i in range(0, 12, 2)).lower())
            count += 1
        if len(mac_list) == 1:
            return mac_list[0]
        else:
            return mac_list

    def decr_ip_addr(self, prefix):
        """Decrements ip address by 1"""
        incr_flag = False
        return self.incr_ip_addr(prefix, incr_flag)

    def incr_ip_subnet_old(self, prefix, mask):
        """Increments ip subnet by 1, Does not work for ip-address octet incrementing over 255"""
        if '.' in str(mask):
            mask = self.prefixlen(mask)
        if mask == 0 or mask == 32:
            return 'ERROR: Mask cannot be 0 or 32'
        orig_bin_val = self.dotted_to_binary(prefix)
        decr_mask = mask - 1
        host_str = orig_bin_val[mask:]
        strt_ptr = (old_div(decr_mask, 8)) * 8
        incr_int = int(str(orig_bin_val[strt_ptr:mask]),2) + 1
        num_sub_dig = mask - strt_ptr
        subnet_str = self.decimal_to_binary(incr_int, num_sub_dig)
        pre_str = orig_bin_val[:strt_ptr]
        ip_addr = self.binary_to_dotted(pre_str + subnet_str + host_str)
        return ip_addr

    def incr_ip_subnet(self, prefix, mask):
        """Increments ip subnet by 1"""
        if '.' in str(mask):
            mask = self.prefixlen(mask)
        if mask == 0 or mask == 32:
            return 'ERROR: Mask cannot be 0 or 32'
        orig_hex = hex(self.convert_prefix_dec_to_hex(prefix))
        decr_mask = mask - 1
        incr_str = ''
        for cnt in range(32):
            incr_str += '0'
        temp_list = list(incr_str)
        temp_list[decr_mask] = '1'
        incr_str = "".join(temp_list)
        incr_hex = hex(int(incr_str, 2))
        new_hex = hex(int(orig_hex, 16) + int(incr_hex, 16))
        ip_addr = self.convert_prefix_hex_to_dec(int(new_hex, 16))
        return ip_addr

    def incr_ip_subnet_count(self, prefix, mask, count=1):
        """Increments ip subnet count number of times"""
        i = 0
        ip_addr = prefix
        while (i < count):
            ip_addr = self.incr_ip_subnet(ip_addr, mask)
            i += 1
        return ip_addr

    def incr_ip_subnet_list(self, prefix, mask, count=1, incr_val=1):
        """Increments ip subnet by incr value and returns the list of count items"""
        i = 0
        ip_addr = prefix
        ip_addr_list = []
        while (i < count):
            j = 0
            while (j < incr_val):
                ip_addr = self.incr_ip_subnet(ip_addr, mask)
                j += 1
            ip_addr_list.append(ip_addr)
            i += 1
        return ip_addr_list

    def convert_prefix_dec_to_hex(self, prefix):
        """Converts ip decimal prefix to hex"""
        return self.convert_prefix(prefix, 0)

    def convert_prefix_hex_to_dec(self, prefix):
        """Converts ip hex prefix to decimal"""
        return self.convert_prefix(prefix, 1)

    def network_addr_from_ip(self, ip, mask):
        """Returns network address from ip & mask"""
        ipaddr = ip+'/'+str(mask)
        ipaddr = IPNetwork(ipaddr)
        return str(ipaddr.network)

    def convert_prefix(self, prefix, direction):
        """Convert prefix in dec to hex and vice-versa"""
        if direction == 0:
            dd_mask = prefix.split('.')
            prefix =  (int(dd_mask[0]) << 24)
            prefix += (int(dd_mask[1]) << 16)
            prefix += (int(dd_mask[2]) << 8)
            prefix +=  int(dd_mask[3])
            hex_prefix = hex(prefix)
            return int(hex_prefix, 16)
        elif direction == 1:
            byteA = int(prefix >> 24 & 0x000000ff)
            byteB = int(prefix >> 16 & 0x000000ff)
            byteC = int(prefix >> 8 & 0x000000ff)
            byteD = int(prefix & 0x000000ff)
            prefix = '%s.%s.%s.%s' % (str(byteA), str(byteB),
                                      str(byteC), str(byteD))
            return prefix

    def ping(self, machine, dest_ip, count=1, wait=50, iface=None):
        if iface is None:
            err = self.call(machine, 'ping', '-q', '-c%s' % count,
                            '-w%s' % wait, dest_ip, '>', '/dev/null', '2>&1')
        else:
            if type(iface) == int:
                iface = 'eth%d' % iface
            err = self.call(machine, 'ping', '-q', '-c%s' % count,
                            '-w%s' % wait, '-I %s' % iface,
                            dest_ip, '>', '/dev/null', '2>&1')
        result = (err == 0)
        if result is True:
            return [result, '%s successfully pinged %s' %
                    (machine, dest_ip)]
        else:
            return [result, '%s failed to ping %s' % (machine, dest_ip)]

    def turn_off_tcp_segmentation_offload(self, machine, iface, vpn_id=0):
        hostname = self.ssh_output(machine, 'hostname')
        if vpn_id == 0:
            if hostname not in ['testbed1.local', 'testbed3.local']:
                self.call(machine, 'ethtool', '-K', iface, 'tso', 'off')
        else:
            if hostname not in ['testbed1.local', 'testbed3.local']:
                self.call(machine, 'ip', 'netns', 'exec', '%d' % vpn_id, 'ethtool', '-K', iface, 'tso', 'off')
        return [True, '']

    def turn_off_generic_segmentation_offload(self, machine, iface, vpn_id=0):
        hostname = self.ssh_output(machine, 'hostname')
        if vpn_id == 0:
            if hostname not in ['testbed1.local', 'testbed3.local']:
                self.call(machine, 'ethtool', '-K', iface, 'gso', 'off')
        else:
            if hostname not in ['testbed1.local', 'testbed3.local']:
                self.call(machine, 'ip', 'netns', 'exec', '%d' % vpn_id, 'ethtool', '-K', iface, 'gso', 'off')
        return [True, '']

    def scp_files_bidirectional(self, machine1, machine2, fname, block_size, count, dest_ip_1, dest_ip_2, dest_path, vpn_id):
        """SCP two files simultaneously"""
        file_1_thread = Thread(None, self.scp_file, args = (machine1, machine2, fname, block_size, count, dest_ip_1, dest_path, vpn_id))
        file_2_thread = Thread(None, self.scp_file, args = (machine2, machine1, fname, block_size, count, dest_ip_2, dest_path, vpn_id))
        file_1_thread.start()
        file_2_thread.start()
        file_1_thread.join()
        file_2_thread.join()
        md5_sum_1 = self.ssh_output(machine1, 'md5sum %s' % fname)
        copy_md5_sum_1 = self.ssh_output(machine2, 'md5sum %s' % dest_path)
        if md5_sum_1.split(' ')[0] == copy_md5_sum_1.split(' ')[0]:
            md5_sum_2 = self.ssh_output(machine2, 'md5sum %s' % fname)
            copy_md5_sum_2 = self.ssh_output(machine1, 'md5sum %s' % dest_path)
            if md5_sum_2.split(' ')[0] == copy_md5_sum_2.split(' ')[0]:
                return [True, 'Both test files were successfully transferred']
            else:
                return [False, 'There was an error transferring the file from %s to %s' % (machine2, machine1)]
        else:
            return [False, 'There was an error transferring the file from %s to %s' % (machine1, machine2)]

    def scp_file(self, machine1, machine2, fname, block_size, count, dest_ip, dest_path, vpn_id):
        hostname = self.ssh_output(machine1, 'hostname')
        self.call(machine1, 'dd', 'if=/dev/urandom', 'of=%s' % fname,
                  'bs=%s' % block_size, 'count=%s' % count)
        md5_sum = self.ssh_output(machine1, 'md5sum %s' % fname)
        start_time = time.localtime()
        if vpn_id == 0:
            self.call(machine1, 'scp', '-o', 'LogLevel=QUIET',
                      '-o', 'UserKnownHostsFile=/dev/null',
                      '-o', 'StrictHostKeyChecking=no',
                      '-o', 'ConnectTimeout=30', fname,
                      'root@%s:%s' % (dest_ip, dest_path), root = True, timeout = 120)
        else:
            self.call(machine1, 'ip', 'netns', 'exec', '%d' % vpn_id, 'scp', '-o', 'LogLevel=QUIET',
                      '-o', 'UserKnownHostsFile=/dev/null',
                      '-o', 'StrictHostKeyChecking=no',
                      '-o', 'ConnectTimeout=30', fname,
                      'root@%s:%s' % (dest_ip, dest_path), root = True, timeout = 120)
        end_time = time.localtime()
        scp_time = self.get_time_difference(end_time, start_time)
        copy_md5_sum = self.ssh_output(machine2, 'md5sum %s' % dest_path)
        if md5_sum.split(' ')[0] == copy_md5_sum.split(' ')[0]:
            print('The test file was successfully transferred in %s seconds' % scp_time)
            return [True, 'The test file was successfully transferred in %s seconds' % scp_time]
        else:
            return [False, 'There was an error transferring the file']

    def start_sshd_vpn(self, machine1, vpn_id):
        ret = self.call(machine1, 'ip', 'netns', 'exec', '%d' % vpn_id, '/usr/sbin/sshd', root = True)
        if ret != 0:
            return [False, 'Could not start sshd daemon']
        return [True, 'The sshd daemon was successfully created']

    def check_key(self, key, dictionary):
        return key in dictionary

    def machine_branch(self, machine):
        try:
            return str(self.config['machines'][machine]['branch'])
        except KeyError:
            return str(self.branch)

    def get_machine_branch(self, machine):
        cmd_bld = SSHCommandBuilder(
            host=self.mgmt_ipaddr(machine), user=self.get_ssh_username(machine), logger=self.logger
        )
        cmd_bld.add_kv_option('ConnectTimeout', 20)
        cmd = cmd_bld.build()
        if six.PY2:
            child1 = pexpect.spawn(cmd, timeout = 25)
        else:
            child1 = pexpect.spawn(cmd, timeout = 25, encoding='utf-8', codec_errors='ignore')
        try:
            index = child1.expect(['.*password:', 'Password:'] + self.get_expect_prompt_list(machine, 0))
            if index <= 1:
                child1.sendline(self.get_ssh_password(machine))
                child1.expect(self.get_expect_prompt_list(machine, 1))
            child1.sendline('show version')
            child1.expect(self.get_expect_prompt_list(machine, 1))
            branch_out = child1.before
            version = branch_out.split('\n')[1].rstrip()
            return version
        except pexpect.EOF:
            return None, None
        finally:
            child1.close()

    def check_machine_branch(self, machine, branch):
        current_branch = self.get_machine_branch(machine)
        if branch == current_branch:
            return [True, 'Current branch is %s'%branch]
        else:
            return [False, 'Current branch is %s, does not match expected %s'%(current_branch, branch)]

    def get_machine_python_interpreter(self, machine):
        # type: (str) -> str
        has_python3 = tuple(self.get_machine_branch(machine).split(".")) >= ("20", "5")
        return "python3" if has_python3 else "python"

    '''
    Temporary workaround to get cEdge version.
    While "show version" in IOS command doesn't return needed information
    '''
    def get_cedge_version_from_file(self, machine, remote = None, upgrade = False, qcow2 = False, diff_image = None):
        '''
        Temporary workaround getting version from cEdge image
        Once 'show version' fixed to show correct version this should not be used
        '''
        exts = ["iso", "qcow2", "vmdk", "bin"]
        for ext in exts:
            image_path = os.path.join(self.workdir, machine, '{}.{}'.format(machine, ext))
            if os.path.isfile(image_path):
                get_version_cmd = 'strings {file_path} | grep -m 1 CW_FULL_VERSION |  cut -d= -f2'.format(
                    file_path=image_path
                )
                result = (
                    subprocess.check_output(get_version_cmd, shell=True, universal_newlines=True).strip().strip('$')
                )
                sdwan_version = '.'.join(result.split('.')[:5])
                return [True, sdwan_version]

    def get_cedge_version(self, machine, remote = None, upgrade = False, qcow2 = False, diff_image = None):
        result = "N/A"
        mgmt_ip = self.mgmt_ipaddr(machine)
        logfile = self.get_log_file_for_machine(machine)
        with CedgeSession(mgmt_ip, logfile) as cedge_session:
            result = cedge_session.show_version()
        return [True, result]

    def get_branch_and_build(self, machine):
        cmd_bld = SSHCommandBuilder(
            host=self.mgmt_ipaddr(machine), user=self.get_ssh_username(machine), logger=self.logger
        )
        cmd_bld.add_kv_option('ConnectTimeout', 20)
        cmd = cmd_bld.build()
        if six.PY2:
            child1 = pexpect.spawn(cmd, timeout = 25)
        else:
            child1 = pexpect.spawn(cmd, timeout = 25, encoding='utf-8', codec_errors='ignore')
        try:
            index = child1.expect(['.*password:', 'Password:'] + self.get_expect_prompt_list(machine, 0))
            if index <= 1:
                child1.sendline(self.get_ssh_password(machine))
                child1.expect(self.get_expect_prompt_list(machine, 1))
            child1.sendline('show version')
            child1.expect(self.get_expect_prompt_list(machine, 1))
            branch_out = child1.before
            version = branch_out.split('\n')[1].rstrip()
            ker_ver=self.device_version_dict.get(machine,True)
            if ker_ver == True:
                ker_ver =  self.device_version_dict[machine] = ''.join(self.get_kernel_ver(machine)[1].split('.')[:-1])
            branch, build_no = misc.parse_version(version)
            if build_no == None:
                build_no = 0
            if ker_ver == None:
                ker_ver = 0
            return branch, build_no, ker_ver
        except pexpect.EOF:
            return None, None
        finally:
            child1.close()

    def get_container_build(self, machine):
        cmd = "show container images | display xml"
        ssh_session = self.get_machine_session(machine)
        ssh_session.sendline(cmd)
        ssh_session.expect(r"#", timeout=10)
        build_string = ssh_session.before
        build_num = re.search(r'<version>(\S+)</version>', build_string).group(1)
        return build_num


    def check_branch_and_build(self, machine, branch, build_no):
        current_branch, current_build_no = self.get_branch_and_build(machine)
        if branch != current_branch or build_no != current_build_no:
            return [False, 'check failed']
        else:
            return [True, 'check passed']

    def pre_cutoff(self, number, branch = None):
        if branch == None:
            branch = self.branch
        return number < int(pref['images'][branch].get('cutoff', -1))

    def images(self):
        try:
            return self.config['images']
        except KeyError:
            return pref['images']

    def images_loc(self, machine, branch = None):
        loc_str = 'loc'
        if branch == None:
            branch = self.machine_branch(machine)

        # prevent picking not supported version for vedge:
        if self.use_vedge_fallback_image(machine, branch):
            self.logger.warning(
                "branch: %s not supported for (%s)vEdge:%s, using alternative image location: loc_vedge",
                branch,
                machine,
                self.personality(machine),
            )
            loc_str = 'loc_vedge'

        try:
            if branch in pref['images']:
                return self.config['images'][branch][loc_str]
            elif self.is_cedge(machine) and "cedge_throttle" in branch:
                base = Path("/auto/sdwan2/builds/cEdge/")
                # List all directories in base_path excluding those in ignore_list
                dirs = [d for d in base.iterdir() if d.is_dir() and d.name not in ["polaris_dev", "lux_dev"]]
                # Sort directories by modification time, descending
                dirs_sorted = sorted(dirs, key=lambda d: d.stat().st_mtime, reverse=True)
                if "3rd_latest" in branch:
                    return base / dirs_sorted[2] / "LATEST"
                elif "2nd_latest" in branch:
                    return base / dirs_sorted[1] / "LATEST"
                elif "latest" in branch:
                    return base / dirs_sorted[0] / "LATEST"
                else:
                    return base / "polaris_dev" / "LATEST"
        except KeyError:
            return pref['images'][branch][loc_str]

    def default_branch(self):
        try:
            return self.branch_mapping(self.config['default_branch'])
        except KeyError:
            return self.branch_mapping(pref['default_branch'])

    def branch_mapping(self, branch):
        return pref['branch_mappings'].get(branch, branch)

    def images_file(self, machine, image, diff_image_type = None, branch = None):
        if diff_image_type != None:
            image = '%s_%s' % (image, diff_image_type)
        if branch == None:
            branch = self.machine_branch(machine)
        try:
            image_file = self.config['images'][branch]['images_names'][image]['file']
        except KeyError:
            if branch in pref['images']:
                image_file = pref['images'][branch]['images_names'][image]['file']
            elif self.is_cedge(machine) and "cedge_throttle" in branch:
                image_file = pref['images']['cedge']['images_names'][image]['file']

        return image_file

    def images_upgrade_file(self, machine, image, diff_image_type = None, branch = None):
        if diff_image_type != None:
            image = '%s_%s' % (image, diff_image_type)
        if branch == None:
            branch = self.machine_branch(machine)
        try:
            image_branch_name = self.config['images'][branch].get('branch_name', branch)
            image_file = self.config['images'][branch]['images_names'][image]['upgrade']
        except KeyError:
            image_branch_name = pref['images'][branch].get('branch_name', branch)
            image_file = pref['images'][branch]['images_names'][image]['upgrade']
        return re.sub('<branch>', image_branch_name, image_file)

