        mch_list = {}
        personality_list = ['vedge', 'kvm_vedge', 'aws_vedge', 'azure_vedge', 'cedge_csr', 'cedge_csr_kvm']
        for mch in self.config['machines']:
            if site_location == None:
                if 'vm' in mch and (self.personality(mch) in personality_list):
                    if self.site_location(mch) != None :
                        if self.site_location(mch) == 'mpls' or self.site_location(mch) == 'internet':
                            mch_list[mch]=True
