        interfaces = self.config['machines'][vcontainer_machine]['interfaces']
        if self.personality(vcontainer_machine) != 'vcontainer':
            return None
        else:
            for intf in interfaces:
                if interfaces[intf]['type'] ==  'transport':
                    if 'vsmarts' in list(interfaces[intf].keys()):
                        return interfaces[intf]['vsmarts']
        return None

