    def get_container_image_path(self, machine, container_image_variable):
        """Get the path to a container's image

        Args:
            machine (str): N/A
            container_image_variable (str): image variable for container in YAML
                Eg: DRE - dre_image_path, HTTP - http_image_path

        Returns:
            image_path(str): path to a container's image
                Eg: file:///auto/sdwan2/builds/cEdge/polaris_dev/PR_NMS_STABLE/appqoe-http-cache.*.tar
        """
        image_redirect = self.config['variables'][container_image_variable]["value"]
        try:
            image = pref[image_redirect]
        except KeyError:
            self.logger.error("variable {} not found in preference YAML".format(image_redirect))
            image = image_redirect

        image_path = self.get_image_source_path_from_preferences(
            machine,
            additional=None,
            remote=None,
            upgrade=False,
            qcow2=False,
            diff_image_type=None,
            image_variable=image,
        )
        self.logger.info("container_image_variable = {}, image_path = {}".format(container_image_variable, image_path))
        return image_path

    def machines_image(self, machine):
        image_redirect = self.config['machines'][machine]['image']
        try:
            image = pref[image_redirect]
            return image
        except KeyError:
            return image_redirect

