    def get_vnet_adapter(self, vnet):
        '''
        Get adapter from topo yaml file using vnet
        '''
        if len(self.adapters()) != 0:
            adapters = list(self.adapters().keys())
            for adapter in adapters:
                if self.adapter_vnet(adapter) == vnet:
                    return [True, '%s'%adapter]
        return [False, 'did not find adapter section']

