    def render_nfvis_vm_vnet_mapping(self, interfaces):
        # TODO: figure out better way to render vnets based on topology
        vnets = []
        if not interfaces:
            return vnets
        for nic in interfaces.values():
            # make sure br-mgmt / GE0 interface will be connected
            # in KVM topology to vnet5 network
            if "wan-br" in nic["intf"]:
                int_idx = 0
            else:
                intf = nic["intf"][0]
                int_idx = re.findall(r"\d+", intf)[0]

            network = {"alias": "net{}".format(int_idx), "network": "vnet{}".format(nic["vnet"])}
            vnets.append(network)
        vnets.sort(key=operator.itemgetter('alias'))
        return vnets

    def interfaces(self, machine, mgmt = False):
        if self.is_nfvis(machine):
            return self.config['machines'][machine]['interfaces']
        if machine is None:
            return None
        if mgmt == False:
            iface_dict = self.config['machines'][machine]['interfaces'].copy()
            if 'vm' in machine:
                mgmt_iface = self.iface_from_vnet(machine, 1)
                del iface_dict[mgmt_iface]
            elif 'pm' in machine and 'CG113' not in self.config['machines'][machine]['personality']:
                del iface_dict['MGMT']
            return iface_dict
        else:
            return self.config['machines'][machine]['interfaces']

    def get_interface(self, machine, interface_name):
        machines = self.config['machines']
        config = machines[machine]
        interfaces = config['interfaces']
        ifc = [i for i in interfaces.values() if interface_name in i['intf']]
        if not ifc:
            return None
        return ifc[0]

    #Returns a Dictionary of Transport Interface as Key Color as Value
    def tloc_color(self, machine):
        interfaceDict= dict(self.interfaces(machine))
        tlocDict = {}
        for intf in interfaceDict:
            interfacePropDict = dict(interfaceDict[intf])
            if interfacePropDict['type'] == 'transport':
                tlocDict[interfacePropDict['intf'][0]] = interfacePropDict['color']
        return tlocDict

    def bfd_count_between_vedges(self, machine1, machine2):
        count = 0
        interfaceDict = {}
        for mch in [machine1, machine2]:
            interfaceDict[mch] = dict(self.interfaces(mch))
            interfaceDict[mch] = {intf:prop for (intf,prop) in list(interfaceDict[mch].items()) if prop['type'] == 'transport' \
                    and ('LR' not in prop or prop['LR'] != True)}
            for intf in interfaceDict[mch]:
                if 'gre' not in interfaceDict[mch][intf]:
                    interfaceDict[mch][intf]['gre'] = False
                if 'ipsec' not in interfaceDict[mch][intf]:
                    interfaceDict[mch][intf]['ipsec'] = False
        for intf in interfaceDict[machine1]:
            interfacePropDict = dict(interfaceDict[machine1][intf])
            if 'restrict' in interfacePropDict and interfacePropDict['restrict'] == True:
                restrict = True
            else:
                restrict = False
            for intf2 in interfaceDict[machine2]:
                colorMatch = False
                restrictMatch = False
                if interfaceDict[machine2][intf2]['color'] == interfacePropDict['color']:
                    colorMatch = True
                elif restrict == False and ('restrict' not in interfaceDict[machine2][intf2] or interfaceDict[machine2][intf2]['restrict'] != True):
                    restrictMatch = True
                if colorMatch or restrictMatch:
                    if interfaceDict[machine2][intf2]['ipsec'] == True and interfacePropDict['ipsec'] == True:
                        count += 1
                    if interfaceDict[machine2][intf2]['gre'] == True and interfacePropDict['gre'] == True:
                        count += 1
        return count

    #Returns a Dictionary of Transport Interface as Key vmanPref as Value
    def tloc_vmanPref(self, machine):
        interfaceDict= dict(self.interfaces(machine))
        tlocDict = {}
        for intf in interfaceDict:
            interfacePropDict = dict(interfaceDict[intf])
            if interfacePropDict['type'] == 'transport':
                if 'vmanPref' in list(interfacePropDict.keys()):
                    if self.check_key('mcc', self.config['machines'][machine]['interfaces'][intf]):
                        if interfacePropDict['mcc'] == 0:
                            continue;
                    if self.check_key('LR', self.config['machines'][machine]['interfaces'][intf]):
                        if interfacePropDict['LR'] == True:
                            continue;
                    else:
                        tlocDict[interfacePropDict['intf'][0]] = interfacePropDict['vmanPref']
                else:
                    if self.check_key('mcc', self.config['machines'][machine]['interfaces'][intf]):
                        if interfacePropDict['mcc'] == 0:
                            continue;
                    if self.check_key('LR', self.config['machines'][machine]['interfaces'][intf]):
                        if interfacePropDict['LR'] == True:
                            continue;
                    else:
                        tlocDict[interfacePropDict['intf'][0]] = 5
        tlocDict = sorted(list(tlocDict.items()), key=operator.itemgetter(1), reverse=True)
        return tlocDict

