    def subnet(self, vnet, conv_v6=False, machine=None):
        subnet = self.config['vnets'][int(vnet)]['subnet']
        if self.trans_ipv6 and conv_v6:
            if self.ipv6_ra:
                return misc.conv_ipv4_to_ipv6_ra(subnet)
            return misc.conv_ipv4_to_ipv6(subnet)
        if self.serv_ipv6 and conv_v6:
            if (machine==None or self.is_cedge(machine)):
                return misc.conv_ipv4_to_ipv6_cedge(subnet)
        return subnet

    def netmask(self, vnet, machine=None):
        mask = self.config['vnets'][int(vnet)]['netmask']
        if machine:
            vpn_id = self.vpn_id_from_vnet(machine, vnet)
        else:
            vpn_id = self.vpn_id_any_mch_vnet(vnet)
        if self.trans_ipv6:
            if (vpn_id == None or int(vpn_id) == 0) and (int(vnet) not in self.special_vnet_list):
                if self.ipv6_ra:
                    return misc.conv_ipv4_mask_to_ipv6_ra(mask, ipv6_new_format=self.ipv6_new_format)
                return misc.conv_ipv4_mask_to_ipv6(mask, ipv6_new_format=self.ipv6_new_format)
        if self.serv_ipv6 and (machine==None or self.is_cedge(machine)):
            if (vpn_id != None and int(vpn_id) != 0 and int(vpn_id) != 512) and (int(vnet) not in self.special_vnet_list):
                return misc.conv_ipv4_mask_to_ipv6_ra(mask, ipv6_new_format=self.ipv6_new_format)
        return mask

