    def get_mgmt_interface_ip(self, machine):
        if self.is_physical_machine(machine):
            return self.config['machines'][machine]['interfaces']['MGMT']['ip']
        else:
            intf_idx = self.iface_from_vnet(machine, 1)
            return self.config['machines'][machine]['interfaces'][intf_idx]['ip']

    def get_mgmt_interface_name(self, machine):
        if self.is_physical_machine(machine):
            return self.config['machines'][machine]['interfaces']['MGMT']['intf'][-1]
        else:
            return self.intf_name(machine, self.iface_from_vnet(machine, 1))

    def get_mgmt_interface_gateway(self, machine):
        if self.is_physical_machine(machine):
            return self.config['machines'][machine]['interfaces']['MGMT'].get('default_gateway')
        else:
            return None

    def ipaddr(self, machine, iface):
        if iface in list(self.config['machines'][machine]['interfaces'].keys()):
            ipaddr = self.config['machines'][machine]['interfaces'][iface]['ip']
        else:
            return False
        vpn_id = self.vpn_id(machine, iface)
        vnet = self.vnet(machine, iface)
        if self.trans_ipv6:
            if (vpn_id == None or int(vpn_id) == 0) and (int(vnet) not in self.special_vnet_list):
                if self.ipv6_ra:
                    if self.is_cedge(machine):
                        return misc.conv_ipv4_to_ipv6_cedge(ipaddr, ipv6_new_format=self.ipv6_new_format)
                    else:
                        return misc.conv_ipv4_to_ipv6_ra(ipaddr, ipv6_new_format=self.ipv6_new_format)
                return misc.conv_ipv4_to_ipv6(ipaddr, ipv6_new_format=self.ipv6_new_format)
        if self.serv_ipv6 and self.is_cedge(machine):
            if (vpn_id != None and int(vpn_id) != 0 and int(vpn_id) != 512) and (int(vnet) not in self.special_vnet_list):
                return misc.conv_ipv4_to_ipv6_ra(ipaddr, ipv6_new_format=self.ipv6_new_format)
        return ipaddr

    def return_hostname(self, sys_ip):
        """ Example: sys_ip = 172.16.255.11/32 return machine -> 'vm1' """
        for machine in self.config['machines']:
            if self.system_ip(machine) == sys_ip:
                return machine
        return (False, 'No machine has that system_ip')

    def return_random_vpn_id(self):
        new_vpn = random.randint(1, self.max_vpn_num)
        while new_vpn in self.reserved_vpn_list:
            new_vpn = random.randint(1, self.max_vpn_num)
        self.reserved_vpn_list.append(new_vpn)
        return new_vpn

    def reserve_random_vpn_id(self, dummy_mach, vpn_id):
        self.reserved_vpn_list.append(vpn_id)
        return [True, 'Reserved vpn_id']

    def free_random_vpn_id(self, dummy_mach, free_vpn_id):
        self.reserved_vpn_list.remove(free_vpn_id)
