    def return_random_vlan_id(self):
        new_vlan = random.randint(1, self.max_vlan_num)
        while new_vlan in self.reserved_vlan_list:
            new_vlan = random.randint(1, self.max_vlan_num)
        self.reserved_vlan_list.append(new_vlan)
        return new_vlan

