    def return_interfaces_belonging_to_vpn(self, machine, vpn=0):
        """return the list of interfaces belonging to the vpn"""
        return_list = []
        if machine not in self.config['machines']:
            return []
        for key in list(self.config['machines'][machine]['interfaces'].keys()):
            if self.config['machines'][machine]['interfaces'][key]['vpn'] == vpn:
                return_list.append(self.config['machines'][machine]['interfaces'][key]['intf'][-1])
