    #Returns a dictionary of tloc_interface as key and the property_name's value as the value.
    #This is a generic function which can be used to get any 'transport' interface's property assigned
    #If the property_name does not exist, the default value for different property_name are returned accordingly
    def return_intf_property(self, machine, property_name):
        interfaceDict = dict(self.interfaces(machine))
        tlocDict_property = {}
        for intf in interfaceDict:
            interfacePropDict = dict(interfaceDict[intf])
            if interfacePropDict['type'] == 'transport':
                if self.check_key(property_name, self.config['machines'][machine]['interfaces'][intf]):
                    tlocDict_property[interfacePropDict['intf'][0]] = self.config['machines'][machine]['interfaces'][intf][property_name]
                else:
                    if property_name == 'mcc':
                        tlocDict_property[interfacePropDict['intf'][0]] = 2
                    elif property_name == 'ipsec':
                        tlocDict_property[interfacePropDict['intf'][0]] = True
                    elif property_name == 'color':
                        tlocDict_property[interfacePropDict['intf'][0]] = 'default'
                    elif property_name == 'ip':
                        tlocDict_property[interfacePropDict['intf'][0]] = None
                    elif property_name == 'mask':
                        tlocDict_property[interfacePropDict['intf'][0]] = 24
                    elif property_name == 'vmanPref':
                        tlocDict_property[interfacePropDict['intf'][0]] = 5
                    else:
                        tlocDict_property[interfacePropDict['intf'][0]] = False
        return tlocDict_property

