    #Returns TRANSPORT interface's ip address
    def ip_of_transport_intf(self, machine, transport_intf, ifName = False):
        interfaces = self.config['machines'][machine]['interfaces']
        if ifName:
            for intf in interfaces:
                if intf == transport_intf:
                    if 'ip' in list(interfaces[intf].keys()):
                        return interfaces[intf]['ip']
                    else:
                        return interfaces[intf]['ipv6']
        for intf in interfaces:
            if interfaces[intf]['type'] ==  'transport' and interfaces[intf]['intf'][0] == transport_intf:
                if 'ip' in list(interfaces[intf].keys()):
                    return interfaces[intf]['ip']
                else:
                    return interfaces[intf]['ipv6']
        return None

