    def system_tb_location_spirent_port(self, location, num_order = False, ref_index = False):
        if ref_index == False:
            ref_index = 0
        if self.check_key('locations', self.config['system_tb_host']):
            for loc in self.config['system_tb_host']['locations']:
                if self.config['system_tb_host']['locations'][loc]['location'] == int(location):
                    if not num_order:
                        if "references" in self.config['system_tb_host']['locations'][loc]:
                            if int(ref_index) in self.config['system_tb_host']['locations'][loc]['references']:
                                ref_index = self.config['system_tb_host']['locations'][loc]['references'].index(int(ref_index))
                            else:
                                continue
                        return self.config['system_tb_host']['locations'][loc]['spirent_port'][int(ref_index)]
                    else:
                        return loc
        return None

    def system_tb_location_spirent_devices(self, location):
        max_ref = 0
        for mch in list(self.mch_by_location_list(location).keys()):
            max_ref = max(max_ref, self.reference(mch))
        spirent_devices_list = [0] * (max_ref + 1)
        if self.check_key('locations', self.config['system_tb_host']):
            for loc in self.config['system_tb_host']['locations']:
                if self.config['system_tb_host']['locations'][loc]['location'] == int(location):
                    if "references" in self.config['system_tb_host']['locations'][loc]:
                        size = len(self.config['system_tb_host']['locations'][loc]['references'])
                        for indx in range(0, size):
                            spirent_devices_list[self.config['system_tb_host']['locations'][loc]['references'][indx]] = self.config['system_tb_host']['locations'][loc]['spirent_devices'][indx]
                    else:
                        return self.config['system_tb_host']['locations'][loc]['spirent_devices']
        if sum(spirent_devices_list) == 0:
            return None
        else:
            return spirent_devices_list

