    def dynamips_sessions(self):
        config_file = self.dynamips_config()
        dynamips_routers = []
        dynamips_consoles = []
        script_loc = os.path.realpath(__file__)
        vtest_dir = os.path.dirname(os.path.dirname(script_loc))
        dynagen_loc = os.path.join(vtest_dir, 'addons', 'dynagen')
        dynagen_fd = open(os.path.join(dynagen_loc, config_file))
        dynagen_fd_content = dynagen_fd.read()
        dynagen_fd.close()

        for dynagen_line in dynagen_fd_content.split('\n'):
            if re.search(r'\[\[ROUTER', dynagen_line):
                dynamips_routers.extend([dynagen_line.strip('[]').split()[1]])
            if re.search('console', dynagen_line):
                dynamips_consoles.extend([dynagen_line.strip().split('=')[-1]])
        if len(dynamips_consoles) != len(dynamips_routers):
            return False
        return dynamips_routers, dynamips_consoles

    def dynamips_state(self, action):
        if action == 'bringup':
            self.logger.info('Found Dynamips Config - Bringing up')
        elif action == 'takedown':
            self.logger.info('Found Dynamips Config - Taking down')
        config_file = self.dynamips_config()
        script_loc = os.path.realpath(__file__)
        vtest_dir = os.path.dirname(os.path.dirname(script_loc))
        dynagen_loc = os.path.join(vtest_dir, 'addons', 'dynagen')
        platform = os.uname()[0]
        dynamips_loc = os.path.join(vtest_dir, 'addons', 'dynamips', platform)

        dynagen_fd = open(os.path.join(dynagen_loc, config_file))
        dynagen_fd_content = dynagen_fd.read()
        dynagen_fd.close()
        dynamips_inst = []
        for dynagen_line in dynagen_fd_content.split('\n'):
            if re.search(r'\[[a-z]*:[0-9]*\]', dynagen_line):
                dynamips_inst.extend([dynagen_line.strip('[]').split(':')[1]])

        if action == 'bringup':
            for instance in dynamips_inst:
                try:
                    self.logger.info('Starting instance %s of Dynamips' % instance)
                    subpr_cmd = 'sudo -b ' + dynamips_loc + '/dynamips.bin -H %s > /dev/null' % instance
                    subprocess.check_call(subpr_cmd, shell=True)
                except subprocess.CalledProcessError as err:
                    self.logger.error('ERROR: Could not start instance %s of Dynamips. Error: %s' % (instance, err.returncode))
                    return 1
            time.sleep(10)
            try:
                self.logger.info('Starting Dynagen network from config file %s' % config_file)
                subpr_config_file = dynagen_loc + '/' + config_file
                subpr_cmd = 'sudo ' + dynagen_loc + '/dynagen -q %s' % subpr_config_file
                subproc = subprocess.check_output(subpr_cmd, shell=True, universal_newlines=True)
                if not 'Network successfully loaded' in subproc.split('\n'):
                    self.logger.error('ERROR: Could not load Dynagen network. Error: %s' % subproc)
                    return 1
            except subprocess.CalledProcessError as err:
                self.logger.error('ERROR: Could not start Dynagen. Error: %s' % err.returncode)
                return 1
            self.logger.info('Dynamips/Dynagen started successfully')
            return 0

        elif action == 'takedown':
            for instance in dynamips_inst:
                try:
                    self.logger.info('Killing instance %s of Dynamips' % instance)
                    procinf = subprocess.check_output(['ps', '-ef'], universal_newlines=True).split('\n')
                    for item in procinf:
                        if re.search('dynamips.bin -H %s.*' % instance, item):
                            subprocess.check_call(['sudo', 'kill', '-9', item.split()[1]])
                except subprocess.CalledProcessError as err:
                    self.logger.error('ERROR: Failed killing instance %s of Dynamips. Error: %s' % (instance, err.returncode))
                    return 1
        self.logger.info('Dynamips/Dynagen successfully stopped')
        return 0

    def check_hw_machines(self):
        for machine in self.machines():
            if self.is_physical_machine(machine):
                if self.is_ucs(machine) or self.is_nfvis(machine) or self.is_highrise(machine):
                    continue
                elif self.is_cedge(machine):
                    # HW cEdge will be brought up later in bringup_hw_cedge()
                    # At this poing it still can be in a bad state.
                    continue
                elif "vedge" in self.personality(machine):
                    child1 = self.check_machine(machine)
                    if child1 == False:
                        self.logger.error('Could not log in to %s, please check to make sure it is not in a bad state' % machine)
                        self.pause_scheduler()
                        self.logger.error('aborted due to errors')
                        return -99
                    child1.close()
        return 0

    def ssh_went_down(self, machine, maxwait = 20):
        # Wait up to maxwait seconds for SSH to go down
        start_time = time.time()
        is_timedout = False
        while self.is_cedge_ssh_up(machine) and not is_timedout:
            is_timedout = int(time.time() - start_time) > maxwait
        return not is_timedout

    def is_cedge_ssh_up(self, machine):
        cmd_bld = SSHCommandBuilder(
            host=self.mgmt_ipaddr(machine), user=self.get_ssh_username(machine), logger=self.logger
        )
        cmd_bld.add_kv_option('ConnectTimeout', 20)
        cmd = cmd_bld.build()
        self.logger.info('Trying to SSH to {}'.format(machine))
        if six.PY2:
            child = pexpect.spawn(cmd)
        else:
            child = pexpect.spawn(cmd,encoding='utf-8', codec_errors='ignore')
        try:
            index = child.expect(['.*password:', 'Password:', r'.*#', r'.*>'], timeout=10)
            if index <= 1:
                child.sendline(self.get_ssh_password(machine))
                child.expect([r'.*#', r'.*>'])
            return True
        except (pexpect.EOF, pexpect.TIMEOUT):
            self.logger.info('Failed to SSH to {}'.format(machine))
            return False
        finally:
            child.close()

    def check_machine(self, machine, netconf=False):
        '''
        This method is used to verify testbed machine liveness.
        It uses SSH to check if port is opened.

        Returns: Either boolean value (for VM true/false)
            or in case of SSH session pexpect spawn process
            if machine is alive or False
        '''
        # TODO:
        #     - Change method name to something more descriptive
        #       and refactor testbed/ scripts
        #     - Change returned value into boolean and refactor
        #       dependent code
        check_result = False
        check_result = self.check_machine_with_ssh(machine, netconf)
        return check_result

    def check_machine_with_ssh(self, machine, netconf=False):
        # FIXME: below snippet should only verify connection with ssh
        #        and return boolean instead of pexpect process. it might
        #        require refactor in other classes to adjust to change.
        if netconf == True:
            ip_addr = self.netconf_mgmt_ipaddr(machine)
        elif netconf == False:
            ip_addr = self.mgmt_ipaddr(machine)
        cmd_bld = SSHCommandBuilder(host=ip_addr, user=self.get_ssh_username(machine), logger=self.logger)
        cmd_bld.add_kv_option('ConnectTimeout', 90)
        cmd = cmd_bld.build()
        if six.PY2:
            child1 = pexpect.spawn(cmd, timeout = 90)
        else:
            child1 = pexpect.spawn(cmd, timeout = 90,encoding='utf-8', codec_errors='ignore')

        try:
            child1.expect(['.*password:', 'Password:'] + self.get_expect_prompt_list(machine, 0))
        except (pexpect.EOF, pexpect.TIMEOUT):
            child1.close()
            return False
        return child1

    def set_machine_personality_next(self, machine, timeout=25,logfile=None):
        """Function to set the personality """
        if machine in self.machines():
            cmd_bld = SSHCommandBuilder(host=self.mgmt_ipaddr(machine), user='admin', logger=self.logger)
            cmd_bld.add_kv_option('ConnectTimeout', 20)
            cmd = cmd_bld.build()
            if six.PY2:
                child1 = pexpect.spawn(cmd, timeout = timeout)
            else:
                child1 = pexpect.spawn(cmd, timeout = timeout, encoding='utf-8', codec_errors='ignore')
            if self.debug is True:
                child1.logfile = sys.stdout
            elif logfile is not None:
                child1.logfile = logfile
            try:
                index = child1.expect(['.*password:', 'Password:'] + self.get_expect_prompt_list(machine, 0))
                if index <= 1:
                    child1.sendline(self.get_ssh_password(machine))
                    index = child1.expect(['Select device personality:'] + self.get_expect_prompt_list(machine, 1))
                    if index == 0:
                        if self.personality(machine) == 'vsmart':
                            persId = '2'
                        else:
                            persId = '1'
                        self.logger.info('Selecting device personality %s for %s' % (persId, machine))
                        child1.sendline(persId)
                        time.sleep(2)
                        child1.close()
                        return True
                    else:
                        #print 'Personality is not selected for %s, might be you took down the testbed before or its not a next image ' %(machine)
                        child1.close()
                        return False
            except (pexpect.EOF, pexpect.TIMEOUT):
                return False
        return False

    def get_ucs_machine_session(self, machine, timeout=90, logfile=None):
        wait = 0
        cmd_bld = SSHCommandBuilder(host=self.mgmt_ipaddr(machine), user='admin', logger=self.logger)
        cmd_bld.add_kv_option('ConnectTimeout', timeout)
        cmd = cmd_bld.build()
        start_time = time.time()
        less_than_max = True
        child1 = None
        while less_than_max:
            if six.PY2:
                child1 = pexpect.spawn(cmd, timeout = timeout)
            else:
                child1 = pexpect.spawn(cmd, timeout = timeout, encoding='utf-8', codec_errors='ignore')
            if self.debug is True:
                child1.logfile = sys.stdout
            elif logfile is not None:
                child1.logfile = logfile
            try:
                index = child1.expect(['.*[Pp]assword:'] + ['.*#'])
                if index <= 1:
                    child1.sendline(self.get_ssh_password(machine))
                    child1.expect(['.*#'])
                break
            except pexpect.EOF:
                less_than_max = int(time.time() - start_time) < wait
                continue
        return child1

    def get_machine_session(
        self, machine, timeout=60, logfile=None, hostname=False, wait=False, root=False, set_clock=False, ncs=False
    ):
        if not self.mgmt_ipaddr(machine):
            self.logger.warning("Machine {} doesn't have 'MGMT' interface configured".format(machine))
            return None
        if machine in self.machines():
            wait_time = 0
            if wait:
                wait_time = self.machine_boot_time(machine)
            if self.is_cedge(machine) or self.is_ucs(machine) or self.is_nfvis(machine):
                if wait:
                    self.machine_boot_wait(hard_sleep=0, max_wait=wait_time, machine_list={machine: True})

                if self.is_ucs(machine) or self.is_nfvis(machine):
                    return self.get_ucs_machine_session(machine, 90, logfile)

                return self.get_cisco_csr_session(machine, timeout, logfile)

            cmd_bld = SSHCommandBuilder(host=self.mgmt_ipaddr(machine), user='admin', logger=self.logger)
            cmd_bld.add_kv_option('ConnectTimeout', 20)
            cmd = cmd_bld.build()

            passwords = list(self.get_ssh_known_passswords(machine))

            def _try_passwords(child, prompt_list, cmd, update_on_success=True):
                if self.is_highrise(machine):
                    child.sendline(self.config['machines'][machine]['host_router']['password'])
                    idx = child.expect(['.*password:', 'Password:'] + prompt_list)
                    return idx > 1
                if not passwords:
                    pwd = self.get_ssh_password(machine)
                    child.sendline(pwd)
                    idx = child.expect(['.*password:', 'Password:'] + prompt_list)
                    if idx > 1 and update_on_success:
                        self.update_machine_config(machine, pwd)
                    return idx > 1
                for pwd in passwords:
                    child.sendline(pwd)
                    idx = child.expect(['.*password:', 'Password:'] + prompt_list)
                    if idx > 1:
                        if update_on_success:
                            self.update_machine_config(machine, pwd)
                        return True
                    print(f'{pwd=} was NOT accepted on {cmd}')
                return False

            start_time = time.time()
            less_than_max = True
            while less_than_max:
                if six.PY2:
                    child1 = pexpect.spawn(cmd, timeout=timeout)
                else:
                    child1 = pexpect.spawn(cmd, timeout = timeout, encoding='utf-8', codec_errors='ignore')
                if self.debug is True:
                    child1.logfile = sys.stdout
                elif logfile is not None:
                    child1.logfile = logfile
                try:
                    index = child1.expect(['.*password:', 'Password:'] + self.get_expect_prompt_list(machine, 0))
                    if index <= 1:
                        _try_passwords(child1, self.get_expect_prompt_list(machine, 0), cmd)
                        if self.personality(machine) == 'vmanage':
                            index = child1.expect(['Select storage device to use:'] + self.get_expect_prompt_list(machine, 1))
                            if index == 0:
                                child1.close()
                                print('Enabling third partition on vmanage')
                                res = self.enable_third_partition(machine)
                                child1 = pexpect.spawn(cmd, timeout=timeout, encoding='utf-8', codec_errors='ignore')
                                index = child1.expect(
                                    ['.*password:', 'Password:'] + self.get_expect_prompt_list(machine, 0)
                                )
                                if index <= 1:
                                    _try_passwords(child1, self.get_expect_prompt_list(machine, 1), cmd)
                        else:
                            child1.sendline()
                            index = child1.expect(['Select device personality:'] + self.get_expect_prompt_list(machine, 1))
                            if index == 0:
                                if self.personality(machine) == 'vsmart':
                                    persId = '2'
                                else:
                                    persId = '1'
                                print('Selecting device personality %s for %s' % (persId, machine))
                                child1.sendline(persId)
                                child1.expect(['The system is going down for reboot NOW!'])
                                child1.close()
                                print('Sleeping for 60 secs for the device to come up')
                                time.sleep(60)
                                if six.PY2:
                                    child1 = pexpect.spawn(cmd, timeout = timeout)
                                else:
                                    child1 = pexpect.spawn(
                                        cmd, timeout=timeout, encoding='utf-8', codec_errors='ignore'
                                    )
                                index = child1.expect(
                                    ['.*password:', 'Password:'] + self.get_expect_prompt_list(machine, 0)
                                )
                                if index <= 1:
                                    _try_passwords(child1, self.get_expect_prompt_list(machine, 1), cmd)
                    break
                except pexpect.EOF:
                    self.logger.error(f'Failed to get ssh session for {machine=}.. Retrying {cmd=}')
                    time.sleep(10)
                    less_than_max = int(time.time() - start_time) < wait_time
                    #self.logger.info('Current Time:%d start_time:%d wait:%s' %(int(time.time()),int(start_time), wait ))
                    continue
                except pexpect.TIMEOUT:
                    self.logger.error(traceback.format_exc())
                    self.logger.error(f'get_machine_session: {machine=} {passwords=}')
            if not less_than_max:
                wait_val = int(time.time() - start_time)
                self.logger.error('Could not log in to %s, please check to make sure it is not in a bad state - waited for %s sec' %(machine,wait_val) )
                self.logger.error(cmd)
                return -99
            if self.is_ucs(machine) or self.is_nfvis(machine):
                return child1
            if self.is_highrise(machine):
                return child1

            child1.sendline('idle-timeout 0')
            child1.expect(self.get_expect_prompt_list(machine, 1))
            child1.sendline('screen-width 200')
            child1.expect(self.get_expect_prompt_list(machine, 1))
            child1.sendline('paginate false')
            child1.expect(self.get_expect_prompt_list(machine, 1))
            child1.sendline('prompt2 \"\\h(\\\\t)(\\m)#\"')
            child1.expect(self.get_expect_prompt_list(machine, 1))
            if hostname == True:
                child1.sendline('config')
                child1.expect(self.get_expect_prompt_list(machine, 0))
                child1.sendline('system host-name %s' % machine)
                child1.expect(self.get_expect_prompt_list(machine, 0))
                child1.sendline('commit')
                index = child1.expect(
                    [
                        'Aborted: the configuration database is locked',
                        'No modifications to commit',
                        'Commit complete',
                        pexpect.TIMEOUT,
                    ],
                    timeout=2,
                )
                if index == 0:
                    child1.sendline('system host-name %s' % machine)
                    child1.expect(self.get_expect_prompt_list(machine, 0))
                    child1.sendline('commit')
                child1.expect(['%s.*#' % machine])
                child1.sendline('end')
                index = child1.expect([r'Uncommitted changes found, commit them\?', pexpect.TIMEOUT], timeout=2)
                if index == 0:
                    child1.sendline('no')
                    child1.expect(['%s.*#' % machine])
                    child1.sendline('end')
                    child1.expect(['%s.*#' % machine])
                else:
                    child1.expect(['%s.*#' % machine])
            if set_clock == True:
                desired_date = time.strftime('%Y-%m-%d', time.gmtime())
                desired_time = time.strftime('%H:%M:%S', time.gmtime())
                str_cmd = 'clock set date %s time %s' % (desired_date, desired_time)
                child1.sendline(str_cmd)
                child1.expect(self.get_expect_prompt_list(machine, 1))
            if root == True:
                child1.sendline('vshell')
                prompt = child1.expect(self.get_expect_prompt_list(machine, 2))
            return child1
        else:
            wait_time = 0
            cmd_bld = SSHCommandBuilder(host=self.mgmt_ipaddr(machine), user='admin', logger=self.logger)
            cmd_bld.add_kv_option('ConnectTimeout', 20)
            cmd = cmd_bld.build()
            start_time = time.time()
            less_than_max = True
            while less_than_max:
                if six.PY2:
                    child1 = pexpect.spawn(cmd, timeout = timeout)
                else:
                    child1 = pexpect.spawn(cmd, timeout = timeout, encoding='utf-8', codec_errors='ignore')
                if self.debug is True:
                    child1.logfile = sys.stdout
                elif logfile is not None:
                    child1.logfile = logfile
                try:
                    index = child1.expect(['.*password:', 'Password:'] + self.get_expect_prompt_list(machine, 0))
                    if index <= 1:
                        child1.sendline(self.get_ssh_password(machine))
                        child1.expect(self.get_expect_prompt_list(machine, 1))
                    break
                except pexpect.EOF:
                    less_than_max = int(time.time() - start_time) < wait_time
                    continue
            return child1
        return None

    def get_cisco_csr_session(self, machine, timeout, logfile=None, hostname=False, wait=False, root=False, set_clock=True, ncs=False):
        """Get the session for cisco cedge"""

        cmd_bld = SSHCommandBuilder(
            host=self.mgmt_ipaddr(machine), user=self.get_ssh_username(machine), logger=self.logger
        )
        known_passwords = list(self.get_ssh_known_passswords(machine))

        cmd_bld.add_kv_option('ConnectTimeout', 90)
        cmd = cmd_bld.build()
        start_time = time.time()
        wait_time = 0
        if wait:
            wait_time = self.machine_boot_time(machine)

        # Start SSH over pexpect only if TCP port of SSH server is responding
        less_than_max = True
        wait_time_tcp = 60
        while less_than_max:
            if check_tcp_port(self.mgmt_ipaddr(machine)):
                break
            time.sleep(5)
            less_than_max = int(time.time() - start_time) < wait_time_tcp

        less_than_max = True
        while less_than_max:
            child1 = pexpect.spawn(cmd, timeout=timeout, encoding='utf-8', codec_errors='ignore')
            if self.debug is True:
                child1.logfile = sys.stdout
            elif logfile is not None:
                child1.logfile = logfile
            try:
                self._check_auth(cmd, known_passwords, child1, machine)
                break
            except (pexpect.EOF, pexpect.TIMEOUT):
                less_than_max = int(time.time() - start_time) < wait_time
                child1.close()
                if not cmd_bld.no_multiplexing:
                    # try closing (if exists) mux socket file
                    cmd_mux = cmd_bld.build_mux_stop_cmd()
                    child = pexpect.spawn(cmd_mux, timeout=timeout, encoding='utf-8', codec_errors='ignore')
                    child.expect([cmd_bld.mux_stop_ok, cmd_bld.mux_stop_error, pexpect.EOF, pexpect.TIMEOUT])
                    child.close()
                continue

        if not child1.isalive():
            self.logger.error(f"[{machine}] get_cisco_csr_session() returns session which is not alive !")
            self.logger.error(f"Tried to spawn pexpect with cmd: {getattr(child1, 'args', 'unknown args')}")
            self.logger.error("", stack_info=True)

        return child1

    def _check_auth(self, cmd, known_passwords, child1, machine, mode=0):
        index = child1.expect([r'.*[pP]assword:'] + self.get_expect_prompt_list(machine, mode))
        if index == 0:
            passwords = known_passwords or [self.get_ssh_password(machine)]
            authed = False
            for passwd in passwords:
                child1.sendline(passwd)
                idx = child1.expect([r'.*#', r'.*[Pp]assword:'])
                if idx == 0:
                    self.update_machine_config(machine, passwd)
                    authed = True
                    break
                self.logger.debug(f'{passwd=} was NOT accepted on {cmd}')
            if authed:
                self.logger.debug(f'{passwd=} was accepted on {cmd}')
                # Set terminal dimensions equivalent to paginate false
                self.send_command_and_check_prompt(child1, "terminal length 0", r".*#")
                self.send_command_and_check_prompt(child1, "terminal width 0", r".*#")
        # case for sessions with automatical login (via SSH keys or preauthenticated SSH mux session)
        elif index > 0:
            self.send_command_and_check_prompt(child1, "terminal length 0", r".*#")
            self.send_command_and_check_prompt(child1, "terminal width 0", r".*#")


    def get_iosxe_cli_session(self, machine, pexpect_timeout, logfile, wait=False):
        """Get iosxe enable prompt"""
        cmd_bld = SSHCommandBuilder(
            host=self.mgmt_ipaddr(machine), user=self.get_ssh_username(machine), logger=self.logger
        )
        cmd_bld.add_kv_option('ConnectTimeout', 20)
        cmd_bld.add_kv_option('ServerAliveInterval', 60)
        cmd_bld.add_kv_option('ServerAliveCountMax', 20)
        cmd = cmd_bld.build()

        start_time = time.time()
        wait_time = 0
        if wait:
            wait_time = self.machine_boot_time(machine)

        # Start SSH over pexpect only if TCP port of SSH server is responding
        less_than_max = True
        wait_time_tcp = 60
        while less_than_max:
            if check_tcp_port(self.mgmt_ipaddr(machine)):
                break
            time.sleep(5)
            less_than_max = int(time.time() - start_time) < wait_time_tcp

        less_than_max = True
        last_exception = None
        known_passwords = self.get_ssh_known_passswords(machine)
        while less_than_max:
            child1 = pexpect.spawn(cmd, timeout=pexpect_timeout, encoding='utf-8', codec_errors='ignore')
            if self.debug is True:
                child1.logfile = sys.stdout
            elif logfile is not None:
                child1.logfile = logfile
            try:
                self._check_auth(cmd, known_passwords, child1, machine)
                break
            except (pexpect.EOF, pexpect.TIMEOUT) as e:
                last_exception = e
                less_than_max = int(time.time() - start_time) < wait_time
                child1.close()
                if not cmd_bld.no_multiplexing:
                    # try closing (if exists) mux socket file
                    cmd_mux = cmd_bld.build_mux_stop_cmd()
                    child = pexpect.spawn(cmd_mux, timeout=pexpect_timeout, encoding='utf-8', codec_errors='ignore')
                    child.expect([cmd_bld.mux_stop_ok, cmd_bld.mux_stop_error, pexpect.EOF, pexpect.TIMEOUT])
                    child.close()
                continue

        if not child1.isalive():
            self.logger.error(f"[{machine}] get_iosxe_cli_session() returns session which is not alive !")
            self.logger.error(f"Tried to spawn pexpect with cmd: {getattr(child1, 'args', 'unknown args')}")
            if last_exception:
                self.logger.error(f"Last exception was: {str(last_exception)}")

        return child1

    def get_all_iosxe_cli_sessions(self, logs_dir=None, log_name=None, no_init=False):
        """Get iosxe session for all iosxe devices in testbed topology"""
        sessions = {}
        cedges = list(filter(self.is_cedge, list(self.machines().keys())))
        p = []
        q = queue.Queue(len(cedges))
        for mch in cedges:
            if no_init:
                sessions[mch] = None
                continue
            confd_log = os.path.join(logs_dir, mch, '%s-%s.log' % (mch, log_name))
            logfile = open(confd_log, 'a+')
            session_args = (mch, 25, logfile)
            all_args = (self.get_iosxe_cli_session, session_args, q, mch)
            proc = Thread(target = self.call_func_as_process, args = all_args)
            proc.start()
            p.append(proc)
        if no_init:
            return sessions
        #Wait for all the threads to get done
        for proc in p:
            proc.join()
        errors = 0
        #Get the sessions from the queue
        sessions = {}
        while q.empty() == False:
            mch, session = q.get()
            if session == -99:
                self.logger.info('Could not get a session for %s' % mch)
                errors += 1
                continue
            sessions[mch] = session
            self.logger.info('Successfully added session for %s' % mch)
        #If there was a failure in creating any of the sessions stop the run
        if errors > 0:
            return -99
        return sessions

    def get_machines_by_personality(self, personality):
        """Get machines based on personality"""
        machines = []
        for machine in self.machines():
            if 'personality' in list(self.config['machines'][machine].keys()) and self.config['machines'][machine]['personality'] == personality:
                machines.append(machine)
        return machines

    def get_machine_session_args(self, mch, logs_dir=None, log_name=None,
                                 root=False, ncs=False):
        '''
        This is a helper function to :get_all_mchs_sessions: to allow
        for creation of deferred sessions.
        '''
        if ncs == True and 'vmanage' not in self.personality(mch):
            return None
        if log_name == None:
            f1 = None
        else:
            confd_log = os.path.join(logs_dir, mch, '%s-%s.log' %(mch, log_name))
            f1 = open(confd_log, 'a+')
        #Create a pexpect session in the cli and put it in the queue
        session_args = (mch, 25, f1, True, False, root, False, ncs)
        return session_args

    def get_all_mchs_sessions(self, logs_dir=None, log_name=None, root=False, ncs=False, no_init=False):
        """
        Get pexpect sessions for all the nodes the testbed topology

        @params
          - logs_dir and log_name: used to specify the log files for the expect
            sessions. Could be None in which case the sessions interacrtions are
            not logged
          - root: if true then the sessions created are root(shell) sessions,
            else they are cli sessions

        @return
          dictionary containing a session for each machien
        """
        sessions = {}
        p = []
        q = queue.Queue(len(self.machines()))
        for mch in self.machines():
            if not self.is_nonsdwan(mch):
                session_args = self.get_machine_session_args(mch, logs_dir, log_name, root, ncs)
                if not session_args:
                    continue
                if no_init:
                    sessions[mch] = None
                    continue
                all_args = (self.get_machine_session, session_args, q, mch)
                proc = Thread(target=self.call_func_as_process, args=all_args)
                proc.start()
                p.append(proc)
        if no_init:
            return sessions
        # Wait for all the threads to get done
        for proc in p:
            proc.join()
        errors = 0
        #Get the sessions from the queue
        sessions = {}
        while q.empty() == False:
            mch, session = q.get()
            if session == -99:
                self.logger.info('Could not get a session for %s' % mch)
                errors += 1
                continue
            sessions[mch] = session
            self.logger.info('Successfully added session for %s' % mch)
        #If there was a failure in creating any of the sessions stop the run
        if errors > 0:
            return -99
        return sessions

    def pause_scheduler(self, message=None, override_pause=False):
        #Don't pause limited number smoke testbeds allocated for cEdge integration tests.
        if 'smoke' in socket.gethostname():
            return
        try:
            server = pref['server']
        except KeyError:
            server = False
        try:
            no_pause = pref['no_pause']
        except KeyError:
            no_pause = False
        if no_pause:
            return
        if str(server) == 'True':
            if message is not None:
                msg = message
            else:
                msg = 'Failure on %s, -x specified' % self.workdir
            if override_pause is True:
                subprocess.call('scheduler pause True -o -t \"%s\" -e cronjob_bot@viptela.com' % msg, shell = True)
            else:
                subprocess.call('scheduler pause True -t \"%s\" -e cronjob_bot@viptela.com' % msg, shell = True)

    def powercycleapc(self, wait = 130):
        for machine in self.machines():
            if self.is_physical_machine(machine):
                if self.pocport(machine) != None:
                    cmd = os.path.join(os.getenv('HOME'), 'vtest/bin/powercycleApc') + " " +  str(self.pocport(machine))
                    subprocess.call(cmd, shell=True)
                    break
        time.sleep(wait)

    def call_wrapper(self, machine, root = False, *args):
        res = self.call(machine, *args, root = root)
        if res == 0:
            return [True, '']
        return [False, str(res)]

    def add_seperator_to_logs(self, machine, log, seperator = None):
        if seperator == None:
            seperator = '>' * 15 + '  ' + '>' * 15
        else:
            seperator = '>' * 15 + ' ' + str(seperator) + ' ' + '>' * 15
        seperator = '=' * 70 + '\n%s\n' % seperator + '=' * 70
        cmd = 'echo "%s" | tee -a /var/log/%s' % (seperator, log)
        res = self.call(machine, cmd, root = True)
        if res == 0:
            return [True, '']
        return [False, str(res)]

    def download_image(self, src, dst, retry_num=3):
        # type: (str, str, int) -> int

        dl_throttler = DownloadThrottler(self.logger, src)

        if dl_throttler.enabled:
            dl_throttler.throttle_concurrency()

        def _download():
            msg = " (with throttling)" if dl_throttler.enabled else ""
            self.logger.info("Downloading{} image from: {}".format(msg, src))
            src_protocol = src.split('://')[0]
            if src_protocol in ['ftp', 'http']:
                return self.download_with_wget(src, dst, retry_num)
            elif src_protocol == 'file':
                localpath = src.split('://')[1]
                return self.copy_image(localpath, dst)
            else:
                if src[0] == '/':
                    return self.copy_image(src, dst)
            raise ValueError("Don't know how to download {}".format(src))

        try:
            return _download()
        except ValueError as ve:
            raise ve
        finally:
            if dl_throttler.enabled:
                dl_throttler.release_lock()

    def copy_image(self, src, dst):
        # type: (str, str) -> int
        self.logger.info("Copying image from: %s to dst: %s" % (src, dst))
        resolved_src = os.path.realpath(src)
        if src != resolved_src:
            self.logger.info("Copying resolved image from: %s to dst: %s" % (resolved_src, dst))
        command = 'cp %s %s' % (src, dst)
        ret = subprocess.call(command, shell=True)
        if ret != 0:
            self.logger.warning("Copying from {} failed with code: {}".format(src, ret))
            return 1
        return 0

    def download_with_wget(self, src, dst, retry_num=3):
        # type: (str, str, int) -> int
        self.logger.info("Downloading image from: %s" % src)
        downloaded = False
        retries = 0
        while not downloaded and retries < retry_num:
            retries += 1
            # Remove previously downloaded image if any
            command = 'wget -nv %s -O %s' % (src, dst)
            if os.path.isfile(dst):
                self.logger.info('Removing file ' + dst)
                os.remove(dst)
                command = 'wget -nv %s -O %s' % (src, dst)
            elif os.path.isdir(dst):
                basename = os.path.basename(src)
                if os.path.isfile(os.path.join(dst, basename)):
                    os.remove(os.path.join(dst, basename))
                pattern = os.path.join(dst, basename + '.[0-9]*')
                for file_name in glob.glob(pattern):
                    self.logger.info('Removing file ' + file_name)
                    os.remove(file_name)
                command = 'wget -nv %s -P %s' % (src, dst)
            elif os.path.isdir(os.path.dirname(dst)):
                self.logger.info(dst + "is file that doesn't exist")
                command = 'wget -nv %s -O %s' % (src, dst)

            ret = subprocess.call(command, shell=True)
            if ret == 0:
                downloaded = True
            else:
                self.logger.warning("Download failed with code: {}".format(ret))
                time.sleep(3)
        if not downloaded:
            self.logger.error('Failed to download image: ' + src)
            return 1
        return 0

    def get_images(self, loc, branch, *args):
        for image in args:
            try:
                self.logger.info("Downloading image at: "+loc + image)
                if self.os_type == 'Linux':
                    ftp = ['wget', '-nv', loc + image]
                elif self.os_type == 'Darwin':
                    ftp = ['ftp', loc + image]
                if os.path.isfile(image):
                    os.remove(image)
                ret = subprocess.call(ftp, stdout=open(os.devnull, 'w'), stderr=open(os.devnull, 'w'))
                complete_loc = ('%s_%s' % (branch, image)).replace("/", "_")
                os.rename(image, complete_loc)
                if ret != 0:
                    return ret
            except OSError as e:
                print(str(e))
                self.logger.error('Could not find command %s' % ftp)
                return 1
        return 0

    def get_images_from_ftp_server(self, dummyvar, branch='next', device_model='vedge-1000', isReleaseImg=False,
                                   loc=None, dest_loc=None, removeFile=False,
                                   get_latest_previous_build_if_missing=False):
        image_URL = loc
        if image_URL is None:
            image_URL = get_default_device_image_location(
                isReleaseImg=isReleaseImg,
                branch=branch,
                device_model=device_model,
                logger=self.logger,
                get_latest_previous_build_if_missing=get_latest_previous_build_if_missing,
            )
        image = os.path.basename(image_URL)
        self.logger.info("Downloading image at: " + image_URL)
        download_cmd = ['wget', '-nv', image_URL]

        command_directory = os.getcwd()
        self.logger.info('Current Directory is %s', command_directory)

        if dest_loc is not None:
            image = os.path.join(dest_loc, image)
            command_directory = dest_loc

        if os.path.isfile(image):
            os.remove(image)

        if removeFile is False:
            with open(os.devnull, 'w') as DEV_NULL:
                return_code = subprocess.call(download_cmd,
                                              stdout=DEV_NULL,
                                              stderr=DEV_NULL,
                                              cwd=command_directory,
                                              )
            if return_code != 0:
                return [False, "Download command %s failed with return code %s" % (download_cmd, return_code)]

        return [True, 0]

    def get_virsh_console(self, machine):
        if six.PY2:
            pexpect_session = pexpect.spawn('virsh console {}'.format(machine), logfile=pexpect.sys.stdout, maxread=10000)
        else:
            pexpect_session = pexpect.spawn('virsh console {}'.format(machine), logfile=pexpect.sys.stdout, maxread=10000, encoding='utf-8', codec_errors='ignore')

        try:
            res = pexpect_session.expect(['Active console session exists', pexpect.TIMEOUT], timeout=2)
            if res == 0:
                self.logger.error('Console for %s is locked by other session' % machine)
                raise TestbedException('Console for %s is locked by other session' % machine)
            return pexpect_session
        except:
            return None

    def get_console_through_serial(self, machine):
        serial_dev = self.config['machines'][machine]['console']['dev']
        serial_baud = self.config['machines'][machine]['console']['baud']
        if six.PY2:
            child = pexpect.spawn('sudo picocom -b {} {}'.format(serial_baud,serial_dev), maxread=10000)
        else:
            child = pexpect.spawn('sudo picocom -b {} {}'.format(serial_baud,serial_dev), maxread=10000, encoding='utf-8', codec_errors='ignore')
        try:
            res = child.expect(['Terminal ready', 'Connection closed by foreign host'])
            if res == 1:
                self.logger.error('Console for %s is locked by other session' % machine)
                raise TestbedException('Console for %s is locked by other session' % machine)
            child.sendline('\r\n')
            res = child.expect(['Connection closed by foreign host', pexpect.TIMEOUT], timeout=3)
            if res == 0:
                self.logger.error('Console for %s is locked by other session' % machine)
                raise TestbedException('Console for %s is locked by other session' % machine)
            #self.go_to_ios_prompt(machine, child)
            #child.sendline('enable')
            #self.send_command_and_check_prompt(child, '\n', '.*\#')
            return child
        except:
            return None

    def get_console_through_telnet(self, machine):
        console_info = self.config['machines'][machine]['console']
        telnet_ip = console_info['ip']
        telnet_port = console_info['port']
        if six.PY2:
            child = pexpect.spawn('telnet {} {}'.format(telnet_ip,telnet_port),
                                  maxread=10000,
                                  logfile=self.get_log_file_for_machine(machine))
        else:
            child = pexpect.spawn('telnet {} {}'.format(telnet_ip,telnet_port),
                                  maxread=10000,
                                  logfile=self.get_log_file_for_machine(machine), encoding='utf-8', codec_errors='ignore')

        res = child.expect(['Connected to', 'Connection closed by foreign host'])
        if res == 1:
            self.logger.error('Console for %s is locked by other session' % machine)
            raise TestbedException('Console for %s is locked by other session' % machine)

        res = child.expect(['login: ', pexpect.TIMEOUT], timeout=2)
        if res == 0:
            if "user" in console_info and "password" in console_info:
                child.sendline(console_info["user"])
                child.expect("[P|p]assword:")
                child.sendline(console_info["password"])
            else:
                raise TestbedException('{}: telnet credentials are not specified in topology YAML'.format(machine))
        child.sendline('\r\n')
        res = child.expect(['Connection closed by foreign host', pexpect.TIMEOUT], timeout=3)
        if res == 0:
            self.logger.error('Console for %s is locked by other session' % machine)
            raise TestbedException('Console for %s is locked by other session' % machine)
        return child

