    def run_func_and_record_exceptions(self, func, args, d, identifier):
        try:
            res = func(*args)
        except BaseException as e:
            d[identifier] = sys.exc_info()

    def call_func_as_process(self, func, args, q, identifier = None):
        try:
            res = func(*args)
        except Exception as e:
            raise Exception(
                    '{}\nAbove exception occurred when calling {}{}'.format(
                    str(e), func.__name__, args))
        if identifier == None:
            q.put(res)
        else:
            q.put([identifier, res])

