    def dotted_to_binary(self, ip_addr):
        binary = ""
        ip_list = ip_addr.split(".")
        counter = 4
        for curr_num in ip_list:
            if curr_num != "":
                binary += self.decimal_to_binary(int(curr_num),8)
                counter -= 1
        while counter > 0:
            binary += "00000000"
            counter -= 1
        return binary


    def decimal_to_binary(self, num, digits=None):
        binary = ""
        while num > 0:
            if num & 1:
                binary = "1" + binary
            else:
                binary = "0" + binary
            num >>= 1
        if digits is not None:
            while len(binary) < digits:
                binary = "0" + binary
        if binary == "": binary = "0"
        return binary

    def binary_to_dotted(self, binary):
        ip_addr = ""
        for i in range(0,len(binary),8):
            ip_addr += str(int(binary[i:i+8],2))+"."
        return ip_addr[:-1]

    #end of copyright functions

    def dotted_to_decimal(self, ip):
        ip_bytes = ip.split('.')
        decimal = int(ip_bytes[0]) << 24
        decimal += int(ip_bytes[1]) << 16
        decimal += int(ip_bytes[2]) << 8
        decimal += int(ip_bytes[3])
        return decimal

    def get_broadcast_address(self, ip, netmask):
        """ """
        mask = self.prefixlen(netmask)
        mask = 32 - mask
        netmask = 0
        for i in range(int(mask)):
            netmask = netmask << 1
            netmask += 1
        broadcast_ip_decimal = self.dotted_to_decimal(ip) | netmask
        binary = self.decimal_to_binary(broadcast_ip_decimal, digits=32)
        return self.binary_to_dotted(binary)

    def time_string_to_secs(self, time):
        """ """
        sec = 0
        days = re.search('[0-9]*[ ]*day(s)?', time)
        if days != None:
            sec += int(days.group().split('day')[0]) * 24 * 3600
        hours = re.search('[0-9]*[ ]*h(ou)?r(s)?', time)
        if hours != None:
            if 'hour' in hours.group():
                split_string = 'hour'
            else:
                split_string = 'hr'
            sec += int(hours.group().split(split_string)[0]) * 3600
        minutes = re.search('[0-9]*[ ]*min(ute)?(s)?', time)
        if minutes != None:
            sec += int(minutes.group().split('min')[0]) * 60
        seconds = re.search('[0-9]*[ ]*sec(ond)?(s)?', time)
        if seconds != None:
            sec += int(seconds.group().split('sec')[0])
        return sec

