    def is_allhw_testbed(self):
        if ('testbed13' in socket.gethostname() and 'testbed132' not in socket.gethostname() and 'testbed133' not in socket.gethostname() and 'testbed134' not in socket.gethostname())\
            or ('testbed18' in socket.gethostname()) or ('testbed43' in socket.gethostname()) or ('testbed44' in socket.gethostname()) \
            or ('testbed51' in socket.gethostname()) or ('testbed53' in socket.gethostname()) or ('testbed54' in socket.gethostname()) :
            return True
        return False

    def get_gw_intf_ip(self, prefix):
        local_os = os.uname()[0]
        if local_os == 'Darwin':
            output = self.get_sh_output(['route', '-n', 'get', prefix])
            output = re.findall(r"[\w']+", output)
            if_out = output[output.index('interface')+1].strip()
            output = self.get_sh_output(['ifconfig', if_out])
            output = re.findall(r"[\w']+", output)
            ip_idx = output.index('inet')+1
            ip_out = '.'.join(output[ip_idx:ip_idx+4])
        elif local_os == 'Linux':
            output = self.get_sh_output(['ip', 'route', 'get', prefix])
            output = re.findall(r"[\w']+", output)
            ip_idx = output.index('src')+1
            ip_out = '.'.join(output[ip_idx:ip_idx+4])
        return ip_out

    def get_sh_output(self, cmd):
        ch = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.STDOUT)
        output, err = ch.communicate()
        return output

    def scp_files_to_vedge(self, machine, src, dst):
        """ Since multiple file transfer is no longer supported on vedge: CSCvs11282, in case a regex
            is provided in scp, we first need to get a list of all files that correspond to the regex
            and then transfer them individually.
        """
        ch = subprocess.Popen("ls "+src, shell = True, stdout=subprocess.PIPE, stderr=subprocess.STDOUT)
        output, err = ch.communicate()
        if type(output) == bytes:
            output = output.decode()
        logging.info(output)
        logging.info(err)
        files_to_be_transferred = output.split()
        self.logger.info("Copying files to %s: %s" % (machine, str(files_to_be_transferred)))
        error = ""
        for file in files_to_be_transferred:
            if len(files_to_be_transferred) > 1:
                source = src + '/' + file
            else:
                source = file
            try:
                self.copy_to_machine(machine, source, dst)
            except Exception as e:
                error = "Failed to scp file %s with error %s" %(file, str(e))
                self.logger.error(error)
                return [False, error]
        self.logger.info("Copied files succesfully to %s"%(machine))
        return [True, error]

