    def compare_list_to_var(self, list_name, comp_var):
        """This function returns True if every list item is equal to the specified variable"""
        for item in list_name:
            if item != comp_var:
                return False
        return True

    def remove_same_elements_in_list(self, list_name):
        """Function to remove same elements in the list"""
        new_list = []
        for item in list_name:
            if item not in new_list:
                new_list.append(item)
        return new_list

