    def get_images_list(self, config, specified_branch = None, diff_image_type = None):
        ## This is not the right way to do this
        ## get_images_list shoud get all params that affect config file (ex: evm, isv etc.) to return the correct list of images

        config = self.get_config(config)
        self.load_config(config)
        self.config = config_utils.setup(self.config)
        if specified_branch != None:
            self.branch = specified_branch
        else:
            self.branch = self.default_branch()
        all_images = []
        for machine in self.machines():
            image = self.machines_image(machine)
            image = re.sub('latest', 'local', image)
            images_dir = pref['images_dir']
            machine_type = self.images_type(machine, image)
            all_images.append(self.images_file(machine, image, diff_image_type))
        self.logger.info(','.join(set(all_images)))
        self.logger.info(pref['images_dir'])
        return 0

    def print_ssh_cmd_err(self, stderr):
        try:
            err = stderr.read()
            stderr.close()
            if len(err.strip()) > 0:
                self.logger.error(err)
                return 1
            return 0
        except IOError:
            return 0

