    def get_passwd(self, machine):
        if self.personality(machine) != 'vmanage':
            self.logger.warning('You tried to gain root access. Please review your code')
            return ''
        new = not self.state.get('old', True)
        if '.999' in self.get_machine_branch(machine):
            return 'NHdsa3hnZG82dA==\n'
        elif any(x in self.get_machine_branch(machine) for x in ['16.1R', '16.1.']):
            return 'IWQzbnQhdHkkQUYj\n'
        elif '-' in self.get_machine_branch(machine):
            return 'NHdsa3hnZG82dA==\n'
        elif any(x in self.get_machine_branch(machine) for x in ['16.2R', '16.2.']):
            return 'azN5JDNjNHIj\n'
        elif any(x in self.get_machine_branch(machine) for x in ['16.3R', '16.3.']):
            return 'V2kkbVlVJDg/\n'
        elif any(x in self.get_machine_branch(machine) for x in ['17.1R', '17.1.']):
            return 'U0VDdVIjcyVEV0FuMTc=\n'
        elif any(x in self.get_machine_branch(machine) for x in ['17.2R', '17.2.']):
            return 'IVNkV2FuSyFsbGVyIzE=\n'
        elif any(x in self.get_machine_branch(machine) for x in ['18.2R', '18.2.']):
            return 'RXUwaCFhdEAkMTg=\n'
        elif any(x in self.get_machine_branch(machine) for x in ['18.3R', '18.3.']):
            return 'MSRhTkw4Z2FjJjA3\n'
        else:
            return 'NHdsa3hnZG82dA==\n'

    def set_machine_state(self, machine, state):
        if float(self.state['ver']) >= 1.2:
            self.state['machines'][machine]['state'] = state

    def dump_tb_state(self):
        if self.lock.locked():
            print("Owner: {}\nTestbed: {}\nSince {}\n".format(self.lock.owner, self.lock.testbed, self.lock.date))

        print('')
        if float(self.state['ver']) >= 1.2:
            for machine in self.state['machines']:
                print('%s state: %s' % (machine, self.state['machines'][machine]['state']))
            print('')

    def dump_tb_state_detail(self, filters):
        if self.lock.locked():
            print("Owner: {}\nTestbed: {}\nSince {}\n".format(self.lock.owner, self.lock.testbed, self.lock.date))

        machines_table = []
        with spinner.SpinnerThread():
            try:
                for machine in filter(self.filter_machine(filters),
                                      self.machines(types=['vm','pm','container'], include_vcontainer=True)):
                    time.sleep(0.4) #added for keyboardinterrupt
                    machine_state = 'down'
                    vers = ''
                    uptime = ''
                    crash = ''
                    processes = cpu = memory = device = ssh = ''
                    if self.machine_is_up(machine):
                        [success, session] = self.get_paramiko_session(self.mgmt_ipaddr(machine), self.get_ssh_username(machine), base64.encodestring(self.get_ssh_password(machine)))
                        if success:
                            try:
                                channel = session.invoke_shell()
                                time.sleep(1)
                                if self.cli_came_up(channel):
                                    machine_state = 'up'
                                    vers = self.get_machine_version(channel)
                                    uptime = self.get_machine_uptime(channel)
                                    crash = self.get_crash_info(channel)
                                    processes, cpu, memory, device = self.get_system_status(channel)
                                    ssh = self.get_num_ssh_session(channel)
                                else:
                                    processes = cpu = memory = device = ssh = ''
                            finally:
                                channel.close()
                                session.close()
                        else:
                            crash = session
                    machines_table.append({'name':machine, 'state':machine_state, 'uptime':uptime, 'crash':crash,\
                                           'image':vers, 'memory_used': memory, 'system_cpu': cpu, 'num_processes': processes,\
                                           'device_type': device, 'ssh': ssh})
                self.draw_machines_table(machines_table)
            except KeyboardInterrupt:
                pass

    def draw_machines_table(self, machines_table):
        table_row = '|{:^7}|{:^7}|{:^24}|{:^24}|{:^30}|{:^9}|{:^9}|{:^10}|{:^5}|{:^14}|'
        row_delim = '+{0:-^7}+{0:-^7}+{0:-^24}+{0:-^24}+{0:-^30}+{0:-^9}+{0:-^9}+{0:-^10}+{0:-^5}+{0:-^14}+'.format('')
        print(row_delim)
        print(table_row.format('Name', 'State', 'UpTime', 'Crash', 'Image', 'MemUsed', 'SysCPU', 'NumProc', 'ssh','Device'))
        print(row_delim)
        for row in machines_table:
            print(table_row.format(row['name'], row['state'], row['uptime'], row['crash'], row['image'],\
                row['memory_used'], row['system_cpu'], row['num_processes'] ,row['ssh'], row['device_type']))
            print(row_delim)

    def get_crash_info(self, channel):
        crash = None
        try:
            channel.sendall('show crash\n')
            resp = ''
            while not resp.endswith('# '):
                resp += channel.recv(9999)
            if 'No entries' in resp.split('\n')[1]:
                crash = resp.split('\n')[1].strip()
            else:
                crash = '{} core files'.format(len(resp.split('\n')) - 6)
        finally:
            return crash

    def get_machine_uptime(self, channel):
        uptime = None
        resp = ''
        try:
            channel.sendall('show uptime\n')
            resp = ''
            while not resp.endswith('# '):
                resp += channel.recv(9999)
            uptime = resp.split('\n')[-2].split(',')[0].strip()
        finally:
            return uptime

    def get_machine_version(self, channel):
        version = None
        try:
            channel.sendall('show version\n')
            resp = ''
            while not resp.endswith('# '):
                resp += channel.recv(9999)
            version = resp.split('\n')[-2].strip()
        finally:
            return version

    def get_system_status(self, channel):
        memory, cpu, device, processes = None, None, None, None
        try:
            channel.sendall('screen-length 80\n')
            resp = ''
            while not resp.endswith('# '):
                resp += channel.recv(9999)
            channel.sendall('show system status\n')
            resp = ''
            while not resp.endswith('# '):
                resp += channel.recv(9999)
            processes, cpu, memory, device = self.get_system_status_info(resp)
        finally:
            return (processes, '{}%'.format(cpu), '{:.4}%'.format(memory), device)

    def get_system_status_info(self, output):
        """ Get required info from system status output """
        processes, cpu, memory, device = None, None, None, None
        for line in output.lower().split('\n'):
            if 'processes' in line:
                match = re.search(r'processes: *([0-9.]+) \w+', line)
                if match != None:
                    processes = match.groups()[0]
            elif 'cpu states' in line:
                match = re.search(r'cpu states: *([0-9.]+)% \w+, *([0-9.]+)% \w+, *([0-9.]+)% \w+', line)
                if match != None:
                    user, system, idle = match.groups()
                    cpu = system
            elif 'memory usage' in line:
                match = re.search(r'memory usage: *([0-9]+)k \w+, *([0-9]+)k \w+, *([0-9]+)k \w+', line)
                if match != None:
                    total, used, free = match.groups()
                    memory = (old_div(float(used),float(total)))*100.0
            elif 'model name' in line:
                match = re.search('model name: *([a-z0-9-]+)', line)
                if match != None:
                    device = match.groups()[0]
        return (processes, cpu, memory, device)

    def get_num_ssh_session(self, channel):
        ssh = None
        try:
            channel.sendall('request execute pgrep ssh | count \n')
            resp = ''
            while not resp.endswith('# '):
                resp += channel.recv(9999)
            ssh = resp.split(":")[-1].split()[0]
        finally:
            return ssh

    def cli_came_up(self, channel):
        responce = False
        try:
            time.sleep(0.2)
            if channel.recv_ready():
                resp = channel.recv(9999)
                if ('# ' in resp) or ('$ ' in resp) or ('connected' in resp):
                    responce = True
        finally:
            return responce

    def get_ssh_session(self, machine):
        session = None
        if machine in self.machines(types=['vm', 'pm', 'container'], include_vcontainer=True):
            cmd_bld = SSHCommandBuilder(host=self.mgmt_ipaddr(machine), user='admin', logger=self.logger)
            cmd_bld.add_kv_option('ConnectTimeout', 20)
            cmd = cmd_bld.build()
            if six.PY2:
                session = pexpect.spawn(cmd, logfile=self.get_log_file_for_machine(machine))
            else:
                session = pexpect.spawn(cmd, logfile=self.get_log_file_for_machine(machine), encoding='utf-8', codec_errors='ignore')
        return session

    def machine_is_up(self, machine):
        if machine in self.machines(types=['pm', 'container'], include_vcontainer=True):
            return self.pm_is_up(machine)
        elif machine in self.machines(types=['vm'], include_vcontainer=True):
            return self.vm_is_up(machine)

    def pm_is_up(self, machine):
        return self.state['machines'][machine]['state'] == 'up'

    # Should be overriden by child classes
    def vm_is_up(self, machine):
        return self.state['machines'][machine]['state'] == 'up'

    def config_common_name_on_local_signing_server(self, machine, timeout = 25, host_name='viptela.testbed'):
        username = self.get_ssh_username(machine)
        password = self.get_ssh_password(machine)
        EXCEPTIONS = [pexpect.EOF, pexpect.TIMEOUT]
        cmd_bld = SSHCommandBuilder(host=self.mgmt_ipaddr(machine), user=username, logger=self.logger)
        cmd_bld.add_kv_option('ConnectTimeout', 20)
        cmd = cmd_bld.build()
        if six.PY2:
            child = pexpect.spawn(cmd, timeout = int(timeout))
        else:
            child = pexpect.spawn(cmd, timeout = int(timeout), encoding='utf-8', codec_errors='ignore')
        l = ['.*password:', 'Password:'] + self.get_expect_prompt_list(machine, 1) + EXCEPTIONS
        index = child.expect(l)
        if index <= 1:
            child.sendline(password)
            l = self.get_expect_prompt_list(machine, 1) + EXCEPTIONS
            index = child.expect(l)
            if index >= len(l) - 2:
                child.close()
                if index == len(l) - 1:
                    return [False, 'Error: incorrect password!']
                else:
                    return [False, 'Error: EOF after enter Password %s to login to %s with Username %s' % (password, machine_ip, username)]
        elif index >= len(l) - 2:
            child.close()
            if index == len(l) - 1:
                return [False, 'Error: unmatched pattern! Failed to ssh to %s with Username %s Password %s' % (machine_ip, username, password)]
            else:
                return [False, 'Error: EOF! Failed to ssh to %s with Username %s Password %s' % (machine_ip, username, password)]

        cmd_list = ['config', 'vpn 0 host %s ip 10.0.1.1' %host_name, 'commit']
        for cmd in cmd_list:
            l = self.get_expect_prompt_list(machine, 0) + EXCEPTIONS
            child.sendline(cmd)
            index = child.expect(l)
            if index >= len(l) - 2:
                child.close()
                if index == len(l) - 1:
                    return [False, 'Error: unmatched pattern while executing command %s' % cmd]
                else:
                    return [False, 'Error: EOF while executing command %s' % cmd]
        return [True, 'Successfully configured host name to "viptela.testbed"']

    def install_rootca(self):
        """Installs root-ca on all devices """
        sessions = {'confd': {}, 'root': {}}
        machines = []
        cert_serial_num_dict = {}
        root_ca_path = os.path.join(self.workdir)
        vmanage_path = os.path.join(root_ca_path,'vmanage_root_ca')
        vmanage_cert_chain_path = os.path.join(vmanage_path, "cacert.pem")

        if not os.path.exists(vmanage_path):
            os.makedirs(vmanage_path)
            self.logger.info("Created ->"+vmanage_path)
        else :
            self.logger.info("Exists ->" +vmanage_path)
        for machine in self.machines():
            machines.append(machine)
            logfile = self.get_log_file_for_machine(machine)
            if self.debug is True:
                logfile = sys.stdout
            confd_session = self.get_machine_session(machine, 25, logfile)
            if confd_session != -99:
                sessions['confd'][machine] = confd_session
            else:
                for machine in sessions['confd']:
                    sessions['confd'][machine].close()
                    if sessions['confd'][machine].logfile != sys.stdout:
                        sessions['confd'][machine].logfile.close()
                return 1
            root_session = self.get_machine_session(machine, 25, logfile, False, False, True)
            if root_session != -99:
                sessions['root'][machine] = root_session
            else:
                for machine in sessions['root']:
                    sessions['root'][machine].close()
                    if sessions['root'][machine].logfile != sys.stdout:
                        sessions['root'][machine].logfile.close()
                return 1
        confd = CONFDSession(self, sessions, self.logger)
        vs = ViptelaSession(self, None, self.logger, confd, False, False, None, None)
        cert = Cert(self, confd, vs)
        '''
        for mch_id in machines:
            if self.personality(mch_id) == 'vmanage':
                rep = self.create_certificate_url_vmanage(mch_id)
                time.sleep(10)
                val = confd.request_nms_start(mch_id)
                if val[0]:
                    self.logger.info('NMS restarted on vmanage')
                else :
                    self.logger.info('NMS restart failed , Aborting testbed bringup!!!!')
                    self.logger.info(val[-1])
                    return False
        '''

        self.populate_default_lists()
        self.populate_gui_lists()
        vmanage_device_list = []
        for mch_id in machines:
            # We are not suppose to do certs on software vEdges. This is the
            # default behavior. Today we still do certs on Hw machines , We
            # keep it that way for backward compatability.
            res = cert.install_root_ca_on_machine(cert_serial_num_dict,
                    mch_id)
        # Gui_certs parts for Diansan
        cert_serial_num_dict = {}
        for machine in self.gui_vedge_list:
            return_str = cert.cert_generate_and_sign_vedge_certs(cert_serial_num_dict, machine, gui = True)
        self.testbed_vmanage_master_cert_creation(vmanage_device_list)
        return True

    def create_certificate_url_vmanage(self, mch):
        result = [True, '']
        script_loc = os.path.abspath(os.path.join(os.path.dirname( __file__ ), '../'))
        root_ca_path = os.path.join(self.workdir)
        vmanage_path = os.path.join(root_ca_path,'vmanage_root_ca')
        webapp = '/opt/web-app/webapps/'
        root_ca = '/opt/data/root_ca/'
        newcerts = root_ca+'newcerts'
        private = root_ca+'private'
        config_file_path = script_loc +'/tools/certificate/openssl.cnf'
        cert_war = script_loc +'/tools/certificate/certificate.war'
        cert_xml = script_loc +'/tools/certificate/certificate.xml'
        create_root_ca = 'openssl req -new -x509 -extensions v3_ca -keyout /opt/data/root_ca/private/cakey.pem -out /opt/data/root_ca/cacert.pem -days 3650 -config /opt/data/root_ca/openssl.cnf -subj "/C=US/ST=California/L=San Jose/OU=vIPtela Test/O=vIPtela Inc/emailAddress=santosh@viptela.com" -passout pass:f3rrar1'
        vmanage_ca_cert = root_ca+'cacert.pem'
        vmanage_private_key_path = os.path.join(private, "cakey.pem")

        #Create root ca directory structure on vmanage
        resp = self.execute_shell_cmd(mch, 'mkdir %s'% root_ca)
        if resp[0]:
            self.execute_shell_cmd(mch, 'mkdir %s'% newcerts)
            self.execute_shell_cmd(mch, 'mkdir %s'% private)
            self.execute_shell_cmd(mch, 'touch /opt/data/root_ca/index.txt')
            self.execute_shell_cmd(mch, 'chmod 777 %s'% root_ca)
            self.execute_shell_cmd(mch, 'chmod 777 %s'% newcerts)
            self.execute_shell_cmd(mch, 'echo \'12345601\' > /opt/data/root_ca/serial')
        #scp openssl file to vmanage
        self.scp_from_machine(mch, config_file_path, root_ca, to_machine=True)
        #scp cert_war file to vmanage
        self.scp_from_machine(mch, cert_war, webapp, to_machine=True)
        #scp cert_xml file to vmanage
        self.scp_from_machine(mch, cert_xml, webapp, to_machine=True)
        #Create root_ca and private key
        self.execute_shell_cmd(mch, create_root_ca)
        self.scp_from_machine(mch, vmanage_private_key_path, vmanage_path)
        res = self.scp_from_machine(mch, vmanage_ca_cert, vmanage_path)
        return res

    def start_ca_server(self, mch):
        root_ca_path = os.path.join(self.workdir,'root_ca')
        script_loc = os.path.abspath(os.path.join(os.path.dirname( __file__ ), '../'))
        ca_server_path = os.path.join(script_loc ,'tools/ca_server')
        os.chdir(ca_server_path)
        self.server = CAServer()
        self.server.start_server(root_ca_path, ca_server_path)
        #subprocess.Popen(['./ca_server', root_ca_path])
        return [True,'']

    def stop_ca_server(self, mch):
        '''Stops the ca server'''
        self.server.stop_server()
        return [True,'']

    def parse_file(self, mch, file1, file2):

        root_ca_path = os.path.join(self.workdir,'root_ca')
        vmanage_serial_file = os.path.join(root_ca_path,'vmanage_vedge_serial')
        fv = open(file1, 'w')
        fi = open(file2, 'w')
        i = 0
        with open(vmanage_serial_file) as f:
            for line in f:
                if i < 3:
                    fv.write(line)
                    i += 1
                else :
                    fi.write(line)
                    i += 1
        fv.close()
        fi.close()
        return [True,'']

    def increment_date(self, date, months=None , inc_days=None):
        import datetime, calendar
        from calendar import monthrange
        if months != None:
            for i in range (0, months):
                days = calendar.monthrange(date.year, date.month)[1]
                date =  date + datetime.timedelta(days=days)
        if inc_days != None :
            date = date + datetime.timedelta(inc_days)
        return date

    def scp_from_server(self, machine, dst_ip, local_path, remote_dst_path, username, passwd):
        '''Scp file to server'''
        #NOTE : please include desination file name in destination path
        ssh_session = self.get_paramiko_session(dst_ip,username,passwd)
        if ssh_session[0] == False:
            return [False, 'Error : %s' % ssh_session[1]]
        else:
            try:
                ftp = ssh_session[1].open_sftp()
                ftp.get(remote_dst_path, local_path)
            except Exception as e:
                print('*** Caught exception: %s: %s' % (e.__class__, e))
                return [False , 'Exception in scp ']
        ftp.close()
        return [True, 'scp Pass']

    def scp_to_server(self, machine, dst_ip, src_path, dst_path, username, passwd):
        '''Scp file to server'''
        #NOTE : please include desination file name in destination path
        ssh_session = self.get_paramiko_session(dst_ip,username,passwd)
        if ssh_session[0] == False:
            return [False, 'Error : %s' % ssh_session[1]]
        else:
            try:
                ftp = ssh_session[1].open_sftp()
                ftp.put(src_path, dst_path)
            except Exception as e:
                print('*** Caught exception: %s: %s' % (e.__class__, e))
                return [False , 'Exception in scp ']
        ftp.close()
        return [True, 'scp Pass']

    def select_disk_option(self, machine, username, password, disk_name='hdb', format_disk=False ,timeout = 25):
        '''Selects disc option when third partition is present and also handles disk format option'''
        cmd_bld = SSHCommandBuilder(
            host=self.mgmt_ipaddr(machine), user=username, logger=self.logger, no_multiplexing=True
        )
        cmd_bld.add_kv_option('ConnectTimeout', 20)
        cmd = cmd_bld.build()
        logfile = None
        if six.PY2:
            child1 = pexpect.spawn(cmd, timeout = int(timeout))
        else:
            child1 = pexpect.spawn(cmd, timeout = int(timeout), encoding='utf-8', codec_errors='ignore')
        if self.debug is True:
            child1.logfile = sys.stdout
        else:
            child1.logfile = self.get_log_file_for_machine(machine)
        try:
            child1.expect(['.*password:', 'Password:'])
            child1.sendline(password)
            child1.expect(['Select storage device to use:'])
            if 'hdb' in child1.before and (disk_name =='hdb'):
                self.logger.info('3rd partition found %s' % child1.before)
                child1.sendline('1')
            else:
                child1.sendline('2')
            child1.expect(['Would you like to format'])
            if format_disk:
                child1.sendline('y')
            else:
                child1.sendline('n')
            child1.expect(['The system is going down for reboot NOW!'])
        except (pexpect.EOF, pexpect.TIMEOUT):
            return [False, 'Exception Raised in Pexpect !!!']
        finally:
            if logfile is not None and logfile != sys.stdout:
                logfile.close()
            child1.close()
        return [True, 'Partition selected']

    def copy_rsa_file_to_home_directory(self, machine, username, password, timeout = 25):
        cmd_bld = SSHCommandBuilder(
            host=self.mgmt_ipaddr(machine), user=username, logger=self.logger, no_multiplexing=True
        )
        cmd_bld.add_kv_option('ConnectTimeout', 20)
        cmd = cmd_bld.build()
        logfile = None
        if six.PY2:
            child = pexpect.spawn(cmd, timeout = int(timeout))
        else:
            child = pexpect.spawn(cmd, timeout = int(timeout), encoding='utf-8', codec_errors='ignore')
        logfile = None
        child.logfile = self.get_log_file_for_machine(machine)
        if self.debug is True:
            child.logfile = sys.stdout
        try:
            child.expect(['.*password:', 'Password:'])
            child.sendline(password)
            child.expect(self.get_expect_prompt_list(machine, 0))
            child.sendline('vshell')
            child.expect(self.get_expect_prompt_list(machine, 2))
            child.sendline('mount /altroot/')
            child.expect(self.get_expect_prompt_list(machine, 3))
            child.sendline('cp -r /altroot/home/admin/.ssh .')
            child.expect(self.get_expect_prompt_list(machine, 3))
        except pexpect.TIMEOUT:
            return [False, 'Could not copy: %s' % machine]
        except pexpect.EOF:
            return [False, '%s' % machine]
        finally:
            if logfile is not None and logfile != sys.stdout:
                logfile.close()
            child.close()
        return [True, '']

