    def resolve_ubuntu_path(self):
        try:
            ubuntu_vm = re.sub('~', '$HOME', pref['ubuntu_vm'])
            ubuntu_vm = os.path.expandvars(ubuntu_vm)
            pref['ubuntu_vm'] = os.path.realpath(ubuntu_vm)
        except KeyError:
            pass

    def machine_number(self, vm):
        last_ip_octet = int(self.mgmt_ipaddr(vm).split('.')[-1])
        return str(last_ip_octet)

    def generate_kvm_mac(self):
        # Start with a locally administered MAC address
        mac = [
            0x52,
            0x54,
            0x00,  # Common prefix for KVM/QEMU
            random.randint(0x00, 0x7F),  # Ensure the locally administered bit is set
            random.randint(0x00, 0xFF),
            random.randint(0x00, 0xFF),
        ]

        # Format the MAC address as a string, python2 compatible
        # mac_address = ':'.join(f'{octet:02x}' for octet in mac)
        mac_address = ':'.join(['%02x' % octet for octet in mac])
        return mac_address

    def mgmt_mac(self, machine):
        if self.is_nfvis(machine):
            interfaces = self.config['machines'][machine]['interfaces']
            return interfaces['MGMT']['mac']
        # VM name is not common name vmxx
        if self.is_cloud_init() and (not re.match(r"vm\d+", machine)):
            return self.generate_kvm_mac()
        if self.is_virtual_machine(machine):
            num = self.machine_number(machine)
            num = hex(int(num))[2:]
            return '00:50:56:00:01:%s' % num.zfill(2)

        # Provide random mac instead of None
        return self.generate_kvm_mac()

    def patch_version(self, readme):
        f = open(readme, 'r')
        content = f.read()
        f.close()
        content = content.split('\n')
        content.pop(0)
        for line in content:
            if len(line) > 0:
                key, value = line.split('base:')
                return value.strip()
        return []

    def compare_versions(self, files, patch_versions):
        outome = True
        for machine in files:
            tar = files[machine]
            tar = tar.replace('_', '').replace('-', '').upper()
            try:
                ver1 = patch_versions[tar]
                machine_version = os.path.join(self.workdir, machine, files[machine], 'etc', 'version')
                f = open(machine_version, 'r')
                mch_ver = f.read().strip()
                if ver1 not in mch_ver:
                    self.logger.info('Patch version does not match image version %s' % machine)
                    self.logger.info('Patch version: %s' % ver1)
                    self.logger.info('Image version: %s' % mch_ver)
                f.close()
            except KeyError:
                self.logger.info('Could not find version number for %s' % machine)
                return False
        return True

    def unpatch_machine(self, machine):
        self.logger.info('Unpatching %s' % machine)
        session = self.get_machine_session(machine, 90)
        if session == -99:
            return 1
        confd = CONFDSession(self, {'confd': {machine: session}}, self.logger)
        try:
            res = confd.request_internal_software_unpatch(machine)
            if res[0] == False:
                self.logger.error('Could not unpatch %s. Error: %s' % (machine, res[1]))
                return 1
        except pexpect.TIMEOUT:
            pass
        session.close()

    def unpatch(self, machines, mach_types):
        machines_list = []
        if machines != None:
            machines_list = machines
        else:
            for tp in mach_types:
                for machine in self.machines():
                    if self.images_type(machine, self.machines_image(machine)) == tp:
                        machines_list.append(machine)
        for machine in machines_list:
            self.unpatch_machine(machine)

    def get_patch_full_version(self, patch_path):
        rand_folder_name = ''.join(random.sample(string.ascii_letters, 8))
        temp_dir = os.path.join('/tmp', rand_folder_name)
        try:
            os.mkdir(temp_dir)
            subprocess.call(['unzip', '-q', patch_path, '-d', temp_dir])
            patch_version_file = os.path.join(temp_dir, "patch_version")
            if os.path.isfile(patch_version_file):
                with open(patch_version_file, 'r') as f:
                    version = f.readline().strip()
                    return version
        except Exception as ex:
            self.logger.error(ex)
            return None
        finally:
            shutil.rmtree(temp_dir)

    def apply_patch(self, machine, url, failed_queue):
        local_dir = "/tmp/patch_%d.zip" % time.time()
        self.scp_from_machine(machine, url, local_dir, True, False, True, expect_timeout=200)
        session = self.get_machine_session(machine, 90)
        if session == -99:
            return 1
        confd = CONFDSession(self, {'confd': {machine: session}}, self.logger)
        try:
            res = confd.create_files_for_signed_image(machine)
            if False in res:
                self.logger.error("Creating required files for patching failed on - %s" % machine)
                failed_queue.put(machine)
                return 1
            print('%s: Starting patch process at %d ' % (machine, time.time()))
            res = confd.request_internal_software_patch(machine, local_dir)
            if res[0] == False:
                self.logger.error('Could not apply patch on %s. Error: %s' % (machine, res[1]))
                failed_queue.put(machine)
                return 1
        except pexpect.TIMEOUT:
            print('%s: patch process errored out at %d ' % (machine, time.time()))
            self.logger.error('Could not apply patch on %s. Error: pexpect timedout' % (machine))
            failed_queue.put(machine)
            return 1
        print('%s: patch process completed at %d ' % (machine, time.time()))
        session.close()
        self.logger.warning('Successfully applied patch to %s' % machine)
        root_ca_path = os.path.join(self.workdir, "root_ca/")
        cert_chain_path = os.path.join(root_ca_path, "cacert.pem")
        time.sleep(75)
        self.machine_boot_wait(machine_list={machine: True})
        time.sleep(10)
        session = self.get_machine_session(machine, 25, wait = True)
        #self.scp_from_machine(machine, cert_chain_path, "/home/admin/", True, False, True)
        if session == -99:
            failed_queue.put(machine)
            self.logger.error('Could not get a session to %s after applying the patch' % machine)
            return 1
        elif session is not None:
            confd = CONFDSession(self, {'confd': {machine: session}}, self.logger)
            patch_version = self.get_patch_full_version(url).replace('  ', ' ')
            machine_version = confd.show_version(machine, False)[1].replace('  ', ' ')
            if patch_version != machine_version:
                failed_queue.put(machine)
                self.logger.info("{}: version {} doesnt match patch version: {}".format(machine, machine_version, patch_version))
                return 1

        confd.sessions[machine] = session
        """
        #Root ca installation is take care by patch script. Commenting out this code
        res = confd.install_root_ca(machine, "/home/admin/cacert.pem")
        if res[1] == False:
            self.logger.error('Could not install the root ca-cert chain on %s. Error: %s' % (machine, res[1]))
            session.close()
            return 1
        self.logger.info('Installed Root CA cert on %s' % machine)
        """
        session.close()
        return 0

    def patch(self, patch_files, machines, mach_type, existing, remote = None,
            overwrite = False, yaml = None, exclude_vmanage=False,
            include_hdp=False, include_vs3=False, include_sec_vb23=False,
            include_vs4=False, include_scaling_vmanage=False, include_vs20
            =False, include_scaling_vmanage6=False, include_tlocExt_gre=False):
        if existing:
            self.verify('up')
        if yaml == None:
            config = 'default'
        else:
            config = yaml
        if remote != None:
            patch_files = {}
            initial_zip = os.path.join(os.getenv("HOME"), 'images', remote)
            subprocess.call(['unzip', '-q', initial_zip, '-d', pref['images_dir']])
            complete_zip = os.path.join(pref['images_dir'] , remote)
            if os.path.exists(os.path.join(complete_zip[:-4], 'config.yaml')):
                config = os.path.join(complete_zip[:-4], 'config.yaml')
            regular = os.path.join(complete_zip[:-4], 'patch.zip')
            if os.path.exists(regular):
                patch_files['regular'] = regular
            vmanage_patch = os.path.join(complete_zip[:-4], 'patch_vmanage.zip')
            if os.path.exists(vmanage_patch):
                patch_files['vmanage'] = vmanage_patch
        patch_tar = 'sysroot-%s.tar.gz'
        tar_name_specified = False
        files = {}
        done = []
        temp_dir = os.path.join(self.workdir, 'patch')
        versions = set()
        self.logger.info("Patch files: {}".format(patch_files))
        for patch_file in list(patch_files.values()):
            self.logger.info("Extracting {}".format(patch_file))
            self.sudo(['unzip', '-q', patch_file, 'README', '-d', pref['testbeds_dir']])
            versions.add(self.patch_version(os.path.join(pref['testbeds_dir'], 'README')))
            self.sudo(['rm', os.path.join(pref['testbeds_dir'], 'README')])
        if len(versions) > 1:
            self.logger.error("The versions of the patches do not match: %s" % versions)
            return 1
        version, build_no = parse_version(versions.pop())
        self.logger.info("Base Image for patch is %s - %s" % (version, build_no))
        branch = '.'.join(version.split('.')[:2])
        if existing == False:
            self.logger.info("Using branch: {} to bring-up testbed".format(branch))
            if build_no == None:
                image = 'LATEST'
            else:
                image = build_no
            start_time = time.time()
            ret = self.create(config, image, overwrite, None, branch, exclude_vmanage=exclude_vmanage, include_hdp=include_hdp, include_vs3=include_vs3, include_sec_vb23=include_sec_vb23, include_vs4=False, include_tlocExt_gre=include_tlocExt_gre)
            self.logger.info('Time taken to create testbed: %s' % str(datetime.timedelta(seconds=(int(time.time()) - int(start_time)))))
            if ret != 0:
                self.logger.error('Could not create the base testbed')
                return ret
            start_time = time.time()
            ret = self.bringup()
            self.logger.info('Time taken to bringup testbed: %s' % str(datetime.timedelta(seconds=(int(time.time()) - int(start_time)))))
            if ret != 0:
                self.logger.error('Could not bringup testbed')
                return ret
        self.logger.info('Applying patch')
        try:
            os.mkdir(temp_dir)
        except OSError as err:
            if 'File exists' in str(err):
                pass
            else:
                if existing == False:
                    start_time = time.time()
                    self.destroy(self.workdir)
                    self.logger.info('Time taken to destroy testbed: %s' % str(datetime.timedelta(seconds=(int(time.time()) - int(start_time)))))
                if remote != None:
                    self.remove_dir(complete_zip[:-4])
                raise OSError(err)
        for patch_file in list(patch_files.values()):
            shutil.copy(patch_file, temp_dir)
        vmanage_machine = None
        if machines != None:
            machines_list = machines
        else:
            machines_list = []
            for item in mach_type:
                for each in self.machines():
                    if self.personality(each) == 'vmanage':
                        vmanage_machine = each
                    elif self.machine_branch(each) not in branch:
                        # Added to handle backward compatibility for vEdge5k testbeds
                        # If testbed branch != machine branch (from topology yaml),
                        # Skip patch for that machine
                        self.logger.info("Skipping patch on %s. Yaml says it can only run on %s" % (each, self.machine_branch(each)))
                        pass
                    else:
                        if item == self.images_type(each, self.machines_image(each)):
                            machines_list.append(each)
        failed_machines = multiprocessing.Queue()
        try:
            threads = []
            patch_file = patch_files.get('regular', None)
            if patch_file:
                is_first_vm = True
                for machine in machines_list:
                    if 'vm' in machine:
                        if not is_first_vm:
                            self.logger.info("Waiting 20 sec before starting patch on next machine")
                            time.sleep(20)
                        is_first_vm = False
                    machine_type = self.images_type(machine, self.machines_image(machine))
                    subnet = self.mgmt_subnet(machine)
                    thread = threading.Thread(None, self.apply_patch, args = (machine, patch_file, failed_machines))
                    threads.append(thread)
                    thread.start()

            patch_file = patch_files.get('vmanage', None)
            if vmanage_machine != None and patch_file:
                machine_type = self.images_type(vmanage_machine, self.machines_image(vmanage_machine))
                subnet = self.mgmt_subnet(vmanage_machine)
                thread = threading.Thread(None, self.apply_patch, args = (vmanage_machine, patch_file, failed_machines))
                threads.append(thread)
                thread.start()

            for thread in threads:
                thread.join()
        except KeyboardInterrupt:
            pass
        finally:
            if failed_machines.empty():
                self.logger.info("Patching completed")
            else:
                raise PatchException("Failed to apply patch {}".format(failed_machines.get()))
        if remote != None:
            self.remove_dir(complete_zip[:-4])
        return 0

    def nfs_server(self, action):
        if self.os_type == 'Linux':
            self.sudo(['service', 'nfs-kernel-server', action], redirect = True)
        elif self.os_type == 'Darwin':
            if action == 'start':
                action = 'enable'
            elif action == 'stop':
                action = 'disable'
            self.sudo(['nfsd', action])
        self.logger.info('NFS service: %s' % action)

    def tftp_server(self, action):
        if action == 'start':
            tftpboot = os.path.abspath(os.path.join(self.workdir, 'tftpboot'))
            if self.os_type == 'Linux':
                link_name = os.path.join('/', 'tftpboot')
                if os.path.exists(link_name):
                    raise Exception('/tftpboot already exists')
                self.sudo(['ln', '-s', tftpboot, link_name])
                self.sudo(['/etc/init.d/xinetd', 'restart'], redirect = True)
            elif self.os_type == 'Darwin':
                self.sudo(['defaults', 'write', self.TFTP_PLIST, 'ProgramArguments', '-array',
                           '/usr/libexec/tftpd', '-i', tftpboot])
                self.sudo(['launchctl', 'load', '-F', self.TFTP_PLIST])
            self.logger.info('Started TFTP service')
        elif action == 'stop':
            if self.os_type == 'Linux':
                link_name = os.path.join('/', 'tftpboot')
                self.sudo(['rm', link_name])
                self.logger.info('Stopped TFTP service')
            elif self.os_type == 'Darwin':
                self.sudo(['launchctl', 'unload', self.TFTP_PLIST])
                self.logger.info('Stopped TFTP service')

    def extend_file_name(self, name_with_wildcards):
        list_of_files = glob.glob(name_with_wildcards)
        if len(list_of_files) == 0:
            raise TestbedException("No file found matching {}".format(name_with_wildcards))
        elif len(list_of_files) > 1:
            raise TestbedException("More than one file matched {},  {}".format(name_with_wildcards, list_of_files))
        else:
            return list_of_files[0]

    def upgrade_machine(self, machine, zip_file, local_ftp_dir):
        image = self.machines_image(machine)
