    def config_machines(self):

        """ We config machines with ip address present in config.yaml"""
        machine_list = list(self.machines().keys())
        print("Will be configuring machines..")
        sessions = {'confd': {}, 'root': {}}
        # Make session if it is not already existing
        for machine in machine_list:
            print("Creating confd session for machine - %s" %machine)
            logfile = self.get_log_file_for_machine(machine)
            if self.debug is True:
                logfile = sys.stdout
            confd_session = self.get_machine_session(machine, 25, logfile)
            if confd_session != -99:
                sessions['confd'][machine] = confd_session
            else:
                for machine in sessions['confd']:
                    sessions['confd'][machine].close()
                    if mch_sessions[machine].logfile != sys.stdout:
                        sessions['confd'][machine].logfile.close()
                return 1
            print("Creating root session for machine - %s" %machine)
            root_session = self.get_machine_session(machine, 25, logfile, False, False, True)
            if root_session != -99:
                sessions['root'][machine] = root_session
            else:
                for machine in sessions['root']:
                    sessions['root'][machine].close()
                    if sessions['root'][machine].logfile != sys.stdout:
                        sessions['root'][machine].logfile.close()
                return 1
        # Initialize Confd session here
        confd = CONFDSession(self, sessions, self.logger)
        return_list = [True]
        for machine in machine_list:
            # config host name
            return_str = confd.config_hostname(machine, hostname=machine)
            if False in return_str:
                print("Failed to config hostname on machine - %s" %machine)
            for iface in self.interfaces(machine):
                vnet = self.vnet(machine, iface)
                vpn_id = self.vpn_id(machine, iface)
                intf = self.intf_name(machine, self.iface_from_vnet(machine, vnet))
                ip = self.ip_from_vnet(machine, vnet)
                print("On Machine - %s configuring intf - %s with ip add - %s on vpn id - %s" %(machine, intf, ip, vpn_id))
                if vpn_id != 0:
                    # We need to remove the interface from the vpn 0 before moving another vpn
                    print('Now moving the interface from vpn : 0 to vpn - %s' %str(vpn_id))
                    return_string = confd.config_vpn_interface(machine=machine, vpn_id=0, iface=intf, ip=None, mask=None, remove=True)
                return_string = confd.config_vpn_interface(machine=machine, vpn_id=vpn_id, iface= intf, ip= ip, mask =24)
                return_string.append(confd.config_vpn_interface_shutdown(machine=machine, vpn_id=vpn_id, iface=intf, remove=True))
                if False in return_string:
                    return_list[0] = False
                    return_list.append('Failed to config intf - %s with ip add - %s on vpn - %s' %(intf, ip, vpn_id))
        return 0

    def config_cisco_machines(self):
        """ Configure Cisco machines with the ip address in the topology yaml file """
        print("Configuring Cisco devices now ...")
        if 'cisco' in self.config:
            cisco_machine_list = list(self.config['cisco'].keys())
        else:
            print("No Cisco machines to config...")
            return 0
        # Found Cisco machines , We need to initialize
        cs = CiscoSession(self, self.logger)
        for machine in cisco_machine_list:
            print("Now configuring cisco machine - %s" %machine)
            return_str = cs.config_cisco_csr_hostname(machine, machine)
            if False in return_str:
                print("Failed to config hostname for machine - %s" %machine)
            for iface in list(self.config['cisco'][machine].keys()):
                # config every one except MGMT
                if iface != 'MGMT':
                    intf = self.config['cisco'][machine][iface]['intf'][-1]
                    ip = self.config['cisco'][machine][iface]['ip']
                    mask = self.config['cisco'][machine][iface]['mask']
                    print("Configuring interface - %s with ip address - %s" %(intf, ip))
                    return_str = cs.config_cisco_csr_intf(machine, intf, ip, mask)
                    if False in return_str:
                        print("Failed to config intf - %s on machine - %s" %(intf, machine))
        return 0

