    def testbed_vmanage_master_cert_creation(self, vmanage_list):
        """ Will create master root cert """
        if not vmanage_list:
            return
        self.logger.info("Waiting for vManages to be operational")
        try:
            for vmanage in Machines().get(vmanage_list):
                with vmanage.get_http(polling_login=False) as http:
                    http.get_version()
        except Exception:
            success = VmanageWaiter(vmanage_list, blind_wait_time=0).wait_on_vmanages()
            if success:
                self.logger.info("vManages are reported to be operational")
            else:
                self.logger.error("Waiting for vManages failed. See logs for details")

        for vmanage in Machines().get(vmanage_list):
            with vmanage.get_http() as http:
                response = http.sync_root_cert_chain()
            if not response.ok:
                self.logger.error('%s: master root cert creation error: %s', vmanage.name, response.text)
        self.load_config()

    def check_erros_in_log_files(self, machine, log_files):
        """This finctions checks for errors in vconfd and vdebug"""
        # Here log file is dictionary with error to check on and corresponding error pattern
        # logfile = {'vconfd': 'oSError*', 'vdebug': 'error'}
        error_msg = {}
        cmds = []
        if self.is_nfvis(machine) or self.is_ucs(machine) or self.is_highrise(machine):
            return [True, error_msg]

        for logfile in log_files:
            #print log_files[logfile]
            pattern = log_files[logfile]
            cmds = ["cat %s | grep \"%s\"" % (logfile, pattern)]
            ret = self.ssh_output(machine, cmds)
            # check if errors are there: print them as syslog message with machine, logfile name and error.
            if ret == '-99':
                error_msg[logfile] = None
            else:
                error_msg[logfile] = ret
        return [True, error_msg]

