    def check_defunct_processes(self, machine, process='ppp'):
        """Check any defunct process in viptela devices"""
        defunct = 'defunct'
        ps_grep_daemon_cmd = "ps aux | grep \"%s\" | grep \"%s\"" %(defunct, process)
        ret_code = self.ssh_output(machine, ps_grep_daemon_cmd)
        if ret_code == '-99':
            return [True, 'No process found with defunct state for process %s'%(process)]
        else:
            return [False, 'Defunct process found for process %s with return code [%s]'%(process, ret_code)]

