    def return_system_multicast_yaml_expanded(self):
        multicast_topo = {}
        if 'tests' not in self.config or 'test_system_multicast' not in self.config['tests']:
            return multicast_topo

        multicast_yaml = self.config['tests']['test_system_multicast']
        for group in list(multicast_yaml.keys()):
            vpn_id = str(multicast_yaml[group]['vpn-id'])
            if vpn_id not in multicast_topo:
                multicast_topo[vpn_id] = {}
            multicast_topo[vpn_id][group] = {}
            multicast_topo[vpn_id][group]['group-ip'] = multicast_yaml[group]['group-ip']
            multicast_topo[vpn_id][group]['rp'] = multicast_yaml[group]['rp']
            multicast_topo[vpn_id][group]['sources'] = []
            for sour in multicast_yaml[group]['sources']:
                multicast_topo[vpn_id][group]['sources'] += self.expand_system_multicast_device_range(sour)

            multicast_topo[vpn_id][group]['replicators'] = []
            for rep in multicast_yaml[group]['replicators']:
                multicast_topo[vpn_id][group]['replicators'] += self.expand_system_multicast_device_range(rep)

            multicast_topo[vpn_id][group]['receivers'] = []
            for rec in multicast_yaml[group]['receivers']:
                multicast_topo[vpn_id][group]['receivers'] += self.expand_system_multicast_device_range(rec)

            multicast_topo[vpn_id][group]['hosts'] = []
            for host in multicast_yaml[group]['hosts']:
                multicast_topo[vpn_id][group]['hosts'] += self.expand_system_multicast_device_range(host)

        return multicast_topo

