    def return_system_multicast_config(self):
        '''
        mcast_topo= { vpn_id: { group: { source:
                                            { hostname: <source> }
                                            { replicator: <[rep list]>}
                                            { rep_count: <rep_count>}
                                        }
                                        { replicators: { <replicator>:
                                                { source: <source>}
                                                { rep_count: <rep_count>}
                                        }}
                                        { recievers: { <receiver>:
                        e                       { replicator: <replicator>}
                                                { rep_count: <rep_count>}
                                        }}}}
        '''
        mcast_topo = {}
        mcast_yaml = self.return_system_multicast_yaml_expanded()
        for vpn_id in mcast_yaml:
            mcast_topo[vpn_id] = {}
            for group in mcast_yaml[vpn_id]:
                group_data = mcast_yaml[vpn_id][group]
                print(group_data)
                group_ip = group_data['group-ip']
                group_sources = group_data['sources']
                group_rp = str(group_data['rp'])
                group_reps = group_data['replicators']
                group_recs = group_data['receivers']
                group_hosts = group_data['hosts']

                mcast_topo[vpn_id][group_ip] = {}
                mcast_group = mcast_topo[vpn_id][group_ip]
                mcast_group['rp'] = group_rp
                mcast_group['sources'] = {}
                mcast_group['replicators'] = {}
                mcast_group['receivers'] = {}

                rec_rep_count_total = {}
                rec_rep_count_total['0.0.0.0'] = 0
                src_ip_list = ['0.0.0.0']
                for src_vedge in group_sources:
                    src_ip = self.return_system_mcast_source(src_vedge)
                    src_ip_list += [src_ip]
                    rec_rep_count_total[src_ip] = 0

                for src_vedge in group_sources:
                    mcast_group['sources'][src_vedge] = {}
                    for src_ip in src_ip_list:
                        mcast_group['sources'][src_vedge][src_ip] = {}
                        mcast_group['sources'][src_vedge][src_ip]['source'] = self.return_system_mcast_source(src_vedge)
                        mcast_group['sources'][src_vedge][src_ip]['replicators'] = [ rep for rep in group_reps if rep not in group_sources]
                        #oif-src: source -> replicator
                        #oif-rep: replicator -> receiver
                        #oif-receiver: receiver -> host
                        mcast_group['sources'][src_vedge][src_ip]['oif-src'] = mcast_group['sources'][src_vedge][src_ip]['replicators']
                        mcast_group['sources'][src_vedge][src_ip]['oif-rep'] = []
                        mcast_group['sources'][src_vedge][src_ip]['oif-rec'] = []
                        mcast_group['sources'][src_vedge][src_ip]['rep-count'] = len(mcast_group['sources'][src_vedge][src_ip]['replicators'])

                for rep_vedge in group_reps:
                    if rep_vedge not in list(mcast_group['sources'].keys()):
                        mcast_group['replicators'][rep_vedge] = {}
                        for src_ip in src_ip_list:
                            mcast_group['replicators'][rep_vedge][src_ip] = {}
                            mcast_group['replicators'][rep_vedge][src_ip]['source'] = [self.return_system_mcast_source(src_vedge) for src in list(mcast_group['sources'].keys())]
                            mcast_group['replicators'][rep_vedge][src_ip]['replicators'] = [rep]
                            mcast_group['replicators'][rep_vedge][src_ip]['oif-src'] = []
                            mcast_group['replicators'][rep_vedge][src_ip]['oif-rep'] = []
                            mcast_group['replicators'][rep_vedge][src_ip]['oif-rec'] = []
                            mcast_group['replicators'][rep_vedge][src_ip]['rep-count'] = 0

                for rec_vedge in group_recs:
                    for src_ip in src_ip_list:
                        rec_rep_count_total[src_ip] += 1
                        if rec_vedge in list(mcast_group['sources'].keys()):
                            mcast_group['sources'][rec_vedge][src_ip]['oif-rec'].append('LOCAL')
                            mcast_group['sources'][rec_vedge][src_ip]['rep-count'] += 1
                        elif rec_vedge in list(mcast_group['replicators'].keys()):
                            mcast_group['replicators'][rec_vedge][src_ip]['oif-rec'].append('LOCAL')
                            mcast_group['replicators'][rec_vedge][src_ip]['rep-count'] += 1
                        else:
                            if rec_vedge not in mcast_group['receivers']:
                                mcast_group['receivers'][rec_vedge] = {}
                            mcast_group['receivers'][rec_vedge][src_ip] = {}
                            mcast_group['receivers'][rec_vedge][src_ip]['source'] = [self.return_system_mcast_source(src_vedge) for src in list(mcast_group['sources'].keys())]
                            #mcast_group['receivers'][rec_vedge][src_ip]['replicators'] = mcast_group['replicators'].keys()
                            mcast_group['receivers'][rec_vedge][src_ip]['replicators'] = group_reps
                            mcast_group['receivers'][rec_vedge][src_ip]['oif-src'] = []
                            mcast_group['receivers'][rec_vedge][src_ip]['oif-rep'] = []
                            mcast_group['receivers'][rec_vedge][src_ip]['oif-rec'] = ['LOCAL']
                            mcast_group['receivers'][rec_vedge][src_ip]['rep-count'] = 1
                            for rep_vedge in group_reps:
                                if rep_vedge in list(mcast_group['sources'].keys()):
                                    mcast_group['sources'][rep_vedge][src_ip]['oif-rep'].append(rec_vedge)
                                    mcast_group['sources'][rep_vedge][src_ip]['rep-count'] += 1
                                else:
                                    mcast_group['replicators'][rep_vedge][src_ip]['oif-rep'].append(rec_vedge)
                                    mcast_group['replicators'][rep_vedge][src_ip]['rep-count'] += 1

                for host in group_hosts:
                    if host in group_recs:
                        continue
                    for src_ip in src_ip_list:
                        rec_rep_count_total[src_ip] += 1
                        if host in list(mcast_group['sources'].keys()):
                            mcast_group['sources'][host][src_ip]['oif-rec'].append('LOCAL')
                            mcast_group['sources'][host][src_ip]['rep-count'] += 1
                        elif host in list(mcast_group['replicators'].keys()):
                            mcast_group['replicators'][host][src_ip]['oif-rec'].append('LOCAL')
                            mcast_group['replicators'][host][src_ip]['rep-count'] += 1
                        else:
                            if 'receivers' not in list(mcast_group.keys()):
                                mcast_group['receivers'] = {}
                            if host not in mcast_group['receivers']:
                                mcast_group['receivers'][host] = {}
                            mcast_group['receivers'][host][src_ip] = {}
                            mcast_group['receivers'][host][src_ip]['source'] = [self.return_system_mcast_source(src_vedge) for src in list(mcast_group['sources'].keys())]
                            #mcast_group['receivers'][host][src_ip]['replicators'] = mcast_group['replicators'].keys()
                            mcast_group['receivers'][host][src_ip]['replicators'] = group_reps
                            mcast_group['receivers'][host][src_ip]['oif-src'] = []
                            mcast_group['receivers'][host][src_ip]['oif-rep'] = []
                            mcast_group['receivers'][host][src_ip]['oif-rec'] = ['LOCAL']
                            mcast_group['receivers'][host][src_ip]['rep-count'] = 1
                            for rep_vedge in group_reps:
                                if rep_vedge in list(mcast_group['sources'].keys()):
                                    mcast_group['sources'][rep_vedge][src_ip]['oif-rep'].append(host)
                                    mcast_group['sources'][rep_vedge][src_ip]['rep-count'] += 1
                                else:
                                    mcast_group['replicators'][rep_vedge][src_ip]['oif-rep'].append(host)
                                    mcast_group['replicators'][rep_vedge][src_ip]['rep-count'] += 1
                mcast_group['devices'] = list(set(list(mcast_group['sources'].keys()) + list(mcast_group['replicators'].keys()) + list(mcast_group['receivers'].keys())))
                mcast_group['rec_rep_count'] = rec_rep_count_total
        return mcast_topo

    #expand pm4001--pm4003 to ['pm4001', 'pm4002', 'pm4003']
    def expand_system_multicast_device_range(self, device):
        if "--" in device:
            device_range = device.split("--")
            p = re.compile('([a-zA-Z]+)([0-9]+)')
            match = p.match(device_range[0])
            if match == None:
                return []
            device_type = match.group(1)
            start = match.group(2)

            match = p.match(device_range[1])
            if match == None:
                return []
            if device_type != match.group(1):
                return []
            end = match.group(2)
            result = []
            for id in range(int(start), int(end) + 1):
                result.append(device_type + str(id))
        else:
            result = [device]

        return result

