    def is_cedge(self, machine, loose=True):
        """Check if machine is cedge, if loose, autonomous and sd-routing is included"""
        if (machine in self.config['machines']) and ('personality' in list(self.config['machines'][machine].keys())) and ('cedge' in self.config['machines'][machine]['personality']):
            return True
        if (machine in self.config['machines']) and ('gui_personality' in list(self.config['machines'][machine].keys())) and ('cedge' in self.config['machines'][machine]['gui_personality']):
            return True

        if loose:
            # traditional xe
            if self.is_xe(machine):
                return True

            # autonomous
            if self.is_autonomous(machine):
                return True

        return False

