    def create_cert_key_on_testbed(self, machine, cert_name, emailId = 'tester@viptela.com', subj = {'C':'US','ST' : 'California', 'L': 'San Jose', 'OU' : 'vIPtela Inc Regression', 'O' : 'vIPtela Inc', 'CN':'viptela.testbed'}):
        """ Generate key, csr and sign by root ca"""
        root_ca_path = os.path.join(self.workdir, "root_ca/")
        openssl_cnf = os.path.join(root_ca_path, "openssl.cnf")
        key_name = os.path.join(root_ca_path, "%s.key"%(cert_name))
        csr_name = os.path.join(root_ca_path, "%s.csr"%(cert_name))
        cert_name = os.path.join(root_ca_path, "%s.crt"%(cert_name))

        private_dir = os.path.join(root_ca_path, 'private')
        root_ca_cert = os.path.join(root_ca_path, 'cacert.pem')
        root_ca_key = os.path.join(private_dir, 'cakey.pem')
        new_certs_dir = os.path.join(root_ca_path, 'newcerts')

        # Generate key
        key_cmd = "openssl genrsa -out %s 2048"%(key_name)
        try:
            subprocess.check_call('%s'%(key_cmd), shell= True)
        except:
            self.logger.info('failed to generate key')
            self.logger.info('%s'%key_cmd)
            return [False, "Failed to create key"]

        #Generate csr
        subject = "/C=%s/ST=%s/L=%s/OU=%s/O=%s/CN=%s/emailAddress=%s"%(subj['C'],subj['ST'],subj['L'],subj['OU'],subj['O'],subj['CN'], emailId)
        csr_cmd = "openssl req -new -key %s -out %s -config %s -subj \"%s\""%(key_name, csr_name, openssl_cnf, subject)
        try:
            subprocess.check_call("%s"%(csr_cmd), shell= True)
        except:
            self.logger.info('failed to generate csr')
            self.logger.info('%s'%csr_cmd)
            return [False, "Failed to create csr"]

        # Generate Cert
        # cert_cmd = "openssl ca -batch -out %s -config %s -cert %s -keyfile %s -passin pass:f3rrar1 -outdir %s -infiles %s"%(cert_name, openssl_cnf, root_ca_cert, root_ca_key, new_certs_dir, csr_name)
        # try:
        #     subprocess.check_call("%s"%(cert_cmd), shell= True)
        # except:
        #     self.logger.info('failed to generate cert')
        #     self.logger.info('%s'%cert_cmd)
        result = self.sign_csr('TB', csr_file_name = os.path.basename(csr_name), out_file_name = os.path.basename(cert_name))
        if False in result:
            return [False, "Failed to create cert"]
        return [True, 'Successfully generated key %s and cert %s'%(key_name, cert_name)]

    def check_ns_lookup_on_ubuntu_services(self, machine, machine_ip, uname, passwd, cmd, dns, dns_ip, timeout = 50):
        """This function verifies the nslookup after dns server has been started for PnP server"""
        ssh_session = self.get_paramiko_session(machine_ip, uname, passwd, timeout = timeout)
        fail_string = "** server can't find %s: SERVFAIL"%(dns)
        pass_string = "Address: %s"%(dns_ip)
        if ssh_session[0] == False:
            return [False, 'Error : %s' % ssh_session[1]]
        else:
            _, stdout, stderr = ssh_session[1].exec_command(cmd)
            out = stderr.read()
            stderr.close()
            if out != b'':
                self.logger.info(out)
                ssh_session[1].close()
                return [False, 'Command %s failed' % cmd]
            else:
                stdout = stdout.read()
                if six.PY3:
                    stdout = stdout.decode()
                self.logger.info(stdout)
                stdout = stdout.split('\n')
                for line in stdout:
                    if pass_string in line:
                        return [True, 'nslookup passed for dns entry %s'%(dns_ip)]
            ssh_session[1].close()
            return [False, 'nslookup failed for dns entry %s'%(dns_ip)]

