    def set_forwarding_on_kvm_testbed_for_PnP(self, machine, bridge, internet_iface):
        """"""
        cmds = ['sudo sysctl net.ipv4.ip_forward=1']
        cmds  += ['sudo sysctl -p']
        cmds += ['sudo iptables -A FORWARD -i %s -o %s -j ACCEPT'%(bridge, internet_iface)]
        for cmd in cmds:
            out = subprocess.call(cmd, shell=True)
        return [True, '']

    def set_nat_rule_for_PnP(self, machine, internet_iface):
        """Set nat rule for PnP traffic to go out"""
        cmd = 'sudo iptables -t nat -A POSTROUTING -o %s -j MASQUERADE'%(internet_iface)
        out = subprocess.call(cmd, shell=True)
        return [True, 'Iptable rule for PnP internet exit set correctly for KVM testbed']

