        vpn = None
        for intf_num in list(self.config['machines'][machine]['interfaces'].keys()):
            intf_entry = self.config['machines'][machine]['interfaces'][intf_num]
            if 'intf' in list(intf_entry.keys()):
                name_list = intf_entry['intf']
                if (len(name_list) == 2 and name_list[1] == intf_name) or name_list[0] == intf_name:
                    if 'vpn' in list(intf_entry.keys()):
                        vpn = intf_entry['vpn']
