    def iface_from_vnet_l2_nim_type(self, machine, vnetId, l2_key, l2_value):
        '''
        usage:
        >>> tb.iface_from_vnet_l2_nim_type('pm5', 100, 'type','l2_vlan')
        [True, 'GigabitEthernet0/2/1']
        '''
        for iface in self.config['machines'][machine]['interfaces']:
            for key in list(self.config['machines'][machine]['interfaces'][iface].keys()):
                if key =='vnet':
                    if str(self.config['machines'][machine]['interfaces'][iface][key]) == str(vnetId):
                        if (l2_key in self.config['machines'][machine]['interfaces'][iface])== True:
                            if self.config['machines'][machine]['interfaces'][iface][l2_key]== l2_value:
                                iface_num =self.config['machines'][machine]['interfaces'][iface]['intf'][1]
                                return [True, iface_num]
                            else:
                                return [False, 'did not find the l2_nim']
                        else:
                            return [False, 'did not find the l2_nim']

