    def get_l2_type_from_interfae(self, machine, interface_name):
        '''
        usage:
        get if interface supports has switch port
        >>> tb.get_l2_type_from_interfae('pm5', 'GigabitEthernet0/3/3')
        [False, 'did not find interface in yaml file ']
        >>> tb.get_l2_type_from_interfae('pm5', 'GigabitEthernet0/0/1')
        found interface_name GigabitEthernet0/0/1 in yaml file
        [False, 'did not find the l2_nim']
        >>> tb.get_l2_type_from_interfae('pm5', 'GigabitEthernet0/2/0')
        found interface_name GigabitEthernet0/2/0 in yaml file
        [True, 'interface GigabitEthernet0/2/0 is switching port']
        >>> tb.get_l2_type_from_interfae('vm6', 'ge0/1')
        [False, 'only appliable for switching port on isr']
        >>>
        '''
        int_list = []
        if self.is_cedge(machine) ==False:
            return [False, 'only appliable for switching port on isr']
        for iface in self.config['machines'][machine]['interfaces']:
            for key in list(self.config['machines'][machine]['interfaces'][iface].keys()):
                if key =='intf':
                    int_list.append(self.config['machines'][machine]['interfaces'][iface][key][1])
        if interface_name in int_list:
            print("found interface_name %s in yaml file" %interface_name)
        else:
            return [False, 'did not find interface in yaml file ']
        for iface in self.config['machines'][machine]['interfaces']:
            for key in list(self.config['machines'][machine]['interfaces'][iface].keys()):
                if key =='intf':
                    if self.config['machines'][machine]['interfaces'][iface][key][1] == interface_name:
                        if ('type' in self.config['machines'][machine]['interfaces'][iface])== True:
                            return [True, 'interface %s is switching port'%interface_name]
                        else:
                            return [False, 'did not find the l2_nim']

    def touch_abort_parallel_file(self, filename):
        """File will be created in /tmp/"""
        subprocess.call(f"touch /tmp/{filename}", shell=True, timeout=60)
        return [True, ""]

    def is_abort_parallel_file_exist(self, filename):
        """Check file is created in /tmp/"""
        cmd = f"ls -lrt /tmp | grep \"{filename}\" | wc -l"
        output = subprocess.check_output(cmd, stderr=subprocess.STDOUT, shell=True, timeout=60).strip()
        file_exist = int(output) == 1
        if file_exist:
            return [True, "file exist"]
        return [False, "file does not exist"]

    def delete_abort_parallel_file(self, filename):
        """Delete abort parallel file from /tmp/"""
        try:
            subprocess.call('rm /tmp/%s' % (filename), shell=True)
        except:
            pass
        return [True, ""]

