    def set_cedge_after_pnp_reset(self, machine):
        """Set cedge hostname in tests scripts, if device is reset"""
        mgmt_ip = self.mgmt_ipaddr(machine)
        logfile = self.get_log_file_for_machine(machine)
        print("Continue configuring HW node in PnP scripts")
        with CedgeSession(mgmt_ip, logfile) as cedge_session:
            pnp_wait = 450
            if not cedge_session.is_confd_running():
                cedge_session.stop_pnp()
                time.sleep(pnp_wait)
            if not cedge_session.is_confd_running():
                raise TestbedBringupError('Confd is still not up after stopping PnP and waiting for {} sec'.format(pnp_wait))
            cedge_session.discard_uncommitted_changes()
            # Set up netconf interface
            #cedge_session.enable_vty()
            cedge_session.logging_persistent()
            cedge_session.set_hostname(machine)
            self.setup_cedge_netconf_interface(machine)

        logging.getLogger(machine).info("Done setting up machine after pnp reset: {}".format(machine))
        return True

    def get_utd_lxc_image(self, machine, branch='next', stable='STABLE', platform=None, username='bamboo', pwd='V1ptela0212'):
        """Download utd lxc image"""
