        utd_image_src_loc = 'ftp://%s:%s@vip-dmzftp01.cisco.com/builds/cEdge/%s/%s/%s'%(username, pwd, branch, stable, utd_image_name)
        utd_image_dst_loc = '~/images/iox-iosxe-utd.tar' #this is the static filename we will be using in scripts
        start_time = time.time()
