    def get_cli_session_ubuntu(self,pexpect_timeout, logfile, wait=False):
        """Get iosxe enable prompt"""
        cmd_bld = SSHCommandBuilder(host='10.0.1.127', user='tester', logger=self.logger, no_multiplexing=True)
        cmd_bld.add_kv_option('ConnectTimeout', 20)
        cmd_bld.add_kv_option('ServerAliveInterval', 60)
        cmd_bld.add_kv_option('ServerAliveCountMax', 20)
        cmd = cmd_bld.build()
        start_time = time.time()
        wait_time = 0
        if wait:
            wait_time = 60
        less_than_max = True
        while less_than_max:
            if six.PY2:
                child1 = pexpect.spawn(cmd, timeout=pexpect_timeout)
            else:
                child1 = pexpect.spawn(cmd, timeout=pexpect_timeout, encoding='utf-8', codec_errors='ignore')
            try:
                index = child1.expect(['.*password:', 'Password:'])
                if index <= 1:
                    child1.sendline(self.password_tb)
                    child1.expect(r'.*\$')
                break
            except pexpect.EOF:
                less_than_max = int(time.time() - start_time) < wait_time
                continue
        return child1

    def exec_command_cli_ubuntu(self, machine, command, pexpect_timeout):
        ubuntu_session = self.get_cli_session_ubuntu(100, None)
        ubuntu_session.sendline(command)
        try:
            index = ubuntu_session.expect([r'.*\$', pexpect.TIMEOUT], timeout=pexpect_timeout)
        except pexpect.EOF:
            self.logger.warn("Couldn't get prompt")
            index = -1
        if index == 0:
            return [True, 'Got prompt']
        else:
            return [False, "Could not get prompt"]

    def get_all_vnets_for_machine(self, machine):
        """get all vnets in a machine from config/topology yaml"""
        vnets = []
        for iface in self.interfaces(machine):
            vnets.append(self.vnet(machine, iface))
        return vnets

    def get_common_vnets_between_machines(self, machine1, machine2):
        """Get common vnets between machines"""
        machine1_vnets = self.get_all_vnets_for_machine(machine1)
        machine2_vnets = self.get_all_vnets_for_machine(machine2)
        return list(set(machine1_vnets) & set(machine2_vnets))

