    def ping_machine_from_testbed_on_a_vnet(self, machine, dest_ip, fail_time):
        """Ping any vnet ip from testbed, eg any tloc ip reachable from testbed"""
        start = int(time.time())
        if self.os_type == 'Darwin':
            wait_tag = 't'
        elif self.os_type == 'Linux':
            wait_tag = 'W'
        while (int(time.time()) - start) <= fail_time:
            ret = subprocess.call(['ping', '-c1', '-%s1.5' % wait_tag, '%s' %
                                   dest_ip], stdout=open(os.devnull, 'w'), stderr=open(os.devnull, 'w'))
            if ret == 0:
                return [True, 'Ping passed for destination ip %s'%(dest_ip)]
        return [False, 'Ping failed for destination ip %s with retry of %s seconds'%(dest_ip, fail_time)]

    def issue_config_reset_and_reload(self, machine, wait_time = 600, additional_cmds = []):
        """Issue config reset on cedge followed by reload by retriggering ZTP process in test_cedge_ztp.ttf"""
        confd_session = self.create_confd_session(machine)
        chassis_no = confd_session.get_cedge_chassis_number(machine)
        global HPID
        HPID = chassis_no.rsplit('-', 1)[0]
        if 'console' not in self.config['machines'][machine]:
            return [False, 'Topology YAML doesnt have console info']
        else:
            self.stop_monitor()
            console_config = self.config['machines'][machine]['console']
            with ConsoleFactory(console_config) as pexpect_session:
                pexpect_session.logfile = sys.stdout
                self.go_to_ios_prompt(machine, pexpect_session)
                time.sleep(15)
                #self.send_command_and_check_prompt(pexpect_session, 'request platform software sdwan config reset', '.*\#')
                pexpect_session.sendline('request platform software sdwan config reset')
                res = pexpect_session.expect(
                    [r'Proceed to reset anyway? [confirm]\?', r'.*#', pexpect.TIMEOUT], timeout=2
                )
                if res == 0:
                    self.send_command_and_check_prompt(pexpect_session, 'yes\n', r'.*#')
                else:
                    self.send_command_and_check_prompt(pexpect_session, '\n', r'.*#')
                time.sleep(15)
                pexpect_session.sendline('reload')
                time.sleep(5)
                try:
                    res = pexpect_session.expect(
                        [
                            r'.*Continue to reload\?',
                            r'configuration has been modified. Save\?',
                            r'.*Proceed with reload\?',
                            pexpect.TIMEOUT,
                        ],
                        timeout=2,
                    )
                    if res == 0:
                        pexpect_session.sendline('yes\n')
                    elif res == 1:
                        pexpect_session.sendline('no')
                    elif res == 2:
                        pexpect_session.sendline('\n')
                except:
                    print('Session closed. Assuming machine went for reload')
            time.sleep(wait_time)
            if additional_cmds:
                for cmd in additional_cmds:
                    os.system(cmd)
                    time.sleep(60)
            return [True, '']

    def issue_config_reset_and_controller_mode_disable(self, machine, wait_time = 600, additional_cmds = []):
        """Issue config reset on cedge followed by reload by retriggering ZTP process in test_cedge_ztp.ttf"""
        if 'console' not in self.config['machines'][machine]:
            return [False, 'Topology YAML doesnt have console info']
        else:
            self.stop_monitor()
            console_config = self.config['machines'][machine]['console']
            with ConsoleFactory(console_config) as pexpect_session:
                pexpect_session.logfile = sys.stdout
                self.go_to_ios_prompt(machine, pexpect_session)
                time.sleep(15)
                #self.send_command_and_check_prompt(pexpect_session, 'request platform software sdwan config reset', '.*\#')
                pexpect_session.sendline('request platform software sdwan config reset')
                res = pexpect_session.expect(
                    [r'Proceed to reset anyway? [confirm]\?', r'.*#', pexpect.TIMEOUT], timeout=2
                )
                if res == 0:
                    self.send_command_and_check_prompt(pexpect_session, 'yes\n', r'.*#')
                else:
                    self.send_command_and_check_prompt(pexpect_session, '\n', r'.*#')
                time.sleep(15)

                pexpect_session.sendline('controller-mode disable')
                res = pexpect_session.expect([r'Continue? [confirm]\?', r'.*#', pexpect.TIMEOUT], timeout=2)
                if res == 0:
                    self.send_command_and_check_prompt(pexpect_session, 'yes\n', r'.*#')
                else:
                    self.send_command_and_check_prompt(pexpect_session, '\n', r'.*#')
                time.sleep(5)

                res = pexpect_session.expect([r'Do you want to abort?\?', r'.*#', pexpect.TIMEOUT], timeout=2)
                if res == 1:
                    self.send_command_and_check_prompt(pexpect_session, 'no\n', r'.*#')
                else:
                    self.send_command_and_check_prompt(pexpect_session, '\n', r'.*#')
                time.sleep(5)

            time.sleep(wait_time)
            if additional_cmds:
                for cmd in additional_cmds:
                    os.system(cmd)
                    time.sleep(60)
            return [True, '']

    def recover_cedge_node_after_unsuccessfull_ztp(self, machine):
        """Login into the reset node , set the transport ssh and mgmt IPs for the further test cases to go through"""
        if 'console' not in self.config['machines'][machine]:
            return [False, 'Topology YAML doesnt have console info']
        else:
            self.stop_monitor()
            console_config = self.config['machines'][machine]['console']
            with ConsoleFactory(console_config) as pexpect_session:
                pexpect_session.logfile = sys.stdout
                self.cedge_stop_pnp(machine, pexpect_session)
                self.go_to_ios_prompt(machine, pexpect_session)
                time.sleep(5)
                self.send_command_and_check_prompt(pexpect_session, 'config-transaction', r'\(config\)#')
                time.sleep(2)
                self.send_command_and_check_prompt(pexpect_session, 'hostname %s' % machine, r'.*#')
                time.sleep(2)
                self.send_command_and_check_prompt(pexpect_session, 'line vty 0 4', r'\(config-line\)#')
                time.sleep(2)
                self.send_command_and_check_prompt(pexpect_session, 'transport input ssh', r'\(config-line\)#')
                time.sleep(2)
                self.send_command_and_check_prompt(
                    pexpect_session,
                    'interface %s' % str(self.intf_name(machine, self.iface_from_vnet(machine, 99))),
                    r'\(config-if\)#',
                )
                time.sleep(2)
                self.send_command_and_check_prompt(pexpect_session, 'ip address dhcp', r'\(config-if\)#')
                time.sleep(2)
                self.send_command_and_check_prompt(
                    pexpect_session,
                    'interface %s' % str(self.intf_name(machine, self.iface_from_vnet(machine, 100))),
                    r'\(config-if\)#',
                )
                time.sleep(2)
                if HPID == "ASR1002-HX" or HPID == "ASR1001-HX":
                    self.send_command_and_check_prompt(pexpect_session, 'no shutdown', r'\(config-if\)#')
                    time.sleep(2)
                self.send_command_and_check_prompt(
                    pexpect_session,
                    'ip address %s 255.255.255.0' % str(self.ip_from_vnet(machine, 100)),
                    r'\(config-if\)#',
                )
                time.sleep(2)
                self.send_command_and_check_prompt(pexpect_session, 'exit', r'\(config\)#')
                time.sleep(2)
                self.send_command_and_check_prompt(pexpect_session, '\n', r'\(config\)#')
                time.sleep(2)
                self.send_command_and_check_prompt(pexpect_session, 'commit', r'.*#', 5)
                time.sleep(2)
                self.send_command_and_check_prompt(pexpect_session, 'exit', r'.*#')
                time.sleep(60)

            return [True, '']

    def _logger_warn_with_caller(self, *args, **kwargs):
        """
        Equivalent of self.logger.warning(*args, *kwargs).
        Emits additional log with caller (first method outside of testbed.py).
        Typically it'll point to offending line in relevant script.
        """
        frames = inspect.stack()
        frame = None
        try:
            self.logger.warn(*args, **kwargs)
            for (frame, filename, lineno, function, code_context, _) in frames:
                if filename != __file__:
                    self.logger.warn("Caused by %s:%s (%s): %s", filename, lineno, function, "\n".join(code_context))
                    break
            else:
                self.logger.warn("Cannot identify caller")
        finally:
            # avoid reference cycle
            del frame
            del frames

    def get_dmz_lab_variables(self, machine= None, var1 = None, var2 = None):
        '''
        Get all the dmz_lab_variables from local.preference.yaml file
        '''
        try:
            return pref['dmz_lab_variables'][var1][var2]
        except KeyError:
            self.logger.error('can not find the dmz_lab_variables key in local.preference.yaml file')

    def netconf_client(self, machine, look_for_keys=True, username=None, password=None):
        nc_extra_args = {}
        if hasattr(ncclient, "__version__"):
            nc_extra_args["hostkey_verify"] = False

        if username is None:
            username = self.get_ssh_username(machine)
        if password is None:
            password = self.get_ssh_password(machine)

        host = self.netconf_mgmt_ipaddr(machine)
        port = 830

        for password in self.get_ssh_known_passswords(machine):
            try:
                conn = ncclient.manager.connect(
                    host=host,
                    port=port,
                    username=username,
                    password=password,
                    allow_agent=False,  # automation should never use agent-forwarded keys
                    look_for_keys=look_for_keys,  # testbed bring-up prepares private key for auth purposes
                    **nc_extra_args,  # version-dependent extra arguments
                )
                self.update_machine_config(machine, password)
                return conn

            except ncclient.transport.errors.AuthenticationError as e:
                self.logger.warning(
                    f"Auth error when connecting to {username}@{host}:{port} with pass {password}:\n{e}"
                )
                self.logger.warning("Trying next password...")

        raise Exception(f"Could not connect netconf on {username}@{host}:{port} ")

    def get_config_yaml(self):
        self.logger.info("Getting config from config.yaml")
        return self.config

    def ubuntu_bringup_include(self, suite, reboot_ubuntu=False, dynamic_ubuntu=False, non_dmz=False, qcow_path=None):
        '''
        This method automates the process of bringing up the ubuntu vm before running any testcase.
        To invoke this method need to pass arguement -iub (include ubuntu)/ -rub (reboot ubuntu)
        If a suite related ubuntu image is present in /auto/selinux_vtest/ubuntu_services_qcow/
        then the script will copy the image from auto path to local dir /home/user_name,
        corresponding creation xml file will be taken from addons/vrt-ubuntu_services directory.
        If ubuntu image is not present in the autopath then image will be taken from ~/ubuntu_services.
        '''

        def default_ubuntu_service_paths():
            # 1. check user home directory for Ubuntu Services XML and if it's missing
            # 2. then use level up folder of vtest
            ubuntu_image_local_path = str(Path.home() / 'ubuntu_services' / 'ubuntu_services.qcow2')
            xml_file = str(Path.home() / 'ubuntu_services' / 'ubuntu_services.xml')
            if not Path(xml_file).exists():
                ubuntu_image_local_path = str(Paths().vtest()) + "/../ubuntu_services/ubuntu_services.qcow2"
                xml_file = str(Paths().vtest()) + "/../ubuntu_services/ubuntu_services.xml"
            return (xml_file, ubuntu_image_local_path)

        def create_xml_based_on_yaml(local_qcow_path):
            def atoi(text):
                return int(text) if text.isdigit() else text

            def natural_keys(text):
                return [atoi(c) for c in re.split(r'(\d+)', text)]

            def sort_func(item):
                """Sorts interfaces by name"""
                return natural_keys(item[1]["intf"][0])

            filename = "/tmp/ubuntu_services.xml"
            ubuntu = self.config.get('ubuntu') or self.config.get('ubuntu-server')
            if not ubuntu:
                self.logger.info("Ubuntu not defined in yaml. Using default xml")
                return default_ubuntu_service_paths()[0]
            jinja_env = Environment(
                loader=FileSystemLoader(str(Path(__file__).parents[1].joinpath('addons', 'ubuntu')))
            )
            template = jinja_env.get_template("template.j2")
            vnets = [
                "vnet{}".format(intf["vnet"]) for _, intf in sorted(ubuntu.get("interfaces", {}).items(), key=sort_func)
            ]
            content = template.render(
                memory=ubuntu.get("memory", "2097152"),
                vcpu=ubuntu.get("vcpu", "2"),
                vnets=vnets,
                local_qcow_path=local_qcow_path,
            )
            with open(filename, mode="w") as xml_file:
                xml_file.write(content)
            return filename

        def copy_ubuntu_image(src_image, dst_image, local_backup_image=None, md_file=None):
            if local_backup_image is None:
                local_backup_image = str(Path.home() / 'ubuntu_services' / 'backup_ubuntu_services.qcow2')

            skip_local_copy = False
            md_file_exists = bool(md_file and Path(md_file).exists())
            self.logger.debug(
                "local_backup_image exists: {}; md_file: {}; md_file exists: {}".format(
                    Path(local_backup_image).exists(), md_file, md_file_exists
                )
            )
            if Path(local_backup_image).exists() and md_file_exists:
                remote_md5 = open(md_file, 'r').read().strip()
                local_md5 = self.get_md5(local_backup_image)
                self.logger.debug("remote_md5: {}; local_md5: {};".format(remote_md5, local_md5))
                if remote_md5 == local_md5:
                    self.logger.info("MD5 sums are equal. Copying image is skipped")
                    skip_local_copy = True

            if not skip_local_copy:
                Path(local_backup_image).parent.mkdir(parents=True, exist_ok=True)
                self.logger.info("Copying image from {} to {}".format(src_image, local_backup_image))
                shutil.copyfile(src_image, local_backup_image)

            try:
                os.remove(dst_image)
            except Exception as ex:
                self.logger.warning("Not able to delete current ubuntu qcow2 image: {}".format(ex))
            self.logger.info("Copying image from {} to {}".format(local_backup_image, dst_image))
            Path(dst_image).parent.mkdir(parents=True, exist_ok=True)
            shutil.copyfile(local_backup_image, dst_image)

        hostip = None
        username = None
        password = None
        self.logger.info('Started ubuntu bringup')
        if self.config.get('ubuntu') is not None:
            hostip = self.config['ubuntu']['interfaces']['MGMT']['ip']
            username = self.config['ubuntu'].get('username', 'tester')
            password = self.config['ubuntu'].get('password', 'v1ptela0212')
        elif self.config.get('ubuntu-server') is not None:
            hostip = self.config['ubuntu-server']['interfaces']['MGMT']['ip']
            username = self.config['ubuntu-server'].get('username', 'tester')
            password = self.config['ubuntu-server'].get('password', 'v1ptela0212')
        else:
            hostip = '10.0.1.127'
            username = 'tester'
            password = 'v1ptela0212'

        ubuntu_obj = UbuntuSession(self.logger, username=username, passwd=password, hostip=hostip)
        addons_dir = str(Path(__file__).parents[1].joinpath('addons'))
        xml_file, ubuntu_image_local_path = default_ubuntu_service_paths()
        local_preference_ubuntu_image = pref.get("ubuntu_qcow_path")
        ubuntu_topology = self.config.get('ubuntu') or self.config.get('ubuntu-server')

        self.logger.info(
            'suite::{},reboot::{},dynamic_ubuntu::{}, Default xml_file::{}, local_preference.yaml::ubuntu_qcow_path::{}'.format(
                suite, reboot_ubuntu, dynamic_ubuntu, xml_file, local_preference_ubuntu_image
            )
        )
        # Check to see if vrt based committed ubuntu xml exists for the given suite
        if reboot_ubuntu:
            image_copied = False
            vrt_image = False
            if qcow_path and Path(qcow_path).exists():
                self.logger.info("Ubuntu image path selected based on cmd arg")
                copy_ubuntu_image(qcow_path, ubuntu_image_local_path)
                image_copied = True
            elif local_preference_ubuntu_image:
                self.logger.info("Ubuntu image path selected based on local.preference.yaml file")
                copy_ubuntu_image(local_preference_ubuntu_image, ubuntu_image_local_path)
                image_copied = True
            elif ubuntu_topology and ubuntu_topology.get("image"):
                self.logger.info("Ubuntu image path selected based on topology file")
                copy_ubuntu_image(ubuntu_topology["image"], ubuntu_image_local_path)
                image_copied = True
            else:
                vrt_image = True

            ubuntu_dir = addons_dir + '/vrt-ubuntu_services'
            ubuntu_xml_path = '{}/vrt-{}.xml'.format(ubuntu_dir, suite)
            self.logger.info('Checking xml File Present::{}'.format(ubuntu_xml_path))
            if Path(ubuntu_xml_path).is_file():
                self.logger.info("Ubuntu xml file selected based on vrt")
                try:
                    vrt_ubuntu_qcow_src_path = Path(
                        '/auto/selinux_vtest/ubuntu_services_qcow/{}/vrt-{}.qcow2'.format(suite, suite)
                    )
                    vrt_xml_file = '{}/vrt-{}.xml'.format(ubuntu_dir, suite)
                    xml_file = vrt_xml_file
                    if vrt_image:
                        self.logger.info("Ubuntu image path selected based on vrt image")
                        if 'ubuntu_services_path' in pref.keys():
                            vrt_ubuntu_qcow_src_path = Path(pref['ubuntu_services_path'])
                            fix_dst_flag = True
                        else:
                            vrt_ubuntu_qcow_src_path = Path(
                                '/auto/selinux_vtest/ubuntu_services_qcow/{}/vrt-{}.qcow2'.format(suite, suite)
                            )
                            fix_dst_flag = False
                        ubuntu_image_local_path = Paths().images() / (
                            "local_ubuntu_services/{}/vrt-{}.qcow2".format(suite, suite)
                            # "local_ubuntu_services/{}/vrt-{}.qcow2".format(suite, suite)
                        )
                        self.logger.info("Start caching remote file check util.log")
                        result_cache = caching_remote_file_with(vrt_ubuntu_qcow_src_path, ubuntu_image_local_path)
                        result_cache = caching_remote_file_with(
                            vrt_ubuntu_qcow_src_path, ubuntu_image_local_path, fix_dst_flag=fix_dst_flag
                        )
                        self.logger.info("Caching result {}".format(result_cache))
                        if result_cache != 0:
                            raise Exception("Fail to caching remote file")
                        image_copied = True
                except Exception as ex:
                    self.logger.error('Failed to copy vrt based ubuntu service qcow2 with exception : {}'.format(ex))
            elif dynamic_ubuntu:
                self.logger.info("Ubuntu xml file selected based on -dub option")
                ubuntu_dir = addons_dir + '/ubuntu'
                if suite == 'gw_vmanage_mt' or 'mt_edge' in suite:
                    xml_file = ubuntu_dir + '/ubuntu_services_mt.xml'
                else:
                    xml_file = ubuntu_dir + '/ubuntu_services.xml'
            elif ubuntu_topology:
                self.logger.info("Ubuntu xml file generated based on topology yaml file")
                xml_file = create_xml_based_on_yaml(local_qcow_path=ubuntu_image_local_path)
            else:
                self.logger.info("Ubuntu default xml file selected")

            if not image_copied:
                self.logger.info("Ubuntu default image selected.")
                Path(ubuntu_image_local_path).parent.mkdir(parents=True, exist_ok=True)
                ubuntu_default_path = '/auto/selinux_vtest/ubuntu_services_qcow/Ubuntu24_04_new.qcow2'
                if not Path(ubuntu_default_path).exists():
                    raise TestbedException(
                        "Path to default Ubuntu image does not exist: {}".format(ubuntu_default_path)
                    )
                ubuntu_md5_file = '/auto/selinux_vtest/ubuntu_services_qcow/Ubuntu24_04_new.qcow2.md5'
                copy_ubuntu_image(ubuntu_default_path, ubuntu_image_local_path, md_file=ubuntu_md5_file)
        if not ubuntu_obj.checkHandle(self, reboot_ubuntu, non_dmz, xml_file, image_path=ubuntu_image_local_path):
            self.logger.error("Couldn't get ubuntu handle")
            raise Exception(
                "Couldn't establish ssh connection with Ubuntu VM. Can't proceed with the test-suite run. Aborting!"
            )
        return ubuntu_obj

    def get_spirent_TC_version(self):
        xml_path = Path(pref['spirent']['install_dir']) / 'ILVersion.xml'
        if not xml_path.is_file():
            self.logger.info(
                "Could not get Spirent version: ILVersion.xml not present in Spirent_TestCenter_Application dir"
            )
            self.logger.info("Assuming old Spirent version 4.54")
            self.logger.info("If not 4.54 please specifiy 'version' in local.preference.yaml under 'spirent'")
            return '4.54'
        with open(str(xml_path), 'r') as file:
            xml_data = file.read()
            root = ET.fromstring(xml_data)
            version = root.attrib.get('Version')
        return version

    def bringup_spirent_vm(self):
        '''
        This proceedure brings up the spirent. It take required data from local.preference.yaml
        Assumption: The bridge interface is already present which vm can used to connect outside.

        1) If 'image_path' present in local.preference.yaml then spirent vm will use that image to bringup.

        2) Based on the 'version' given in local.preference.yaml the spirent vm will be brought up.
        If the version field is not present in the local.preference.yaml then version from
        install_dir: Spirent_TestCenter_Application_Linux/ILVersion.xml will be read
        If ILVersion.xml version is not present then it's assumed that '4.54' version as spirent vm since
        many regression tb has 4.54 and does not have ILVersion.xml under
        install_dir: ~/Spirent_TestCenter_4.54/Spirent_TestCenter_Application_Linux64Client.

        3) If version is given in local.prefernce.yaml and does not match with Spirent_TestCenter_Application_Linux version
        then version based on local.prefernce.yaml  used and same versioned Spirent_TestCenter_Application_Linux will be copiedinto install_dir.

        4) If 'dhcp: True' present in the local.preference.yaml then spirent vm will configured with dhcp.
        If 'network_bridge': 'bridge name' in the local.preference.yaml then this bridge is used for bringing up the vm to connect outside.
        If 'network_bridge' not present in local.preference.yaml then 'br0' will be used as default.

        5) Spirent image will be located in Paths().images() dir and if md5sum of local spirent image does not match with
        one in /auto/selinux_vtest/spirent_vm_img/<version> then it will be copied to local.
        Temporary copy of that image is used every time to bringup the vm.

        6) New parameters used in local.preference.yaml: Eg:
        ```
        spirent:
            image_path: /scratch/vtest/spirent/stcqemu/images/latest.img -> optional -> If not given will take image according to install_dir version
            install_dir: /scratch/vtest/spirent/linux-client/Spirent_TestCenter_Application_Linux
            chassis_ip: xx.xx.xx.xx
            server_ip: xx.xx.xx
            vstc_ip: xx.xx.xx.xx
            version: 5.04 -> optional ->  If not given will take image according to install_dir version
            dhcp: True -> default is static ip
            network_bridge: br_vms_mgmt -> default is br0
            ports:
                0: {slot: 1, port: 1, ip: 56.0.1.100, mask: 24, gateway: 56.0.1.15, type: EthernetCopper}
                1: {slot: 1, port: 2, ip: 60.0.1.100, mask: 24, gateway: 60.0.1.16, type: EthernetCopper}
                #2: {slot: 1, port: 3, ip: 57.0.1.100, mask: 24, gateway: 57.0.1.15, type: EthernetCopper}
                #3: {slot: 1, port: 4, ip: 61.0.1.100, mask: 24, gateway: 61.0.1.16, type: EthernetCopper}
            type: EthernetCopper
        ```
        '''
        spirent_vm_version_from_pref = pref['spirent'].get('version')
        if spirent_vm_version_from_pref:
            spirent_vm_version = '.'.join(str(pref['spirent'].get('version')).split(".")[:2])
            stc_appliction_local_path = Path(pref['spirent']['install_dir']).parent
            if not stc_appliction_local_path.is_dir():
                stc_appliction_local_path.mkdir(parents=True, exist_ok=True)
                copy_STC = True
            else:
                try:
                    spirent_stc_app_version = self.get_spirent_TC_version()
                    self.logger.info("Found STC Application with version {}".format(spirent_stc_app_version))
                    copy_STC = spirent_vm_version != spirent_stc_app_version
                except Exception:
                    self.logger.warning("file not found")
                    copy_STC = True
            if copy_STC:
                # check for linuxclient_version
                self.logger.info(
                    "Found version mismatch between stc application and spirent version required or folder missing"
                )
                stc_appliction_remote_path = Path(
                    '/auto/selinux_vtest/spirent_vm_img/{}/Spirent_TestCenter_{}/Spirent_TestCenter_Application_Linux'.format(
                        spirent_vm_version, spirent_vm_version
                    )
                )
                self.logger.info(
                    "copying linux stc application from {} to {}".format(
                        stc_appliction_remote_path, stc_appliction_local_path
                    )
                )
                if Path(pref['spirent']['install_dir']).is_dir():
                    self.remove_dir(pref['spirent']['install_dir'])
                shutil.copytree(str(stc_appliction_remote_path), pref['spirent']['install_dir'])
        spirent_image_path = pref['spirent'].get('image_path')
        if not spirent_image_path:
            auto_path_folder = '/auto/selinux_vtest/spirent_vm_img/'
            images_dir = Paths().images()
            if not images_dir.is_dir():
                images_dir.mkdir(parents=True, exist_ok=True)
            spirent_image_path = str(images_dir / 'spirent.img')
            if not spirent_vm_version_from_pref:
                spirent_vm_version = self.get_spirent_TC_version()
            spirent_remote_path = '{}/{}/spirent.img'.format(auto_path_folder, spirent_vm_version)
            with open('{}/{}/md5sum.txt'.format(auto_path_folder, spirent_vm_version), 'r') as f:
                spirent_remote_path_md5sum = f.read().split()[0]
            copy_file = True
            if Path(spirent_image_path).is_file():
                spirent_local_path_md5sum = self.get_md5(spirent_image_path)
                if spirent_remote_path_md5sum == spirent_local_path_md5sum:
                    self.logger.info(
                        "Spirent image {} md5sum matches with remote {}".format(spirent_image_path, spirent_remote_path)
                    )
                    self.logger.info("Not copying spirent image")
                    copy_file = False
            if copy_file:
                self.logger.info("Copying spirent image from {} to {}".format(spirent_remote_path, spirent_image_path))
                shutil.copy(spirent_remote_path, spirent_image_path)
        spirent_img_tb_path = Paths().images() / 'spirent_tmp.img'
        if spirent_img_tb_path.is_file():
            self.remove_dir(str(spirent_img_tb_path))
        self.logger.info(
            "Copying spirent image from {} to {} : temporary location".format(spirent_image_path, spirent_img_tb_path)
        )
        shutil.copy(spirent_image_path, str(spirent_img_tb_path))
        xml_dir = Paths().addons() / 'spirent_xmls'
        vnet_dir = xml_dir / 'networks'
        vm_xml_path = str(xml_dir / 'stcvm.xml')
        with open(vm_xml_path, 'r') as f:
            xmlstr = f.read()
            xmlstr = xmlstr.format(
                SPIRENT_IMAGE_PATH=str(spirent_img_tb_path),
                BRIDGE=pref['spirent'].get('network_bridge', 'br0'),
            )
        SpirentUtil(logger=self.logger).create_stc_vm(
            vnet_dir, xmlstr, self.get_ubuntu_iface_addr(self.get_ubuntu_mgmt_interface())
        )

    def use_vedge_fallback_image(self, machine, branch):
        if self.personality(machine) in ['vedge', 'linux_vedge', 'ztp']:
            if 'next' in branch:
                return True
            try:
                # Sanitize branch string by removing any non-numeric suffixes (x, X, R, etc.)
                stripped_branch = re.sub(r'[^0-9.].*$', '', branch)
                if stripped_branch and StrictVersion(stripped_branch) >= StrictVersion("20.10"):
                    return True
            except (ValueError, TypeError) as e:
                self.logger.warning(
                    f"StrictVersion comparison failed for branch '{branch}' (sanitized: '{stripped_branch}'): {e}."
                )
                pass
        return False

    def copyFromUbuntu(
        self, src_path, dst_path='/home/tester/', src_ip="", user='tester', recursive=False, password=""
    ):
        if recursive is True:
            cmd = "scp -r -o StrictHostKeyChecking=no %s@%s:%s %s" % (user, src_ip, src_path, dst_path)
        else:
            cmd = "scp -o StrictHostKeyChecking=no %s@%s:%s %s" % (user, src_ip, src_path, dst_path)
        self.logger.info(cmd)
        handle = pexpect.spawn(cmd, timeout=1800)
        try:
            handle.before = ''
            handle.after = ''
            handle.sendline(cmd)
            prompt = handle.expect(['.*assword:'])
            if prompt == 0:
                handle.sendline(password)
                handle.expect([pexpect.EOF])
            elif prompt == 1:
                handle.expect([pexpect.EOF])
            self.logger.debug(handle.before)
            self.logger.debug(handle.after)
            handle.close()
            return True
        except Exception as e:
            self.logger.error("Failed to copy to ubuntu vm: {}".format(e))
            self.logger.info("Output: {}\n{}".format(handle.before, handle.after))
            handle.close()
            return False

    def enable_fips_mode_during_bringup(self):
        # type: () -> None
        """Enable FIPS mode during testbed bringup on selected machines."""
        if not isinstance(self.enable_fips, list):
            self.logger.debug("No devices requested to enable FIPS mode - procedure will be skipped")
            self.logger.debug(
                "enable_fips: {} ({}), expecting list of hostnames".format(self.enable_fips, type(self.enable_fips))
            )
            return

        all_machines = self.machines()
        machines = []
        # all cedges in topology requested by specifying bare -fips
        if self.enable_fips[0] == 'all':
            for m in all_machines:
                if self.is_cedge(m):
                    machines.append(m)
        else:
            for machine in self.enable_fips:
                if machine not in all_machines:
                    self.logger.warning("Enable FIPS mode: requested machine {} not found in topology")
                else:
                    machines.append(machine)
        self.enable_fips_mode_on_machines(machines)

    def enable_fips_mode_on_machines(self, machines):
        # type: (List[str]) -> None
        """Enable FIPS mode on provided machines.

        Procedure is done in parallel on selected machines.

        Args:
            machines: list of hostnames on which FIPS mode should be enabled
        """
        if not machines:
            self.logger.warning("List of machines to enable FIPS mode is empty")
            return

        self.logger.info("Enabling FIPS mode on: {}".format(", ".join(machines)))

        threads = []
        for machine in machines:
            confd = self.create_confd_session(machine)
            thread = Thread(target=confd.enable_fips_mode, args=(machine,))
            thread.start()
            threads.append(thread)

        for thread in threads:
            thread.join()
        self.logger.info("Enabling FIPS mode completed")

    def check_hw_cedge_bootstrap(self, machine, session):
        self.cedge_stop_pnp(machine, session)
        self.go_to_ios_prompt(machine, session)
        self.logger.info(
            "{}: check loading of bootstrap".format(
                machine,
            )
        )
        self.setup_machine_terminal_and_logging(session)
        session.sendline("show logging | include bootstrap|vip-confd-startup")
        result = session.expect(["LOAD_DAY0_CONFIG=true", "LOAD_DAY0_CONFIG=false", pexpect.TIMEOUT], timeout=5)
        if result == 0:
            self.logger.info("{}: bootstrap flag true - {} ".format(machine, session.after))
        elif result == 1:
            self.logger.info("{}: bootstrap flag false - {} ".format(machine, session.after))
        result = session.expect(["Loading day-0 user bootstrap config", pexpect.TIMEOUT], timeout=5)
        if result == 0:
            self.logger.info("{}: loading bootstrap config - {} ".format(machine, session.after))
        else:
            self.logger.info("{}: loading bootstrap config log missing".format(machine))
        result = session.expect([r"Successfully extracted .*ciscosdwan.*\.cfg", pexpect.TIMEOUT], timeout=5)
        if result == 0:
            self.logger.info("{}: bootstrap extracted - {} ".format(machine, session.after))
        else:
            self.logger.info("{}: bootstrap extracted log missing".format(machine))
        result = session.expect(["Loading ciscosdwan.* bootstrap failed", pexpect.TIMEOUT], timeout=5)
        if result == 0:
            self.logger.error("{}: loading bootstrap failed - {} ".format(machine, session.after))
            raise TestbedException("{}".format(session.after))

